static int metal_profile_enabled(const uocr_metal_context *ctx) {
    return ctx != NULL && uocr_profile_is_enabled(ctx->profile);
}

static void metal_profile_add_event_now(const uocr_metal_context *ctx, const char *name, uint64_t start_ns) {
    if (metal_profile_enabled(ctx)) {
        uocr_profile_add_event_now(ctx->profile, name, start_ns);
    }
}

static void metal_profile_add_event_now_f(const uocr_metal_context *ctx, uint64_t start_ns, const char *fmt, ...) {
    if (!metal_profile_enabled(ctx) || fmt == NULL) {
        return;
    }
    char name[UOCR_PROFILE_EVENT_NAME_SIZE];
    va_list ap;
    va_start(ap, fmt);
    (void)vsnprintf(name, sizeof(name), fmt, ap);
    va_end(ap);
    name[sizeof(name) - 1u] = '\0';
    uocr_profile_add_event_now(ctx->profile, name, start_ns);
}

static void metal_profile_add_event_ms(const uocr_metal_context *ctx, const char *name, double elapsed_ms) {
    if (metal_profile_enabled(ctx)) {
        uocr_profile_add_event_ms(ctx->profile, name, elapsed_ms);
    }
}

static void metal_profile_count_buffer(const uocr_metal_context *ctx, uint64_t bytes) {
    if (metal_profile_enabled(ctx)) {
        uocr_profile_add_metal_buffer_allocation(ctx->profile, bytes);
    }
}

static int metal_memory_reserve(uocr_metal_context *ctx,
                                uocr_memory_category category,
                                uint64_t bytes,
                                const char *label,
                                char *error,
                                size_t error_size) {
    if (ctx == NULL || ctx->memory_tracker == NULL || bytes == 0u) {
        return 1;
    }
    const int status = uocr_memory_reserve(ctx->memory_tracker, category, bytes);
    if (status != UOCR_OK) {
        return metal_fail(error,
                          error_size,
                          "failed to account Metal %s memory (%llu bytes): %s",
                          label != NULL ? label : "buffer",
                          (unsigned long long)bytes,
                          uocr_status_string(status));
    }
    return 1;
}

static void metal_memory_release(uocr_metal_context *ctx, uocr_memory_category category, uint64_t bytes) {
    if (ctx != NULL && ctx->memory_tracker != NULL && bytes != 0u) {
        (void)uocr_memory_release(ctx->memory_tracker, category, bytes);
    }
}

static void metal_profile_count_buffer_if_allocated(const uocr_metal_context *ctx, id<MTLBuffer> buffer, NSUInteger bytes) {
    if (buffer != nil) {
        metal_profile_count_buffer(ctx, (uint64_t)bytes);
    }
}

static id<MTLBuffer> metal_new_buffer_with_length(uocr_metal_context *ctx, NSUInteger length, MTLResourceOptions options) {
    if (ctx == NULL || ctx->device == nil) {
        return nil;
    }
    id<MTLBuffer> buffer = [ctx->device newBufferWithLength:length options:options];
    metal_profile_count_buffer_if_allocated(ctx, buffer, length);
    return buffer;
}

static id<MTLBuffer> metal_new_buffer_with_bytes(uocr_metal_context *ctx,
                                                 const void *bytes,
                                                 NSUInteger length,
                                                 MTLResourceOptions options) {
    if (ctx == NULL || ctx->device == nil) {
        return nil;
    }
    id<MTLBuffer> buffer = [ctx->device newBufferWithBytes:bytes length:length options:options];
    metal_profile_count_buffer_if_allocated(ctx, buffer, length);
    return buffer;
}

static id<MTLBuffer> metal_new_buffer_with_bytes_no_copy(uocr_metal_context *ctx,
                                                         void *bytes,
                                                         NSUInteger length,
                                                         MTLResourceOptions options,
                                                         void (^deallocator)(void *, NSUInteger)) {
    if (ctx == NULL || ctx->device == nil) {
        return nil;
    }
    id<MTLBuffer> buffer = [ctx->device newBufferWithBytesNoCopy:bytes
                                                          length:length
                                                         options:options
                                                     deallocator:deallocator];
    metal_profile_count_buffer_if_allocated(ctx, buffer, length);
    return buffer;
}

/* Legacy helpers still allocate their own command buffer and call the wait
 * macro directly.  When a higher-level stage has opened active_command_buffer,
 * metal_new_command_buffer() returns that batch buffer and this macro records a
 * deferred wait instead of committing in the middle of the command graph.
 */
#define UOCR_METAL_COMMIT_AND_WAIT_PROFILED(ctx_, cb_)                                  \
    do {                                                                                 \
        uocr_metal_context *uocr_metal_wait_ctx__ = (ctx_);                              \
        id<MTLCommandBuffer> uocr_metal_wait_cb__ = (cb_);                               \
        if (uocr_metal_wait_cb__ != nil && uocr_metal_wait_ctx__ != NULL &&               \
            uocr_metal_wait_ctx__->active_command_buffer == uocr_metal_wait_cb__) {       \
            if (metal_profile_enabled(uocr_metal_wait_ctx__)) {                           \
                uocr_profile_add_event_ms(uocr_metal_wait_ctx__->profile,                 \
                                          "metal.command_buffer_wait_deferred",           \
                                          0.0);                                           \
            }                                                                            \
        } else {                                                                         \
            const uint64_t uocr_metal_wait_start_ns__ = uocr_profile_now_ns();            \
            [uocr_metal_wait_cb__ commit];                                               \
            [uocr_metal_wait_cb__ waitUntilCompleted];                                   \
            if (metal_profile_enabled(uocr_metal_wait_ctx__)) {                           \
                uocr_profile_add_metal_command_buffer_wait(uocr_metal_wait_ctx__->profile); \
                uocr_profile_add_event_now(uocr_metal_wait_ctx__->profile,                \
                                           "metal.command_buffer_wait",                  \
                                           uocr_metal_wait_start_ns__);                   \
            }                                                                            \
        }                                                                                \
    } while (0)

