static void metal_remove_transient_retained_object(NSMutableArray *retained_objects, id object) {
    if (retained_objects == nil || object == nil) {
        return;
    }
    const NSUInteger index = [retained_objects indexOfObjectIdenticalTo:object];
    if (index != NSNotFound) {
        [retained_objects removeObjectAtIndex:index];
    }
}

static int metal_retain_transient_until_completed(uocr_metal_context *ctx,
                                                  id<MTLCommandBuffer> command_buffer,
                                                  id object,
                                                  char *error,
                                                  size_t error_size) {
    if (ctx == NULL || ctx->transient_retains == nil || command_buffer == nil || object == nil) {
        return metal_fail(error, error_size, "invalid Metal transient retain request");
    }

    NSMutableArray *retained_objects = [ctx->transient_retains retain];
    @synchronized(retained_objects) {
        [retained_objects addObject:object];
    }
    if (metal_profile_enabled(ctx)) {
        uocr_profile_add_metal_transient_retain_object(ctx->profile);
    }
    [command_buffer addCompletedHandler:^(id<MTLCommandBuffer> completed) {
        (void)completed;
        @synchronized(retained_objects) {
            metal_remove_transient_retained_object(retained_objects, object);
        }
        [retained_objects release];
    }];
    return 1;
}

static int metal_retain_mps_matmul_arrays_until_completed(uocr_metal_context *ctx,
                                                          id<MTLCommandBuffer> command_buffer,
                                                          id input_array,
                                                          id weight_array,
                                                          id output_array,
                                                          char *error,
                                                          size_t error_size) {
    if (ctx == NULL || ctx->transient_retains == nil || command_buffer == nil ||
        input_array == nil || weight_array == nil || output_array == nil) {
        return metal_fail(error, error_size, "invalid Metal MPS matmul transient retain request");
    }

    NSMutableArray *retained_objects = [ctx->transient_retains retain];
    @synchronized(retained_objects) {
        [retained_objects addObject:input_array];
        [retained_objects addObject:weight_array];
        [retained_objects addObject:output_array];
    }
    if (metal_profile_enabled(ctx)) {
        uocr_profile_add_metal_transient_retain_object(ctx->profile);
    }
    [command_buffer addCompletedHandler:^(id<MTLCommandBuffer> completed) {
        (void)completed;
        @synchronized(retained_objects) {
            metal_remove_transient_retained_object(retained_objects, input_array);
            metal_remove_transient_retained_object(retained_objects, weight_array);
            metal_remove_transient_retained_object(retained_objects, output_array);
        }
        [retained_objects release];
    }];
    return 1;
}

static id<MTLComputePipelineState> metal_get_pipeline(uocr_metal_context *ctx,
                                                       const char *function_name,
                                                       char *error,
                                                       size_t error_size) {
    if (ctx == NULL || function_name == NULL || function_name[0] == '\0') {
        (void)metal_fail(error, error_size, "invalid Metal pipeline request");
        return nil;
    }

    NSString *key = [NSString stringWithUTF8String:function_name];
    id<MTLComputePipelineState> cached = [ctx->pipeline_cache objectForKey:key];
    if (cached != nil) {
        return cached;
    }

    NSError *ns_error = nil;
    id<MTLFunction> fn = [ctx->library newFunctionWithName:key];
    if (fn == nil) {
        (void)metal_fail(error, error_size, "Metal function %s not found", function_name);
        return nil;
    }

    id<MTLComputePipelineState> pipeline = [ctx->device newComputePipelineStateWithFunction:fn error:&ns_error];
    [fn release];
    if (pipeline == nil) {
        (void)metal_fail(error,
                         error_size,
                         "Metal pipeline %s failed: %s",
                         function_name,
                         [[ns_error localizedDescription] UTF8String]);
        return nil;
    }

    [ctx->pipeline_cache setObject:pipeline forKey:key];
    [pipeline release];
    return [ctx->pipeline_cache objectForKey:key];
}

static NSUInteger metal_power2_threadgroup_width(NSUInteger preferred, NSUInteger max_allowed) {
    NSUInteger width = 1u;
    if (preferred == 0u || max_allowed == 0u) {
        return width;
    }
    NSUInteger limit = preferred < max_allowed ? preferred : max_allowed;
    while (width <= limit / 2u) {
        width *= 2u;
    }
    return width;
}

static void metal_output_tile_threadgroup_2d(NSUInteger max_total_threads,
                                             NSUInteger *out_spatial_threads,
                                             NSUInteger *out_channel_threads) {
    const NSUInteger preferred_spatial = 16u;
    const NSUInteger preferred_channels = 16u;
    const NSUInteger max_threads = max_total_threads == 0u ? 1u : max_total_threads;
    NSUInteger spatial_threads = preferred_spatial <= max_threads ? preferred_spatial : max_threads;
    if (spatial_threads == 0u) {
        spatial_threads = 1u;
    }
    NSUInteger channel_limit = max_threads / spatial_threads;
    if (channel_limit == 0u) {
        channel_limit = 1u;
    }
    const NSUInteger channel_threads = metal_power2_threadgroup_width(preferred_channels, channel_limit);
    if (out_spatial_threads != NULL) {
        *out_spatial_threads = spatial_threads;
    }
    if (out_channel_threads != NULL) {
        *out_channel_threads = channel_threads;
    }
}

int uocr_metal_is_available(void) {
    @autoreleasepool {
        id<MTLDevice> device = MTLCreateSystemDefaultDevice();
        if (device != nil) {
            [device release];
            return 1;
        }
        return 0;
    }
}

const char *uocr_metal_backend_name(void) {
    return "metal";
}

uint64_t uocr_metal_recommended_working_set_size(void) {
    @autoreleasepool {
        id<MTLDevice> device = MTLCreateSystemDefaultDevice();
        if (device == nil) {
            return 0u;
        }
        const uint64_t size = (uint64_t)[device recommendedMaxWorkingSetSize];
        [device release];
        return size;
    }
}

uint64_t uocr_metal_default_memory_budget_bytes(uint64_t recommended_working_set_bytes) {
    if (recommended_working_set_bytes == 0u) {
        return 0u;
    }
    /* The runtime estimate already includes its own safety margin; keep most
     * of Metal's recommendation available while still leaving OS/driver room.
     */
    return (recommended_working_set_bytes / 100u) * 95u + ((recommended_working_set_bytes % 100u) * 95u) / 100u;
}

uocr_metal_context *uocr_metal_context_create(const char *resource_path, char *error, size_t error_size) {
    metal_clear_error(error, error_size);

    @autoreleasepool {
        uocr_metal_context *ctx = (uocr_metal_context *)calloc(1u, sizeof(*ctx));
        if (ctx == NULL) {
            (void)metal_fail(error, error_size, "failed to allocate Metal context");
            return NULL;
        }

        ctx->device = MTLCreateSystemDefaultDevice();
        if (ctx->device == nil) {
            (void)metal_fail(error, error_size, "Metal device not available");
            uocr_metal_context_destroy(ctx);
            return NULL;
        }

        ctx->queue = [ctx->device newCommandQueue];
        if (ctx->queue == nil) {
            (void)metal_fail(error, error_size, "failed to create Metal command queue");
            uocr_metal_context_destroy(ctx);
            return NULL;
        }

        ctx->pipeline_cache = [[NSMutableDictionary alloc] init];
        if (ctx->pipeline_cache == nil) {
            (void)metal_fail(error, error_size, "failed to allocate Metal pipeline cache");
            uocr_metal_context_destroy(ctx);
            return NULL;
        }

        ctx->mps_descriptor_cache = [[NSMutableDictionary alloc] init];
        if (ctx->mps_descriptor_cache == nil) {
            (void)metal_fail(error, error_size, "failed to allocate Metal MPS descriptor cache");
            uocr_metal_context_destroy(ctx);
            return NULL;
        }

        ctx->mps_weight_ndarray_cache = [[NSMutableDictionary alloc] init];
        if (ctx->mps_weight_ndarray_cache == nil) {
            (void)metal_fail(error, error_size, "failed to allocate Metal MPS weight NDArray cache");
            uocr_metal_context_destroy(ctx);
            return NULL;
        }

        ctx->mps_workspace_ndarray_cache = [[NSMutableDictionary alloc] init];
        if (ctx->mps_workspace_ndarray_cache == nil) {
            (void)metal_fail(error, error_size, "failed to allocate Metal MPS workspace NDArray cache");
            uocr_metal_context_destroy(ctx);
            return NULL;
        }

        ctx->transient_retains = [[NSMutableArray alloc] init];
        if (ctx->transient_retains == nil) {
            (void)metal_fail(error, error_size, "failed to allocate Metal transient-retain array");
            uocr_metal_context_destroy(ctx);
            return NULL;
        }

        char metallib_diagnostic[512];
        memset(metallib_diagnostic, 0, sizeof(metallib_diagnostic));
        ctx->library = load_precompiled_library(ctx->device, resource_path, metallib_diagnostic, sizeof(metallib_diagnostic));

        if (ctx->library == nil) {
#if UOCR_METAL_RUNTIME_COMPILE
            NSString *source = load_runtime_source(resource_path, error, error_size);
            if (source == nil) {
                uocr_metal_context_destroy(ctx);
                return NULL;
            }

            MTLCompileOptions *options = [MTLCompileOptions new];
            NSError *compile_error = nil;
            ctx->library = [ctx->device newLibraryWithSource:source options:options error:&compile_error];
            [options release];
            if (ctx->library == nil) {
                (void)metal_fail(error,
                                 error_size,
                                 "Metal shader compilation failed after %s: %s",
                                 metallib_diagnostic[0] != '\0' ? metallib_diagnostic : "precompiled Metal library was unavailable",
                                 [[compile_error localizedDescription] UTF8String]);
                uocr_metal_context_destroy(ctx);
                return NULL;
            }
#else
            (void)metal_fail(error,
                             error_size,
                             "Metal runtime source compilation is disabled and %s",
                             metallib_diagnostic[0] != '\0' ? metallib_diagnostic : "precompiled Metal library was unavailable");
            uocr_metal_context_destroy(ctx);
            return NULL;
#endif
        }

        return ctx;
    }
}

static uint64_t metal_device_max_buffer_length(id<MTLDevice> device) {
    if (device == nil) {
        return 0u;
    }
    const NSUInteger max_length = [device maxBufferLength];
    return (uint64_t)max_length;
}

static int payload_tensor_count(const uocr_model_file *model, uint32_t *out_count) {
    if (model == NULL || out_count == NULL) {
        return 0;
    }
    uint32_t count = 0u;
    for (uint32_t i = 0u; i < model->tensor_count; ++i) {
        const uocr_tensor_entry *tensor = &model->tensors[i];
        if (tensor->usage != UOCR_TENSOR_USAGE_OMITTED_WITH_REASON && tensor->payload_size != 0u) {
            ++count;
        }
    }
    *out_count = count;
    return 1;
}

static uocr_metal_payload_span *build_payload_spans(const uocr_model_file *model,
                                                     uint64_t page_size,
                                                     uint32_t payload_count,
                                                     char *error,
                                                     size_t error_size) {
    uocr_metal_payload_span *spans = (uocr_metal_payload_span *)calloc(payload_count, sizeof(spans[0]));
    if (spans == NULL) {
        (void)metal_fail(error, error_size, "failed to allocate Metal model payload span plan");
        return NULL;
    }

    uint32_t out = 0u;
    for (uint32_t i = 0u; i < model->tensor_count; ++i) {
        const uocr_tensor_entry *tensor = &model->tensors[i];
        if (tensor->usage == UOCR_TENSOR_USAGE_OMITTED_WITH_REASON || tensor->payload_size == 0u) {
            continue;
        }

        uint64_t payload_end = 0u;
        uint64_t page_end = 0u;
        if (!checked_add_u64(tensor->payload_offset, tensor->payload_size, &payload_end) ||
            !align_up_u64_checked(payload_end, page_size, &page_end)) {
            free(spans);
            (void)metal_fail(error,
                             error_size,
                             "tensor %u payload range overflows during Metal view planning",
                             tensor->id);
            return NULL;
        }
        if (page_end > (uint64_t)model->size) {
            page_end = (uint64_t)model->size;
        }
        if (page_end < payload_end) {
            free(spans);
            (void)metal_fail(error,
                             error_size,
                             "tensor %u payload end exceeds mapped file during Metal view planning",
                             tensor->id);
            return NULL;
        }

        spans[out].tensor_index = i;
        spans[out].tensor_id = tensor->id;
        spans[out].payload_start = tensor->payload_offset;
        spans[out].payload_end = payload_end;
        spans[out].page_start = align_down_u64(tensor->payload_offset, page_size);
        spans[out].page_end = page_end;
        ++out;
    }

    qsort(spans, payload_count, sizeof(spans[0]), payload_span_compare);
    return spans;
}

static int append_model_view_plan(uocr_metal_model_view **views,
                                  uint32_t *count,
                                  uint32_t *capacity,
                                  uint64_t start,
                                  uint64_t end,
                                  char *error,
                                  size_t error_size) {
    if (views == NULL || count == NULL || capacity == NULL || end <= start) {
        return metal_fail(error, error_size, "invalid Metal model view plan append");
    }
    if (*count == *capacity) {
        const uint32_t new_capacity = *capacity == 0u ? 4u : *capacity * 2u;
        if (new_capacity <= *capacity) {
            return metal_fail(error, error_size, "too many Metal model views");
        }
        uocr_metal_model_view *new_views = (uocr_metal_model_view *)realloc(*views, (size_t)new_capacity * sizeof(new_views[0]));
        if (new_views == NULL) {
            return metal_fail(error, error_size, "failed to grow Metal model view plan");
        }
        memset(new_views + *capacity, 0, (size_t)(new_capacity - *capacity) * sizeof(new_views[0]));
        *views = new_views;
        *capacity = new_capacity;
    }
    (*views)[*count].file_offset = start;
    (*views)[*count].length = end - start;
    (*views)[*count].buffer = nil;
    ++(*count);
    return 1;
}

static uocr_metal_model_view *build_model_view_plan(const uocr_metal_payload_span *spans,
                                                     uint32_t payload_count,
                                                     uint64_t max_buffer_length,
                                                     uint32_t *out_view_count,
                                                     char *error,
                                                     size_t error_size) {
    *out_view_count = 0u;
    if (payload_count == 0u) {
        return NULL;
    }

    uocr_metal_model_view *views = NULL;
    uint32_t view_count = 0u;
    uint32_t view_capacity = 0u;
    uint64_t current_start = 0u;
    uint64_t current_end = 0u;
    int have_current = 0;

    for (uint32_t i = 0u; i < payload_count; ++i) {
        const uocr_metal_payload_span *span = &spans[i];
        if (span->page_end <= span->page_start) {
            free(views);
            (void)metal_fail(error, error_size, "tensor %u has empty page span", span->tensor_id);
            return NULL;
        }
        if (span->page_end - span->page_start > max_buffer_length) {
            free(views);
            (void)metal_fail(error,
                             error_size,
                             "tensor %u requires %llu byte no-copy view, exceeding Metal maxBufferLength %llu",
                             span->tensor_id,
                             (unsigned long long)(span->page_end - span->page_start),
                             (unsigned long long)max_buffer_length);
            return NULL;
        }

        if (!have_current) {
            current_start = span->page_start;
            current_end = span->page_end;
            have_current = 1;
            continue;
        }

        uint64_t merged_end = current_end;
        if (span->page_end > merged_end) {
            merged_end = span->page_end;
        }
        if (merged_end - current_start <= max_buffer_length) {
            current_end = merged_end;
            continue;
        }

        if (!append_model_view_plan(&views, &view_count, &view_capacity, current_start, current_end, error, error_size)) {
            free(views);
            return NULL;
        }
        current_start = span->page_start;
        current_end = span->page_end;
    }

    if (have_current && !append_model_view_plan(&views, &view_count, &view_capacity, current_start, current_end, error, error_size)) {
        free(views);
        return NULL;
    }

    *out_view_count = view_count;
    return views;
}

static int find_view_for_payload(const uocr_metal_model_view *views,
                                 uint32_t view_count,
                                 uint64_t payload_start,
                                 uint64_t payload_size,
                                 uint32_t *out_view_index,
                                 uint64_t *out_inner_offset) {
    uint64_t payload_end = 0u;
    if (!checked_add_u64(payload_start, payload_size, &payload_end)) {
        return 0;
    }
    for (uint32_t i = 0u; i < view_count; ++i) {
        const uint64_t view_start = views[i].file_offset;
        const uint64_t view_end = view_start + views[i].length;
        if (payload_start >= view_start && payload_end <= view_end) {
            *out_view_index = i;
            *out_inner_offset = payload_start - view_start;
            return 1;
        }
    }
    return 0;
}

static void metal_invalidate_decoder_binding_cache(uocr_metal_context *ctx, const char *reason);
static int metal_refresh_decoder_binding_cache(uocr_metal_context *ctx,
                                               const uocr_model_file *model,
                                               char *error,
                                               size_t error_size);
static void metal_invalidate_vision_binding_cache(uocr_metal_context *ctx, const char *reason);
static int metal_refresh_vision_binding_cache(uocr_metal_context *ctx,
                                              const uocr_model_file *model,
                                              char *error,
                                              size_t error_size);
static int metal_prebuild_mps_model_objects(uocr_metal_context *ctx,
                                            const uocr_model_file *model,
                                            char *error,
                                            size_t error_size);
static int metal_vision_weight_cache_build_direct(const uocr_metal_vision_binding_cache *binding_cache,
                                                  uocr_metal_vision_weights_f16 *out_weights,
                                                  char *error,
                                                  size_t error_size);
static const uocr_metal_vision_weights_f16 *metal_require_vision_weights_f16(const uocr_metal_context *ctx,
                                                                             char *error,
                                                                             size_t error_size);
static int metal_sam_transformer_block_has_weights(const uocr_metal_sam_transformer_block_f16 *block);
static int metal_clip_transformer_block_has_weights(const uocr_metal_clip_transformer_block_f16 *block);
static void metal_copy_error_detail(char *detail, size_t detail_size, const char *error);

static uocr_metal_tensor_binding_internal *build_tensor_bindings(const uocr_model_file *model,
                                                                  const uocr_metal_model_view *views,
                                                                  uint32_t view_count,
                                                                  uint32_t binding_count,
                                                                  char *error,
                                                                  size_t error_size) {
    if (binding_count == 0u) {
        return NULL;
    }
    uocr_metal_tensor_binding_internal *bindings =
        (uocr_metal_tensor_binding_internal *)calloc(binding_count, sizeof(bindings[0]));
    if (bindings == NULL) {
        (void)metal_fail(error, error_size, "failed to allocate Metal tensor binding table");
        return NULL;
    }

    uint32_t out = 0u;
    for (uint32_t i = 0u; i < model->tensor_count; ++i) {
        const uocr_tensor_entry *tensor = &model->tensors[i];
        if (tensor->usage == UOCR_TENSOR_USAGE_OMITTED_WITH_REASON || tensor->payload_size == 0u) {
            continue;
        }
        uint32_t view_index = 0u;
        uint64_t inner_offset = 0u;
        if (!find_view_for_payload(views, view_count, tensor->payload_offset, tensor->payload_size, &view_index, &inner_offset)) {
            free(bindings);
            (void)metal_fail(error,
                             error_size,
                             "tensor %u was not covered by any Metal model view",
                             tensor->id);
            return NULL;
        }
        bindings[out].tensor_id = tensor->id;
        bindings[out].view_index = view_index;
        bindings[out].inner_offset = inner_offset;
        bindings[out].payload_size = tensor->payload_size;
        ++out;
    }
    return bindings;
}

static void metal_clear_mps_weight_ndarray_cache(uocr_metal_context *ctx) {
    if (ctx != NULL && ctx->mps_weight_ndarray_cache != nil) {
        [ctx->mps_weight_ndarray_cache removeAllObjects];
    }
}

static void metal_clear_mps_workspace_ndarray_cache(uocr_metal_context *ctx) {
    if (ctx == NULL) {
        return;
    }
    if (ctx->mps_workspace_ndarray_cache != nil) {
        [ctx->mps_workspace_ndarray_cache removeAllObjects];
    }
    ++ctx->mps_workspace_cache_generation;
    ctx->mps_runtime_workspace_prebuild_generation = 0u;
    ctx->mps_runtime_workspace_prebuild_token_count = 0u;
    ctx->mps_vision_workspace_prebuild_generation = 0u;
    ctx->mps_vision_workspace_prebuild_shape_mask = 0u;
    ctx->mps_vision_workspace_prebuild_projected_row_capacity = 0u;
    ctx->mps_vision_workspace_prebuild_local_view_count = 0u;
    ctx->mps_vision_workspace_prebuild_global_view_count = 0u;
}

void uocr_metal_context_unmap_model(uocr_metal_context *ctx) {
    if (ctx == NULL) {
        return;
    }
    @autoreleasepool {
        metal_clear_mps_weight_ndarray_cache(ctx);
        if (ctx->model_views != NULL) {
            for (uint32_t i = 0u; i < ctx->model_view_count; ++i) {
                [ctx->model_views[i].buffer release];
                ctx->model_views[i].buffer = nil;
            }
        }
        free(ctx->model_views);
        ctx->model_views = NULL;
        ctx->model_view_count = 0u;
        free(ctx->tensor_bindings);
        ctx->tensor_bindings = NULL;
        ctx->tensor_binding_count = 0u;
        metal_invalidate_decoder_binding_cache(ctx, "no mapped model");
        metal_invalidate_vision_binding_cache(ctx, "no mapped model");
        ctx->model_view_bytes = 0u;
        ctx->last_model_warmup_bytes = 0u;
    }
}

int uocr_metal_context_map_model(uocr_metal_context *ctx, const uocr_model_file *model, char *error, size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || model == NULL || model->data == NULL || model->tensors == NULL) {
        return metal_fail(error, error_size, "Metal model mapping requires a context and loaded .uocr model");
    }

    const uocr_section_entry *tensor_data = uocr_model_file_find_section(model, UOCR_SECTION_TENSOR_DATA);
    if (tensor_data == NULL || tensor_data->size == 0u) {
        return metal_fail(error, error_size, ".uocr model has no tensor-data section to map");
    }

    uint32_t payload_count = 0u;
    if (!payload_tensor_count(model, &payload_count) || payload_count == 0u) {
        return metal_fail(error, error_size, ".uocr model has no tensor payloads to map");
    }

    long page_size_long = sysconf(_SC_PAGESIZE);
    if (page_size_long <= 0) {
        page_size_long = (long)UOCR_TENSOR_DATA_ALIGNMENT;
    }
    const uint64_t page_size = (uint64_t)page_size_long;
    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (max_buffer_length < page_size) {
        return metal_fail(error,
                          error_size,
                          "Metal maxBufferLength %llu is smaller than page size %llu",
                          (unsigned long long)max_buffer_length,
                          (unsigned long long)page_size);
    }

    uocr_metal_payload_span *spans = build_payload_spans(model, page_size, payload_count, error, error_size);
    if (spans == NULL) {
        return 0;
    }

    uint32_t view_count = 0u;
    uocr_metal_model_view *views = build_model_view_plan(spans, payload_count, max_buffer_length, &view_count, error, error_size);
    free(spans);
    if (views == NULL || view_count == 0u) {
        free(views);
        return 0;
    }

    uocr_metal_tensor_binding_internal *bindings =
        build_tensor_bindings(model, views, view_count, payload_count, error, error_size);
    if (bindings == NULL) {
        free(views);
        return 0;
    }

    @autoreleasepool {
        for (uint32_t i = 0u; i < view_count; ++i) {
            if (views[i].length > (uint64_t)SIZE_MAX) {
                free(bindings);
                free(views);
                return metal_fail(error, error_size, "Metal model view %u is too large for this platform", i);
            }
            void *view_ptr = (void *)(uintptr_t)(model->data + views[i].file_offset);
            id<MTLBuffer> buffer = metal_new_buffer_with_bytes_no_copy(ctx, view_ptr, (NSUInteger)views[i].length, MTLResourceStorageModeShared, nil);
            if (buffer == nil) {
                for (uint32_t j = 0u; j < i; ++j) {
                    [views[j].buffer release];
                    views[j].buffer = nil;
                }
                free(bindings);
                free(views);
                return metal_fail(error,
                                  error_size,
                                  "newBufferWithBytesNoCopy failed for model view %u at file offset %llu length %llu",
                                  i,
                                  (unsigned long long)views[i].file_offset,
                                  (unsigned long long)views[i].length);
            }
            buffer.label = [NSString stringWithFormat:@"uocr_model_view_%u", i];
            views[i].buffer = buffer;
        }
    }

    uocr_metal_context_unmap_model(ctx);
    ctx->model_views = views;
    ctx->model_view_count = view_count;
    ctx->tensor_bindings = bindings;
    ctx->tensor_binding_count = payload_count;
    ctx->model_view_bytes = tensor_data->size;

    char decoder_error[256];
    memset(decoder_error, 0, sizeof(decoder_error));
    if (!metal_refresh_decoder_binding_cache(ctx, model, decoder_error, sizeof(decoder_error))) {
        metal_invalidate_decoder_binding_cache(ctx,
                                               decoder_error[0] != '\0' ? decoder_error : "decoder tensor bindings are not available");
    }
    char vision_error[256];
    memset(vision_error, 0, sizeof(vision_error));
    if (!metal_refresh_vision_binding_cache(ctx, model, vision_error, sizeof(vision_error))) {
        metal_invalidate_vision_binding_cache(ctx,
                                              vision_error[0] != '\0' ? vision_error : "vision tensor bindings are not available");
    }

    char mps_error[256];
    memset(mps_error, 0, sizeof(mps_error));
    if (!metal_prebuild_mps_model_objects(ctx, model, mps_error, sizeof(mps_error))) {
        uocr_metal_context_unmap_model(ctx);
        return metal_fail(error,
                          error_size,
                          "failed to prebuild Metal MPS model objects: %s",
                          mps_error[0] != '\0' ? mps_error : "unknown error");
    }

    metal_clear_error(error, error_size);
    return 1;
}

uint32_t uocr_metal_context_model_view_count(const uocr_metal_context *ctx) {
    return ctx != NULL ? ctx->model_view_count : 0u;
}

uint32_t uocr_metal_context_tensor_binding_count(const uocr_metal_context *ctx) {
    return ctx != NULL ? ctx->tensor_binding_count : 0u;
}

uint32_t uocr_metal_context_library_function_count(const uocr_metal_context *ctx) {
    @autoreleasepool {
        if (ctx == NULL || ctx->library == nil) {
            return 0u;
        }
        return (uint32_t)[[ctx->library functionNames] count];
    }
}

uint32_t uocr_metal_context_pipeline_cache_count(const uocr_metal_context *ctx) {
    @autoreleasepool {
        if (ctx == NULL || ctx->pipeline_cache == nil) {
            return 0u;
        }
        return (uint32_t)[ctx->pipeline_cache count];
    }
}

int uocr_metal_context_compile_all_pipelines(uocr_metal_context *ctx,
                                             uint32_t *out_pipeline_count,
                                             char *error,
                                             size_t error_size) {
    metal_clear_error(error, error_size);
    if (out_pipeline_count != NULL) {
        *out_pipeline_count = 0u;
    }
    if (ctx == NULL || ctx->library == nil) {
        return metal_fail(error, error_size, "invalid Metal context for pipeline compilation");
    }

    @autoreleasepool {
        NSArray<NSString *> *names = [[ctx->library functionNames] sortedArrayUsingSelector:@selector(compare:)];
        if ([names count] == 0u) {
            return metal_fail(error, error_size, "Metal library contains no compute functions");
        }
        for (NSString *name in names) {
            const char *function_name = [name UTF8String];
            if (function_name == NULL || function_name[0] == '\0') {
                return metal_fail(error, error_size, "Metal library contains an invalid function name");
            }
            if (metal_get_pipeline(ctx, function_name, error, error_size) == nil) {
                return 0;
            }
        }
        if (out_pipeline_count != NULL) {
            *out_pipeline_count = (uint32_t)[ctx->pipeline_cache count];
        }
    }
    metal_clear_error(error, error_size);
    return 1;
}

uint64_t uocr_metal_context_model_view_bytes(const uocr_metal_context *ctx) {
    return ctx != NULL ? ctx->model_view_bytes : 0u;
}

int uocr_metal_context_get_model_view_info(const uocr_metal_context *ctx,
                                           uint32_t view_index,
                                           uocr_metal_model_view_info *out_info) {
    if (ctx == NULL || out_info == NULL || view_index >= ctx->model_view_count) {
        return 0;
    }
    out_info->file_offset = ctx->model_views[view_index].file_offset;
    out_info->length = ctx->model_views[view_index].length;
    return 1;
}

static const uocr_metal_tensor_binding_internal *metal_find_tensor_binding(const uocr_metal_context *ctx,
                                                                            uint32_t tensor_id) {
    if (ctx == NULL || ctx->tensor_bindings == NULL || tensor_id == 0u) {
        return NULL;
    }
    uint32_t lo = 0u;
    uint32_t hi = ctx->tensor_binding_count;
    while (lo < hi) {
        const uint32_t mid = lo + (hi - lo) / 2u;
        const uint32_t mid_id = ctx->tensor_bindings[mid].tensor_id;
        if (mid_id == tensor_id) {
            return &ctx->tensor_bindings[mid];
        }
        if (mid_id < tensor_id) {
            lo = mid + 1u;
        } else {
            hi = mid;
        }
    }
    return NULL;
}

int uocr_metal_context_get_tensor_binding(const uocr_metal_context *ctx,
                                          uint32_t tensor_id,
                                          uocr_metal_tensor_binding *out_binding) {
    if (out_binding == NULL) {
        return 0;
    }
    const uocr_metal_tensor_binding_internal *binding = metal_find_tensor_binding(ctx, tensor_id);
    if (binding == NULL) {
        return 0;
    }
    out_binding->tensor_id = binding->tensor_id;
    out_binding->view_index = binding->view_index;
    out_binding->inner_offset = binding->inner_offset;
    out_binding->payload_size = binding->payload_size;
    return 1;
}

static int metal_get_mapped_tensor_buffer(const uocr_metal_context *ctx,
                                          uint32_t tensor_id,
                                          uint64_t expected_payload_size,
                                          id<MTLBuffer> *out_buffer,
                                          NSUInteger *out_offset,
                                          char *error,
                                          size_t error_size) {
    if (out_buffer == NULL || out_offset == NULL) {
        return metal_fail(error, error_size, "invalid Metal mapped tensor output request");
    }
    *out_buffer = nil;
    *out_offset = 0u;
    if (ctx == NULL || ctx->model_views == NULL || ctx->model_view_count == 0u) {
        return metal_fail(error, error_size, "Metal mapped tensor %u requires mapped model views", tensor_id);
    }
    const uocr_metal_tensor_binding_internal *binding = metal_find_tensor_binding(ctx, tensor_id);
    if (binding == NULL) {
        return metal_fail(error, error_size, "Metal mapped tensor %u is not present in mapped model views", tensor_id);
    }
    if (binding->view_index >= ctx->model_view_count || ctx->model_views[binding->view_index].buffer == nil) {
        return metal_fail(error, error_size, "Metal mapped tensor %u has an invalid model-view binding", tensor_id);
    }
    if (binding->payload_size != expected_payload_size) {
        return metal_fail(error,
                          error_size,
                          "Metal mapped tensor %u payload size mismatch: got %llu expected %llu",
                          tensor_id,
                          (unsigned long long)binding->payload_size,
                          (unsigned long long)expected_payload_size);
    }
    if (binding->inner_offset > (uint64_t)NSUIntegerMax) {
        return metal_fail(error, error_size, "Metal mapped tensor %u offset exceeds platform limit", tensor_id);
    }
    *out_buffer = ctx->model_views[binding->view_index].buffer;
    *out_offset = (NSUInteger)binding->inner_offset;
    return 1;
}

static void metal_decoder_binding_cache_init(uocr_metal_decoder_binding_cache *cache) {
    if (cache == NULL) {
        return;
    }
    memset(cache, 0, sizeof(*cache));
    cache->token_embedding = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
    cache->lm_head = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
    cache->final_norm = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
    for (uint32_t layer = 0u; layer < UOCR_DECODER_LAYERS; ++layer) {
        uocr_metal_decoder_layer_binding_cache *layer_cache = &cache->layers[layer];
        layer_cache->input_norm = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        layer_cache->post_attn_norm = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        layer_cache->q_proj = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        layer_cache->k_proj = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        layer_cache->v_proj = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        layer_cache->o_proj = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        layer_cache->dense_gate = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        layer_cache->dense_up = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        layer_cache->dense_down = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        layer_cache->moe_router = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        layer_cache->moe_shared_gate = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        layer_cache->moe_shared_up = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        layer_cache->moe_shared_down = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        layer_cache->expert_slab.valid = 0;
        layer_cache->expert_slab.buffer = nil;
        layer_cache->expert_slab.offset = 0u;
        layer_cache->expert_slab.byte_length = 0u;
    }
}

static void metal_invalidate_decoder_binding_cache(uocr_metal_context *ctx, const char *reason) {
    if (ctx == NULL) {
        return;
    }
    metal_decoder_binding_cache_init(&ctx->decoder_bindings);
    if (reason == NULL || reason[0] == '\0') {
        reason = "decoder tensor bindings are not validated";
    }
    (void)snprintf(ctx->decoder_binding_error, sizeof(ctx->decoder_binding_error), "%s", reason);
}

static int metal_tensor_expected_payload_bytes(uint32_t rank,
                                               const uint32_t dims[UOCR_TENSOR_MAX_DIMS],
                                               uint64_t *out_bytes) {
    if (dims == NULL || out_bytes == NULL || rank == 0u || rank > UOCR_TENSOR_MAX_DIMS) {
        return 0;
    }
    uint64_t values = 1u;
    for (uint32_t i = 0u; i < rank; ++i) {
        if (dims[i] == 0u || !checked_mul_u64(values, (uint64_t)dims[i], &values)) {
            return 0;
        }
    }
    return checked_mul_u64(values, 2u, out_bytes);
}

static int metal_validate_decoder_tensor_metadata(const uocr_tensor_entry *tensor,
                                                  uint32_t tensor_id,
                                                  uint32_t family,
                                                  int32_t layer,
                                                  int32_t expert,
                                                  uint32_t projection,
                                                  uint32_t rank,
                                                  const uint32_t dims[UOCR_TENSOR_MAX_DIMS],
                                                  uint64_t expected_payload_size,
                                                  char *error,
                                                  size_t error_size) {
    if (tensor == NULL) {
        return metal_fail(error, error_size, "missing decoder tensor %u", tensor_id);
    }
    if (tensor->id != tensor_id) {
        return metal_fail(error, error_size, "decoder tensor id mismatch: got %u expected %u", tensor->id, tensor_id);
    }
    if (tensor->usage != UOCR_TENSOR_USAGE_RUNTIME) {
        return metal_fail(error,
                          error_size,
                          "decoder tensor %u has unsupported usage %s",
                          tensor_id,
                          uocr_tensor_usage_name(tensor->usage));
    }
    if (tensor->qtype != UOCR_TENSOR_F16) {
        return metal_fail(error,
                          error_size,
                          "decoder tensor %u has unsupported qtype %s; integrated fp16 decoder requires f16",
                          tensor_id,
                          uocr_tensor_qtype_name(tensor->qtype));
    }
    if (tensor->family != family || tensor->layer != layer || tensor->expert != expert || tensor->projection != projection) {
        return metal_fail(error,
                          error_size,
                          "decoder tensor %u registry metadata mismatch: family=%s layer=%d expert=%d projection=%u",
                          tensor_id,
                          uocr_tensor_family_name(tensor->family),
                          tensor->layer,
                          tensor->expert,
                          tensor->projection);
    }
    if (tensor->rank != rank) {
        return metal_fail(error,
                          error_size,
                          "decoder tensor %u rank mismatch: got %u expected %u",
                          tensor_id,
                          tensor->rank,
                          rank);
    }
    for (uint32_t i = 0u; i < rank; ++i) {
        if (tensor->logical_shape[i] != dims[i] || tensor->physical_shape[i] != dims[i]) {
            return metal_fail(error,
                              error_size,
                              "decoder tensor %u shape[%u] mismatch: logical=%u physical=%u expected=%u",
                              tensor_id,
                              i,
                              tensor->logical_shape[i],
                              tensor->physical_shape[i],
                              dims[i]);
        }
    }
    for (uint32_t i = rank; i < UOCR_TENSOR_MAX_DIMS; ++i) {
        if (tensor->logical_shape[i] != 0u || tensor->physical_shape[i] != 0u) {
            return metal_fail(error,
                              error_size,
                              "decoder tensor %u has non-zero trailing shape[%u]: logical=%u physical=%u",
                              tensor_id,
                              i,
                              tensor->logical_shape[i],
                              tensor->physical_shape[i]);
        }
    }
    if (tensor->payload_size != expected_payload_size) {
        return metal_fail(error,
                          error_size,
                          "decoder tensor %u payload size mismatch: got %llu expected %llu",
                          tensor_id,
                          (unsigned long long)tensor->payload_size,
                          (unsigned long long)expected_payload_size);
    }
    return 1;
}

static int metal_append_decoder_binding(uocr_metal_context *ctx,
                                        const uocr_model_file *model,
                                        uocr_metal_decoder_binding_cache *cache,
                                        uint32_t tensor_id,
                                        uint32_t family,
                                        int32_t layer,
                                        int32_t expert,
                                        uint32_t projection,
                                        uint32_t rank,
                                        const uint32_t dims[UOCR_TENSOR_MAX_DIMS],
                                        char *error,
                                        size_t error_size) {
    if (ctx == NULL || model == NULL || cache == NULL || cache->count >= UOCR_METAL_DECODER_REQUIRED_TENSOR_COUNT) {
        return metal_fail(error, error_size, "decoder tensor binding cache overflow");
    }
    uint64_t expected_payload_size = 0u;
    if (!metal_tensor_expected_payload_bytes(rank, dims, &expected_payload_size)) {
        return metal_fail(error, error_size, "decoder tensor %u expected byte-size overflow", tensor_id);
    }
    const uocr_tensor_entry *tensor = uocr_model_file_find_tensor(model, tensor_id);
    if (!metal_validate_decoder_tensor_metadata(tensor,
                                                tensor_id,
                                                family,
                                                layer,
                                                expert,
                                                projection,
                                                rank,
                                                dims,
                                                expected_payload_size,
                                                error,
                                                error_size)) {
        return 0;
    }

    id<MTLBuffer> buffer = nil;
    NSUInteger offset = 0u;
    if (!metal_get_mapped_tensor_buffer(ctx, tensor_id, expected_payload_size, &buffer, &offset, error, error_size)) {
        return 0;
    }

    uocr_metal_decoder_binding *binding = &cache->tensors[cache->count++];
    binding->tensor_id = tensor_id;
    binding->reserved = 0u;
    binding->buffer = buffer;
    binding->offset = offset;
    binding->payload_size = expected_payload_size;
    return 1;
}

static int metal_append_decoder_binding1(uocr_metal_context *ctx,
                                         const uocr_model_file *model,
                                         uocr_metal_decoder_binding_cache *cache,
                                         uint32_t tensor_id,
                                         uint32_t family,
                                         int32_t layer,
                                         int32_t expert,
                                         uint32_t projection,
                                         uint32_t d0,
                                         char *error,
                                         size_t error_size) {
    const uint32_t dims[UOCR_TENSOR_MAX_DIMS] = {d0, 0u, 0u, 0u};
    return metal_append_decoder_binding(ctx, model, cache, tensor_id, family, layer, expert, projection, 1u, dims, error, error_size);
}

static int metal_append_decoder_binding2(uocr_metal_context *ctx,
                                         const uocr_model_file *model,
                                         uocr_metal_decoder_binding_cache *cache,
                                         uint32_t tensor_id,
                                         uint32_t family,
                                         int32_t layer,
                                         int32_t expert,
                                         uint32_t projection,
                                         uint32_t d0,
                                         uint32_t d1,
                                         char *error,
                                         size_t error_size) {
    const uint32_t dims[UOCR_TENSOR_MAX_DIMS] = {d0, d1, 0u, 0u};
    return metal_append_decoder_binding(ctx, model, cache, tensor_id, family, layer, expert, projection, 2u, dims, error, error_size);
}

static int metal_decoder_binding_cache_find_index(const uocr_metal_decoder_binding_cache *cache,
                                                  uint32_t tensor_id,
                                                  uint32_t *out_index) {
    if (cache == NULL || out_index == NULL || tensor_id == 0u) {
        return 0;
    }
    for (uint32_t i = 0u; i < cache->count; ++i) {
        if (cache->tensors[i].tensor_id == tensor_id) {
            *out_index = i;
            return 1;
        }
    }
    return 0;
}

static int metal_decoder_binding_cache_require_index(const uocr_metal_decoder_binding_cache *cache,
                                                     uint32_t tensor_id,
                                                     const char *label,
                                                     uint32_t *out_index,
                                                     char *error,
                                                     size_t error_size) {
    if (!metal_decoder_binding_cache_find_index(cache, tensor_id, out_index)) {
        return metal_fail(error,
                          error_size,
                          "missing validated decoder tensor for %s (id=%u)",
                          label != NULL ? label : "binding",
                          tensor_id);
    }
    const uocr_metal_decoder_binding *binding = &cache->tensors[*out_index];
    if (binding->buffer == nil) {
        return metal_fail(error,
                          error_size,
                          "validated decoder tensor for %s has no Metal buffer (id=%u)",
                          label != NULL ? label : "binding",
                          tensor_id);
    }
    return 1;
}

static int metal_decoder_binding_cache_validate_expert_slab(const uocr_metal_decoder_binding_cache *cache,
                                                            uint32_t layer,
                                                            uocr_metal_decoder_expert_slab_cache *out_slab,
                                                            char *error,
                                                            size_t error_size) {
    if (cache == NULL || out_slab == NULL || layer == 0u || layer >= UOCR_DECODER_LAYERS) {
        return metal_fail(error, error_size, "invalid decoder MoE expert slab cache request");
    }
    memset(out_slab, 0, sizeof(*out_slab));
    const uint64_t projection_values = (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE * (uint64_t)UOCR_HIDDEN_SIZE;
    const uint64_t projection_bytes = projection_values * 2u;
    const uint64_t expert_stride_bytes = projection_bytes * 3u;
    const uint64_t total_bytes = expert_stride_bytes * (uint64_t)UOCR_ROUTED_EXPERTS;

    uint32_t gate0_index = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
    if (!metal_decoder_binding_cache_require_index(cache,
                                                   uocr_tensor_id_moe_expert(layer, 0u, UOCR_TENSOR_PROJ_GATE),
                                                   "MoE expert0 gate",
                                                   &gate0_index,
                                                   error,
                                                   error_size)) {
        return 0;
    }
    const uocr_metal_decoder_binding *gate0 = &cache->tensors[gate0_index];
    if (gate0->offset > NSUIntegerMax || !metal_buffer_range_valid(gate0->buffer, gate0->offset, total_bytes)) {
        return metal_fail(error,
                          error_size,
                          "integrated MoE expert slab for layer %u is not contiguous in one Metal view",
                          layer);
    }

    for (uint32_t expert = 0u; expert < UOCR_ROUTED_EXPERTS; ++expert) {
        const uint64_t base = (uint64_t)gate0->offset + (uint64_t)expert * expert_stride_bytes;
        uint32_t gate_index = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        uint32_t up_index = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        uint32_t down_index = UOCR_METAL_DECODER_BINDING_INDEX_INVALID;
        if (!metal_decoder_binding_cache_require_index(cache,
                                                       uocr_tensor_id_moe_expert(layer, expert, UOCR_TENSOR_PROJ_GATE),
                                                       "MoE expert gate",
                                                       &gate_index,
                                                       error,
                                                       error_size) ||
            !metal_decoder_binding_cache_require_index(cache,
                                                       uocr_tensor_id_moe_expert(layer, expert, UOCR_TENSOR_PROJ_UP),
                                                       "MoE expert up",
                                                       &up_index,
                                                       error,
                                                       error_size) ||
            !metal_decoder_binding_cache_require_index(cache,
                                                       uocr_tensor_id_moe_expert(layer, expert, UOCR_TENSOR_PROJ_DOWN),
                                                       "MoE expert down",
                                                       &down_index,
                                                       error,
                                                       error_size)) {
            return 0;
        }
        const uocr_metal_decoder_binding *gate = &cache->tensors[gate_index];
        const uocr_metal_decoder_binding *up = &cache->tensors[up_index];
        const uocr_metal_decoder_binding *down = &cache->tensors[down_index];
        if (gate->buffer != gate0->buffer || up->buffer != gate0->buffer || down->buffer != gate0->buffer ||
            (uint64_t)gate->offset != base || (uint64_t)up->offset != base + projection_bytes ||
            (uint64_t)down->offset != base + 2u * projection_bytes) {
            return metal_fail(error,
                              error_size,
                              "integrated MoE expert tensors for layer %u are not interleaved-contiguous at expert %u",
                              layer,
                              expert);
        }
    }

    out_slab->valid = 1;
    out_slab->buffer = gate0->buffer;
    out_slab->offset = gate0->offset;
    out_slab->byte_length = total_bytes;
    return 1;
}

static int metal_decoder_binding_cache_build_direct(uocr_metal_context *ctx,
                                                    uocr_metal_decoder_binding_cache *cache,
                                                    char *error,
                                                    size_t error_size) {
    if (ctx == NULL || cache == NULL) {
        return metal_fail(error, error_size, "invalid decoder direct binding cache request");
    }

    if (!metal_decoder_binding_cache_require_index(cache,
                                                   UOCR_TENSOR_ID_TOK_EMBED,
                                                   "token embedding",
                                                   &cache->token_embedding,
                                                   error,
                                                   error_size) ||
        !metal_decoder_binding_cache_require_index(cache,
                                                   UOCR_TENSOR_ID_LM_HEAD,
                                                   "LM head",
                                                   &cache->lm_head,
                                                   error,
                                                   error_size) ||
        !metal_decoder_binding_cache_require_index(cache,
                                                   UOCR_TENSOR_ID_FINAL_NORM,
                                                   "final norm",
                                                   &cache->final_norm,
                                                   error,
                                                   error_size)) {
        return 0;
    }

    for (uint32_t layer = 0u; layer < UOCR_DECODER_LAYERS; ++layer) {
        uocr_metal_decoder_layer_binding_cache *layer_cache = &cache->layers[layer];
        if (!metal_decoder_binding_cache_require_index(cache,
                                                       uocr_tensor_id_layer_input_norm(layer),
                                                       "layer input norm",
                                                       &layer_cache->input_norm,
                                                       error,
                                                       error_size) ||
            !metal_decoder_binding_cache_require_index(cache,
                                                       uocr_tensor_id_layer_post_attn_norm(layer),
                                                       "layer post-attention norm",
                                                       &layer_cache->post_attn_norm,
                                                       error,
                                                       error_size) ||
            !metal_decoder_binding_cache_require_index(cache,
                                                       uocr_tensor_id_layer_attn(layer, UOCR_TENSOR_PROJ_Q),
                                                       "attention q_proj",
                                                       &layer_cache->q_proj,
                                                       error,
                                                       error_size) ||
            !metal_decoder_binding_cache_require_index(cache,
                                                       uocr_tensor_id_layer_attn(layer, UOCR_TENSOR_PROJ_K),
                                                       "attention k_proj",
                                                       &layer_cache->k_proj,
                                                       error,
                                                       error_size) ||
            !metal_decoder_binding_cache_require_index(cache,
                                                       uocr_tensor_id_layer_attn(layer, UOCR_TENSOR_PROJ_V),
                                                       "attention v_proj",
                                                       &layer_cache->v_proj,
                                                       error,
                                                       error_size) ||
            !metal_decoder_binding_cache_require_index(cache,
                                                       uocr_tensor_id_layer_attn(layer, UOCR_TENSOR_PROJ_O),
                                                       "attention o_proj",
                                                       &layer_cache->o_proj,
                                                       error,
                                                       error_size)) {
            return 0;
        }
    }

    uocr_metal_decoder_layer_binding_cache *dense_layer = &cache->layers[0];
    if (!metal_decoder_binding_cache_require_index(cache,
                                                   uocr_tensor_id_layer_dense_mlp(UOCR_TENSOR_PROJ_GATE),
                                                   "layer0 dense gate",
                                                   &dense_layer->dense_gate,
                                                   error,
                                                   error_size) ||
        !metal_decoder_binding_cache_require_index(cache,
                                                   uocr_tensor_id_layer_dense_mlp(UOCR_TENSOR_PROJ_UP),
                                                   "layer0 dense up",
                                                   &dense_layer->dense_up,
                                                   error,
                                                   error_size) ||
        !metal_decoder_binding_cache_require_index(cache,
                                                   uocr_tensor_id_layer_dense_mlp(UOCR_TENSOR_PROJ_DOWN),
                                                   "layer0 dense down",
                                                   &dense_layer->dense_down,
                                                   error,
                                                   error_size)) {
        return 0;
    }

    for (uint32_t layer = 1u; layer < UOCR_DECODER_LAYERS; ++layer) {
        uocr_metal_decoder_layer_binding_cache *layer_cache = &cache->layers[layer];
        if (!metal_decoder_binding_cache_require_index(cache,
                                                       uocr_tensor_id_moe_router(layer),
                                                       "MoE router",
                                                       &layer_cache->moe_router,
                                                       error,
                                                       error_size) ||
            !metal_decoder_binding_cache_require_index(cache,
                                                       uocr_tensor_id_moe_shared(layer, UOCR_TENSOR_PROJ_GATE),
                                                       "MoE shared gate",
                                                       &layer_cache->moe_shared_gate,
                                                       error,
                                                       error_size) ||
            !metal_decoder_binding_cache_require_index(cache,
                                                       uocr_tensor_id_moe_shared(layer, UOCR_TENSOR_PROJ_UP),
                                                       "MoE shared up",
                                                       &layer_cache->moe_shared_up,
                                                       error,
                                                       error_size) ||
            !metal_decoder_binding_cache_require_index(cache,
                                                       uocr_tensor_id_moe_shared(layer, UOCR_TENSOR_PROJ_DOWN),
                                                       "MoE shared down",
                                                       &layer_cache->moe_shared_down,
                                                       error,
                                                       error_size)) {
            return 0;
        }
        const uint64_t expert_slab_validation_start_ns = uocr_profile_now_ns();
        if (!metal_decoder_binding_cache_validate_expert_slab(cache,
                                                              layer,
                                                              &layer_cache->expert_slab,
                                                              error,
                                                              error_size)) {
            return 0;
        }
        metal_profile_add_event_now(ctx,
                                    "metal.decoder_binding_cache.expert_slab_validation",
                                    expert_slab_validation_start_ns);
    }
    return 1;
}

static int metal_refresh_decoder_binding_cache(uocr_metal_context *ctx,
                                               const uocr_model_file *model,
                                               char *error,
                                               size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || model == NULL || ctx->model_views == NULL || ctx->tensor_bindings == NULL) {
        return metal_fail(error, error_size, "decoder tensor binding validation requires a mapped model");
    }

    uocr_metal_decoder_binding_cache cache;
    metal_decoder_binding_cache_init(&cache);

#define APPEND1(tensor_id, family, layer, expert, projection, d0) \
    do { \
        if (!metal_append_decoder_binding1(ctx, model, &cache, (tensor_id), (family), (layer), (expert), (projection), (d0), error, error_size)) { \
            return 0; \
        } \
    } while (0)
#define APPEND2(tensor_id, family, layer, expert, projection, d0, d1) \
    do { \
        if (!metal_append_decoder_binding2(ctx, model, &cache, (tensor_id), (family), (layer), (expert), (projection), (d0), (d1), error, error_size)) { \
            return 0; \
        } \
    } while (0)

    APPEND2(UOCR_TENSOR_ID_TOK_EMBED,
            UOCR_TENSOR_FAMILY_TOK_EMBED,
            -1,
            -1,
            UOCR_TENSOR_PROJ_WEIGHT,
            UOCR_VOCAB_SIZE,
            UOCR_HIDDEN_SIZE);
    APPEND2(UOCR_TENSOR_ID_LM_HEAD,
            UOCR_TENSOR_FAMILY_LM_HEAD,
            -1,
            -1,
            UOCR_TENSOR_PROJ_WEIGHT,
            UOCR_VOCAB_SIZE,
            UOCR_HIDDEN_SIZE);
    APPEND1(UOCR_TENSOR_ID_FINAL_NORM,
            UOCR_TENSOR_FAMILY_FINAL_NORM,
            -1,
            -1,
            UOCR_TENSOR_PROJ_WEIGHT,
            UOCR_HIDDEN_SIZE);

    for (uint32_t layer = 0u; layer < UOCR_DECODER_LAYERS; ++layer) {
        APPEND1(uocr_tensor_id_layer_input_norm(layer),
                UOCR_TENSOR_FAMILY_LAYER_NORM,
                (int32_t)layer,
                -1,
                UOCR_TENSOR_PROJ_WEIGHT,
                UOCR_HIDDEN_SIZE);
        APPEND1(uocr_tensor_id_layer_post_attn_norm(layer),
                UOCR_TENSOR_FAMILY_LAYER_NORM,
                (int32_t)layer,
                -1,
                UOCR_TENSOR_PROJ_WEIGHT,
                UOCR_HIDDEN_SIZE);
        APPEND2(uocr_tensor_id_layer_attn(layer, UOCR_TENSOR_PROJ_Q),
                UOCR_TENSOR_FAMILY_LAYER_ATTN,
                (int32_t)layer,
                -1,
                UOCR_TENSOR_PROJ_Q,
                UOCR_HIDDEN_SIZE,
                UOCR_HIDDEN_SIZE);
        APPEND2(uocr_tensor_id_layer_attn(layer, UOCR_TENSOR_PROJ_K),
                UOCR_TENSOR_FAMILY_LAYER_ATTN,
                (int32_t)layer,
                -1,
                UOCR_TENSOR_PROJ_K,
                UOCR_HIDDEN_SIZE,
                UOCR_HIDDEN_SIZE);
        APPEND2(uocr_tensor_id_layer_attn(layer, UOCR_TENSOR_PROJ_V),
                UOCR_TENSOR_FAMILY_LAYER_ATTN,
                (int32_t)layer,
                -1,
                UOCR_TENSOR_PROJ_V,
                UOCR_HIDDEN_SIZE,
                UOCR_HIDDEN_SIZE);
        APPEND2(uocr_tensor_id_layer_attn(layer, UOCR_TENSOR_PROJ_O),
                UOCR_TENSOR_FAMILY_LAYER_ATTN,
                (int32_t)layer,
                -1,
                UOCR_TENSOR_PROJ_O,
                UOCR_HIDDEN_SIZE,
                UOCR_HIDDEN_SIZE);
    }

    APPEND2(uocr_tensor_id_layer_dense_mlp(UOCR_TENSOR_PROJ_GATE),
            UOCR_TENSOR_FAMILY_LAYER_DENSE_MLP,
            0,
            -1,
            UOCR_TENSOR_PROJ_GATE,
            UOCR_DENSE_LAYER0_INTERMEDIATE,
            UOCR_HIDDEN_SIZE);
    APPEND2(uocr_tensor_id_layer_dense_mlp(UOCR_TENSOR_PROJ_UP),
            UOCR_TENSOR_FAMILY_LAYER_DENSE_MLP,
            0,
            -1,
            UOCR_TENSOR_PROJ_UP,
            UOCR_DENSE_LAYER0_INTERMEDIATE,
            UOCR_HIDDEN_SIZE);
    APPEND2(uocr_tensor_id_layer_dense_mlp(UOCR_TENSOR_PROJ_DOWN),
            UOCR_TENSOR_FAMILY_LAYER_DENSE_MLP,
            0,
            -1,
            UOCR_TENSOR_PROJ_DOWN,
            UOCR_HIDDEN_SIZE,
            UOCR_DENSE_LAYER0_INTERMEDIATE);

    for (uint32_t layer = 1u; layer < UOCR_DECODER_LAYERS; ++layer) {
        APPEND2(uocr_tensor_id_moe_router(layer),
                UOCR_TENSOR_FAMILY_MOE_ROUTER,
                (int32_t)layer,
                -1,
                UOCR_TENSOR_PROJ_WEIGHT,
                UOCR_ROUTED_EXPERTS,
                UOCR_HIDDEN_SIZE);
        APPEND2(uocr_tensor_id_moe_shared(layer, UOCR_TENSOR_PROJ_GATE),
                UOCR_TENSOR_FAMILY_MOE_SHARED,
                (int32_t)layer,
                -1,
                UOCR_TENSOR_PROJ_GATE,
                UOCR_MOE_SHARED_INTERMEDIATE,
                UOCR_HIDDEN_SIZE);
        APPEND2(uocr_tensor_id_moe_shared(layer, UOCR_TENSOR_PROJ_UP),
                UOCR_TENSOR_FAMILY_MOE_SHARED,
                (int32_t)layer,
                -1,
                UOCR_TENSOR_PROJ_UP,
                UOCR_MOE_SHARED_INTERMEDIATE,
                UOCR_HIDDEN_SIZE);
        APPEND2(uocr_tensor_id_moe_shared(layer, UOCR_TENSOR_PROJ_DOWN),
                UOCR_TENSOR_FAMILY_MOE_SHARED,
                (int32_t)layer,
                -1,
                UOCR_TENSOR_PROJ_DOWN,
                UOCR_HIDDEN_SIZE,
                UOCR_MOE_SHARED_INTERMEDIATE);
        for (uint32_t expert = 0u; expert < UOCR_ROUTED_EXPERTS; ++expert) {
            APPEND2(uocr_tensor_id_moe_expert(layer, expert, UOCR_TENSOR_PROJ_GATE),
                    UOCR_TENSOR_FAMILY_MOE_EXPERT,
                    (int32_t)layer,
                    (int32_t)expert,
                    UOCR_TENSOR_PROJ_GATE,
                    UOCR_MOE_EXPERT_INTERMEDIATE,
                    UOCR_HIDDEN_SIZE);
            APPEND2(uocr_tensor_id_moe_expert(layer, expert, UOCR_TENSOR_PROJ_UP),
                    UOCR_TENSOR_FAMILY_MOE_EXPERT,
                    (int32_t)layer,
                    (int32_t)expert,
                    UOCR_TENSOR_PROJ_UP,
                    UOCR_MOE_EXPERT_INTERMEDIATE,
                    UOCR_HIDDEN_SIZE);
            APPEND2(uocr_tensor_id_moe_expert(layer, expert, UOCR_TENSOR_PROJ_DOWN),
                    UOCR_TENSOR_FAMILY_MOE_EXPERT,
                    (int32_t)layer,
                    (int32_t)expert,
                    UOCR_TENSOR_PROJ_DOWN,
                    UOCR_HIDDEN_SIZE,
                    UOCR_MOE_EXPERT_INTERMEDIATE);
        }
    }

#undef APPEND1
#undef APPEND2

    if (cache.count != UOCR_METAL_DECODER_REQUIRED_TENSOR_COUNT) {
        return metal_fail(error,
                          error_size,
                          "decoder tensor binding count mismatch: got %u expected %u",
                          cache.count,
                          (uint32_t)UOCR_METAL_DECODER_REQUIRED_TENSOR_COUNT);
    }
    const uint64_t direct_cache_start_ns = uocr_profile_now_ns();
    if (!metal_decoder_binding_cache_build_direct(ctx, &cache, error, error_size)) {
        return 0;
    }
    metal_profile_add_event_now(ctx, "metal.decoder_binding_cache.direct", direct_cache_start_ns);
    cache.valid = 1;
    ctx->decoder_bindings = cache;
    ctx->decoder_binding_error[0] = '\0';
    return 1;
}

uint32_t uocr_metal_context_decoder_binding_count(const uocr_metal_context *ctx) {
    return ctx != NULL && ctx->decoder_bindings.valid ? ctx->decoder_bindings.count : 0u;
}

int uocr_metal_context_decoder_bindings_ready(const uocr_metal_context *ctx) {
    return ctx != NULL && ctx->decoder_bindings.valid &&
           ctx->decoder_bindings.count == UOCR_METAL_DECODER_REQUIRED_TENSOR_COUNT;
}

static void metal_invalidate_vision_binding_cache(uocr_metal_context *ctx, const char *reason) {
    if (ctx == NULL) {
        return;
    }
    memset(&ctx->vision_bindings, 0, sizeof(ctx->vision_bindings));
    memset(&ctx->vision_weights, 0, sizeof(ctx->vision_weights));
    if (reason == NULL || reason[0] == '\0') {
        reason = "vision tensor bindings are not validated";
    }
    (void)snprintf(ctx->vision_binding_error, sizeof(ctx->vision_binding_error), "%s", reason);
}

static int metal_validate_vision_tensor_metadata(const uocr_tensor_entry *tensor,
                                                 uint32_t tensor_id,
                                                 const char *role,
                                                 uint32_t family,
                                                 int32_t layer,
                                                 int32_t expert,
                                                 uint32_t projection,
                                                 uint32_t rank,
                                                 const uint32_t dims[UOCR_TENSOR_MAX_DIMS],
                                                 uint64_t expected_payload_size,
                                                 char *error,
                                                 size_t error_size) {
    if (role == NULL || role[0] == '\0') {
        role = "vision tensor";
    }
    if (tensor == NULL) {
        return metal_fail(error, error_size, "missing %s %u", role, tensor_id);
    }
    if (tensor->id != tensor_id) {
        return metal_fail(error, error_size, "%s id mismatch: got %u expected %u", role, tensor->id, tensor_id);
    }
    if (tensor->usage != UOCR_TENSOR_USAGE_RUNTIME) {
        return metal_fail(error,
                          error_size,
                          "%s %u has unsupported usage %s",
                          role,
                          tensor_id,
                          uocr_tensor_usage_name(tensor->usage));
    }
    if (tensor->qtype != UOCR_TENSOR_F16) {
        return metal_fail(error,
                          error_size,
                          "%s %u has unsupported qtype %s; production Metal vision requires f16",
                          role,
                          tensor_id,
                          uocr_tensor_qtype_name(tensor->qtype));
    }
    if (tensor->family != family || tensor->layer != layer || tensor->expert != expert || tensor->projection != projection) {
        return metal_fail(error,
                          error_size,
                          "%s %u registry metadata mismatch: family=%s layer=%d expert=%d projection=%u",
                          role,
                          tensor_id,
                          uocr_tensor_family_name(tensor->family),
                          tensor->layer,
                          tensor->expert,
                          tensor->projection);
    }
    if (tensor->rank != rank) {
        return metal_fail(error,
                          error_size,
                          "%s %u rank mismatch: got %u expected %u",
                          role,
                          tensor_id,
                          tensor->rank,
                          rank);
    }
    for (uint32_t i = 0u; i < rank; ++i) {
        if (tensor->logical_shape[i] != dims[i] || tensor->physical_shape[i] != dims[i]) {
            return metal_fail(error,
                              error_size,
                              "%s %u shape[%u] mismatch: logical=%u physical=%u expected=%u",
                              role,
                              tensor_id,
                              i,
                              tensor->logical_shape[i],
                              tensor->physical_shape[i],
                              dims[i]);
        }
    }
    for (uint32_t i = rank; i < UOCR_TENSOR_MAX_DIMS; ++i) {
        if (tensor->logical_shape[i] != 0u || tensor->physical_shape[i] != 0u) {
            return metal_fail(error,
                              error_size,
                              "%s %u has non-zero trailing shape[%u]: logical=%u physical=%u",
                              role,
                              tensor_id,
                              i,
                              tensor->logical_shape[i],
                              tensor->physical_shape[i]);
        }
    }
    if (tensor->payload_size != expected_payload_size) {
        return metal_fail(error,
                          error_size,
                          "%s %u payload size mismatch: got %llu expected %llu",
                          role,
                          tensor_id,
                          (unsigned long long)tensor->payload_size,
                          (unsigned long long)expected_payload_size);
    }
    return 1;
}

static int metal_append_vision_binding(uocr_metal_context *ctx,
                                       const uocr_model_file *model,
                                       uocr_metal_vision_binding_cache *cache,
                                       uint32_t tensor_id,
                                       const char *role,
                                       uint32_t family,
                                       int32_t layer,
                                       int32_t expert,
                                       uint32_t projection,
                                       uint32_t rank,
                                       const uint32_t dims[UOCR_TENSOR_MAX_DIMS],
                                       char *error,
                                       size_t error_size) {
    if (ctx == NULL || model == NULL || cache == NULL || cache->count >= UOCR_METAL_VISION_REQUIRED_TENSOR_COUNT) {
        return metal_fail(error, error_size, "vision tensor binding cache overflow");
    }
    uint64_t expected_payload_size = 0u;
    if (!metal_tensor_expected_payload_bytes(rank, dims, &expected_payload_size)) {
        return metal_fail(error, error_size, "vision tensor %u expected byte-size overflow", tensor_id);
    }
    const uocr_tensor_entry *tensor = uocr_model_file_find_tensor(model, tensor_id);
    if (!metal_validate_vision_tensor_metadata(tensor,
                                               tensor_id,
                                               role,
                                               family,
                                               layer,
                                               expert,
                                               projection,
                                               rank,
                                               dims,
                                               expected_payload_size,
                                               error,
                                               error_size)) {
        return 0;
    }

    id<MTLBuffer> buffer = nil;
    NSUInteger offset = 0u;
    if (!metal_get_mapped_tensor_buffer(ctx, tensor_id, expected_payload_size, &buffer, &offset, error, error_size)) {
        return 0;
    }

    uocr_metal_vision_binding *binding = &cache->tensors[cache->count++];
    binding->tensor_id = tensor_id;
    binding->reserved = 0u;
    binding->buffer = buffer;
    binding->offset = offset;
    binding->payload_size = expected_payload_size;
    return 1;
}

static int metal_append_vision_binding1(uocr_metal_context *ctx,
                                        const uocr_model_file *model,
                                        uocr_metal_vision_binding_cache *cache,
                                        uint32_t tensor_id,
                                        const char *role,
                                        uint32_t family,
                                        int32_t layer,
                                        int32_t expert,
                                        uint32_t projection,
                                        uint32_t d0,
                                        char *error,
                                        size_t error_size) {
    const uint32_t dims[UOCR_TENSOR_MAX_DIMS] = {d0, 0u, 0u, 0u};
    return metal_append_vision_binding(ctx, model, cache, tensor_id, role, family, layer, expert, projection, 1u, dims, error, error_size);
}

static int metal_append_vision_binding2(uocr_metal_context *ctx,
                                        const uocr_model_file *model,
                                        uocr_metal_vision_binding_cache *cache,
                                        uint32_t tensor_id,
                                        const char *role,
                                        uint32_t family,
                                        int32_t layer,
                                        int32_t expert,
                                        uint32_t projection,
                                        uint32_t d0,
                                        uint32_t d1,
                                        char *error,
                                        size_t error_size) {
    const uint32_t dims[UOCR_TENSOR_MAX_DIMS] = {d0, d1, 0u, 0u};
    return metal_append_vision_binding(ctx, model, cache, tensor_id, role, family, layer, expert, projection, 2u, dims, error, error_size);
}

static int metal_append_vision_binding4(uocr_metal_context *ctx,
                                        const uocr_model_file *model,
                                        uocr_metal_vision_binding_cache *cache,
                                        uint32_t tensor_id,
                                        const char *role,
                                        uint32_t family,
                                        int32_t layer,
                                        int32_t expert,
                                        uint32_t projection,
                                        uint32_t d0,
                                        uint32_t d1,
                                        uint32_t d2,
                                        uint32_t d3,
                                        char *error,
                                        size_t error_size) {
    const uint32_t dims[UOCR_TENSOR_MAX_DIMS] = {d0, d1, d2, d3};
    return metal_append_vision_binding(ctx, model, cache, tensor_id, role, family, layer, expert, projection, 4u, dims, error, error_size);
}

static int metal_refresh_vision_binding_cache(uocr_metal_context *ctx,
                                              const uocr_model_file *model,
                                              char *error,
                                              size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || model == NULL || ctx->model_views == NULL || ctx->tensor_bindings == NULL) {
        return metal_fail(error, error_size, "vision tensor binding validation requires a mapped model");
    }

    uocr_metal_vision_binding_cache cache;
    memset(&cache, 0, sizeof(cache));

#define VAPPEND1(tensor_id, role, family, layer, expert, projection, d0) \
    do { \
        if (!metal_append_vision_binding1(ctx, model, &cache, (tensor_id), (role), (family), (layer), (expert), (projection), (d0), error, error_size)) { \
            return 0; \
        } \
    } while (0)
#define VAPPEND2(tensor_id, role, family, layer, expert, projection, d0, d1) \
    do { \
        if (!metal_append_vision_binding2(ctx, model, &cache, (tensor_id), (role), (family), (layer), (expert), (projection), (d0), (d1), error, error_size)) { \
            return 0; \
        } \
    } while (0)
#define VAPPEND4(tensor_id, role, family, layer, expert, projection, d0, d1, d2, d3) \
    do { \
        if (!metal_append_vision_binding4(ctx, model, &cache, (tensor_id), (role), (family), (layer), (expert), (projection), (d0), (d1), (d2), (d3), error, error_size)) { \
            return 0; \
        } \
    } while (0)

    VAPPEND1(UOCR_TENSOR_ID_IMAGE_NEWLINE,
             "image newline tensor",
             UOCR_TENSOR_FAMILY_IMAGE_NEWLINE,
             -1,
             -1,
             UOCR_TENSOR_PROJ_NONE,
             UOCR_HIDDEN_SIZE);
    VAPPEND1(UOCR_TENSOR_ID_VIEW_SEPARATOR,
             "view separator tensor",
             UOCR_TENSOR_FAMILY_VIEW_SEPARATOR,
             -1,
             -1,
             UOCR_TENSOR_PROJ_NONE,
             UOCR_HIDDEN_SIZE);
    VAPPEND2(UOCR_TENSOR_ID_PROJECTOR_WEIGHT,
             "visual projector weight",
             UOCR_TENSOR_FAMILY_PROJECTOR,
             -1,
             -1,
             UOCR_TENSOR_PROJ_WEIGHT,
             UOCR_HIDDEN_SIZE,
             UOCR_PROJECTOR_IN_SIZE);
    VAPPEND1(UOCR_TENSOR_ID_PROJECTOR_BIAS,
             "visual projector bias",
             UOCR_TENSOR_FAMILY_PROJECTOR,
             -1,
             -1,
             UOCR_TENSOR_PROJ_BIAS,
             UOCR_HIDDEN_SIZE);

    static const uint32_t sam_block_name_order[UOCR_SAM_BLOCKS] = {0u, 1u, 10u, 11u, 2u, 3u, 4u, 5u, 6u, 7u, 8u, 9u};
    for (uint32_t sorted_block = 0u; sorted_block < UOCR_SAM_BLOCKS; ++sorted_block) {
        const uint32_t source_block = sam_block_name_order[sorted_block];
        const uint32_t base = UOCR_TENSOR_ID_VISION_SAM_BASE + sorted_block * 14u;
        const uint32_t rel_pos_length = uocr_sam_block_uses_global_attention(source_block) ? UOCR_SAM_MAX_REL_POS_SIZE : UOCR_SAM_WINDOW_REL_POS_SIZE;
        VAPPEND1(base + 0u, "SAM attention projection bias", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_HIDDEN_SIZE);
        VAPPEND2(base + 1u, "SAM attention projection weight", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE);
        VAPPEND1(base + 2u, "SAM attention qkv bias", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_QKV_SIZE);
        VAPPEND2(base + 3u, "SAM attention qkv weight", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_QKV_SIZE, UOCR_SAM_HIDDEN_SIZE);
        VAPPEND2(base + 4u, "SAM relative position H", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, rel_pos_length, UOCR_SAM_HEAD_DIM);
        VAPPEND2(base + 5u, "SAM relative position W", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, rel_pos_length, UOCR_SAM_HEAD_DIM);
        VAPPEND1(base + 6u, "SAM MLP lin1 bias", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_MLP_INTERMEDIATE);
        VAPPEND2(base + 7u, "SAM MLP lin1 weight", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_MLP_INTERMEDIATE, UOCR_SAM_HIDDEN_SIZE);
        VAPPEND1(base + 8u, "SAM MLP lin2 bias", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_HIDDEN_SIZE);
        VAPPEND2(base + 9u, "SAM MLP lin2 weight", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_MLP_INTERMEDIATE);
        VAPPEND1(base + 10u, "SAM norm1 bias", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_HIDDEN_SIZE);
        VAPPEND1(base + 11u, "SAM norm1 weight", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_HIDDEN_SIZE);
        VAPPEND1(base + 12u, "SAM norm2 bias", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_HIDDEN_SIZE);
        VAPPEND1(base + 13u, "SAM norm2 weight", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_HIDDEN_SIZE);
    }

    const uint32_t sam_extra = UOCR_TENSOR_ID_VISION_SAM_BASE + UOCR_SAM_BLOCKS * 14u;
    VAPPEND4(sam_extra + 0u, "SAM neck 1x1 conv weight", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_NECK_CHANNELS, UOCR_SAM_HIDDEN_SIZE, 1u, 1u);
    VAPPEND1(sam_extra + 1u, "SAM neck norm1 bias", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_NECK_CHANNELS);
    VAPPEND1(sam_extra + 2u, "SAM neck norm1 weight", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_NECK_CHANNELS);
    VAPPEND4(sam_extra + 3u, "SAM neck 3x3 conv weight", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_NECK_CHANNELS, UOCR_SAM_NECK_CHANNELS, UOCR_SAM_NECK_KERNEL_SIZE, UOCR_SAM_NECK_KERNEL_SIZE);
    VAPPEND1(sam_extra + 4u, "SAM neck norm2 bias", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_NECK_CHANNELS);
    VAPPEND1(sam_extra + 5u, "SAM neck norm2 weight", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_NECK_CHANNELS);
    VAPPEND4(sam_extra + 6u, "SAM net_2 conv weight", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_NET2_CHANNELS, UOCR_SAM_NECK_CHANNELS, UOCR_SAM_NECK_KERNEL_SIZE, UOCR_SAM_NECK_KERNEL_SIZE);
    VAPPEND4(sam_extra + 7u, "SAM net_3 conv weight", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_NET3_CHANNELS, UOCR_SAM_NET2_CHANNELS, UOCR_SAM_NECK_KERNEL_SIZE, UOCR_SAM_NECK_KERNEL_SIZE);
    VAPPEND1(sam_extra + 8u, "SAM patch-embed bias", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_HIDDEN_SIZE);
    VAPPEND4(sam_extra + 9u, "SAM patch-embed weight", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_SAM_HIDDEN_SIZE, 3u, UOCR_VISION_PATCH_SIZE, UOCR_VISION_PATCH_SIZE);
    VAPPEND4(sam_extra + 10u, "SAM absolute position embedding", UOCR_TENSOR_FAMILY_VISION_SAM, -1, -1, UOCR_TENSOR_PROJ_NONE, 1u, UOCR_SAM_MAX_GRID_SIZE, UOCR_SAM_MAX_GRID_SIZE, UOCR_SAM_HIDDEN_SIZE);

    VAPPEND1(UOCR_TENSOR_ID_VISION_CLIP_BASE + 0u,
             "CLIP class embedding",
             UOCR_TENSOR_FAMILY_VISION_CLIP,
             -1,
             -1,
             UOCR_TENSOR_PROJ_NONE,
             UOCR_CLIP_HIDDEN_SIZE);
    /* model.vision_model.embeddings.patch_embedding.weight is deliberately not
     * required for normal OCR inference: CLIP consumes SAM patch embeddings.
     */
    VAPPEND2(UOCR_TENSOR_ID_VISION_CLIP_BASE + 2u,
             "CLIP position embedding",
             UOCR_TENSOR_FAMILY_VISION_CLIP,
             -1,
             -1,
             UOCR_TENSOR_PROJ_NONE,
             UOCR_CLIP_GLOBAL_TOKENS,
             UOCR_CLIP_HIDDEN_SIZE);
    VAPPEND1(UOCR_TENSOR_ID_VISION_CLIP_BASE + 3u, "CLIP pre-LayerNorm bias", UOCR_TENSOR_FAMILY_VISION_CLIP, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_CLIP_HIDDEN_SIZE);
    VAPPEND1(UOCR_TENSOR_ID_VISION_CLIP_BASE + 4u, "CLIP pre-LayerNorm weight", UOCR_TENSOR_FAMILY_VISION_CLIP, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_CLIP_HIDDEN_SIZE);

    for (uint32_t sorted_layer = 0u; sorted_layer < UOCR_CLIP_BLOCKS; ++sorted_layer) {
        const uint32_t base = UOCR_TENSOR_ID_VISION_CLIP_BASE + 5u + sorted_layer * 12u;
        VAPPEND1(base + 0u, "CLIP layer_norm1 bias", UOCR_TENSOR_FAMILY_VISION_CLIP, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_CLIP_HIDDEN_SIZE);
        VAPPEND1(base + 1u, "CLIP layer_norm1 weight", UOCR_TENSOR_FAMILY_VISION_CLIP, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_CLIP_HIDDEN_SIZE);
        VAPPEND1(base + 2u, "CLIP layer_norm2 bias", UOCR_TENSOR_FAMILY_VISION_CLIP, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_CLIP_HIDDEN_SIZE);
        VAPPEND1(base + 3u, "CLIP layer_norm2 weight", UOCR_TENSOR_FAMILY_VISION_CLIP, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_CLIP_HIDDEN_SIZE);
        VAPPEND1(base + 4u, "CLIP MLP fc1 bias", UOCR_TENSOR_FAMILY_VISION_CLIP, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_CLIP_MLP_INTERMEDIATE);
        VAPPEND2(base + 5u, "CLIP MLP fc1 weight", UOCR_TENSOR_FAMILY_VISION_CLIP, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_CLIP_MLP_INTERMEDIATE, UOCR_CLIP_HIDDEN_SIZE);
        VAPPEND1(base + 6u, "CLIP MLP fc2 bias", UOCR_TENSOR_FAMILY_VISION_CLIP, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_CLIP_HIDDEN_SIZE);
        VAPPEND2(base + 7u, "CLIP MLP fc2 weight", UOCR_TENSOR_FAMILY_VISION_CLIP, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_CLIP_HIDDEN_SIZE, UOCR_CLIP_MLP_INTERMEDIATE);
        VAPPEND1(base + 8u, "CLIP attention output bias", UOCR_TENSOR_FAMILY_VISION_CLIP, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_CLIP_HIDDEN_SIZE);
        VAPPEND2(base + 9u, "CLIP attention output weight", UOCR_TENSOR_FAMILY_VISION_CLIP, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_CLIP_HIDDEN_SIZE, UOCR_CLIP_HIDDEN_SIZE);
        VAPPEND1(base + 10u, "CLIP attention qkv bias", UOCR_TENSOR_FAMILY_VISION_CLIP, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_CLIP_QKV_SIZE);
        VAPPEND2(base + 11u, "CLIP attention qkv weight", UOCR_TENSOR_FAMILY_VISION_CLIP, -1, -1, UOCR_TENSOR_PROJ_NONE, UOCR_CLIP_QKV_SIZE, UOCR_CLIP_HIDDEN_SIZE);
    }

#undef VAPPEND1
#undef VAPPEND2
#undef VAPPEND4

    if (cache.count != UOCR_METAL_VISION_REQUIRED_TENSOR_COUNT) {
        return metal_fail(error,
                          error_size,
                          "vision tensor binding count mismatch: got %u expected %u",
                          cache.count,
                          (uint32_t)UOCR_METAL_VISION_REQUIRED_TENSOR_COUNT);
    }
    uocr_metal_vision_weights_f16 weights;
    const uint64_t direct_cache_start_ns = uocr_profile_now_ns();
    if (!metal_vision_weight_cache_build_direct(&cache, &weights, error, error_size)) {
        return 0;
    }
    metal_profile_add_event_now(ctx, "metal.vision_binding_cache.direct", direct_cache_start_ns);
    cache.valid = 1;
    ctx->vision_bindings = cache;
    ctx->vision_weights = weights;
    ctx->vision_binding_error[0] = '\0';
    return 1;
}

uint32_t uocr_metal_context_vision_binding_count(const uocr_metal_context *ctx) {
    return ctx != NULL && ctx->vision_bindings.valid ? ctx->vision_bindings.count : 0u;
}

int uocr_metal_context_vision_bindings_ready(const uocr_metal_context *ctx) {
    return ctx != NULL && ctx->vision_bindings.valid && ctx->vision_weights.valid &&
           ctx->vision_bindings.count == UOCR_METAL_VISION_REQUIRED_TENSOR_COUNT &&
           ctx->vision_weights.count == UOCR_METAL_VISION_REQUIRED_TENSOR_COUNT;
}

const char *uocr_metal_context_vision_binding_error(const uocr_metal_context *ctx) {
    if (ctx == NULL || ctx->vision_binding_error[0] == '\0') {
        return "vision tensor bindings are not validated";
    }
    return ctx->vision_binding_error;
}

static const uocr_metal_vision_binding *metal_find_vision_binding_in_cache(const uocr_metal_vision_binding_cache *cache,
                                                                           uint32_t tensor_id) {
    if (cache == NULL || tensor_id == 0u) {
        return NULL;
    }
    for (uint32_t i = 0u; i < cache->count; ++i) {
        if (cache->tensors[i].tensor_id == tensor_id) {
            return &cache->tensors[i];
        }
    }
    return NULL;
}

static uint32_t metal_sam_sorted_block_index_for_layer(uint32_t layer) {
    if (layer <= 1u) {
        return layer;
    }
    if (layer <= 9u) {
        return layer + 2u;
    }
    return layer - 8u;
}

static uint32_t metal_clip_sorted_layer_index_for_layer(uint32_t layer) {
    if (layer <= 1u) {
        return layer;
    }
    if (layer >= 10u && layer <= 19u) {
        return 2u + (layer - 10u);
    }
    if (layer == 2u) {
        return 12u;
    }
    if (layer >= 20u && layer <= 23u) {
        return 13u + (layer - 20u);
    }
    return 17u + (layer - 3u);
}

static int metal_vision_tensor_from_binding_cache_f16(const uocr_metal_vision_binding_cache *cache,
                                                      uint32_t tensor_id,
                                                      const char *role,
                                                      uocr_metal_vision_tensor_f16 *out_tensor,
                                                      char *error,
                                                      size_t error_size) {
    if (out_tensor == NULL) {
        return metal_fail(error, error_size, "invalid Metal vision tensor slice output");
    }
    memset(out_tensor, 0, sizeof(*out_tensor));
    if (role == NULL || role[0] == '\0') {
        role = "vision tensor";
    }
    const uocr_metal_vision_binding *binding = metal_find_vision_binding_in_cache(cache, tensor_id);
    if (binding == NULL) {
        return metal_fail(error, error_size, "missing validated %s binding for tensor %u", role, tensor_id);
    }
    if ((binding->payload_size % 2u) != 0u || ((uint64_t)binding->offset % 2u) != 0u) {
        return metal_fail(error, error_size, "%s tensor %u has an unaligned fp16 payload", role, tensor_id);
    }
    if (binding->buffer == nil) {
        return metal_fail(error, error_size, "vision tensor %u has a nil Metal buffer binding", tensor_id);
    }
    if (!metal_buffer_range_valid(binding->buffer, binding->offset, binding->payload_size)) {
        return metal_fail(error,
                          error_size,
                          "%s tensor %u range is outside its Metal model view",
                          role,
                          tensor_id);
    }
    const uint8_t *contents = (const uint8_t *)[binding->buffer contents];
    if (contents == NULL) {
        return metal_fail(error,
                          error_size,
                          "vision tensor %u is not CPU-visible for the current host-pointer vision helpers",
                          tensor_id);
    }
    out_tensor->slice.buffer = binding->buffer;
    out_tensor->slice.offset = binding->offset;
    out_tensor->byte_length = binding->payload_size;
    out_tensor->host_f16 = (const uint16_t *)(const void *)(contents + binding->offset);
    return 1;
}

static int metal_vision_weight_cache_build_direct(const uocr_metal_vision_binding_cache *binding_cache,
                                                  uocr_metal_vision_weights_f16 *out_weights,
                                                  char *error,
                                                  size_t error_size) {
    if (binding_cache == NULL || out_weights == NULL) {
        return metal_fail(error, error_size, "invalid Metal vision direct weight-cache request");
    }
    if (binding_cache->count != UOCR_METAL_VISION_REQUIRED_TENSOR_COUNT) {
        return metal_fail(error,
                          error_size,
                          "vision direct weight-cache count mismatch: got %u expected %u",
                          binding_cache->count,
                          (uint32_t)UOCR_METAL_VISION_REQUIRED_TENSOR_COUNT);
    }
    memset(out_weights, 0, sizeof(*out_weights));

#define ASSIGN_VISION_TENSOR(field, tensor_id, role)                                                   \
    do {                                                                                                \
        if (!metal_vision_tensor_from_binding_cache_f16(binding_cache,                                  \
                                                        (tensor_id),                                    \
                                                        (role),                                         \
                                                        &(out_weights->field),                          \
                                                        error,                                          \
                                                        error_size)) {                                  \
            return 0;                                                                                   \
        }                                                                                               \
    } while (0)

    ASSIGN_VISION_TENSOR(image_newline, UOCR_TENSOR_ID_IMAGE_NEWLINE, "image newline");
    ASSIGN_VISION_TENSOR(view_separator, UOCR_TENSOR_ID_VIEW_SEPARATOR, "view separator");
    ASSIGN_VISION_TENSOR(projector_weight, UOCR_TENSOR_ID_PROJECTOR_WEIGHT, "visual projector weight");
    ASSIGN_VISION_TENSOR(projector_bias, UOCR_TENSOR_ID_PROJECTOR_BIAS, "visual projector bias");

    const uint32_t sam_extra = UOCR_TENSOR_ID_VISION_SAM_BASE + UOCR_SAM_BLOCKS * 14u;
    ASSIGN_VISION_TENSOR(sam_neck_conv1x1_weight, sam_extra + 0u, "SAM neck 1x1 weight");
    ASSIGN_VISION_TENSOR(sam_neck_norm1_bias, sam_extra + 1u, "SAM neck norm1 bias");
    ASSIGN_VISION_TENSOR(sam_neck_norm1_weight, sam_extra + 2u, "SAM neck norm1 weight");
    ASSIGN_VISION_TENSOR(sam_neck_conv3x3_weight, sam_extra + 3u, "SAM neck 3x3 weight");
    ASSIGN_VISION_TENSOR(sam_neck_norm2_bias, sam_extra + 4u, "SAM neck norm2 bias");
    ASSIGN_VISION_TENSOR(sam_neck_norm2_weight, sam_extra + 5u, "SAM neck norm2 weight");
    ASSIGN_VISION_TENSOR(sam_net2_weight, sam_extra + 6u, "SAM net_2 weight");
    ASSIGN_VISION_TENSOR(sam_net3_weight, sam_extra + 7u, "SAM net_3 weight");
    ASSIGN_VISION_TENSOR(sam_patch_bias, sam_extra + 8u, "SAM patch bias");
    ASSIGN_VISION_TENSOR(sam_patch_weight, sam_extra + 9u, "SAM patch weight");
    ASSIGN_VISION_TENSOR(sam_pos_embed, sam_extra + 10u, "SAM absolute position embedding");

    ASSIGN_VISION_TENSOR(clip_class_embedding, UOCR_TENSOR_ID_VISION_CLIP_BASE + 0u, "CLIP class embedding");
    ASSIGN_VISION_TENSOR(clip_pos_embed, UOCR_TENSOR_ID_VISION_CLIP_BASE + 2u, "CLIP position embedding");
    ASSIGN_VISION_TENSOR(clip_pre_ln_bias, UOCR_TENSOR_ID_VISION_CLIP_BASE + 3u, "CLIP pre-LayerNorm bias");
    ASSIGN_VISION_TENSOR(clip_pre_ln_weight, UOCR_TENSOR_ID_VISION_CLIP_BASE + 4u, "CLIP pre-LayerNorm weight");

#undef ASSIGN_VISION_TENSOR

#define ASSIGN_SAM_BLOCK_TENSOR(block_field, tensor_id, role, host_field)                              \
    do {                                                                                                \
        if (!metal_vision_tensor_from_binding_cache_f16(binding_cache,                                  \
                                                        (tensor_id),                                    \
                                                        (role),                                         \
                                                        &(direct_block->block_field),                   \
                                                        error,                                          \
                                                        error_size)) {                                  \
            return 0;                                                                                   \
        }                                                                                               \
        host_block->host_field = direct_block->block_field.host_f16;                                    \
    } while (0)

    for (uint32_t layer = 0u; layer < UOCR_SAM_BLOCKS; ++layer) {
        const uint32_t base = UOCR_TENSOR_ID_VISION_SAM_BASE + metal_sam_sorted_block_index_for_layer(layer) * 14u;
        uocr_metal_sam_transformer_block_slices_f16 *direct_block = &out_weights->sam_block_slices[layer];
        uocr_metal_sam_transformer_block_f16 *host_block = &out_weights->sam_blocks[layer];
        ASSIGN_SAM_BLOCK_TENSOR(proj_bias, base + 0u, "SAM attention projection bias", proj_bias_f16);
        ASSIGN_SAM_BLOCK_TENSOR(proj_weight, base + 1u, "SAM attention projection weight", proj_weight_f16);
        ASSIGN_SAM_BLOCK_TENSOR(qkv_bias, base + 2u, "SAM attention qkv bias", qkv_bias_f16);
        ASSIGN_SAM_BLOCK_TENSOR(qkv_weight, base + 3u, "SAM attention qkv weight", qkv_weight_f16);
        ASSIGN_SAM_BLOCK_TENSOR(rel_pos_h, base + 4u, "SAM relative position H", rel_pos_h_f16);
        ASSIGN_SAM_BLOCK_TENSOR(rel_pos_w, base + 5u, "SAM relative position W", rel_pos_w_f16);
        ASSIGN_SAM_BLOCK_TENSOR(mlp_lin1_bias, base + 6u, "SAM MLP lin1 bias", mlp_lin1_bias_f16);
        ASSIGN_SAM_BLOCK_TENSOR(mlp_lin1_weight, base + 7u, "SAM MLP lin1 weight", mlp_lin1_weight_f16);
        ASSIGN_SAM_BLOCK_TENSOR(mlp_lin2_bias, base + 8u, "SAM MLP lin2 bias", mlp_lin2_bias_f16);
        ASSIGN_SAM_BLOCK_TENSOR(mlp_lin2_weight, base + 9u, "SAM MLP lin2 weight", mlp_lin2_weight_f16);
        ASSIGN_SAM_BLOCK_TENSOR(norm1_bias, base + 10u, "SAM norm1 bias", norm1_bias_f16);
        ASSIGN_SAM_BLOCK_TENSOR(norm1_weight, base + 11u, "SAM norm1 weight", norm1_weight_f16);
        ASSIGN_SAM_BLOCK_TENSOR(norm2_bias, base + 12u, "SAM norm2 bias", norm2_bias_f16);
        ASSIGN_SAM_BLOCK_TENSOR(norm2_weight, base + 13u, "SAM norm2 weight", norm2_weight_f16);
        direct_block->rel_pos_h_length = uocr_sam_block_uses_global_attention(layer) ? UOCR_SAM_MAX_REL_POS_SIZE : UOCR_SAM_WINDOW_REL_POS_SIZE;
        direct_block->rel_pos_w_length = direct_block->rel_pos_h_length;
        host_block->rel_pos_h_length = direct_block->rel_pos_h_length;
        host_block->rel_pos_w_length = direct_block->rel_pos_w_length;
        if (!metal_sam_transformer_block_has_weights(host_block)) {
            return metal_fail(error, error_size, "incomplete SAM transformer block %u direct vision bindings", layer);
        }
    }

#undef ASSIGN_SAM_BLOCK_TENSOR

#define ASSIGN_CLIP_BLOCK_TENSOR(block_field, tensor_id, role, host_field)                             \
    do {                                                                                                \
        if (!metal_vision_tensor_from_binding_cache_f16(binding_cache,                                  \
                                                        (tensor_id),                                    \
                                                        (role),                                         \
                                                        &(direct_block->block_field),                   \
                                                        error,                                          \
                                                        error_size)) {                                  \
            return 0;                                                                                   \
        }                                                                                               \
        host_block->host_field = direct_block->block_field.host_f16;                                    \
    } while (0)

    for (uint32_t layer = 0u; layer < UOCR_CLIP_BLOCKS; ++layer) {
        const uint32_t base = UOCR_TENSOR_ID_VISION_CLIP_BASE + 5u + metal_clip_sorted_layer_index_for_layer(layer) * 12u;
        uocr_metal_clip_transformer_block_slices_f16 *direct_block = &out_weights->clip_block_slices[layer];
        uocr_metal_clip_transformer_block_f16 *host_block = &out_weights->clip_blocks[layer];
        ASSIGN_CLIP_BLOCK_TENSOR(ln1_bias, base + 0u, "CLIP layer_norm1 bias", ln1_bias_f16);
        ASSIGN_CLIP_BLOCK_TENSOR(ln1_weight, base + 1u, "CLIP layer_norm1 weight", ln1_weight_f16);
        ASSIGN_CLIP_BLOCK_TENSOR(ln2_bias, base + 2u, "CLIP layer_norm2 bias", ln2_bias_f16);
        ASSIGN_CLIP_BLOCK_TENSOR(ln2_weight, base + 3u, "CLIP layer_norm2 weight", ln2_weight_f16);
        ASSIGN_CLIP_BLOCK_TENSOR(mlp_fc1_bias, base + 4u, "CLIP MLP fc1 bias", mlp_fc1_bias_f16);
        ASSIGN_CLIP_BLOCK_TENSOR(mlp_fc1_weight, base + 5u, "CLIP MLP fc1 weight", mlp_fc1_weight_f16);
        ASSIGN_CLIP_BLOCK_TENSOR(mlp_fc2_bias, base + 6u, "CLIP MLP fc2 bias", mlp_fc2_bias_f16);
        ASSIGN_CLIP_BLOCK_TENSOR(mlp_fc2_weight, base + 7u, "CLIP MLP fc2 weight", mlp_fc2_weight_f16);
        ASSIGN_CLIP_BLOCK_TENSOR(out_proj_bias, base + 8u, "CLIP attention output bias", out_proj_bias_f16);
        ASSIGN_CLIP_BLOCK_TENSOR(out_proj_weight, base + 9u, "CLIP attention output weight", out_proj_weight_f16);
        ASSIGN_CLIP_BLOCK_TENSOR(qkv_bias, base + 10u, "CLIP attention qkv bias", qkv_bias_f16);
        ASSIGN_CLIP_BLOCK_TENSOR(qkv_weight, base + 11u, "CLIP attention qkv weight", qkv_weight_f16);
        if (!metal_clip_transformer_block_has_weights(host_block)) {
            return metal_fail(error, error_size, "incomplete CLIP transformer block %u direct vision bindings", layer);
        }
    }

#undef ASSIGN_CLIP_BLOCK_TENSOR

    out_weights->valid = 1;
    out_weights->count = binding_cache->count;
    return 1;
}

static const uocr_metal_vision_weights_f16 *metal_require_vision_weights_f16(const uocr_metal_context *ctx,
                                                                             char *error,
                                                                             size_t error_size) {
    if (ctx == NULL || !ctx->vision_weights.valid ||
        ctx->vision_weights.count != UOCR_METAL_VISION_REQUIRED_TENSOR_COUNT) {
        (void)metal_fail(error,
                         error_size,
                         "Metal vision encoding requires direct fp16 vision weight slices: %s",
                         uocr_metal_context_vision_binding_error(ctx));
        return NULL;
    }
    return &ctx->vision_weights;
}

typedef struct uocr_metal_vision_workspace_slice {
    id<MTLBuffer> buffer;
    NSUInteger offset;
    uint64_t bytes;
    uint16_t *f16;
} uocr_metal_vision_workspace_slice;

typedef struct uocr_metal_vision_workspace {
    uocr_metal_vision_workspace_slice sam_patch_bhwc;
    uocr_metal_vision_workspace_slice sam_pos_bhwc;
    uocr_metal_vision_workspace_slice sam_transformer_bhwc;
    uocr_metal_vision_workspace_slice sam_transformer_batch_bhwc;
    uocr_metal_vision_workspace_slice sam_block_norm1_bhwc;
    uocr_metal_vision_workspace_slice sam_block_window_tokens;
    uocr_metal_vision_workspace_slice sam_block_q;
    uocr_metal_vision_workspace_slice sam_block_k;
    uocr_metal_vision_workspace_slice sam_block_v;
    uocr_metal_vision_workspace_slice sam_block_attention;
    uocr_metal_vision_workspace_slice sam_block_projected_windows;
    uocr_metal_vision_workspace_slice sam_block_attention_bhwc;
    uocr_metal_vision_workspace_slice sam_block_residual1_bhwc;
    uocr_metal_vision_workspace_slice sam_block_norm2_bhwc;
    uocr_metal_vision_workspace_slice sam_block_mlp_intermediate;
    uocr_metal_vision_workspace_slice sam_block_mlp_bhwc;
    uocr_metal_vision_workspace_slice sam_neck_a_nchw;
    uocr_metal_vision_workspace_slice sam_neck_b_nchw;
    uocr_metal_vision_workspace_slice sam_net2_nchw;
    uocr_metal_vision_workspace_slice sam_net3_nchw;
    uocr_metal_vision_workspace_slice clip_a;
    uocr_metal_vision_workspace_slice clip_b;
    uocr_metal_vision_workspace_slice clip_final;
    uocr_metal_vision_workspace_slice clip_block_norm1;
    uocr_metal_vision_workspace_slice clip_block_q;
    uocr_metal_vision_workspace_slice clip_block_k;
    uocr_metal_vision_workspace_slice clip_block_v;
    uocr_metal_vision_workspace_slice clip_block_attention;
    uocr_metal_vision_workspace_slice clip_block_projected;
    uocr_metal_vision_workspace_slice clip_block_residual1;
    uocr_metal_vision_workspace_slice clip_block_norm2;
    uocr_metal_vision_workspace_slice clip_block_mlp;
    uocr_metal_vision_workspace_slice clip_mlp_fc1;
    uocr_metal_vision_workspace_slice clip_mlp_activated;
    uocr_metal_vision_workspace_slice concat;
    uocr_metal_vision_workspace_slice projected_rows;
    uocr_metal_vision_workspace_slice final_visual_rows;
    uint32_t sam_patch_view_capacity;
    uint32_t projected_row_capacity;
    uint32_t final_visual_row_capacity;
    uint64_t required_bytes;
} uocr_metal_vision_workspace;

static void metal_vision_workspace_reset(uocr_metal_vision_workspace *workspace) {
    if (workspace != NULL) {
        memset(workspace, 0, sizeof(*workspace));
    }
}

static int metal_vision_workspace_add_slice_size(uint64_t *cursor,
                                                 uint64_t value_count,
                                                 const char *label,
                                                 char *error,
                                                 size_t error_size) {
    if (cursor == NULL || value_count == 0u) {
        return metal_fail(error, error_size, "invalid Metal vision workspace slice request");
    }
    uint64_t bytes = 0u;
    if (!checked_mul_u64(value_count, 2u, &bytes) || bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error, error_size, "Metal vision workspace slice for %s overflows", label != NULL ? label : "buffer");
    }
    if (!align_up_u64_checked(*cursor, 256u, cursor) || !checked_add_u64(*cursor, bytes, cursor)) {
        return metal_fail(error, error_size, "Metal vision workspace byte-size overflow for %s", label != NULL ? label : "buffer");
    }
    return 1;
}

/* Legacy diagnostic helpers still accept host pointers, but production vision
 * now keeps workspace scratch private.  For private scratch, f16 fields carry
 * opaque offset tokens that metal_vision_scratch_pointer_slice() maps back to
 * the retained MTLBuffer without ever dereferencing them.
 */
static uint16_t *metal_private_workspace_token(NSUInteger offset) {
    const uintptr_t base = UOCR_METAL_PRIVATE_WORKSPACE_PTR_BASE;
    const uintptr_t offset_value = (uintptr_t)offset;
    if (offset_value > UINTPTR_MAX - base) {
        return NULL;
    }
    return (uint16_t *)(void *)(base + offset_value);
}

static int metal_vision_workspace_assign_slice(uocr_metal_vision_workspace_slice *slice,
                                               id<MTLBuffer> buffer,
                                               uint8_t *base,
                                               uint64_t *cursor,
                                               uint64_t value_count,
                                               const char *label,
                                               char *error,
                                               size_t error_size) {
    if (slice == NULL || buffer == nil || cursor == NULL || value_count == 0u) {
        return metal_fail(error, error_size, "invalid Metal vision workspace slice assignment");
    }
    uint64_t bytes = 0u;
    if (!checked_mul_u64(value_count, 2u, &bytes) || bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error, error_size, "Metal vision workspace slice for %s overflows", label != NULL ? label : "buffer");
    }
    if (!align_up_u64_checked(*cursor, 256u, cursor) || *cursor > (uint64_t)NSUIntegerMax) {
        return metal_fail(error, error_size, "Metal vision workspace offset overflow for %s", label != NULL ? label : "buffer");
    }
    const uint64_t offset = *cursor;
    if (!checked_add_u64(offset, bytes, cursor) || *cursor > (uint64_t)[buffer length]) {
        return metal_fail(error, error_size, "Metal vision workspace backing buffer is too small for %s", label != NULL ? label : "buffer");
    }
    slice->buffer = buffer;
    slice->offset = (NSUInteger)offset;
    slice->bytes = bytes;
    if (base != NULL) {
        slice->f16 = (uint16_t *)(void *)(base + (size_t)offset);
    } else {
        slice->f16 = metal_private_workspace_token((NSUInteger)offset);
        if (slice->f16 == NULL) {
            return metal_fail(error, error_size, "Metal private vision workspace token overflow for %s", label != NULL ? label : "buffer");
        }
    }
    return 1;
}

static int metal_vision_workspace_shape_for_view_size(uint32_t max_view_size,
                                                       uint32_t *out_patch_grid,
                                                       uint32_t *out_projected_grid,
                                                       char *error,
                                                       size_t error_size) {
    if (out_patch_grid == NULL || out_projected_grid == NULL) {
        return metal_fail(error, error_size, "invalid Metal vision workspace shape output");
    }
    if (max_view_size == UOCR_GLOBAL_VIEW_SIZE) {
        *out_patch_grid = UOCR_GLOBAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE;
        *out_projected_grid = UOCR_GLOBAL_GRID_QUERIES;
        return 1;
    }
    if (max_view_size == UOCR_LOCAL_VIEW_SIZE) {
        *out_patch_grid = UOCR_LOCAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE;
        *out_projected_grid = UOCR_LOCAL_GRID_QUERIES;
        return 1;
    }
    return metal_fail(error,
                      error_size,
                      "Metal vision workspace max view size must be %u or %u, got %u",
                      UOCR_LOCAL_VIEW_SIZE,
                      UOCR_GLOBAL_VIEW_SIZE,
                      max_view_size);
}

static int metal_vision_workspace_init(uocr_metal_context *ctx,
                                       uocr_metal_vision_workspace *workspace,
                                       uint32_t max_view_size,
                                       uint32_t sam_patch_view_capacity,
                                       uint32_t projected_row_capacity,
                                       uint32_t final_visual_row_capacity,
                                       int cpu_visible,
                                       char *error,
                                       size_t error_size) {
    if (ctx == NULL || workspace == NULL) {
        return metal_fail(error, error_size, "Metal vision workspace output is null");
    }
    memset(workspace, 0, sizeof(*workspace));
    uint32_t patch_grid = 0u;
    uint32_t projected_grid = 0u;
    if (!metal_vision_workspace_shape_for_view_size(max_view_size, &patch_grid, &projected_grid, error, error_size)) {
        return 0;
    }
    const uint32_t patch_view_capacity = sam_patch_view_capacity == 0u ? 1u : sam_patch_view_capacity;
    const uint64_t patch_tokens = (uint64_t)patch_grid * (uint64_t)patch_grid;
    const uint64_t projected_tokens_per_view = (uint64_t)projected_grid * (uint64_t)projected_grid;
    const uint64_t projected_rows_for_chunk = projected_row_capacity != 0u ?
                                                  (uint64_t)projected_row_capacity :
                                                  projected_tokens_per_view;
    const uint64_t sam_bhwc_values = patch_tokens * (uint64_t)UOCR_SAM_HIDDEN_SIZE;
    uint64_t patch_batch_views_for_max_shape = (projected_rows_for_chunk + projected_tokens_per_view - 1u) /
                                               projected_tokens_per_view;
    if (patch_batch_views_for_max_shape == 0u) {
        patch_batch_views_for_max_shape = 1u;
    }
    uint64_t patch_batch_tokens = 0u;
    if (!checked_mul_u64(patch_tokens, patch_batch_views_for_max_shape, &patch_batch_tokens)) {
        return metal_fail(error, error_size, "Metal batched SAM patch workspace byte-size overflow");
    }
    if (max_view_size >= UOCR_GLOBAL_VIEW_SIZE && patch_view_capacity > 1u) {
        const uint64_t local_patch_grid = (uint64_t)UOCR_LOCAL_VIEW_SIZE / (uint64_t)UOCR_VISION_PATCH_SIZE;
        uint64_t local_patch_tokens = 0u;
        uint64_t local_patch_batch_tokens = 0u;
        if (!checked_mul_u64(local_patch_grid, local_patch_grid, &local_patch_tokens) ||
            !checked_mul_u64(local_patch_tokens, (uint64_t)patch_view_capacity, &local_patch_batch_tokens)) {
            return metal_fail(error, error_size, "Metal local SAM patch workspace byte-size overflow");
        }
        if (local_patch_batch_tokens > patch_batch_tokens) {
            patch_batch_tokens = local_patch_batch_tokens;
        }
    }
    uint64_t sam_patch_bhwc_values = 0u;
    if (!checked_mul_u64(patch_batch_tokens, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &sam_patch_bhwc_values)) {
        return metal_fail(error, error_size, "Metal batched SAM patch workspace byte-size overflow");
    }
    const uint64_t sam_transformer_batch_values_per_view = patch_tokens * (uint64_t)UOCR_SAM_HIDDEN_SIZE;
    const uint64_t sam_neck_values_per_view = (uint64_t)UOCR_SAM_NECK_CHANNELS * patch_tokens;
    const uint64_t max_net2_grid = ((uint64_t)patch_grid + 1u) / 2u;
    const uint64_t max_net3_grid = (max_net2_grid + 1u) / 2u;
    const uint64_t sam_net2_values_per_view = (uint64_t)UOCR_SAM_NET2_CHANNELS * max_net2_grid * max_net2_grid;
    const uint64_t sam_net3_values_per_view = (uint64_t)UOCR_SAM_NET3_CHANNELS * max_net3_grid * max_net3_grid;
    const uint64_t clip_tokens = projected_tokens_per_view + (uint64_t)UOCR_CLIP_CLASS_TOKENS;
    uint64_t clip_view_capacity = (projected_rows_for_chunk + projected_tokens_per_view - 1u) / projected_tokens_per_view;
    if (clip_view_capacity == 0u) {
        clip_view_capacity = 1u;
    }
    uint64_t sam_transformer_batch_values = 0u;
    uint64_t sam_neck_values = 0u;
    uint64_t sam_net2_values = 0u;
    uint64_t sam_net3_values = 0u;
    uint64_t clip_values = 0u;
    uint64_t clip_final_values = 0u;
    uint64_t clip_mlp_batch_values = 0u;
    uint64_t concat_values = 0u;
    if (!checked_mul_u64(clip_tokens, (uint64_t)UOCR_CLIP_HIDDEN_SIZE, &clip_values) ||
        !checked_mul_u64(sam_transformer_batch_values_per_view, clip_view_capacity, &sam_transformer_batch_values) ||
        !checked_mul_u64(sam_neck_values_per_view, clip_view_capacity, &sam_neck_values) ||
        !checked_mul_u64(sam_net2_values_per_view, clip_view_capacity, &sam_net2_values) ||
        !checked_mul_u64(sam_net3_values_per_view, clip_view_capacity, &sam_net3_values) ||
        !checked_mul_u64(clip_values, clip_view_capacity, &clip_final_values) ||
        !checked_mul_u64(projected_rows_for_chunk, (uint64_t)UOCR_PROJECTOR_IN_SIZE, &concat_values)) {
        return metal_fail(error, error_size, "Metal batched SAM neck/CLIP workspace byte-size overflow");
    }
    uint64_t sam_window_count = 0u;
    uint64_t sam_window_attention_tokens = 0u;
    uint64_t sam_attention_tokens = patch_tokens;
    uint64_t sam_attention_values = 0u;
    uint64_t sam_attention_batch_values = 0u;
    uint64_t sam_mlp_values = 0u;
    uint64_t sam_mlp_batch_values = 0u;
    uint64_t clip_mlp_values = 0u;
    uint64_t projected_values = 0u;
    uint64_t final_visual_values = 0u;
    const uint64_t sam_windows_per_side = ((uint64_t)patch_grid + (uint64_t)UOCR_SAM_WINDOW_SIZE - 1u) /
                                           (uint64_t)UOCR_SAM_WINDOW_SIZE;
    if (!checked_mul_u64(sam_windows_per_side, sam_windows_per_side, &sam_window_count) ||
        !checked_mul_u64(sam_window_count, (uint64_t)UOCR_SAM_WINDOW_TOKENS, &sam_window_attention_tokens) ||
        !checked_mul_u64(sam_attention_tokens > sam_window_attention_tokens ? sam_attention_tokens : sam_window_attention_tokens,
                         (uint64_t)UOCR_SAM_HIDDEN_SIZE,
                         &sam_attention_values) ||
        !checked_mul_u64(sam_attention_values, clip_view_capacity, &sam_attention_batch_values) ||
        !checked_mul_u64(patch_tokens, (uint64_t)UOCR_SAM_MLP_INTERMEDIATE, &sam_mlp_values) ||
        !checked_mul_u64(sam_mlp_values, clip_view_capacity, &sam_mlp_batch_values) ||
        !checked_mul_u64(clip_tokens, (uint64_t)UOCR_CLIP_MLP_INTERMEDIATE, &clip_mlp_values) ||
        !checked_mul_u64(clip_mlp_values, clip_view_capacity, &clip_mlp_batch_values)) {
        return metal_fail(error, error_size, "Metal transformer vision workspace byte-size overflow");
    }
    if (projected_row_capacity != 0u &&
        !checked_mul_u64((uint64_t)projected_row_capacity, (uint64_t)UOCR_HIDDEN_SIZE, &projected_values)) {
        return metal_fail(error, error_size, "Metal projected visual workspace byte-size overflow");
    }
    if (final_visual_row_capacity != 0u &&
        !checked_mul_u64((uint64_t)final_visual_row_capacity, (uint64_t)UOCR_HIDDEN_SIZE, &final_visual_values)) {
        return metal_fail(error, error_size, "Metal final visual workspace byte-size overflow");
    }
    uint64_t final_visual_bytes = 0u;
    if (final_visual_values != 0u && !checked_mul_u64(final_visual_values, 2u, &final_visual_bytes)) {
        return metal_fail(error, error_size, "Metal final visual workspace byte-size overflow");
    }

    uint64_t required_bytes = 0u;
#define ADD_WORKSPACE_SLICE(values, label) \
    do {                                   \
        if (!metal_vision_workspace_add_slice_size(&required_bytes, (values), (label), error, error_size)) { \
            return 0;                      \
        }                                  \
    } while (0)

    ADD_WORKSPACE_SLICE(sam_patch_bhwc_values, "SAM patch BHWC batch");
    ADD_WORKSPACE_SLICE(sam_transformer_batch_values, "SAM positioned BHWC");
    ADD_WORKSPACE_SLICE(sam_bhwc_values, "SAM transformer BHWC");
    ADD_WORKSPACE_SLICE(sam_transformer_batch_values, "SAM transformer BHWC batch");
    ADD_WORKSPACE_SLICE(sam_transformer_batch_values, "SAM block norm1 BHWC");
    ADD_WORKSPACE_SLICE(sam_attention_batch_values, "SAM block window tokens");
    ADD_WORKSPACE_SLICE(sam_attention_batch_values, "SAM block Q");
    ADD_WORKSPACE_SLICE(sam_attention_batch_values, "SAM block K");
    ADD_WORKSPACE_SLICE(sam_attention_batch_values, "SAM block V");
    ADD_WORKSPACE_SLICE(sam_attention_batch_values, "SAM block attention");
    ADD_WORKSPACE_SLICE(sam_attention_batch_values, "SAM block projected windows");
    ADD_WORKSPACE_SLICE(sam_transformer_batch_values, "SAM block attention BHWC");
    ADD_WORKSPACE_SLICE(sam_transformer_batch_values, "SAM block residual1 BHWC");
    ADD_WORKSPACE_SLICE(sam_transformer_batch_values, "SAM block norm2 BHWC");
    ADD_WORKSPACE_SLICE(sam_mlp_batch_values, "SAM block MLP intermediate");
    ADD_WORKSPACE_SLICE(sam_transformer_batch_values, "SAM block MLP BHWC");
    ADD_WORKSPACE_SLICE(sam_neck_values, "SAM neck A NCHW");
    ADD_WORKSPACE_SLICE(sam_neck_values, "SAM neck B NCHW");
    ADD_WORKSPACE_SLICE(sam_net2_values, "SAM net_2 NCHW");
    ADD_WORKSPACE_SLICE(sam_net3_values, "SAM net_3 NCHW");
    ADD_WORKSPACE_SLICE(clip_final_values, "CLIP token A");
    ADD_WORKSPACE_SLICE(clip_final_values, "CLIP token B");
    ADD_WORKSPACE_SLICE(clip_final_values, "CLIP transformer output");
    ADD_WORKSPACE_SLICE(clip_final_values, "CLIP block norm1");
    ADD_WORKSPACE_SLICE(clip_final_values, "CLIP block Q");
    ADD_WORKSPACE_SLICE(clip_final_values, "CLIP block K");
    ADD_WORKSPACE_SLICE(clip_final_values, "CLIP block V");
    ADD_WORKSPACE_SLICE(clip_final_values, "CLIP block attention");
    ADD_WORKSPACE_SLICE(clip_final_values, "CLIP block projected");
    ADD_WORKSPACE_SLICE(clip_final_values, "CLIP block residual1");
    ADD_WORKSPACE_SLICE(clip_final_values, "CLIP block norm2");
    ADD_WORKSPACE_SLICE(clip_final_values, "CLIP block MLP");
    ADD_WORKSPACE_SLICE(clip_mlp_batch_values, "CLIP MLP fc1");
    ADD_WORKSPACE_SLICE(clip_mlp_batch_values, "CLIP MLP activated");
    ADD_WORKSPACE_SLICE(concat_values, "CLIP/SAM concat");
    if (projected_values != 0u) {
        ADD_WORKSPACE_SLICE(projected_values, "projected visual chunk rows");
    }
    if (final_visual_values != 0u) {
        ADD_WORKSPACE_SLICE(final_visual_values, "final formatted visual rows");
    }

#undef ADD_WORKSPACE_SLICE

    if (!metal_context_ensure_scratch_accounted(ctx,
                                                UOCR_METAL_SCRATCH_VISION,
                                                required_bytes,
                                                cpu_visible,
                                                UOCR_MEMORY_VISION_FINAL_FEATURES,
                                                final_visual_bytes,
                                                error,
                                                error_size)) {
        return 0;
    }
    id<MTLBuffer> buffer = ctx->scratch[UOCR_METAL_SCRATCH_VISION].buffer;
    uint8_t *base = (cpu_visible && buffer != nil) ? (uint8_t *)[buffer contents] : NULL;
    if (buffer == nil || (cpu_visible && base == NULL)) {
        return metal_fail(error,
                          error_size,
                          "Metal vision workspace scratch buffer is not %s",
                          cpu_visible ? "CPU-visible" : "allocated");
    }

    uint64_t cursor = 0u;
#define ASSIGN_WORKSPACE_SLICE(field, values, label) \
    do {                                             \
        if (!metal_vision_workspace_assign_slice(&(workspace->field), buffer, base, &cursor, (values), (label), error, error_size)) { \
            metal_vision_workspace_reset(workspace); \
            return 0;                                \
        }                                            \
    } while (0)

    ASSIGN_WORKSPACE_SLICE(sam_patch_bhwc, sam_patch_bhwc_values, "SAM patch BHWC batch");
    ASSIGN_WORKSPACE_SLICE(sam_pos_bhwc, sam_transformer_batch_values, "SAM positioned BHWC");
    ASSIGN_WORKSPACE_SLICE(sam_transformer_bhwc, sam_bhwc_values, "SAM transformer BHWC");
    ASSIGN_WORKSPACE_SLICE(sam_transformer_batch_bhwc, sam_transformer_batch_values, "SAM transformer BHWC batch");
    ASSIGN_WORKSPACE_SLICE(sam_block_norm1_bhwc, sam_transformer_batch_values, "SAM block norm1 BHWC");
    ASSIGN_WORKSPACE_SLICE(sam_block_window_tokens, sam_attention_batch_values, "SAM block window tokens");
    ASSIGN_WORKSPACE_SLICE(sam_block_q, sam_attention_batch_values, "SAM block Q");
    ASSIGN_WORKSPACE_SLICE(sam_block_k, sam_attention_batch_values, "SAM block K");
    ASSIGN_WORKSPACE_SLICE(sam_block_v, sam_attention_batch_values, "SAM block V");
    ASSIGN_WORKSPACE_SLICE(sam_block_attention, sam_attention_batch_values, "SAM block attention");
    ASSIGN_WORKSPACE_SLICE(sam_block_projected_windows, sam_attention_batch_values, "SAM block projected windows");
    ASSIGN_WORKSPACE_SLICE(sam_block_attention_bhwc, sam_transformer_batch_values, "SAM block attention BHWC");
    ASSIGN_WORKSPACE_SLICE(sam_block_residual1_bhwc, sam_transformer_batch_values, "SAM block residual1 BHWC");
    ASSIGN_WORKSPACE_SLICE(sam_block_norm2_bhwc, sam_transformer_batch_values, "SAM block norm2 BHWC");
    ASSIGN_WORKSPACE_SLICE(sam_block_mlp_intermediate, sam_mlp_batch_values, "SAM block MLP intermediate");
    ASSIGN_WORKSPACE_SLICE(sam_block_mlp_bhwc, sam_transformer_batch_values, "SAM block MLP BHWC");
    ASSIGN_WORKSPACE_SLICE(sam_neck_a_nchw, sam_neck_values, "SAM neck A NCHW");
    ASSIGN_WORKSPACE_SLICE(sam_neck_b_nchw, sam_neck_values, "SAM neck B NCHW");
    ASSIGN_WORKSPACE_SLICE(sam_net2_nchw, sam_net2_values, "SAM net_2 NCHW");
    ASSIGN_WORKSPACE_SLICE(sam_net3_nchw, sam_net3_values, "SAM net_3 NCHW");
    ASSIGN_WORKSPACE_SLICE(clip_a, clip_final_values, "CLIP token A");
    ASSIGN_WORKSPACE_SLICE(clip_b, clip_final_values, "CLIP token B");
    ASSIGN_WORKSPACE_SLICE(clip_final, clip_final_values, "CLIP transformer output");
    ASSIGN_WORKSPACE_SLICE(clip_block_norm1, clip_final_values, "CLIP block norm1");
    ASSIGN_WORKSPACE_SLICE(clip_block_q, clip_final_values, "CLIP block Q");
    ASSIGN_WORKSPACE_SLICE(clip_block_k, clip_final_values, "CLIP block K");
    ASSIGN_WORKSPACE_SLICE(clip_block_v, clip_final_values, "CLIP block V");
    ASSIGN_WORKSPACE_SLICE(clip_block_attention, clip_final_values, "CLIP block attention");
    ASSIGN_WORKSPACE_SLICE(clip_block_projected, clip_final_values, "CLIP block projected");
    ASSIGN_WORKSPACE_SLICE(clip_block_residual1, clip_final_values, "CLIP block residual1");
    ASSIGN_WORKSPACE_SLICE(clip_block_norm2, clip_final_values, "CLIP block norm2");
    ASSIGN_WORKSPACE_SLICE(clip_block_mlp, clip_final_values, "CLIP block MLP");
    ASSIGN_WORKSPACE_SLICE(clip_mlp_fc1, clip_mlp_batch_values, "CLIP MLP fc1");
    ASSIGN_WORKSPACE_SLICE(clip_mlp_activated, clip_mlp_batch_values, "CLIP MLP activated");
    ASSIGN_WORKSPACE_SLICE(concat, concat_values, "CLIP/SAM concat");
    if (projected_values != 0u) {
        ASSIGN_WORKSPACE_SLICE(projected_rows, projected_values, "projected visual chunk rows");
    }
    if (final_visual_values != 0u) {
        ASSIGN_WORKSPACE_SLICE(final_visual_rows, final_visual_values, "final formatted visual rows");
    }

#undef ASSIGN_WORKSPACE_SLICE

    workspace->sam_patch_view_capacity = patch_view_capacity;
    workspace->projected_row_capacity = projected_row_capacity;
    workspace->final_visual_row_capacity = final_visual_row_capacity;
    workspace->required_bytes = required_bytes;
    return 1;
}

