        !metal_vision_require_workspace_slice_f16(out_nchw, bytes, "SAM neck 3x3 output", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(weight, weight_bytes, "SAM neck 3x3 weight", error, error_size)) {
