                                                             UOCR_METAL_LAYERNORM_OUTPUT_F16,
                                                             out_tokens.f16,
                                                             "Metal CLIP pre-LayerNorm",
                                                             error,
                                                             error_size);
}

static int metal_context_clip_sam_concat_batch_f16_to_slice(uocr_metal_context *ctx,
                                                            uocr_metal_vision_workspace_slice clip_tokens,
                                                            uocr_metal_vision_workspace_slice sam_nchw,
                                                            uint32_t grid_w,
                                                            uint32_t grid_h,
                                                            uint32_t view_count,
                                                            uocr_metal_vision_workspace_slice out_concat,
                                                            char *error,
                                                            size_t error_size) {
    uint64_t spatial = 0u;
    uint64_t clip_token_count = 0u;
    uint64_t clip_values_per_view = 0u;
    uint64_t clip_values = 0u;
    uint64_t sam_values_per_view = 0u;
    uint64_t sam_values = 0u;
    uint64_t output_values_per_view = 0u;
    uint64_t output_values = 0u;
    uint64_t clip_bytes = 0u;
    uint64_t sam_bytes = 0u;
    uint64_t output_bytes = 0u;
    if (view_count == 0u || !checked_mul_u64((uint64_t)grid_w, (uint64_t)grid_h, &spatial) ||
        !checked_add_u64(spatial, (uint64_t)UOCR_CLIP_CLASS_TOKENS, &clip_token_count) ||
        !checked_mul_u64(clip_token_count, (uint64_t)UOCR_CLIP_HIDDEN_SIZE, &clip_values_per_view) ||
        !checked_mul_u64(clip_values_per_view, (uint64_t)view_count, &clip_values) ||
        !checked_mul_u64(spatial, (uint64_t)UOCR_SAM_FEATURE_CHANNELS, &sam_values_per_view) ||
        !checked_mul_u64(sam_values_per_view, (uint64_t)view_count, &sam_values) ||
        !checked_mul_u64(spatial, (uint64_t)UOCR_PROJECTOR_IN_SIZE, &output_values_per_view) ||
        !checked_mul_u64(output_values_per_view, (uint64_t)view_count, &output_values) ||
        !metal_vision_f16_bytes(clip_values, &clip_bytes) ||
        !metal_vision_f16_bytes(sam_values, &sam_bytes) ||
        !metal_vision_f16_bytes(output_values, &output_bytes) ||
        !metal_vision_require_workspace_slice_f16(clip_tokens, clip_bytes, "CLIP/SAM concat CLIP input", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(sam_nchw, sam_bytes, "CLIP/SAM concat SAM input", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(out_concat, output_bytes, "CLIP/SAM concat output", error, error_size)) {
        return 0;
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_clip_sam_concat_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            return metal_fail(error, error_size, "failed to create Metal CLIP/SAM concat command buffer");
        }
        cb.label = @"uocr_clip_sam_concat_command_buffer";
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal CLIP/SAM concat encoder");
        }
        uocr_metal_clip_sam_concat_params params;
        params.grid_width = grid_w;
        params.grid_height = grid_h;
        params.hidden_size = UOCR_CLIP_HIDDEN_SIZE;
        params.projector_in_size = UOCR_PROJECTOR_IN_SIZE;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:clip_tokens.buffer offset:clip_tokens.offset atIndex:0u];
        [enc setBuffer:sam_nchw.buffer offset:sam_nchw.offset atIndex:1u];
        [enc setBuffer:out_concat.buffer offset:out_concat.offset atIndex:2u];
        [enc setBytes:&params length:sizeof(params) atIndex:3u];
        NSUInteger threads_x = pipeline.threadExecutionWidth;
        if (threads_x == 0u || threads_x > (NSUInteger)UOCR_PROJECTOR_IN_SIZE) {
            threads_x = 32u;
        }
        if (threads_x > pipeline.maxTotalThreadsPerThreadgroup) {
            threads_x = pipeline.maxTotalThreadsPerThreadgroup;
        }
        if (threads_x == 0u) {
            threads_x = 1u;
        }
        [enc dispatchThreads:MTLSizeMake((NSUInteger)UOCR_PROJECTOR_IN_SIZE, (NSUInteger)spatial, (NSUInteger)view_count)
       threadsPerThreadgroup:MTLSizeMake(threads_x, 1u, 1u)];
        [enc endEncoding];
        UOCR_METAL_COMMIT_AND_WAIT_PROFILED(ctx, cb);
        if (cb.status == MTLCommandBufferStatusError) {
            NSString *description = cb.error != nil ? [cb.error localizedDescription] : @"unknown command-buffer error";
            return metal_fail(error, error_size, "Metal CLIP/SAM concat command failed: %s", [description UTF8String]);
        }
        metal_clear_error(error, error_size);
        return 1;
    }
}

static int metal_context_clip_sam_concat_f16_to_slice(uocr_metal_context *ctx,
                                                      uocr_metal_vision_workspace_slice clip_tokens,
                                                      uocr_metal_vision_workspace_slice sam_nchw,
                                                      uint32_t grid_w,
                                                      uint32_t grid_h,
                                                      uocr_metal_vision_workspace_slice out_concat,
                                                      char *error,
                                                      size_t error_size) {
    return metal_context_clip_sam_concat_batch_f16_to_slice(ctx,
                                                           clip_tokens,
                                                           sam_nchw,
                                                           grid_w,
                                                           grid_h,
                                                           1u,
                                                           out_concat,
                                                           error,
                                                           error_size);
}

static int metal_context_visual_projector_f16_to_slice(uocr_metal_context *ctx,
                                                       uocr_metal_vision_workspace_slice input,
                                                       uocr_metal_vision_tensor_f16 weight,
                                                       uocr_metal_vision_tensor_f16 bias,
                                                       uint32_t n_rows,
                                                       uocr_metal_vision_workspace_slice out_rows,
                                                       char *error,
                                                       size_t error_size) {
    uint64_t input_values = 0u;
    uint64_t input_bytes = 0u;
    uint64_t output_values = 0u;
    uint64_t output_bytes = 0u;
    const uint64_t weight_bytes = (uint64_t)UOCR_HIDDEN_SIZE * (uint64_t)UOCR_PROJECTOR_IN_SIZE * 2u;
    const uint64_t bias_bytes = (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (!checked_mul_u64((uint64_t)n_rows, (uint64_t)UOCR_PROJECTOR_IN_SIZE, &input_values) ||
        !checked_mul_u64((uint64_t)n_rows, (uint64_t)UOCR_HIDDEN_SIZE, &output_values) ||
        !metal_vision_f16_bytes(input_values, &input_bytes) ||
        !metal_vision_f16_bytes(output_values, &output_bytes) ||
        !metal_vision_require_workspace_slice_f16(input, input_bytes, "visual projector input", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(out_rows, output_bytes, "visual projector output", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(weight, weight_bytes, "visual projector weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(bias, bias_bytes, "visual projector bias", error, error_size)) {
        return 0;
    }
    return uocr_metal_context_diagnostic_visual_projector_f16(ctx,
                                                   input.f16,
                                                   weight.host_f16,
                                                   bias.host_f16,
                                                   n_rows,
                                                   UOCR_METAL_DENSE_OUTPUT_F16,
                                                   out_rows.f16,
                                                   error,
                                                   error_size);
}

static int metal_encode_one_view_sam_transformer_f16(uocr_metal_vision_project_context *project,
                                                       const uocr_image_view *view,
                                                       uocr_metal_vision_workspace_slice precomputed_patch_bhwc,
                                                       uint32_t precomputed_patch_grid_w,
                                                       uint32_t precomputed_patch_grid_h,
                                                       uocr_metal_vision_workspace_slice out_transformer_bhwc,
                                                       uint32_t *out_patch_grid_w,
                                                       uint32_t *out_patch_grid_h,
                                                       char *error,
                                                       size_t error_size) {
    if (project == NULL || project->ctx == NULL || project->weights == NULL || project->scratch == NULL ||
        view == NULL || out_transformer_bhwc.buffer == nil || out_patch_grid_w == NULL || out_patch_grid_h == NULL) {
        return metal_fail(error, error_size, "invalid Metal SAM transformer view-encoding request");
    }
    const uint32_t expected_patch_grid = view->width / UOCR_VISION_PATCH_SIZE;
    const uocr_metal_vision_weights_f16 *weights = project->weights;
    uocr_metal_vision_workspace *scratch = project->scratch;
    uocr_metal_context *ctx = project->ctx;

#define RUN_VISION_STEP(step_name, call_expr)                                                        \
    do {                                                                                             \
        const uint64_t vision_step_start_ns__ = uocr_profile_now_ns();                                \
        if (!(call_expr)) {                                                                          \
            char detail[512];                                                                        \
            metal_copy_error_detail(detail, sizeof(detail), error);                                   \
            return metal_fail(error, error_size, "failed to compute Metal vision %s: %s", step_name, detail); \
        }                                                                                            \
        metal_profile_add_event_now_f(ctx, vision_step_start_ns__, "metal.vision.%s", step_name);    \
    } while (0)

    uint32_t patch_grid_w = precomputed_patch_grid_w;
    uint32_t patch_grid_h = precomputed_patch_grid_h;
    uocr_metal_vision_workspace_slice patch_bhwc = precomputed_patch_bhwc;
    if (patch_bhwc.buffer == nil) {
        patch_bhwc = scratch->sam_patch_bhwc;
        const uint64_t sam_patch_start_ns = uocr_profile_now_ns();
        RUN_VISION_STEP("SAM patch embedding",
                        metal_context_sam_patch_embed_f16_to_slice(ctx,
                                                                    view,
                                                                    weights->sam_patch_weight,
                                                                    weights->sam_patch_bias,
                                                                    patch_bhwc,
                                                                    &patch_grid_w,
                                                                    &patch_grid_h,
                                                                    error,
                                                                    error_size));
        metal_profile_add_event_now(ctx, "metal.vision.sam_patch", sam_patch_start_ns);
    }
    if (patch_grid_w != expected_patch_grid || patch_grid_h != expected_patch_grid) {
        return metal_fail(error,
                          error_size,
                          "SAM patch embedding produced grid %ux%u, expected %ux%u",
                          patch_grid_w,
                          patch_grid_h,
                          expected_patch_grid,
                          expected_patch_grid);
    }

    RUN_VISION_STEP("SAM absolute position add",
                    metal_context_sam_add_abs_pos_f16_to_slice(ctx,
                                                                patch_bhwc,
                                                                weights->sam_pos_embed,
                                                                patch_grid_w,
                                                                patch_grid_h,
                                                                scratch->sam_pos_bhwc,
                                                                error,
                                                                error_size));
    RUN_VISION_STEP("SAM transformer",
                    metal_context_sam_transformer_batch_workspace_f16_to_slice(ctx,
                                                                              scratch->sam_pos_bhwc,
                                                                              weights->sam_block_slices,
                                                                              UOCR_SAM_BLOCKS,
                                                                              patch_grid_w,
                                                                              patch_grid_h,
                                                                              1u,
                                                                              out_transformer_bhwc,
                                                                              scratch,
                                                                              error,
                                                                              error_size));
    *out_patch_grid_w = patch_grid_w;
    *out_patch_grid_h = patch_grid_h;

#undef RUN_VISION_STEP

    return 1;
}

static int metal_encode_one_view_sam_features_f16(uocr_metal_vision_project_context *project,
                                                  const uocr_image_view *view,
                                                  uocr_metal_vision_workspace_slice precomputed_patch_bhwc,
                                                  uint32_t precomputed_patch_grid_w,
                                                  uint32_t precomputed_patch_grid_h,
                                                  uocr_metal_vision_workspace_slice out_sam_nchw,
                                                  uint32_t *out_grid_w,
                                                  uint32_t *out_grid_h,
                                                  char *error,
                                                  size_t error_size) {
    if (project == NULL || project->scratch == NULL || view == NULL || out_grid_w == NULL || out_grid_h == NULL) {
        return metal_fail(error, error_size, "invalid Metal SAM view-encoding request");
    }
    uint32_t patch_grid_w = 0u;
    uint32_t patch_grid_h = 0u;
    if (!metal_encode_one_view_sam_transformer_f16(project,
                                                   view,
                                                   precomputed_patch_bhwc,
                                                   precomputed_patch_grid_w,
                                                   precomputed_patch_grid_h,
                                                   project->scratch->sam_transformer_bhwc,
                                                   &patch_grid_w,
                                                   &patch_grid_h,
                                                   error,
                                                   error_size)) {
        return 0;
    }
    if (!metal_context_sam_neck_batch_f16_to_slice(project,
                                                   project->scratch->sam_transformer_bhwc,
                                                   patch_grid_w,
                                                   patch_grid_h,
                                                   1u,
                                                   out_sam_nchw,
                                                   out_grid_w,
                                                   out_grid_h,
                                                   error,
                                                   error_size)) {
        return 0;
    }
    const uint32_t expected_sam_grid = view->kind == UOCR_VIEW_LOCAL ? UOCR_LOCAL_GRID_QUERIES : UOCR_GLOBAL_GRID_QUERIES;
    if (*out_grid_w != expected_sam_grid || *out_grid_h != expected_sam_grid) {
        return metal_fail(error,
                          error_size,
                          "SAM net output grid %ux%u, expected %ux%u",
                          *out_grid_w,
                          *out_grid_h,
                          expected_sam_grid,
                          expected_sam_grid);
    }
    return 1;
}

static int metal_encode_one_view_clip_features_f16(uocr_metal_vision_project_context *project,
                                                    const uocr_image_view *view,
                                                    uocr_metal_vision_workspace_slice precomputed_patch_bhwc,
                                                    uint32_t precomputed_patch_grid_w,
                                                    uint32_t precomputed_patch_grid_h,
                                                    uocr_metal_vision_workspace_slice out_sam_nchw,
                                                    uocr_metal_vision_workspace_slice out_clip_tokens,
                                                    uint32_t *out_token_count,
                                                    uint32_t *out_grid_w,
                                                    uint32_t *out_grid_h,
                                                    char *error,
                                                    size_t error_size) {
    if (project == NULL || project->ctx == NULL || project->weights == NULL || project->scratch == NULL ||
        view == NULL || out_clip_tokens.buffer == nil || out_token_count == NULL || out_grid_w == NULL || out_grid_h == NULL) {
        return metal_fail(error, error_size, "invalid Metal CLIP view-encoding request");
    }
    const uint32_t expected_projected_grid = view->kind == UOCR_VIEW_LOCAL ? UOCR_LOCAL_GRID_QUERIES : UOCR_GLOBAL_GRID_QUERIES;
    const uint32_t expected_clip_tokens = UOCR_CLIP_CLASS_TOKENS + expected_projected_grid * expected_projected_grid;
    const uocr_metal_vision_weights_f16 *weights = project->weights;
    uocr_metal_vision_workspace *scratch = project->scratch;
    uocr_metal_context *ctx = project->ctx;
    uint32_t sam_grid_w = 0u;
    uint32_t sam_grid_h = 0u;

    if (!metal_encode_one_view_sam_features_f16(project,
                                                view,
                                                precomputed_patch_bhwc,
                                                precomputed_patch_grid_w,
                                                precomputed_patch_grid_h,
                                                out_sam_nchw,
                                                &sam_grid_w,
                                                &sam_grid_h,
                                                error,
                                                error_size)) {
        return 0;
    }

#define RUN_VISION_STEP(step_name, call_expr)                                                        \
    do {                                                                                             \
        const uint64_t vision_step_start_ns__ = uocr_profile_now_ns();                                \
        if (!(call_expr)) {                                                                          \
            char detail[512];                                                                        \
            metal_copy_error_detail(detail, sizeof(detail), error);                                   \
            return metal_fail(error, error_size, "failed to compute Metal vision %s: %s", step_name, detail); \
        }                                                                                            \
        metal_profile_add_event_now_f(ctx, vision_step_start_ns__, "metal.vision.%s", step_name);    \
    } while (0)

    RUN_VISION_STEP("CLIP SAM embedding",
                    metal_context_clip_embed_sam_f16_to_slice(ctx,
                                                              out_sam_nchw,
                                                              weights->clip_class_embedding,
                                                              sam_grid_w,
                                                              sam_grid_h,
                                                              scratch->clip_a,
                                                              error,
                                                              error_size));
    RUN_VISION_STEP("CLIP absolute position add",
                    metal_context_clip_add_abs_pos_f16_to_slice(ctx,
                                                                scratch->clip_a,
                                                                weights->clip_pos_embed,
                                                                sam_grid_w,
                                                                sam_grid_h,
                                                                scratch->clip_b,
                                                                error,
                                                                error_size));
    RUN_VISION_STEP("CLIP pre-LayerNorm",
                    metal_context_clip_pre_layernorm_f16_to_slice(ctx,
                                                                  scratch->clip_b,
                                                                  weights->clip_pre_ln_weight,
                                                                  weights->clip_pre_ln_bias,
                                                                  expected_clip_tokens,
                                                                  scratch->clip_a,
                                                                  error,
                                                                  error_size));
    RUN_VISION_STEP("CLIP transformer",
                    metal_context_clip_transformer_batch_workspace_f16_to_slice(ctx,
                                                                               scratch->clip_a,
                                                                               weights->clip_block_slices,
                                                                               UOCR_CLIP_BLOCKS,
                                                                               expected_clip_tokens,
                                                                               1u,
                                                                               out_clip_tokens,
                                                                               scratch,
                                                                               error,
                                                                               error_size));

#undef RUN_VISION_STEP

    *out_token_count = expected_clip_tokens;
    *out_grid_w = sam_grid_w;
    *out_grid_h = sam_grid_h;
    return 1;
}

static int metal_context_sam_patch_embed_batch_f16_to_slice(uocr_metal_vision_project_context *project,
                                                            const uocr_vision_chunk *chunk,
                                                            uocr_metal_vision_workspace_slice out_bhwc,
                                                            uint32_t *out_grid_w,
                                                            uint32_t *out_grid_h,
                                                            char *error,
                                                            size_t error_size) {
    if (project == NULL || project->ctx == NULL || project->request == NULL || project->weights == NULL || chunk == NULL ||
        out_grid_w == NULL || out_grid_h == NULL || chunk->view_count == 0u || out_bhwc.buffer == nil || out_bhwc.f16 == NULL) {
        return metal_fail(error, error_size, "invalid Metal batched SAM patch request");
    }
    if (project->scratch == NULL || chunk->view_count > project->scratch->sam_patch_view_capacity) {
        return metal_fail(error, error_size, "Metal batched SAM patch view count exceeds workspace capacity");
    }
    if (chunk->first_view > project->request->n_views || chunk->view_count > project->request->n_views - chunk->first_view) {
        return metal_fail(error, error_size, "Metal batched SAM patch view range is invalid");
    }

    const uocr_image_view *first = &project->request->views[chunk->first_view];
    if (first->kind != (chunk->kind == UOCR_VISION_CHUNK_LOCAL ? UOCR_VIEW_LOCAL : UOCR_VIEW_GLOBAL) ||
        (first->format != UOCR_PIXEL_F16_NCHW && first->format != UOCR_PIXEL_F32_NCHW) ||
        first->width == 0u || first->height == 0u ||
        (first->width % UOCR_VISION_PATCH_SIZE) != 0u || (first->height % UOCR_VISION_PATCH_SIZE) != 0u) {
        return metal_fail(error, error_size, "Metal batched SAM patch first view is invalid");
    }
    for (uint32_t view_index = 1u; view_index < chunk->view_count; ++view_index) {
        const uocr_image_view *view = &project->request->views[chunk->first_view + view_index];
        if (view->kind != first->kind || view->format != first->format || view->width != first->width || view->height != first->height) {
            return metal_fail(error,
                              error_size,
                              "Metal batched SAM patch requires same kind/format/shape within a shape group");
        }
    }

    const uint32_t grid_w = first->width / UOCR_VISION_PATCH_SIZE;
    const uint32_t grid_h = first->height / UOCR_VISION_PATCH_SIZE;
    const uint64_t element_size = first->format == UOCR_PIXEL_F16_NCHW ? 2u : 4u;
    uint64_t pixel_values = 0u;
    uint64_t pixel_bytes_per_view = 0u;
    uint64_t pixel_bytes = 0u;
    uint64_t output_patches = 0u;
    uint64_t output_values_per_view = 0u;
    uint64_t output_values = 0u;
    uint64_t output_bytes = 0u;
    uint64_t weight_values = 0u;
    uint64_t weight_bytes = 0u;
    const uint64_t bias_bytes = (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    if (!checked_mul_u64(3u, (uint64_t)first->width, &pixel_values) ||
        !checked_mul_u64(pixel_values, (uint64_t)first->height, &pixel_values) ||
        !checked_mul_u64(pixel_values, element_size, &pixel_bytes_per_view) ||
        !checked_mul_u64(pixel_bytes_per_view, (uint64_t)chunk->view_count, &pixel_bytes) ||
        !checked_mul_u64((uint64_t)grid_w, (uint64_t)grid_h, &output_patches) ||
        !checked_mul_u64(output_patches, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &output_values_per_view) ||
        !checked_mul_u64(output_values_per_view, (uint64_t)chunk->view_count, &output_values) ||
        !metal_vision_f16_bytes(output_values, &output_bytes) ||
        !checked_mul_u64((uint64_t)UOCR_SAM_HIDDEN_SIZE,
                         3u * (uint64_t)UOCR_VISION_PATCH_SIZE * (uint64_t)UOCR_VISION_PATCH_SIZE,
                         &weight_values) ||
        !metal_vision_f16_bytes(weight_values, &weight_bytes) ||
        pixel_bytes > (uint64_t)SIZE_MAX ||
        !metal_vision_require_workspace_slice_f16(out_bhwc, output_bytes, "batched SAM patch output", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(project->weights->sam_patch_weight, weight_bytes, "SAM patch weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(project->weights->sam_patch_bias, bias_bytes, "SAM patch bias", error, error_size)) {
        return 0;
    }

    @autoreleasepool {
        id<MTLBuffer> pixel_buffer = metal_new_buffer_with_length(project->ctx, (NSUInteger)pixel_bytes, MTLResourceStorageModeShared);
        if (pixel_buffer == nil || [pixel_buffer contents] == NULL) {
            if (pixel_buffer != nil) [pixel_buffer release];
            return metal_fail(error, error_size, "failed to allocate Metal batched SAM patch pixel buffer");
        }
        pixel_buffer.label = @"uocr_sam_patch_pixels_batch";
        uint8_t *dst_pixels = (uint8_t *)[pixel_buffer contents];
        for (uint32_t view_index = 0u; view_index < chunk->view_count; ++view_index) {
            const uocr_image_view *view = &project->request->views[chunk->first_view + view_index];
            memcpy(dst_pixels + (size_t)view_index * (size_t)pixel_bytes_per_view,
                   view->pixels,
                   (size_t)pixel_bytes_per_view);
        }

        const char *function_name = first->format == UOCR_PIXEL_F16_NCHW ?
                                        "uocr_sam_patch_embed_f16_input" :
                                        "uocr_sam_patch_embed_f32_input";
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(project->ctx, function_name, error, error_size);
        if (pipeline == nil) {
            [pixel_buffer release];
            return 0;
        }
        const NSUInteger threads_x = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        const uint64_t partial_bytes = (uint64_t)threads_x * (uint64_t)sizeof(float);
        if (partial_bytes > (uint64_t)project->ctx->device.maxThreadgroupMemoryLength) {
            [pixel_buffer release];
            return metal_fail(error, error_size, "Metal batched SAM patch tiled reduction exceeds threadgroup memory limit");
        }

        id<MTLCommandBuffer> cb = metal_new_command_buffer(project->ctx);
        if (cb == nil) {
            [pixel_buffer release];
            return metal_fail(error, error_size, "failed to create Metal batched SAM patch command buffer");
        }
        cb.label = @"uocr_sam_patch_embed_batch_command_buffer";
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(project->ctx, cb);
        if (enc == nil) {
            [pixel_buffer release];
            return metal_fail(error, error_size, "failed to create Metal batched SAM patch encoder");
        }

        uocr_metal_sam_patch_embed_params params;
        memset(&params, 0, sizeof(params));
        params.width = first->width;
        params.height = first->height;
        params.out_width = grid_w;
        params.out_height = grid_h;
        params.has_bias = 1u;

        [enc setComputePipelineState:pipeline];
        [enc setBuffer:pixel_buffer offset:0u atIndex:0u];
        [enc setBuffer:project->weights->sam_patch_weight.slice.buffer offset:project->weights->sam_patch_weight.slice.offset atIndex:1u];
        [enc setBuffer:project->weights->sam_patch_bias.slice.buffer offset:project->weights->sam_patch_bias.slice.offset atIndex:2u];
        [enc setBuffer:out_bhwc.buffer offset:out_bhwc.offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc setThreadgroupMemoryLength:(NSUInteger)partial_bytes atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)UOCR_SAM_HIDDEN_SIZE,
                                              (NSUInteger)output_patches,
                                              (NSUInteger)chunk->view_count)
             threadsPerThreadgroup:MTLSizeMake(threads_x, 1u, 1u)];
        [enc endEncoding];
        if (project->ctx->active_command_buffer == cb &&
            !metal_retain_transient_until_completed(project->ctx, cb, pixel_buffer, error, error_size)) {
            [pixel_buffer release];
            return 0;
        }
        UOCR_METAL_COMMIT_AND_WAIT_PROFILED(project->ctx, cb);
        int ok = 1;
        if (cb.status == MTLCommandBufferStatusError) {
            NSString *description = cb.error != nil ? [cb.error localizedDescription] : @"unknown command-buffer error";
            ok = metal_fail(error, error_size, "Metal batched SAM patch command failed: %s", [description UTF8String]);
        } else {
            *out_grid_w = grid_w;
            *out_grid_h = grid_h;
            metal_clear_error(error, error_size);
        }
        [pixel_buffer release];
        return ok;
    }
}

static int metal_encode_one_view_projected_f16(uocr_metal_vision_project_context *project,
                                               const uocr_image_view *view,
                                               uocr_metal_vision_workspace_slice precomputed_patch_bhwc,
                                               uint32_t precomputed_patch_grid_w,
                                               uint32_t precomputed_patch_grid_h,
                                               uocr_metal_vision_workspace_slice out_projected_rows,
                                               char *error,
                                               size_t error_size) {
    if (project == NULL || project->ctx == NULL || project->weights == NULL || project->scratch == NULL ||
        view == NULL || out_projected_rows.buffer == nil || out_projected_rows.f16 == NULL) {
        return metal_fail(error, error_size, "invalid Metal vision view-encoding request");
    }
    const uint32_t expected_projected_grid = view->kind == UOCR_VIEW_LOCAL ? UOCR_LOCAL_GRID_QUERIES : UOCR_GLOBAL_GRID_QUERIES;
    const uint32_t expected_clip_tokens = UOCR_CLIP_CLASS_TOKENS + expected_projected_grid * expected_projected_grid;
    const uint64_t expected_projected_bytes = (uint64_t)expected_projected_grid * (uint64_t)expected_projected_grid *
                                              (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (out_projected_rows.bytes < expected_projected_bytes ||
        !metal_slice_valid((uocr_metal_buffer_slice){out_projected_rows.buffer, out_projected_rows.offset}, expected_projected_bytes)) {
        return metal_fail(error, error_size, "Metal projected-row output slice is too small");
    }
    const uocr_metal_vision_weights_f16 *weights = project->weights;
    uocr_metal_vision_workspace *scratch = project->scratch;
    uocr_metal_context *ctx = project->ctx;
    uint32_t clip_token_count = 0u;
    uint32_t sam_grid_w = 0u;
    uint32_t sam_grid_h = 0u;

    if (!metal_encode_one_view_clip_features_f16(project,
                                                 view,
                                                 precomputed_patch_bhwc,
                                                 precomputed_patch_grid_w,
                                                 precomputed_patch_grid_h,
                                                 scratch->sam_net3_nchw,
                                                 scratch->clip_final,
                                                 &clip_token_count,
                                                 &sam_grid_w,
                                                 &sam_grid_h,
                                                 error,
                                                 error_size)) {
        return 0;
    }
    if (clip_token_count != expected_clip_tokens) {
        return metal_fail(error,
                          error_size,
                          "CLIP output token count %u, expected %u",
                          clip_token_count,
                          expected_clip_tokens);
    }

#define RUN_VISION_STEP(step_name, call_expr)                                                        \
    do {                                                                                             \
        const uint64_t vision_step_start_ns__ = uocr_profile_now_ns();                                \
        if (!(call_expr)) {                                                                          \
            char detail[512];                                                                        \
            metal_copy_error_detail(detail, sizeof(detail), error);                                   \
            return metal_fail(error, error_size, "failed to compute Metal vision %s: %s", step_name, detail); \
        }                                                                                            \
        metal_profile_add_event_now_f(ctx, vision_step_start_ns__, "metal.vision.%s", step_name);    \
    } while (0)

    const uint64_t concat_start_ns = uocr_profile_now_ns();
    RUN_VISION_STEP("CLIP/SAM concat",
                    metal_context_clip_sam_concat_f16_to_slice(ctx,
                                                              scratch->clip_final,
                                                              scratch->sam_net3_nchw,
                                                              sam_grid_w,
                                                              sam_grid_h,
                                                              scratch->concat,
                                                              error,
                                                              error_size));
    metal_profile_add_event_now(ctx, "metal.vision.concat", concat_start_ns);
    const uint64_t projector_start_ns = uocr_profile_now_ns();
    RUN_VISION_STEP("visual projector",
                    metal_context_visual_projector_f16_to_slice(ctx,
                                                               scratch->concat,
                                                               weights->projector_weight,
                                                               weights->projector_bias,
                                                               sam_grid_w * sam_grid_h,
                                                               out_projected_rows,
                                                               error,
                                                               error_size));
    metal_profile_add_event_now(ctx, "metal.vision.projector", projector_start_ns);

#undef RUN_VISION_STEP

    return 1;
}

static int metal_dispatch_visual_format_kernel(uocr_metal_context *ctx,
                                               const char *function_name,
                                               const char *op_name,
                                               id<MTLBuffer> buffer0,
                                               NSUInteger offset0,
                                               id<MTLBuffer> buffer1,
                                               NSUInteger offset1,
                                               id<MTLBuffer> buffer2,
                                               NSUInteger offset2,
                                               id<MTLBuffer> buffer3,
                                               NSUInteger offset3,
                                               const void *params,
                                               NSUInteger params_size,
                                               uint32_t hidden_size,
                                               uint32_t rows,
                                               char *error,
                                               size_t error_size) {
    if (ctx == NULL || function_name == NULL || op_name == NULL || buffer0 == nil || buffer1 == nil ||
        params == NULL || params_size == 0u || hidden_size == 0u || rows == 0u) {
        return metal_fail(error, error_size, "invalid Metal visual formatter request");
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, function_name, error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            return metal_fail(error, error_size, "failed to create %s command buffer", op_name);
        }
        cb.label = [NSString stringWithFormat:@"%s_command_buffer", op_name];
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create %s encoder", op_name);
        }
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:buffer0 offset:offset0 atIndex:0u];
        [enc setBuffer:buffer1 offset:offset1 atIndex:1u];
        if (buffer2 != nil) {
            [enc setBuffer:buffer2 offset:offset2 atIndex:2u];
        }
        if (buffer3 != nil) {
            [enc setBuffer:buffer3 offset:offset3 atIndex:3u];
            [enc setBytes:params length:params_size atIndex:4u];
        } else {
            [enc setBytes:params length:params_size atIndex:2u];
        }
        NSUInteger threads_x = pipeline.threadExecutionWidth;
        if (threads_x == 0u || threads_x > (NSUInteger)hidden_size) {
            threads_x = 32u;
        }
        if (threads_x > pipeline.maxTotalThreadsPerThreadgroup) {
            threads_x = pipeline.maxTotalThreadsPerThreadgroup;
        }
        if (threads_x == 0u) {
            threads_x = 1u;
        }
        [enc dispatchThreads:MTLSizeMake((NSUInteger)hidden_size, (NSUInteger)rows, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads_x, 1u, 1u)];
        [enc endEncoding];
        UOCR_METAL_COMMIT_AND_WAIT_PROFILED(ctx, cb);
        if (cb.status == MTLCommandBufferStatusError) {
            NSString *description = cb.error != nil ? [cb.error localizedDescription] : @"unknown command-buffer error";
            return metal_fail(error, error_size, "%s command failed: %s", op_name, [description UTF8String]);
        }
    }
    metal_clear_error(error, error_size);
    return 1;
}

static int metal_format_global_visual_rows_f16(uocr_metal_context *ctx,
                                               uocr_metal_vision_workspace_slice projected_rows,
                                               uocr_metal_vision_tensor_f16 image_newline,
                                               uocr_metal_vision_tensor_f16 view_separator,
                                               uocr_metal_vision_workspace_slice dst_rows,
                                               uint32_t grid_size,
                                               uint32_t view_count,
                                               uint32_t dst_token_base,
                                               char *error,
                                               size_t error_size) {
    if (view_count == 0u || grid_size == 0u) {
        return metal_fail(error, error_size, "invalid Metal global visual formatter shape");
    }
    const uint32_t projected_tokens_per_view = grid_size * grid_size;
    const uint32_t visual_tokens_per_view = grid_size * (grid_size + 1u) + 1u;
    const uint64_t projected_bytes = (uint64_t)view_count * (uint64_t)projected_tokens_per_view * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t dst_end_bytes = ((uint64_t)dst_token_base + (uint64_t)view_count * (uint64_t)visual_tokens_per_view) *
                                   (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (!metal_slice_valid((uocr_metal_buffer_slice){projected_rows.buffer, projected_rows.offset}, projected_bytes) ||
        !metal_slice_valid(image_newline.slice, (uint64_t)UOCR_HIDDEN_SIZE * 2u) ||
        !metal_slice_valid(view_separator.slice, (uint64_t)UOCR_HIDDEN_SIZE * 2u) ||
        !metal_slice_valid((uocr_metal_buffer_slice){dst_rows.buffer, dst_rows.offset}, dst_end_bytes)) {
        return metal_fail(error, error_size, "invalid Metal global visual formatter slices");
    }
    uocr_metal_visual_format_global_params params;
    memset(&params, 0, sizeof(params));
    params.hidden_size = UOCR_HIDDEN_SIZE;
    params.grid_size = grid_size;
    params.visual_tokens_per_view = visual_tokens_per_view;
    params.view_count = view_count;
    params.dst_token_base = dst_token_base;
    return metal_dispatch_visual_format_kernel(ctx,
                                               "uocr_format_global_visual_rows_f16",
                                               "Metal global visual formatter",
                                               projected_rows.buffer,
                                               projected_rows.offset,
                                               image_newline.slice.buffer,
                                               image_newline.slice.offset,
                                               view_separator.slice.buffer,
                                               view_separator.slice.offset,
                                               dst_rows.buffer,
                                               dst_rows.offset,
                                               &params,
                                               (NSUInteger)sizeof(params),
                                               UOCR_HIDDEN_SIZE,
                                               view_count * visual_tokens_per_view,
                                               error,
                                               error_size);
}

static int metal_fill_local_visual_newlines_f16(uocr_metal_context *ctx,
                                                uocr_metal_vision_tensor_f16 image_newline,
                                                uocr_metal_vision_workspace_slice dst_rows,
                                                uint32_t crop_grid_w,
                                                uint32_t crop_grid_h,
                                                uint32_t dst_token_base,
                                                char *error,
                                                size_t error_size) {
    if (crop_grid_w == 0u || crop_grid_h == 0u) {
        return metal_fail(error, error_size, "invalid Metal local newline formatter grid");
    }
    const uint32_t local_rows = crop_grid_h * UOCR_LOCAL_GRID_QUERIES;
    const uint32_t local_visual_tokens = uocr_local_visual_token_count(crop_grid_w, crop_grid_h);
    const uint64_t dst_end_bytes = ((uint64_t)dst_token_base + (uint64_t)local_visual_tokens) *
                                   (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (!metal_slice_valid(image_newline.slice, (uint64_t)UOCR_HIDDEN_SIZE * 2u) ||
        !metal_slice_valid((uocr_metal_buffer_slice){dst_rows.buffer, dst_rows.offset}, dst_end_bytes)) {
        return metal_fail(error, error_size, "invalid Metal local newline formatter slices");
    }
    uocr_metal_visual_format_local_params params;
    memset(&params, 0, sizeof(params));
    params.hidden_size = UOCR_HIDDEN_SIZE;
    params.grid_size = UOCR_LOCAL_GRID_QUERIES;
    params.crop_grid_w = crop_grid_w;
    params.chunk_view_count = crop_grid_h;
    params.dst_token_base = dst_token_base;
    return metal_dispatch_visual_format_kernel(ctx,
                                               "uocr_fill_local_visual_newlines_f16",
                                               "Metal local newline formatter",
                                               image_newline.slice.buffer,
                                               image_newline.slice.offset,
                                               dst_rows.buffer,
                                               dst_rows.offset,
                                               nil,
                                               0u,
                                               nil,
                                               0u,
                                               &params,
                                               (NSUInteger)sizeof(params),
                                               UOCR_HIDDEN_SIZE,
                                               local_rows,
                                               error,
                                               error_size);
}

static int metal_format_local_visual_rows_f16(uocr_metal_context *ctx,
                                              const uocr_vision_chunk *chunk,
                                              uocr_metal_vision_workspace_slice projected_rows,
                                              uocr_metal_vision_workspace_slice dst_rows,
                                              uint32_t crop_grid_w,
                                              char *error,
                                              size_t error_size) {
    if (chunk == NULL || chunk->kind != UOCR_VISION_CHUNK_LOCAL || crop_grid_w == 0u || chunk->view_count == 0u) {
        return metal_fail(error, error_size, "invalid Metal local visual formatter request");
    }
    const uint32_t projected_rows_count = chunk->view_count * UOCR_LOCAL_GRID_QUERIES * UOCR_LOCAL_GRID_QUERIES;
    const uint64_t projected_bytes = (uint64_t)projected_rows_count * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint32_t last_local_view = chunk->first_view + chunk->view_count - 1u;
    const uint64_t dst_min_rows = (uint64_t)uocr_local_visual_token_count(crop_grid_w, 1u + last_local_view / crop_grid_w);
    if ((uint64_t)chunk->final_token_count < dst_min_rows) {
        return metal_fail(error, error_size, "Metal local visual formatter final range is too small");
    }
    const uint64_t dst_end_bytes = ((uint64_t)chunk->final_token_start + (uint64_t)chunk->final_token_count) *
                                   (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (!metal_slice_valid((uocr_metal_buffer_slice){projected_rows.buffer, projected_rows.offset}, projected_bytes) ||
        !metal_slice_valid((uocr_metal_buffer_slice){dst_rows.buffer, dst_rows.offset}, dst_end_bytes)) {
        return metal_fail(error, error_size, "invalid Metal local visual formatter slices");
    }
    uocr_metal_visual_format_local_params params;
    memset(&params, 0, sizeof(params));
    params.hidden_size = UOCR_HIDDEN_SIZE;
    params.grid_size = UOCR_LOCAL_GRID_QUERIES;
    params.crop_grid_w = crop_grid_w;
    params.chunk_first_view = chunk->first_view;
    params.chunk_view_count = chunk->view_count;
    params.dst_token_base = chunk->final_token_start;
    return metal_dispatch_visual_format_kernel(ctx,
                                               "uocr_format_local_visual_rows_f16",
                                               "Metal local visual formatter",
                                               projected_rows.buffer,
                                               projected_rows.offset,
                                               dst_rows.buffer,
                                               dst_rows.offset,
                                               nil,
                                               0u,
                                               nil,
                                               0u,
                                               &params,
                                               (NSUInteger)sizeof(params),
                                               UOCR_HIDDEN_SIZE,
                                               projected_rows_count,
                                               error,
                                               error_size);
}

static int metal_project_vision_chunk_f16(const uocr_vision_chunk *chunk,
                                          uocr_metal_vision_workspace_slice projected_rows,
                                          uint32_t projected_scratch_rows,
                                          void *user_data,
                                          char *error,
                                          size_t error_size) {
    if (chunk == NULL || projected_rows.buffer == nil || projected_rows.f16 == NULL || user_data == NULL) {
        (void)metal_fail(error, error_size, "invalid Metal vision chunk projection request");
        return UOCR_ERROR_INVALID_ARGUMENT;
    }
    if (projected_scratch_rows < chunk->projected_token_count) {
        (void)metal_fail(error,
                         error_size,
                         "Metal vision projected scratch has %u rows, need %u",
                         projected_scratch_rows,
                         chunk->projected_token_count);
        return UOCR_ERROR_OUT_OF_MEMORY;
    }
    const uint64_t projected_bytes = (uint64_t)chunk->projected_token_count * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (projected_rows.bytes < projected_bytes ||
        !metal_slice_valid((uocr_metal_buffer_slice){projected_rows.buffer, projected_rows.offset}, projected_bytes)) {
        (void)metal_fail(error, error_size, "Metal vision projected-row slice is too small for chunk");
        return UOCR_ERROR_OUT_OF_MEMORY;
    }

    uocr_metal_vision_project_context *project = (uocr_metal_vision_project_context *)user_data;
    if (project->request == NULL || chunk->first_view > project->request->n_views ||
        chunk->view_count > project->request->n_views - chunk->first_view) {
        (void)metal_fail(error, error_size, "Metal vision chunk view range is invalid");
        return UOCR_ERROR_INVALID_ARGUMENT;
    }

    const uint64_t chunk_encode_start_ns = uocr_profile_now_ns();
    uint32_t batched_patch_grid_w = 0u;
    uint32_t batched_patch_grid_h = 0u;
    if (chunk->view_count > 1u) {
        const uint64_t sam_patch_batch_start_ns = uocr_profile_now_ns();
        if (!metal_context_sam_patch_embed_batch_f16_to_slice(project,
                                                             chunk,
                                                             project->scratch->sam_patch_bhwc,
                                                             &batched_patch_grid_w,
                                                             &batched_patch_grid_h,
                                                             error,
                                                             error_size)) {
            return UOCR_ERROR_INTERNAL;
        }
        metal_profile_add_event_now(project->ctx, "metal.vision.sam_patch_batch", sam_patch_batch_start_ns);
    }
    if (chunk->view_count > 1u) {
        const uint32_t projected_tokens_per_view = chunk->projected_tokens_per_view;
        const uint32_t clip_tokens_per_view = projected_tokens_per_view + UOCR_CLIP_CLASS_TOKENS;
        if (clip_tokens_per_view == 0u || chunk->view_count > UINT32_MAX / clip_tokens_per_view) {
            (void)metal_fail(error, error_size, "Metal batched CLIP token count overflow");
            return UOCR_ERROR_INTERNAL;
        }
        const uint32_t batch_clip_tokens = clip_tokens_per_view * chunk->view_count;
        const uint32_t patch_grid_w = batched_patch_grid_w;
        const uint32_t patch_grid_h = batched_patch_grid_h;
        const uint64_t sam_transformer_batch_start_ns = uocr_profile_now_ns();
        if (!metal_context_sam_add_abs_pos_batch_f16_to_slice(project->ctx,
                                                             project->scratch->sam_patch_bhwc,
                                                             project->weights->sam_pos_embed,
                                                             patch_grid_w,
                                                             patch_grid_h,
                                                             chunk->view_count,
                                                             project->scratch->sam_pos_bhwc,
                                                             error,
                                                             error_size) ||
            !metal_context_sam_transformer_batch_workspace_f16_to_slice(project->ctx,
                                                                        project->scratch->sam_pos_bhwc,
                                                                        project->weights->sam_block_slices,
                                                                        UOCR_SAM_BLOCKS,
                                                                        patch_grid_w,
                                                                        patch_grid_h,
                                                                        chunk->view_count,
                                                                        project->scratch->sam_transformer_batch_bhwc,
                                                                        project->scratch,
                                                                        error,
                                                                        error_size)) {
            return UOCR_ERROR_INTERNAL;
        }
        metal_profile_add_event_now(project->ctx, "metal.vision.sam_transformer_batch", sam_transformer_batch_start_ns);
        uint32_t sam_grid_w = 0u;
        uint32_t sam_grid_h = 0u;
        if (!metal_context_sam_neck_batch_f16_to_slice(project,
                                                       project->scratch->sam_transformer_batch_bhwc,
                                                       patch_grid_w,
                                                       patch_grid_h,
                                                       chunk->view_count,
                                                       project->scratch->sam_net3_nchw,
                                                       &sam_grid_w,
                                                       &sam_grid_h,
                                                       error,
                                                       error_size)) {
            return UOCR_ERROR_INTERNAL;
        }
        if (sam_grid_w * sam_grid_h != projected_tokens_per_view) {
            (void)metal_fail(error, error_size, "Metal batched SAM neck grid does not match projected token count");
            return UOCR_ERROR_INTERNAL;
        }
        const uint64_t clip_frontend_start_ns = uocr_profile_now_ns();
        if (!metal_context_clip_embed_sam_batch_f16_to_slice(project->ctx,
                                                            project->scratch->sam_net3_nchw,
                                                            project->weights->clip_class_embedding,
                                                            sam_grid_w,
                                                            sam_grid_h,
                                                            chunk->view_count,
                                                            project->scratch->clip_a,
                                                            error,
                                                            error_size) ||
            !metal_context_clip_add_abs_pos_batch_f16_to_slice(project->ctx,
                                                              project->scratch->clip_a,
                                                              project->weights->clip_pos_embed,
                                                              sam_grid_w,
                                                              sam_grid_h,
                                                              chunk->view_count,
                                                              project->scratch->clip_b,
                                                              error,
                                                              error_size) ||
            !metal_context_clip_pre_layernorm_f16_to_slice(project->ctx,
                                                           project->scratch->clip_b,
                                                           project->weights->clip_pre_ln_weight,
                                                           project->weights->clip_pre_ln_bias,
                                                           batch_clip_tokens,
                                                           project->scratch->clip_a,
                                                           error,
                                                           error_size)) {
            return UOCR_ERROR_INTERNAL;
        }
        metal_profile_add_event_now(project->ctx, "metal.vision.clip_frontend_batch", clip_frontend_start_ns);
        const uint64_t clip_transformer_start_ns = uocr_profile_now_ns();
        if (!metal_context_clip_transformer_batch_workspace_f16_to_slice(project->ctx,
                                                                         project->scratch->clip_a,
                                                                         project->weights->clip_block_slices,
                                                                         UOCR_CLIP_BLOCKS,
                                                                         clip_tokens_per_view,
                                                                         chunk->view_count,
                                                                         project->scratch->clip_final,
                                                                         project->scratch,
                                                                         error,
                                                                         error_size)) {
            return UOCR_ERROR_INTERNAL;
        }
        metal_profile_add_event_now(project->ctx, "metal.vision.clip_transformer_batch", clip_transformer_start_ns);
        const uint64_t concat_start_ns = uocr_profile_now_ns();
        if (!metal_context_clip_sam_concat_batch_f16_to_slice(project->ctx,
                                                             project->scratch->clip_final,
                                                             project->scratch->sam_net3_nchw,
                                                             sam_grid_w,
                                                             sam_grid_h,
                                                             chunk->view_count,
                                                             project->scratch->concat,
                                                             error,
                                                             error_size)) {
            return UOCR_ERROR_INTERNAL;
        }
        metal_profile_add_event_now(project->ctx, "metal.vision.concat_batch", concat_start_ns);
        const uint64_t projector_start_ns = uocr_profile_now_ns();
        if (!metal_context_visual_projector_f16_to_slice(project->ctx,
                                                        project->scratch->concat,
                                                        project->weights->projector_weight,
                                                        project->weights->projector_bias,
                                                        chunk->projected_token_count,
                                                        projected_rows,
                                                        error,
                                                        error_size)) {
            return UOCR_ERROR_INTERNAL;
        }
        metal_profile_add_event_now(project->ctx, "metal.vision.projector_batch", projector_start_ns);
    } else {
        const uocr_image_view *view = &project->request->views[chunk->first_view];
        if (!metal_encode_one_view_projected_f16(project,
                                                 view,
                                                 (uocr_metal_vision_workspace_slice){0},
                                                 0u,
                                                 0u,
                                                 projected_rows,
                                                 error,
                                                 error_size)) {
            return UOCR_ERROR_INTERNAL;
        }
    }
    const uint64_t chunk_encode_end_ns = uocr_profile_now_ns();
    project->chunk_encode_ms += uocr_profile_elapsed_ms(chunk_encode_start_ns, chunk_encode_end_ns);
    metal_profile_add_event_now(project->ctx, "metal.vision.chunk_encode", chunk_encode_start_ns);

    return UOCR_OK;
}

static int metal_context_encode_visual_features_to_workspace_f16(uocr_metal_context *ctx,
                                                                 const uocr_prepared_request *request,
                                                                 uint32_t max_views_per_chunk,
                                                                 const uocr_vision_schedule *schedule,
                                                                 uocr_metal_vision_workspace *scratch,
                                                                 int cpu_visible_workspace,
                                                                 char *error,
                                                                 size_t error_size) {
    if (ctx == NULL || request == NULL || schedule == NULL || scratch == NULL || schedule->final_visual_tokens == 0u) {
        return metal_fail(error, error_size, "invalid Metal vision workspace encoding request");
    }

    const uocr_metal_vision_weights_f16 *weights = metal_require_vision_weights_f16(ctx, error, error_size);
    if (weights == NULL) {
        return 0;
    }

    uint32_t max_view_size = 0u;
    for (uint32_t i = 0u; i < request->n_views; ++i) {
        const uint32_t view_size = request->views[i].width > request->views[i].height ? request->views[i].width : request->views[i].height;
        if (view_size > max_view_size) {
            max_view_size = view_size;
        }
    }

    if (!metal_vision_workspace_init(ctx,
                                     scratch,
                                     max_view_size,
                                     schedule->max_chunk_views,
                                     schedule->max_chunk_projected_tokens,
                                     schedule->final_visual_tokens,
                                     cpu_visible_workspace,
                                     error,
                                     error_size)) {
        return 0;
    }
    if (scratch->projected_rows.f16 == NULL || scratch->projected_row_capacity < schedule->max_chunk_projected_tokens ||
        scratch->final_visual_rows.f16 == NULL || scratch->final_visual_row_capacity < schedule->final_visual_tokens) {
        metal_vision_workspace_reset(scratch);
        return metal_fail(error, error_size, "Metal vision workspace did not provide required projected/final slices");
    }
    if (!metal_prebuild_mps_vision_workspace_ndarrays(ctx,
                                                       scratch,
                                                       schedule->local_view_count,
                                                       schedule->global_view_count,
                                                       error,
                                                       error_size)) {
        metal_vision_workspace_reset(scratch);
        return 0;
    }

    uocr_metal_vision_project_context project;
    memset(&project, 0, sizeof(project));
    project.ctx = ctx;
    project.request = request;
    project.weights = weights;
    project.scratch = scratch;

    uocr_vision_chunk *chunks = (uocr_vision_chunk *)calloc(schedule->chunk_count, sizeof(chunks[0]));
    if (chunks == NULL) {
        metal_vision_workspace_reset(scratch);
        return metal_fail(error, error_size, "failed to allocate Metal vision chunk schedule");
    }
    uocr_vision_schedule planned;
    memset(&planned, 0, sizeof(planned));
    const int schedule_status = uocr_plan_vision_schedule(request,
                                                          max_views_per_chunk,
                                                          chunks,
                                                          schedule->chunk_count,
                                                          &planned,
                                                          error,
                                                          error_size);
    if (schedule_status != UOCR_OK || planned.chunk_count != schedule->chunk_count ||
        planned.final_visual_tokens != schedule->final_visual_tokens ||
        planned.max_chunk_projected_tokens != schedule->max_chunk_projected_tokens) {
        char detail[512];
        metal_copy_error_detail(detail, sizeof(detail), error);
        free(chunks);
        metal_vision_workspace_reset(scratch);
        return metal_fail(error, error_size, "Metal vision schedule changed before encoding: %s", detail);
    }

    const uint64_t chunk_processing_start_ns = uocr_profile_now_ns();
    uint64_t formatter_ns = 0u;
    int process_status = UOCR_OK;
    uint32_t local_newlines_encoded = 0u;
    for (uint32_t chunk_index = 0u; process_status == UOCR_OK && chunk_index < schedule->chunk_count; ++chunk_index) {
        const uocr_vision_chunk *chunk = &chunks[chunk_index];
        const int had_active_batch = metal_command_batch_active(ctx);
        const char *shape_group_op = chunk->kind == UOCR_VISION_CHUNK_LOCAL ?
                                         "Metal local vision shape-group graph" :
                                         "Metal global vision shape-group graph";
        if (!had_active_batch && !metal_command_batch_begin(ctx, error, error_size)) {
            process_status = UOCR_ERROR_INTERNAL;
            break;
        }

        if (chunk->kind == UOCR_VISION_CHUNK_LOCAL && !local_newlines_encoded) {
            const uint64_t formatter_start_ns = uocr_profile_now_ns();
            if (!metal_fill_local_visual_newlines_f16(ctx,
                                                      weights->image_newline,
                                                      scratch->final_visual_rows,
                                                      request->crop_grid_w,
                                                      request->crop_grid_h,
                                                      chunk->final_token_start,
                                                      error,
                                                      error_size)) {
                process_status = UOCR_ERROR_INTERNAL;
            } else {
                local_newlines_encoded = 1u;
            }
            formatter_ns += uocr_profile_now_ns() - formatter_start_ns;
        }

        if (process_status == UOCR_OK) {
            process_status = metal_project_vision_chunk_f16(chunk,
                                                            scratch->projected_rows,
                                                            scratch->projected_row_capacity,
                                                            &project,
                                                            error,
                                                            error_size);
        }

        if (process_status == UOCR_OK) {
            const uint64_t formatter_start_ns = uocr_profile_now_ns();
            if (chunk->kind == UOCR_VISION_CHUNK_LOCAL) {
                if (!metal_format_local_visual_rows_f16(ctx,
                                                        chunk,
                                                        scratch->projected_rows,
                                                        scratch->final_visual_rows,
                                                        request->crop_grid_w,
                                                        error,
                                                        error_size)) {
                    process_status = UOCR_ERROR_INTERNAL;
                }
            } else {
                if (chunk->final_token_count != chunk->view_count * UOCR_GLOBAL_VISUAL_TOKENS) {
                    process_status = UOCR_ERROR_INTERNAL;
                    (void)metal_fail(error, error_size, "Metal global visual formatter final range is invalid");
                } else if (!metal_format_global_visual_rows_f16(ctx,
                                                                 scratch->projected_rows,
                                                                 weights->image_newline,
                                                                 weights->view_separator,
                                                                 scratch->final_visual_rows,
                                                                 chunk->projected_grid_w,
                                                                 chunk->view_count,
                                                                 chunk->final_token_start,
                                                                 error,
                                                                 error_size)) {
                    process_status = UOCR_ERROR_INTERNAL;
                }
            }
            formatter_ns += uocr_profile_now_ns() - formatter_start_ns;
        }

        if (!had_active_batch) {
            if (process_status == UOCR_OK) {
                const uint64_t shape_group_wait_start_ns = uocr_profile_now_ns();
                if (!metal_command_batch_commit_and_wait(ctx, shape_group_op, error, error_size)) {
                    process_status = UOCR_ERROR_INTERNAL;
                } else {
                    metal_profile_add_event_now(ctx,
                                                chunk->kind == UOCR_VISION_CHUNK_LOCAL ?
                                                    "metal.vision.local_shape_group_command_wait" :
                                                    "metal.vision.global_shape_group_command_wait",
                                                shape_group_wait_start_ns);
                }
            } else {
                metal_command_batch_abort(ctx);
            }
        }
    }
    free(chunks);

    const double chunk_processing_ms = uocr_profile_elapsed_ms(chunk_processing_start_ns, uocr_profile_now_ns());
    if (process_status == UOCR_OK) {
        metal_profile_add_event_ms(ctx, "metal.vision.chunk_processing", chunk_processing_ms);
        metal_profile_add_event_ms(ctx, "metal.vision.formatter", (double)formatter_ns / 1000000.0);
        return 1;
    }

    char detail[512];
    metal_copy_error_detail(detail, sizeof(detail), error);
    metal_vision_workspace_reset(scratch);
    return metal_fail(error, error_size, "Metal vision encoding failed: %s", detail);
}

/* Diagnostic host-output vision helpers. Public OCR dispatch must use
 * uocr_metal_context_generate_image_f16(), which keeps the final visual rows in
 * the reusable Metal workspace and binds that slice directly into prompt
 * assembly. These helpers deliberately copy results back to caller-owned host
 * buffers for parity probes only; profile markers make accidental production
 * use visible.
 */
int uocr_metal_context_diagnostic_encode_visual_features_f16(uocr_metal_context *ctx,
                                                  const uocr_prepared_request *request,
                                                  uint32_t max_views_per_chunk,
                                                  uint16_t *out_visual_features_f16,
                                                  uint32_t out_visual_rows,
                                                  char *error,
                                                  size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || request == NULL) {
        return metal_fail(error, error_size, "Metal vision encoding requires a context and prepared request");
    }
    metal_profile_add_event_ms(ctx, "metal.vision.diagnostic_final_host_output", 0.0);
    if (!uocr_metal_context_vision_bindings_ready(ctx)) {
        return metal_fail(error,
                          error_size,
                          "Metal vision encoding requires validated fp16 vision tensor bindings: %s",
                          uocr_metal_context_vision_binding_error(ctx));
    }
    if (out_visual_rows != 0u && out_visual_features_f16 == NULL) {
        return metal_fail(error, error_size, "Metal vision output buffer is null for %u rows", out_visual_rows);
    }

    uocr_vision_schedule schedule;
    memset(&schedule, 0, sizeof(schedule));
    const int plan_status = uocr_plan_vision_schedule(request,
                                                      max_views_per_chunk,
                                                      NULL,
                                                      0u,
                                                      &schedule,
                                                      error,
                                                      error_size);
    if (plan_status != UOCR_OK) {
        char detail[512];
        metal_copy_error_detail(detail, sizeof(detail), error);
        return metal_fail(error, error_size, "invalid Metal vision request: %s", detail);
    }
    if (out_visual_rows != schedule.final_visual_tokens) {
        return metal_fail(error,
                          error_size,
                          "Metal vision output row count mismatch: got %u expected %u",
                          out_visual_rows,
                          schedule.final_visual_tokens);
    }
    if (schedule.final_visual_tokens == 0u) {
        metal_clear_error(error, error_size);
        return 1;
    }

    uocr_metal_vision_workspace scratch;
    if (!metal_context_encode_visual_features_to_workspace_f16(ctx,
                                                               request,
                                                               max_views_per_chunk,
                                                               &schedule,
                                                               &scratch,
                                                               1,
                                                               error,
                                                               error_size)) {
        return 0;
    }
    if (scratch.final_visual_rows.bytes > (uint64_t)SIZE_MAX) {
        metal_vision_workspace_reset(&scratch);
        return metal_fail(error, error_size, "Metal final visual row copy exceeds platform size");
    }
    memcpy(out_visual_features_f16, scratch.final_visual_rows.f16, (size_t)scratch.final_visual_rows.bytes);
    metal_vision_workspace_reset(&scratch);

    metal_clear_error(error, error_size);
    return 1;
}

int uocr_metal_context_diagnostic_encode_sam_features_f16(uocr_metal_context *ctx,
                                               const uocr_image_view *view,
                                               uint16_t *out_sam_features_f16,
                                               uint32_t out_grid_w,
                                               uint32_t out_grid_h,
                                               char *error,
                                               size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || view == NULL || out_sam_features_f16 == NULL) {
        return metal_fail(error, error_size, "Metal SAM encoding requires a context, view, and output buffer");
    }
    metal_profile_add_event_ms(ctx, "metal.vision.diagnostic_sam_host_output", 0.0);
    if (!uocr_metal_context_vision_bindings_ready(ctx)) {
        return metal_fail(error,
                          error_size,
                          "Metal SAM encoding requires validated fp16 vision tensor bindings: %s",
                          uocr_metal_context_vision_binding_error(ctx));
    }
    const uint32_t expected_grid = view->kind == UOCR_VIEW_LOCAL ? UOCR_LOCAL_GRID_QUERIES : UOCR_GLOBAL_GRID_QUERIES;
    const uint32_t expected_size = view->kind == UOCR_VIEW_LOCAL ? UOCR_LOCAL_VIEW_SIZE : UOCR_GLOBAL_VIEW_SIZE;
    if (view->kind != UOCR_VIEW_LOCAL && view->kind != UOCR_VIEW_GLOBAL) {
        return metal_fail(error, error_size, "Metal SAM encoding has invalid view kind %d", (int)view->kind);
    }
    if (view->width != expected_size || view->height != expected_size) {
        return metal_fail(error,
                          error_size,
                          "Metal SAM encoding expected %ux%u %s view, got %ux%u",
                          expected_size,
                          expected_size,
                          view->kind == UOCR_VIEW_LOCAL ? "local" : "global",
                          view->width,
                          view->height);
    }
    if (out_grid_w != expected_grid || out_grid_h != expected_grid) {
        return metal_fail(error,
                          error_size,
                          "Metal SAM output grid mismatch: got %ux%u expected %ux%u",
                          out_grid_w,
                          out_grid_h,
                          expected_grid,
                          expected_grid);
    }

    const uocr_metal_vision_weights_f16 *weights = metal_require_vision_weights_f16(ctx, error, error_size);
    if (weights == NULL) {
        return 0;
    }

    uocr_metal_vision_workspace scratch;
    if (!metal_vision_workspace_init(ctx, &scratch, expected_size, 1u, 0u, 0u, 1, error, error_size)) {
        return 0;
    }

    uocr_metal_vision_project_context project;
    memset(&project, 0, sizeof(project));
    project.ctx = ctx;
    project.weights = weights;
    project.scratch = &scratch;

    uint32_t actual_grid_w = 0u;
    uint32_t actual_grid_h = 0u;
    const int ok = metal_encode_one_view_sam_features_f16(&project,
                                                          view,
                                                          (uocr_metal_vision_workspace_slice){0},
                                                          0u,
                                                          0u,
                                                          scratch.sam_net3_nchw,
                                                          &actual_grid_w,
                                                          &actual_grid_h,
                                                          error,
                                                          error_size);
    if (ok) {
        memcpy(out_sam_features_f16, scratch.sam_net3_nchw.f16, (size_t)scratch.sam_net3_nchw.bytes);
    }
    metal_vision_workspace_reset(&scratch);
    if (!ok) {
        return 0;
    }
    if (actual_grid_w != out_grid_w || actual_grid_h != out_grid_h) {
        return metal_fail(error,
                          error_size,
                          "Metal SAM output grid changed during encoding: got %ux%u expected %ux%u",
                          actual_grid_w,
                          actual_grid_h,
                          out_grid_w,
                          out_grid_h);
    }

    metal_clear_error(error, error_size);
    return 1;
}

int uocr_metal_context_diagnostic_encode_clip_features_f16(uocr_metal_context *ctx,
                                                const uocr_image_view *view,
                                                uint16_t *out_clip_features_f16,
                                                uint32_t out_token_count,
                                                char *error,
                                                size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || view == NULL || out_clip_features_f16 == NULL) {
        return metal_fail(error, error_size, "Metal CLIP encoding requires a context, view, and output buffer");
    }
    metal_profile_add_event_ms(ctx, "metal.vision.diagnostic_clip_host_output", 0.0);
    if (!uocr_metal_context_vision_bindings_ready(ctx)) {
        return metal_fail(error,
                          error_size,
                          "Metal CLIP encoding requires validated fp16 vision tensor bindings: %s",
                          uocr_metal_context_vision_binding_error(ctx));
    }
    if (view->kind != UOCR_VIEW_LOCAL && view->kind != UOCR_VIEW_GLOBAL) {
        return metal_fail(error, error_size, "Metal CLIP encoding has invalid view kind %d", (int)view->kind);
    }
    const uint32_t expected_grid = view->kind == UOCR_VIEW_LOCAL ? UOCR_LOCAL_GRID_QUERIES : UOCR_GLOBAL_GRID_QUERIES;
    const uint32_t expected_size = view->kind == UOCR_VIEW_LOCAL ? UOCR_LOCAL_VIEW_SIZE : UOCR_GLOBAL_VIEW_SIZE;
    const uint32_t expected_tokens = UOCR_CLIP_CLASS_TOKENS + expected_grid * expected_grid;
    if (view->width != expected_size || view->height != expected_size) {
        return metal_fail(error,
                          error_size,
                          "Metal CLIP encoding expected %ux%u %s view, got %ux%u",
                          expected_size,
                          expected_size,
                          view->kind == UOCR_VIEW_LOCAL ? "local" : "global",
                          view->width,
                          view->height);
    }
    if (out_token_count != expected_tokens) {
        return metal_fail(error,
                          error_size,
                          "Metal CLIP output token count mismatch: got %u expected %u",
                          out_token_count,
                          expected_tokens);
    }

    const uocr_metal_vision_weights_f16 *weights = metal_require_vision_weights_f16(ctx, error, error_size);
    if (weights == NULL) {
        return 0;
    }

    uocr_metal_vision_workspace scratch;
    if (!metal_vision_workspace_init(ctx, &scratch, expected_size, 1u, 0u, 0u, 1, error, error_size)) {
        return 0;
    }

    uocr_metal_vision_project_context project;
    memset(&project, 0, sizeof(project));
    project.ctx = ctx;
    project.weights = weights;
    project.scratch = &scratch;

    uint32_t actual_tokens = 0u;
    uint32_t actual_grid_w = 0u;
    uint32_t actual_grid_h = 0u;
    const int ok = metal_encode_one_view_clip_features_f16(&project,
                                                           view,
                                                           (uocr_metal_vision_workspace_slice){0},
                                                           0u,
                                                           0u,
                                                           scratch.sam_net3_nchw,
                                                           scratch.clip_final,
                                                           &actual_tokens,
                                                           &actual_grid_w,
                                                           &actual_grid_h,
                                                           error,
                                                           error_size);
    if (ok) {
        memcpy(out_clip_features_f16, scratch.clip_final.f16, (size_t)scratch.clip_final.bytes);
    }
    metal_vision_workspace_reset(&scratch);
    if (!ok) {
        return 0;
    }
    if (actual_tokens != out_token_count || actual_grid_w != expected_grid || actual_grid_h != expected_grid) {
        return metal_fail(error,
                          error_size,
                          "Metal CLIP output shape changed during encoding: got tokens=%u grid=%ux%u expected tokens=%u grid=%ux%u",
                          actual_tokens,
                          actual_grid_w,
                          actual_grid_h,
                          out_token_count,
                          expected_grid,
                          expected_grid);
    }

    metal_clear_error(error, error_size);
    return 1;
}

int uocr_metal_context_diagnostic_encode_projected_features_f16(uocr_metal_context *ctx,
                                                     const uocr_image_view *view,
                                                     uint16_t *out_projected_features_f16,
                                                     uint32_t out_projected_rows,
                                                     char *error,
                                                     size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || view == NULL || out_projected_features_f16 == NULL) {
        return metal_fail(error, error_size, "Metal projected-feature encoding requires a context, view, and output buffer");
    }
    metal_profile_add_event_ms(ctx, "metal.vision.diagnostic_projected_host_output", 0.0);
    if (!uocr_metal_context_vision_bindings_ready(ctx)) {
        return metal_fail(error,
                          error_size,
                          "Metal projected-feature encoding requires validated fp16 vision tensor bindings: %s",
                          uocr_metal_context_vision_binding_error(ctx));
    }
    if (view->kind != UOCR_VIEW_LOCAL && view->kind != UOCR_VIEW_GLOBAL) {
        return metal_fail(error, error_size, "Metal projected-feature encoding has invalid view kind %d", (int)view->kind);
    }
    const uint32_t expected_grid = view->kind == UOCR_VIEW_LOCAL ? UOCR_LOCAL_GRID_QUERIES : UOCR_GLOBAL_GRID_QUERIES;
    const uint32_t expected_size = view->kind == UOCR_VIEW_LOCAL ? UOCR_LOCAL_VIEW_SIZE : UOCR_GLOBAL_VIEW_SIZE;
    const uint32_t expected_rows = expected_grid * expected_grid;
    if (view->width != expected_size || view->height != expected_size) {
        return metal_fail(error,
                          error_size,
                          "Metal projected-feature encoding expected %ux%u %s view, got %ux%u",
                          expected_size,
                          expected_size,
                          view->kind == UOCR_VIEW_LOCAL ? "local" : "global",
                          view->width,
                          view->height);
    }
    if (out_projected_rows != expected_rows) {
        return metal_fail(error,
                          error_size,
                          "Metal projected-feature row count mismatch: got %u expected %u",
                          out_projected_rows,
                          expected_rows);
    }

    const uocr_metal_vision_weights_f16 *weights = metal_require_vision_weights_f16(ctx, error, error_size);
    if (weights == NULL) {
        return 0;
    }

    uocr_metal_vision_workspace scratch;
    if (!metal_vision_workspace_init(ctx, &scratch, expected_size, 1u, expected_rows, 0u, 1, error, error_size)) {
        return 0;
    }

    uocr_metal_vision_project_context project;
    memset(&project, 0, sizeof(project));
    project.ctx = ctx;
    project.weights = weights;
    project.scratch = &scratch;

    const int ok = metal_encode_one_view_projected_f16(&project,
                                                       view,
                                                       (uocr_metal_vision_workspace_slice){0},
                                                       0u,
                                                       0u,
                                                       scratch.projected_rows,
                                                       error,
                                                       error_size);
    if (ok) {
        memcpy(out_projected_features_f16, scratch.projected_rows.f16, (size_t)scratch.projected_rows.bytes);
    }
    metal_vision_workspace_reset(&scratch);
    if (!ok) {
        return 0;
    }

    metal_clear_error(error, error_size);
    return 1;
}

static int scratch_slot_valid(uocr_metal_scratch_slot slot) {
    return slot >= UOCR_METAL_SCRATCH_VISION && slot < UOCR_METAL_SCRATCH_COUNT;
}

static const char *scratch_slot_name(uocr_metal_scratch_slot slot) {
    switch (slot) {
        case UOCR_METAL_SCRATCH_VISION:
            return "vision";
        case UOCR_METAL_SCRATCH_DECODER:
            return "decoder";
        case UOCR_METAL_SCRATCH_MOE:
            return "moe";
        case UOCR_METAL_SCRATCH_LOGITS:
            return "logits";
        case UOCR_METAL_SCRATCH_TRANSIENT:
            return "transient";
        default:
            return "unknown";
    }
}

static uocr_memory_category scratch_slot_memory_category(uocr_metal_scratch_slot slot) {
    switch (slot) {
        case UOCR_METAL_SCRATCH_VISION:
            return UOCR_MEMORY_VISION_GPU_WORKSPACE;
        case UOCR_METAL_SCRATCH_DECODER:
            return UOCR_MEMORY_DECODER_SCRATCH;
        case UOCR_METAL_SCRATCH_MOE:
            return UOCR_MEMORY_MOE_SCRATCH;
        case UOCR_METAL_SCRATCH_LOGITS:
            return UOCR_MEMORY_DECODER_SCRATCH;
        case UOCR_METAL_SCRATCH_TRANSIENT:
        default:
            return UOCR_MEMORY_TRANSIENT_BUFFERS;
    }
}

static int scratch_capacity_for_request(uocr_metal_scratch_slot slot,
                                        uint64_t current_capacity,
                                        uint64_t min_length,
                                        uint64_t *out_capacity) {
    const uint64_t min_allocation = 4096u;
    uint64_t requested = 0u;
    if (!align_up_u64_checked(min_length, 256u, &requested)) {
        return 0;
    }
    if (requested < min_allocation) {
        requested = min_allocation;
    }

    /* Vision scratch is the public request-shaped workspace reported in memory
     * estimates.  Allocate it to the exact aligned request size on first use so
     * a fresh base request does not inherit the generic power-of-two slack used
     * for small transient/decoder scratch buffers.
     */
    if (slot == UOCR_METAL_SCRATCH_VISION) {
        *out_capacity = requested;
        return 1;
    }

    uint64_t capacity = current_capacity;
    if (capacity < min_allocation) {
        capacity = min_allocation;
    }
    while (capacity < requested) {
        if (capacity > UINT64_MAX / 2u) {
            capacity = requested;
            break;
        }
        capacity *= 2u;
    }
    *out_capacity = capacity;
    return 1;
}

static void metal_scratch_release_accounting(uocr_metal_context *ctx, uocr_metal_scratch_buffer *scratch) {
    if (ctx == NULL || scratch == NULL) {
        return;
    }
    metal_memory_release(ctx, scratch->primary_accounted_category, scratch->primary_accounted_bytes);
    metal_memory_release(ctx, scratch->secondary_accounted_category, scratch->secondary_accounted_bytes);
    scratch->primary_accounted_bytes = 0u;
    scratch->secondary_accounted_bytes = 0u;
    scratch->primary_accounted_category = UOCR_MEMORY_TRANSIENT_BUFFERS;
    scratch->secondary_accounted_category = UOCR_MEMORY_TRANSIENT_BUFFERS;
}

static int metal_scratch_reserve_accounting(uocr_metal_context *ctx,
                                            uocr_memory_category primary_category,
                                            uint64_t primary_bytes,
                                            uocr_memory_category secondary_category,
                                            uint64_t secondary_bytes,
                                            const char *label,
                                            char *error,
                                            size_t error_size) {
    if (!metal_memory_reserve(ctx, primary_category, primary_bytes, label, error, error_size)) {
        return 0;
    }
    if (!metal_memory_reserve(ctx, secondary_category, secondary_bytes, label, error, error_size)) {
        metal_memory_release(ctx, primary_category, primary_bytes);
        return 0;
    }
    return 1;
}

static int metal_scratch_rebalance_accounting(uocr_metal_context *ctx,
                                              uocr_metal_scratch_buffer *scratch,
                                              uocr_memory_category primary_category,
                                              uint64_t primary_bytes,
                                              uocr_memory_category secondary_category,
                                              uint64_t secondary_bytes,
                                              const char *label,
                                              char *error,
                                              size_t error_size) {
    if (scratch == NULL) {
        return metal_fail(error, error_size, "invalid Metal scratch accounting request");
    }
    if (scratch->primary_accounted_category == primary_category && scratch->primary_accounted_bytes == primary_bytes &&
        scratch->secondary_accounted_category == secondary_category && scratch->secondary_accounted_bytes == secondary_bytes) {
        return 1;
    }
    metal_scratch_release_accounting(ctx, scratch);
    if (!metal_scratch_reserve_accounting(ctx,
                                          primary_category,
                                          primary_bytes,
                                          secondary_category,
                                          secondary_bytes,
                                          label,
                                          error,
                                          error_size)) {
        return 0;
    }
    scratch->primary_accounted_category = primary_category;
    scratch->primary_accounted_bytes = primary_bytes;
    scratch->secondary_accounted_category = secondary_category;
    scratch->secondary_accounted_bytes = secondary_bytes;
    return 1;
}

static int metal_context_ensure_scratch_accounted(uocr_metal_context *ctx,
                                                  uocr_metal_scratch_slot slot,
                                                  uint64_t min_length,
                                                  int cpu_visible,
                                                  uocr_memory_category secondary_category,
                                                  uint64_t secondary_bytes,
                                                  char *error,
                                                  size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || !scratch_slot_valid(slot)) {
        return metal_fail(error, error_size, "invalid Metal scratch buffer request");
    }
    if (min_length == 0u) {
        return 1;
    }
    if (min_length > (uint64_t)SIZE_MAX) {
        return metal_fail(error,
                          error_size,
                          "Metal scratch request for %s is too large: %llu bytes",
                          scratch_slot_name(slot),
                          (unsigned long long)min_length);
    }

    uocr_metal_scratch_buffer *scratch = &ctx->scratch[slot];
    const int wants_cpu_visible = cpu_visible ? 1 : 0;
    const uocr_memory_category primary_category = scratch_slot_memory_category(slot);
    if (scratch->buffer != nil && scratch->capacity >= min_length && scratch->cpu_visible == wants_cpu_visible) {
        if (secondary_bytes > scratch->capacity) {
            return metal_fail(error,
                              error_size,
                              "Metal scratch accounting split for %s exceeds retained capacity",
                              scratch_slot_name(slot));
        }
        const uint64_t primary_bytes = scratch->capacity - secondary_bytes;
        if (!metal_scratch_rebalance_accounting(ctx,
                                                scratch,
                                                primary_category,
                                                primary_bytes,
                                                secondary_category,
                                                secondary_bytes,
                                                scratch_slot_name(slot),
                                                error,
                                                error_size)) {
            return 0;
        }
        if (scratch->high_watermark < min_length) {
            scratch->high_watermark = min_length;
        }
        return 1;
    }

    uint64_t new_capacity = 0u;
    if (!scratch_capacity_for_request(slot, scratch->capacity, min_length, &new_capacity) ||
        new_capacity > (uint64_t)SIZE_MAX) {
        return metal_fail(error,
                          error_size,
                          "Metal scratch capacity overflow for %s request of %llu bytes",
                          scratch_slot_name(slot),
                          (unsigned long long)min_length);
    }
    if (secondary_bytes > new_capacity) {
        return metal_fail(error,
                          error_size,
                          "Metal scratch accounting split for %s exceeds new capacity",
                          scratch_slot_name(slot));
    }
    const uint64_t primary_bytes = new_capacity - secondary_bytes;

    @autoreleasepool {
        const MTLResourceOptions storage_mode = wants_cpu_visible ? MTLResourceStorageModeShared : MTLResourceStorageModePrivate;
        id<MTLBuffer> buffer = metal_new_buffer_with_length(ctx, (NSUInteger)new_capacity, storage_mode);
        if (buffer == nil) {
            return metal_fail(error,
                              error_size,
                              "failed to allocate %s Metal scratch buffer with %llu bytes",
                              scratch_slot_name(slot),
                              (unsigned long long)new_capacity);
        }
        if (!metal_scratch_reserve_accounting(ctx,
                                              primary_category,
                                              primary_bytes,
                                              secondary_category,
                                              secondary_bytes,
                                              scratch_slot_name(slot),
                                              error,
                                              error_size)) {
            [buffer release];
            return 0;
        }
        buffer.label = [NSString stringWithFormat:@"uocr_scratch_%s", scratch_slot_name(slot)];
        metal_clear_mps_workspace_ndarray_cache(ctx);
        [scratch->buffer release];
        metal_scratch_release_accounting(ctx, scratch);
        scratch->buffer = buffer;
        scratch->capacity = new_capacity;
        scratch->cpu_visible = wants_cpu_visible;
        scratch->primary_accounted_category = primary_category;
        scratch->primary_accounted_bytes = primary_bytes;
        scratch->secondary_accounted_category = secondary_category;
        scratch->secondary_accounted_bytes = secondary_bytes;
        if (scratch->high_watermark < min_length) {
            scratch->high_watermark = min_length;
        }
    }
    return 1;
}

int uocr_metal_context_ensure_scratch(uocr_metal_context *ctx,
                                      uocr_metal_scratch_slot slot,
                                      uint64_t min_length,
                                      int cpu_visible,
                                      char *error,
                                      size_t error_size) {
    return metal_context_ensure_scratch_accounted(ctx,
                                                  slot,
                                                  min_length,
                                                  cpu_visible,
                                                  UOCR_MEMORY_TRANSIENT_BUFFERS,
                                                  0u,
                                                  error,
                                                  error_size);
}

void uocr_metal_context_release_scratch(uocr_metal_context *ctx, uocr_metal_scratch_slot slot) {
    if (ctx == NULL || !scratch_slot_valid(slot)) {
        return;
    }
    @autoreleasepool {
        uocr_metal_scratch_buffer *scratch = &ctx->scratch[slot];
        metal_clear_mps_workspace_ndarray_cache(ctx);
        [scratch->buffer release];
        scratch->buffer = nil;
        scratch->capacity = 0u;
        scratch->cpu_visible = 0;
        metal_scratch_release_accounting(ctx, scratch);
    }
}

uint64_t uocr_metal_context_scratch_capacity(const uocr_metal_context *ctx, uocr_metal_scratch_slot slot) {
    if (ctx == NULL || !scratch_slot_valid(slot)) {
        return 0u;
    }
    return ctx->scratch[slot].capacity;
}

uint64_t uocr_metal_context_scratch_high_watermark(const uocr_metal_context *ctx, uocr_metal_scratch_slot slot) {
    if (ctx == NULL || !scratch_slot_valid(slot)) {
        return 0u;
    }
    return ctx->scratch[slot].high_watermark;
}

uint64_t uocr_metal_context_total_scratch_capacity(const uocr_metal_context *ctx) {
    uint64_t total = 0u;
    if (ctx == NULL) {
        return 0u;
    }
    for (uint32_t i = 0u; i < (uint32_t)UOCR_METAL_SCRATCH_COUNT; ++i) {
        if (!checked_add_u64(total, ctx->scratch[i].capacity, &total)) {
            return UINT64_MAX;
        }
    }
    return total;
}

uint64_t uocr_metal_context_total_scratch_high_watermark(const uocr_metal_context *ctx) {
    uint64_t total = 0u;
    if (ctx == NULL) {
        return 0u;
    }
    for (uint32_t i = 0u; i < (uint32_t)UOCR_METAL_SCRATCH_COUNT; ++i) {
        if (!checked_add_u64(total, ctx->scratch[i].high_watermark, &total)) {
            return UINT64_MAX;
        }
    }
    return total;
}

static void release_all_scratch(uocr_metal_context *ctx) {
    if (ctx == NULL) {
        return;
    }
    for (uint32_t i = 0u; i < (uint32_t)UOCR_METAL_SCRATCH_COUNT; ++i) {
        uocr_metal_context_release_scratch(ctx, (uocr_metal_scratch_slot)i);
    }
}

int uocr_metal_context_warmup_model_views(uocr_metal_context *ctx,
                                          uint64_t max_bytes_per_view,
                                          char *error,
                                          size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL) {
        return metal_fail(error, error_size, "Metal model-view warmup requires a context");
    }
    if (ctx->model_views == NULL || ctx->model_view_count == 0u) {
        return metal_fail(error, error_size, "Metal model-view warmup requires mapped model views");
    }

    long page_size_long = sysconf(_SC_PAGESIZE);
    if (page_size_long <= 0) {
        page_size_long = (long)UOCR_TENSOR_DATA_ALIGNMENT;
    }
    uint64_t stride_words_u64 = (uint64_t)page_size_long / sizeof(uint32_t);
    if (stride_words_u64 == 0u) {
        stride_words_u64 = 1u;
    }
    if (stride_words_u64 > UINT32_MAX) {
        return metal_fail(error, error_size, "Metal warmup page stride is too large");
    }
    const uint32_t stride_words = (uint32_t)stride_words_u64;

    uint64_t total_probe_count = 0u;
    uint64_t total_warmup_bytes = 0u;
    for (uint32_t i = 0u; i < ctx->model_view_count; ++i) {
        uint64_t bytes = ctx->model_views[i].length;
        if (max_bytes_per_view != 0u && bytes > max_bytes_per_view) {
            bytes = max_bytes_per_view;
        }
        const uint64_t words = bytes / sizeof(uint32_t);
        if (words == 0u) {
            continue;
        }
        if (words > UINT32_MAX) {
            return metal_fail(error, error_size, "Metal model-view warmup view %u is too large for u32 probe indexing", i);
        }
        const uint64_t probes = (words + (uint64_t)stride_words - 1u) / (uint64_t)stride_words;
        if (probes > UINT32_MAX || total_probe_count > (uint64_t)UINT32_MAX - probes) {
            return metal_fail(error, error_size, "Metal model-view warmup would need too many probe outputs");
        }
        if (!checked_add_u64(total_warmup_bytes, words * sizeof(uint32_t), &total_warmup_bytes)) {
            return metal_fail(error, error_size, "Metal model-view warmup byte count overflow");
        }
        total_probe_count += probes;
    }

    if (total_probe_count == 0u) {
        ctx->last_model_warmup_bytes = 0u;
        return 1;
    }
    const uint64_t output_bytes = total_probe_count * sizeof(uint32_t);
    if (!uocr_metal_context_ensure_scratch(ctx, UOCR_METAL_SCRATCH_TRANSIENT, output_bytes, 1, error, error_size)) {
        return 0;
    }

    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_touch_u32", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        id<MTLBuffer> dst = ctx->scratch[UOCR_METAL_SCRATCH_TRANSIENT].buffer;
        if (dst == nil || [dst contents] == NULL) {
            return metal_fail(error, error_size, "Metal model-view warmup has no CPU-visible scratch output");
        }
        memset([dst contents], 0, (size_t)output_bytes);

        id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            return metal_fail(error, error_size, "failed to create Metal warmup command buffer");
        }
        cb.label = @"uocr_model_view_warmup_command_buffer";

        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal warmup command encoder");
        }
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:dst offset:0u atIndex:1u];

        uint32_t dst_base = 0u;
        for (uint32_t i = 0u; i < ctx->model_view_count; ++i) {
            uint64_t bytes = ctx->model_views[i].length;
            if (max_bytes_per_view != 0u && bytes > max_bytes_per_view) {
                bytes = max_bytes_per_view;
            }
            const uint64_t words = bytes / sizeof(uint32_t);
            if (words == 0u) {
                continue;
            }
            const uint32_t probes = (uint32_t)((words + (uint64_t)stride_words - 1u) / (uint64_t)stride_words);
            uocr_metal_touch_params params;
            params.n_words = (uint32_t)words;
            params.stride_words = stride_words;
            params.dst_base = dst_base;
            params.reserved = 0u;

            [enc setBuffer:ctx->model_views[i].buffer offset:0u atIndex:0u];
            [enc setBytes:&params length:sizeof(params) atIndex:2u];

            NSUInteger threads_per_group = pipeline.threadExecutionWidth;
            if (threads_per_group == 0u) {
                threads_per_group = 1u;
            }
            if (threads_per_group > (NSUInteger)probes) {
                threads_per_group = (NSUInteger)probes;
            }
            [enc dispatchThreads:MTLSizeMake((NSUInteger)probes, 1u, 1u)
           threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
            dst_base += probes;
        }
        [enc endEncoding];

        UOCR_METAL_COMMIT_AND_WAIT_PROFILED(ctx, cb);
        if (cb.status == MTLCommandBufferStatusError) {
            NSString *description = cb.error != nil ? [cb.error localizedDescription] : @"unknown command-buffer error";
            return metal_fail(error, error_size, "Metal model-view warmup failed: %s", [description UTF8String]);
        }
    }

    ctx->last_model_warmup_bytes = total_warmup_bytes;
    metal_clear_error(error, error_size);
    return 1;
}

uint64_t uocr_metal_context_last_warmup_bytes(const uocr_metal_context *ctx) {
    return ctx != NULL ? ctx->last_model_warmup_bytes : 0u;
}

static int runtime_arena_slot_valid(uocr_metal_runtime_arena_slot slot) {
    return slot >= UOCR_METAL_ARENA_KV_CACHE && slot < UOCR_METAL_ARENA_COUNT;
}

static const char *runtime_arena_slot_name(uocr_metal_runtime_arena_slot slot) {
    switch (slot) {
        case UOCR_METAL_ARENA_KV_CACHE:
            return "kv-cache";
        case UOCR_METAL_ARENA_PROMPT_EMBEDDINGS:
            return "prompt-embeddings";
        case UOCR_METAL_ARENA_HIDDEN_PINGPONG:
            return "hidden-pingpong";
        case UOCR_METAL_ARENA_ROUTER_TOPK:
            return "router-topk";
        case UOCR_METAL_ARENA_MOE_INTERMEDIATE:
            return "moe-intermediate";
        case UOCR_METAL_ARENA_VISION_SCRATCH:
            return "vision-scratch";
        case UOCR_METAL_ARENA_LOGITS_READBACK:
            return "logits-readback";
        default:
            return "unknown";
    }
}

static int runtime_arena_is_cpu_visible(uocr_metal_runtime_arena_slot slot) {
    return slot == UOCR_METAL_ARENA_LOGITS_READBACK;
}

static int metal_init_kv_cache_layout(uint32_t batch_slots,
                                      uint32_t prompt_token_capacity,
                                      uocr_metal_kv_cache_layout *out_layout) {
    if (out_layout == NULL || batch_slots == 0u || prompt_token_capacity == 0u) {
        return 0;
    }

    uint64_t cache_token_capacity = 0u;
    uint64_t token_stride = 0u;
    uint64_t slot_stride = 0u;
    uint64_t layer_stride = 0u;
    uint64_t tensor_bytes = 0u;
    uint64_t total_bytes = 0u;
    if (!checked_add_u64((uint64_t)prompt_token_capacity,
                         (uint64_t)UOCR_GENERATED_RING_WINDOW,
                         &cache_token_capacity) ||
        cache_token_capacity > (uint64_t)UINT32_MAX ||
        !checked_mul_u64((uint64_t)UOCR_KV_HEADS, (uint64_t)UOCR_HEAD_DIM, &token_stride) ||
        !checked_mul_u64(token_stride, 2u, &token_stride) ||
        !checked_mul_u64(cache_token_capacity, token_stride, &slot_stride) ||
        !checked_mul_u64((uint64_t)batch_slots, slot_stride, &layer_stride) ||
        !checked_mul_u64((uint64_t)UOCR_DECODER_LAYERS, layer_stride, &tensor_bytes) ||
        !checked_mul_u64(tensor_bytes, 2u, &total_bytes)) {
        return 0;
    }

    memset(out_layout, 0, sizeof(*out_layout));
    out_layout->decoder_layers = UOCR_DECODER_LAYERS;
    out_layout->batch_slots = batch_slots;
    out_layout->prompt_token_capacity = prompt_token_capacity;
    out_layout->cache_token_capacity = (uint32_t)cache_token_capacity;
    out_layout->kv_heads = UOCR_KV_HEADS;
    out_layout->head_dim = UOCR_HEAD_DIM;
    out_layout->generated_ring_window = UOCR_GENERATED_RING_WINDOW;
    out_layout->token_stride_bytes = token_stride;
    out_layout->slot_stride_bytes = slot_stride;
    out_layout->layer_stride_bytes = layer_stride;
    out_layout->tensor_bytes = tensor_bytes;
    out_layout->k_offset_bytes = 0u;
    out_layout->v_offset_bytes = tensor_bytes;
    out_layout->total_bytes = total_bytes;
    return 1;
}

static int runtime_arena_capacities(uint32_t batch_slots,
                                    uint32_t prompt_token_capacity,
                                    uint64_t capacities[UOCR_METAL_ARENA_COUNT]) {
    if (capacities == NULL || batch_slots == 0u || prompt_token_capacity == 0u) {
        return UOCR_ERROR_INVALID_ARGUMENT;
    }
    memset(capacities, 0, (size_t)UOCR_METAL_ARENA_COUNT * sizeof(capacities[0]));

    int status = uocr_estimate_kv_cache_bytes(batch_slots, prompt_token_capacity, &capacities[UOCR_METAL_ARENA_KV_CACHE]);
    if (status != UOCR_OK) {
        return status;
    }
    status = uocr_estimate_prompt_embedding_bytes(batch_slots,
                                                  prompt_token_capacity,
                                                  &capacities[UOCR_METAL_ARENA_PROMPT_EMBEDDINGS]);
    if (status != UOCR_OK) {
        return status;
    }
    status = uocr_estimate_decoder_scratch_bytes(batch_slots,
                                                 prompt_token_capacity,
                                                 &capacities[UOCR_METAL_ARENA_HIDDEN_PINGPONG]);
    if (status != UOCR_OK) {
        return status;
    }
    status = uocr_estimate_moe_router_topk_bytes(batch_slots,
                                                 prompt_token_capacity,
                                                 &capacities[UOCR_METAL_ARENA_ROUTER_TOPK]);
    if (status != UOCR_OK) {
        return status;
    }
    status = uocr_estimate_moe_intermediate_bytes(batch_slots,
                                                  prompt_token_capacity,
                                                  &capacities[UOCR_METAL_ARENA_MOE_INTERMEDIATE]);
    if (status != UOCR_OK) {
        return status;
    }
    /* Vision workspace is request-shaped and grow-on-demand via
     * UOCR_METAL_SCRATCH_VISION.  Do not reserve a stale prompt-sized
     * runtime arena at engine open.
     */
    capacities[UOCR_METAL_ARENA_VISION_SCRATCH] = 0u;
    status = uocr_estimate_logits_readback_bytes(batch_slots, &capacities[UOCR_METAL_ARENA_LOGITS_READBACK]);
    if (status != UOCR_OK) {
        return status;
    }
    return UOCR_OK;
}

void uocr_metal_context_release_runtime_arenas(uocr_metal_context *ctx) {
    if (ctx == NULL) {
        return;
    }
    @autoreleasepool {
        int changed = ctx->prompt_token_ids_buffer != nil || ctx->no_repeat_sequence_buffer != nil || ctx->has_kv_cache_layout != 0;
        metal_clear_mps_workspace_ndarray_cache(ctx);
        for (uint32_t i = 0u; i < (uint32_t)UOCR_METAL_ARENA_COUNT; ++i) {
            uocr_metal_runtime_arena *arena = &ctx->runtime_arenas[i];
            if (arena->buffer != nil || arena->capacity != 0u) {
                changed = 1;
            }
            [arena->buffer release];
            arena->buffer = nil;
            arena->capacity = 0u;
            arena->cpu_visible = 0;
        }
        [ctx->prompt_token_ids_buffer release];
        ctx->prompt_token_ids_buffer = nil;
        ctx->prompt_token_ids_capacity = 0u;
        ctx->prompt_token_ids_batch_slots = 0u;
        ctx->prompt_token_ids_prompt_capacity = 0u;
        [ctx->no_repeat_sequence_buffer release];
        ctx->no_repeat_sequence_buffer = nil;
        ctx->no_repeat_sequence_capacity = 0u;
        ctx->no_repeat_sequence_batch_slots = 0u;
        ctx->no_repeat_sequence_token_capacity = 0u;
        memset(&ctx->kv_cache_layout, 0, sizeof(ctx->kv_cache_layout));
        ctx->has_kv_cache_layout = 0;
        ctx->has_integrated_prefill = 0;
        ctx->integrated_prefill_slot = 0u;
        ctx->integrated_prefill_tokens = 0u;
        ctx->integrated_prefill_final_segment = 0u;
        if (changed) {
            ++ctx->runtime_arena_generation;
        }
    }
}

int uocr_metal_context_allocate_runtime_arenas(uocr_metal_context *ctx,
                                               uint32_t batch_slots,
                                               uint32_t prompt_token_capacity,
                                               char *error,
                                               size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || batch_slots == 0u || prompt_token_capacity == 0u) {
        return metal_fail(error, error_size, "invalid Metal runtime arena allocation request");
    }
    if (ctx->active_command_buffer != nil) {
        return metal_fail(error,
                          error_size,
                          "Metal runtime arenas must be grown before command encoding; active command batch is in progress");
    }

    uint64_t capacities[UOCR_METAL_ARENA_COUNT];
    const int estimate_status = runtime_arena_capacities(batch_slots, prompt_token_capacity, capacities);
    if (estimate_status != UOCR_OK) {
        return metal_fail(error,
                          error_size,
                          "failed to estimate Metal runtime arena sizes: %s",
                          uocr_status_string(estimate_status));
    }

    uocr_metal_kv_cache_layout kv_layout;
    if (!metal_init_kv_cache_layout(batch_slots, prompt_token_capacity, &kv_layout) ||
        kv_layout.total_bytes != capacities[UOCR_METAL_ARENA_KV_CACHE]) {
        return metal_fail(error, error_size, "failed to build Metal KV cache layout");
    }

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (max_buffer_length == 0u) {
        return metal_fail(error, error_size, "Metal device reported maxBufferLength=0");
    }

    uocr_metal_context_release_runtime_arenas(ctx);
    @autoreleasepool {
        for (uint32_t i = 0u; i < (uint32_t)UOCR_METAL_ARENA_COUNT; ++i) {
            const uocr_metal_runtime_arena_slot slot = (uocr_metal_runtime_arena_slot)i;
            const uint64_t bytes = capacities[i];
            if (bytes == 0u) {
                continue;
            }
            if (bytes > max_buffer_length || bytes > (uint64_t)SIZE_MAX) {
                uocr_metal_context_release_runtime_arenas(ctx);
                return metal_fail(error,
                                  error_size,
                                  "Metal runtime arena %s needs %llu bytes, exceeding maxBufferLength %llu",
                                  runtime_arena_slot_name(slot),
                                  (unsigned long long)bytes,
                                  (unsigned long long)max_buffer_length);
            }
            const int cpu_visible = runtime_arena_is_cpu_visible(slot);
            const MTLResourceOptions storage_mode = cpu_visible ? MTLResourceStorageModeShared : MTLResourceStorageModePrivate;
            id<MTLBuffer> buffer = metal_new_buffer_with_length(ctx, (NSUInteger)bytes, storage_mode);
            if (buffer == nil) {
                uocr_metal_context_release_runtime_arenas(ctx);
                return metal_fail(error,
                                  error_size,
                                  "failed to allocate Metal runtime arena %s with %llu bytes",
                                  runtime_arena_slot_name(slot),
                                  (unsigned long long)bytes);
            }
            buffer.label = [NSString stringWithFormat:@"uocr_arena_%s", runtime_arena_slot_name(slot)];
            ctx->runtime_arenas[i].buffer = buffer;
            ctx->runtime_arenas[i].capacity = bytes;
            ctx->runtime_arenas[i].cpu_visible = cpu_visible;
        }
        uint64_t prompt_token_id_bytes = 0u;
        if (!checked_mul_u64((uint64_t)batch_slots, (uint64_t)prompt_token_capacity, &prompt_token_id_bytes) ||
            !checked_mul_u64(prompt_token_id_bytes, (uint64_t)sizeof(int32_t), &prompt_token_id_bytes) ||
            prompt_token_id_bytes > max_buffer_length || prompt_token_id_bytes > (uint64_t)SIZE_MAX) {
            uocr_metal_context_release_runtime_arenas(ctx);
            return metal_fail(error, error_size, "Metal prompt token-id arena byte-size overflow");
        }
        id<MTLBuffer> prompt_tokens = metal_new_buffer_with_length(ctx,
                                                                   (NSUInteger)prompt_token_id_bytes,
                                                                   MTLResourceStorageModeShared);
        if (prompt_tokens == nil) {
            uocr_metal_context_release_runtime_arenas(ctx);
            return metal_fail(error,
                              error_size,
                              "failed to allocate persistent Metal prompt token-id buffer with %llu bytes",
                              (unsigned long long)prompt_token_id_bytes);
        }
        prompt_tokens.label = @"uocr_persistent_prompt_token_ids";
        ctx->prompt_token_ids_buffer = prompt_tokens;
        ctx->prompt_token_ids_capacity = prompt_token_id_bytes;
        ctx->prompt_token_ids_batch_slots = batch_slots;
        ctx->prompt_token_ids_prompt_capacity = prompt_token_capacity;

        uint64_t no_repeat_sequence_bytes = 0u;
        if (!checked_mul_u64((uint64_t)batch_slots, (uint64_t)UOCR_MAX_POSITIONS, &no_repeat_sequence_bytes) ||
            !checked_mul_u64(no_repeat_sequence_bytes, (uint64_t)sizeof(int32_t), &no_repeat_sequence_bytes) ||
            no_repeat_sequence_bytes > max_buffer_length || no_repeat_sequence_bytes > (uint64_t)SIZE_MAX) {
            uocr_metal_context_release_runtime_arenas(ctx);
            return metal_fail(error, error_size, "Metal no-repeat sequence arena byte-size overflow");
        }
        id<MTLBuffer> no_repeat_sequence = metal_new_buffer_with_length(ctx,
                                                                        (NSUInteger)no_repeat_sequence_bytes,
                                                                        MTLResourceStorageModePrivate);
        if (no_repeat_sequence == nil) {
            uocr_metal_context_release_runtime_arenas(ctx);
            return metal_fail(error,
                              error_size,
                              "failed to allocate reusable Metal no-repeat sequence buffer with %llu bytes",
                              (unsigned long long)no_repeat_sequence_bytes);
        }
        no_repeat_sequence.label = @"uocr_reusable_no_repeat_sequence";
        ctx->no_repeat_sequence_buffer = no_repeat_sequence;
        ctx->no_repeat_sequence_capacity = no_repeat_sequence_bytes;
        ctx->no_repeat_sequence_batch_slots = batch_slots;
        ctx->no_repeat_sequence_token_capacity = UOCR_MAX_POSITIONS;

        ctx->kv_cache_layout = kv_layout;
        ctx->has_kv_cache_layout = 1;
        ++ctx->runtime_arena_generation;
        if (!metal_prebuild_mps_runtime_workspace_ndarrays(ctx, prompt_token_capacity, error, error_size)) {
            uocr_metal_context_release_runtime_arenas(ctx);
            return 0;
        }
    }
    return 1;
}

uint64_t uocr_metal_context_runtime_arena_capacity(const uocr_metal_context *ctx,
                                                   uocr_metal_runtime_arena_slot slot) {
    if (ctx == NULL || !runtime_arena_slot_valid(slot)) {
        return 0u;
    }
    return ctx->runtime_arenas[slot].capacity;
}

uint64_t uocr_metal_context_total_runtime_arena_capacity(const uocr_metal_context *ctx) {
    uint64_t total = 0u;
    if (ctx == NULL) {
        return 0u;
    }
    for (uint32_t i = 0u; i < (uint32_t)UOCR_METAL_ARENA_COUNT; ++i) {
        if (!checked_add_u64(total, ctx->runtime_arenas[i].capacity, &total)) {
            return UINT64_MAX;
        }
    }
    return total;
}

uint32_t uocr_metal_context_runtime_arena_batch_slots(const uocr_metal_context *ctx) {
    return (ctx != NULL && ctx->has_kv_cache_layout) ? ctx->kv_cache_layout.batch_slots : 0u;
}

uint32_t uocr_metal_context_runtime_arena_prompt_token_capacity(const uocr_metal_context *ctx) {
    return (ctx != NULL && ctx->has_kv_cache_layout) ? ctx->kv_cache_layout.prompt_token_capacity : 0u;
}

int uocr_metal_context_get_kv_cache_layout(const uocr_metal_context *ctx,
                                           uocr_metal_kv_cache_layout *out_layout) {
    if (ctx == NULL || out_layout == NULL || !ctx->has_kv_cache_layout) {
        return 0;
    }
    *out_layout = ctx->kv_cache_layout;
    return 1;
}

int uocr_metal_kv_cache_offset(const uocr_metal_kv_cache_layout *layout,
                               int value_cache,
                               uint32_t layer,
                               uint32_t slot,
                               uint32_t cache_token,
                               uint32_t head,
                               uint32_t dim,
                               uint64_t *out_offset_bytes) {
    if (layout == NULL || out_offset_bytes == NULL || (value_cache != 0 && value_cache != 1) ||
        layout->total_bytes < 2u || layer >= layout->decoder_layers || slot >= layout->batch_slots ||
        cache_token >= layout->cache_token_capacity || head >= layout->kv_heads || dim >= layout->head_dim) {
        return 0;
    }

    uint64_t offset = value_cache ? layout->v_offset_bytes : layout->k_offset_bytes;
    uint64_t term = 0u;
    if (!checked_mul_u64((uint64_t)layer, layout->layer_stride_bytes, &term) ||
        !checked_add_u64(offset, term, &offset) ||
        !checked_mul_u64((uint64_t)slot, layout->slot_stride_bytes, &term) ||
        !checked_add_u64(offset, term, &offset) ||
        !checked_mul_u64((uint64_t)cache_token, layout->token_stride_bytes, &term) ||
        !checked_add_u64(offset, term, &offset) ||
        !checked_mul_u64((uint64_t)head, (uint64_t)layout->head_dim * 2u, &term) ||
        !checked_add_u64(offset, term, &offset) ||
        !checked_mul_u64((uint64_t)dim, 2u, &term) ||
        !checked_add_u64(offset, term, &offset) ||
        offset > layout->total_bytes - 2u) {
        return 0;
    }

    *out_offset_bytes = offset;
    return 1;
}

int uocr_metal_kv_cache_token_for_position(uint32_t prompt_length,
                                           uint32_t prompt_token_capacity,
                                           uint32_t position,
                                           uint32_t *out_cache_token) {
    if (out_cache_token == NULL || prompt_length == 0u || prompt_length > prompt_token_capacity ||
        position >= UOCR_MAX_POSITIONS) {
        return 0;
    }
    if (position < prompt_length) {
        *out_cache_token = position;
        return 1;
    }
    *out_cache_token = prompt_length + ((position - prompt_length) % UOCR_GENERATED_RING_WINDOW);
    return 1;
}

int uocr_metal_kv_cache_attention_length(uint32_t prompt_length,
                                         uint32_t generated_count,
                                         uint32_t *out_attention_length) {
    if (out_attention_length == NULL || prompt_length == 0u || prompt_length > UOCR_MAX_POSITIONS) {
        return 0;
    }
    const uint32_t live_generated = generated_count < UOCR_GENERATED_RING_WINDOW ? generated_count : UOCR_GENERATED_RING_WINDOW;
    if (prompt_length > UOCR_MAX_POSITIONS - live_generated) {
        return 0;
    }
    *out_attention_length = prompt_length + live_generated;
    return 1;
}

int uocr_metal_kv_cache_decode_attention_plan(uint32_t prompt_length,
                                             uint32_t prompt_token_capacity,
                                             uint32_t generated_count,
                                             uocr_metal_decode_attention_plan *out_plan) {
    if (out_plan == NULL || prompt_length == 0u || prompt_length > prompt_token_capacity ||
        prompt_length > UOCR_MAX_POSITIONS || generated_count > UOCR_MAX_POSITIONS - prompt_length) {
        return 0;
    }

    uint64_t cache_token_capacity = 0u;
    if (!checked_add_u64((uint64_t)prompt_token_capacity,
                         (uint64_t)UOCR_GENERATED_RING_WINDOW,
                         &cache_token_capacity) ||
        cache_token_capacity > (uint64_t)UINT32_MAX) {
        return 0;
    }

    uint32_t attention_length = 0u;
    if (!uocr_metal_kv_cache_attention_length(prompt_length, generated_count, &attention_length)) {
        return 0;
    }

    const uint32_t live_generated = generated_count < UOCR_GENERATED_RING_WINDOW ? generated_count : UOCR_GENERATED_RING_WINDOW;
    const uint32_t first_generated_index = generated_count - live_generated;
    const uint32_t first_generated_position = prompt_length + first_generated_index;
    const uint32_t query_position = generated_count == 0u ? prompt_length : prompt_length + generated_count - 1u;

    memset(out_plan, 0, sizeof(*out_plan));
    out_plan->prompt_length = prompt_length;
    out_plan->prompt_token_capacity = prompt_token_capacity;
    out_plan->cache_token_capacity = (uint32_t)cache_token_capacity;
    out_plan->generated_count = generated_count;
    out_plan->live_generated = live_generated;
    out_plan->first_generated_index = first_generated_index;
    out_plan->first_generated_position = first_generated_position;
    out_plan->query_position = query_position;
    out_plan->attention_length = attention_length;
    out_plan->generated_ring_window = UOCR_GENERATED_RING_WINDOW;
    return 1;
}

int uocr_metal_kv_cache_decode_position_allowed(const uocr_metal_decode_attention_plan *plan,
                                                uint32_t key_position) {
    if (plan == NULL || plan->prompt_length == 0u || plan->generated_ring_window != UOCR_GENERATED_RING_WINDOW ||
        key_position >= UOCR_MAX_POSITIONS) {
        return 0;
    }
    if (key_position < plan->prompt_length) {
        return 1;
    }
    if (plan->live_generated == 0u) {
        return 0;
    }
    return key_position >= plan->first_generated_position && key_position <= plan->query_position;
}

int uocr_metal_kv_cache_decode_attention_index_to_token(const uocr_metal_decode_attention_plan *plan,
                                                        uint32_t attention_index,
                                                        uint32_t *out_cache_token) {
    if (plan == NULL || out_cache_token == NULL || plan->prompt_length == 0u ||
        plan->generated_ring_window != UOCR_GENERATED_RING_WINDOW || attention_index >= plan->attention_length) {
        return 0;
    }
    if (attention_index < plan->prompt_length) {
        *out_cache_token = attention_index;
        return 1;
    }

    const uint32_t generated_offset = attention_index - plan->prompt_length;
    if (generated_offset >= plan->live_generated) {
        return 0;
    }
    const uint32_t logical_generated = plan->first_generated_index + generated_offset;
    const uint32_t cache_token = plan->prompt_length + (logical_generated % plan->generated_ring_window);
    if (cache_token >= plan->cache_token_capacity) {
        return 0;
    }
    *out_cache_token = cache_token;
    return 1;
}

int uocr_metal_kv_cache_token_for_attention_index(uint32_t prompt_length,
                                                  uint32_t prompt_token_capacity,
                                                  uint32_t generated_count,
                                                  uint32_t attention_index,
                                                  uint32_t *out_cache_token) {
    uocr_metal_decode_attention_plan plan;
    if (!uocr_metal_kv_cache_decode_attention_plan(prompt_length,
                                                   prompt_token_capacity,
                                                   generated_count,
                                                   &plan)) {
        return 0;
    }
    return uocr_metal_kv_cache_decode_attention_index_to_token(&plan, attention_index, out_cache_token);
}

static void metal_decoder_result_reset(uocr_metal_decoder_result_f16 *result) {
    if (result == NULL) {
        return;
    }
    result->generated_count = 0u;
    result->stopped_on_eos = 0u;
    result->last_token_id = UINT32_MAX;
    result->last_score_f32 = 0.0f;
    result->reserved0 = 0u;
}

static void metal_integrated_decoder_state_reset(uocr_metal_context *ctx, uint32_t slot) {
    if (ctx == NULL) {
        return;
    }
    ctx->has_integrated_prefill = 0;
    ctx->integrated_prefill_slot = slot;
    ctx->integrated_prefill_tokens = 0u;
    ctx->integrated_prefill_final_segment = 0u;
}

static int metal_decoder_runtime_arenas_ready(const uocr_metal_context *ctx) {
    if (ctx == NULL || !ctx->has_kv_cache_layout) {
        return 0;
    }
    return ctx->runtime_arenas[UOCR_METAL_ARENA_KV_CACHE].buffer != nil &&
           ctx->runtime_arenas[UOCR_METAL_ARENA_PROMPT_EMBEDDINGS].buffer != nil &&
           ctx->runtime_arenas[UOCR_METAL_ARENA_HIDDEN_PINGPONG].buffer != nil &&
           ctx->runtime_arenas[UOCR_METAL_ARENA_ROUTER_TOPK].buffer != nil &&
           ctx->runtime_arenas[UOCR_METAL_ARENA_MOE_INTERMEDIATE].buffer != nil &&
           ctx->runtime_arenas[UOCR_METAL_ARENA_LOGITS_READBACK].buffer != nil;
}

typedef struct uocr_metal_runtime_arena_guard {
    uint64_t generation;
    uint64_t capacity;
    uint32_t batch_slots;
    uint32_t prompt_token_capacity;
} uocr_metal_runtime_arena_guard;

typedef struct uocr_metal_hot_path_alloc_guard {
    uocr_alloc_guard core_alloc_guard;
    uint64_t scratch_capacity;
    uocr_metal_runtime_arena_guard runtime_arena;
    NSUInteger pipeline_cache_count;
} uocr_metal_hot_path_alloc_guard;

static uocr_metal_runtime_arena_guard metal_runtime_arena_guard_begin(const uocr_metal_context *ctx) {
    uocr_metal_runtime_arena_guard guard;
    guard.generation = ctx != NULL ? ctx->runtime_arena_generation : 0u;
    guard.capacity = uocr_metal_context_total_runtime_arena_capacity(ctx);
    guard.batch_slots = uocr_metal_context_runtime_arena_batch_slots(ctx);
    guard.prompt_token_capacity = uocr_metal_context_runtime_arena_prompt_token_capacity(ctx);
    return guard;
}

static int metal_runtime_arena_guard_end(const uocr_metal_context *ctx,
                                         const uocr_metal_runtime_arena_guard *guard,
                                         const char *label,
                                         char *error,
                                         size_t error_size) {
    if (ctx == NULL || guard == NULL) {
        return metal_fail(error, error_size, "invalid %s runtime-arena guard", label != NULL ? label : "Metal hot path");
    }
    const uint64_t generation = ctx->runtime_arena_generation;
    const uint64_t capacity = uocr_metal_context_total_runtime_arena_capacity(ctx);
    const uint32_t batch_slots = uocr_metal_context_runtime_arena_batch_slots(ctx);
    const uint32_t prompt_token_capacity = uocr_metal_context_runtime_arena_prompt_token_capacity(ctx);
    if (generation != guard->generation || capacity != guard->capacity || batch_slots != guard->batch_slots ||
        prompt_token_capacity != guard->prompt_token_capacity) {
        return metal_fail(error,
                          error_size,
                          "%s changed runtime arena state "
                          "(generation %llu->%llu, capacity %llu->%llu bytes, batch_slots %u->%u, prompt_capacity %u->%u)",
                          label != NULL ? label : "Metal hot path",
                          (unsigned long long)guard->generation,
                          (unsigned long long)generation,
                          (unsigned long long)guard->capacity,
                          (unsigned long long)capacity,
                          guard->batch_slots,
                          batch_slots,
                          guard->prompt_token_capacity,
                          prompt_token_capacity);
    }
    metal_profile_add_event_ms(ctx, "metal.runtime_arena_guard.no_growth", 0.0);
    return 1;
}

static uocr_metal_hot_path_alloc_guard metal_hot_path_alloc_guard_begin(const uocr_metal_context *ctx) {
    uocr_metal_hot_path_alloc_guard guard;
    guard.core_alloc_guard = uocr_alloc_guard_begin();
    guard.scratch_capacity = uocr_metal_context_total_scratch_capacity(ctx);
    guard.runtime_arena = metal_runtime_arena_guard_begin(ctx);
    guard.pipeline_cache_count = (ctx != NULL && ctx->pipeline_cache != nil) ? [ctx->pipeline_cache count] : 0u;
    return guard;
}

static int metal_hot_path_alloc_guard_end(const uocr_metal_context *ctx,
                                          const uocr_metal_hot_path_alloc_guard *guard,
                                          const char *label,
                                          char *error,
                                          size_t error_size) {
    if (ctx == NULL || guard == NULL) {
        return metal_fail(error, error_size, "invalid %s allocation guard", label != NULL ? label : "Metal hot path");
    }
    if (!uocr_alloc_guard_end_no_alloc(&guard->core_alloc_guard)) {
        return metal_fail(error,
                          error_size,
                          "%s allocated through the core allocator",
                          label != NULL ? label : "Metal hot path");
    }
    const uint64_t scratch_capacity = uocr_metal_context_total_scratch_capacity(ctx);
    if (scratch_capacity != guard->scratch_capacity) {
        return metal_fail(error,
                          error_size,
                          "%s grew Metal scratch capacity from %llu to %llu bytes",
                          label != NULL ? label : "Metal hot path",
                          (unsigned long long)guard->scratch_capacity,
                          (unsigned long long)scratch_capacity);
    }
    if (!metal_runtime_arena_guard_end(ctx, &guard->runtime_arena, label, error, error_size)) {
        return 0;
    }
    const NSUInteger pipeline_cache_count = ctx->pipeline_cache != nil ? [ctx->pipeline_cache count] : 0u;
    if (pipeline_cache_count != guard->pipeline_cache_count) {
        return metal_fail(error,
                          error_size,
                          "%s grew Metal pipeline cache from %llu to %llu entries",
                          label != NULL ? label : "Metal hot path",
                          (unsigned long long)guard->pipeline_cache_count,
                          (unsigned long long)pipeline_cache_count);
    }
    return 1;
}

static int metal_mps_framework_available(void);
static id metal_ensure_mps_matmul_kernel(uocr_metal_context *ctx, char *error, size_t error_size);

static int metal_prewarm_integrated_decoder_pipelines(uocr_metal_context *ctx, char *error, size_t error_size) {
    static const char *const pipeline_names[] = {
        "uocr_rmsnorm_f16_to_f16",
        "uocr_dense_f16_to_f32",
        "uocr_no_repeat_collect_banned_i32",
        "uocr_lm_head_argmax_f16",
        "uocr_argmax_pairs_f32",
        "uocr_get_rows_f16_to_f16",
        "uocr_assemble_prompt_text_f16",
        "uocr_assemble_prompt_text_skip_image_f16",
        "uocr_assemble_prompt_with_image_f16",
        "uocr_attention_qkvo_f16_to_f16",
        "uocr_rope_qk_f16_to_f16",
        "uocr_kv_cache_write_f16",
        "uocr_prefill_attention_flash_f16_to_f16",
        "uocr_decode_attention_flash_f16_to_f16",
        "uocr_attention_output_residual_f16_to_f16",
        "uocr_clip_residual_add_f16_to_f16",
        "uocr_dense_swiglu_gate_up_f16",
        "uocr_dense_swiglu_down_f16_to_f16",
        "uocr_moe_router_logits_f16_to_f32",
        "uocr_moe_router_softmax_topk_f32",
        "uocr_moe_prefill_interleaved_gate_up_f16",
        "uocr_moe_prefill_interleaved_down_sum_f16_to_f16",
        "uocr_moe_combine_f16_to_f16",
    };
    @autoreleasepool {
        for (uint32_t i = 0u; i < (uint32_t)(sizeof(pipeline_names) / sizeof(pipeline_names[0])); ++i) {
            if (metal_get_pipeline(ctx, pipeline_names[i], error, error_size) == nil) {
                return 0;
            }
        }
        if (metal_mps_framework_available() && metal_ensure_mps_matmul_kernel(ctx, error, error_size) == nil) {
            return 0;
        }
    }
    return 1;
}

static int metal_prompt_arena_slot_offset(const uocr_metal_context *ctx,
                                          uint32_t slot,
                                          uint32_t n_tokens,
                                          uint64_t *out_offset,
                                          uint64_t *out_bytes);
static int metal_prompt_token_ids_slice(const uocr_metal_context *ctx,
                                        uint32_t slot,
                                        uint32_t n_tokens,
                                        uocr_metal_buffer_slice *out_slice,
                                        uint64_t *out_bytes);
static int metal_context_assemble_prompt_from_model_to_arena_f16(uocr_metal_context *ctx,
                                                                  const int32_t *input_ids,
                                                                  uint32_t n_tokens,
                                                                  uint32_t image_span_start,
                                                                  uint32_t image_span_length,
                                                                  const uint16_t *image_features_f16,
                                                                  id<MTLBuffer> image_features_buffer,
                                                                  NSUInteger image_features_offset,
                                                                  uint32_t slot,
                                                                  char *error,
                                                                  size_t error_size);

static int metal_buffer_range_valid(id<MTLBuffer> buffer, NSUInteger offset, uint64_t bytes) {
    if (buffer == nil || bytes > (uint64_t)NSUIntegerMax) {
        return 0;
    }
    const uint64_t length = (uint64_t)[buffer length];
    const uint64_t offset64 = (uint64_t)offset;
    uint64_t end = 0u;
    return offset64 <= length && checked_add_u64(offset64, bytes, &end) && end <= length;
}

static int metal_slice_valid(uocr_metal_buffer_slice slice, uint64_t bytes) {
    return metal_buffer_range_valid(slice.buffer, slice.offset, bytes);
}

static int metal_slice_is_model_backed(const uocr_metal_context *ctx, uocr_metal_buffer_slice slice, uint64_t bytes) {
    if (ctx == NULL || slice.buffer == nil || bytes == 0u || bytes > (uint64_t)NSUIntegerMax || ctx->model_views == NULL) {
        return 0;
    }
    const uint64_t offset = (uint64_t)slice.offset;
    uint64_t end = 0u;
    if (!checked_add_u64(offset, bytes, &end)) {
        return 0;
    }
    for (uint32_t i = 0u; i < ctx->model_view_count; ++i) {
        if (ctx->model_views[i].buffer == slice.buffer && end <= ctx->model_views[i].length) {
            return 1;
        }
    }
    return 0;
}

static int metal_slice_is_workspace_backed(const uocr_metal_context *ctx, uocr_metal_buffer_slice slice, uint64_t bytes) {
    if (ctx == NULL || slice.buffer == nil || bytes == 0u || bytes > (uint64_t)NSUIntegerMax) {
        return 0;
    }
    const uint64_t offset = (uint64_t)slice.offset;
    uint64_t end = 0u;
    if (!checked_add_u64(offset, bytes, &end)) {
        return 0;
    }
    for (uint32_t i = 0u; i < (uint32_t)UOCR_METAL_SCRATCH_COUNT; ++i) {
        const uocr_metal_scratch_buffer *scratch = &ctx->scratch[i];
        if (scratch->buffer == slice.buffer && end <= scratch->capacity) {
            return 1;
        }
    }
    for (uint32_t i = 0u; i < (uint32_t)UOCR_METAL_ARENA_COUNT; ++i) {
        const uocr_metal_runtime_arena *arena = &ctx->runtime_arenas[i];
        if (arena->buffer == slice.buffer && end <= arena->capacity) {
            return 1;
        }
    }
    return 0;
}

static int metal_host_range_to_slice(id<MTLBuffer> buffer,
                                     NSUInteger buffer_offset,
                                     uint64_t byte_length,
                                     const void *bytes,
                                     uint64_t request_length,
                                     uocr_metal_buffer_slice *out_slice) {
    if (buffer == nil || bytes == NULL || out_slice == NULL || byte_length == 0u || request_length == 0u ||
        request_length > (uint64_t)NSUIntegerMax || !metal_buffer_range_valid(buffer, buffer_offset, byte_length)) {
        return 0;
    }
    const uint8_t *contents = (const uint8_t *)[buffer contents];
    if (contents == NULL) {
        return 0;
    }
    const uintptr_t request_start = (uintptr_t)bytes;
    if (request_start > UINTPTR_MAX - (uintptr_t)request_length) {
        return 0;
    }
    const uintptr_t request_end = request_start + (uintptr_t)request_length;
    const uintptr_t slice_start = (uintptr_t)(const void *)(contents + buffer_offset);
    if (slice_start > UINTPTR_MAX - (uintptr_t)byte_length) {
        return 0;
    }
    const uintptr_t slice_end = slice_start + (uintptr_t)byte_length;
    if (request_start < slice_start || request_end > slice_end) {
        return 0;
    }
    const uintptr_t inner_delta = request_start - slice_start;
    if ((uint64_t)inner_delta > (uint64_t)NSUIntegerMax - (uint64_t)buffer_offset) {
        return 0;
    }
    out_slice->buffer = buffer;
    out_slice->offset = buffer_offset + (NSUInteger)inner_delta;
    return 1;
}

static int metal_vision_scratch_pointer_slice(const uocr_metal_context *ctx,
                                              const void *bytes,
                                              uint64_t byte_length,
                                              uocr_metal_buffer_slice *out_slice) {
    if (out_slice == NULL) {
        return 0;
    }
    out_slice->buffer = nil;
    out_slice->offset = 0u;
    if (ctx == NULL || bytes == NULL || byte_length == 0u || byte_length > (uint64_t)NSUIntegerMax) {
        return 0;
    }
    const uocr_metal_scratch_buffer *vision_scratch = &ctx->scratch[UOCR_METAL_SCRATCH_VISION];
    if (vision_scratch->buffer == nil || vision_scratch->capacity == 0u) {
        return 0;
    }
    if (vision_scratch->cpu_visible) {
        return metal_host_range_to_slice(vision_scratch->buffer, 0u, vision_scratch->capacity, bytes, byte_length, out_slice);
    }

    const uintptr_t token = (uintptr_t)bytes;
    const uintptr_t base = UOCR_METAL_PRIVATE_WORKSPACE_PTR_BASE;
    if (token < base) {
        return 0;
    }
    const uint64_t inner_offset = (uint64_t)(token - base);
    uint64_t end = 0u;
    if (inner_offset > vision_scratch->capacity || !checked_add_u64(inner_offset, byte_length, &end) ||
        end > vision_scratch->capacity || inner_offset > (uint64_t)NSUIntegerMax) {
        return 0;
    }
    out_slice->buffer = vision_scratch->buffer;
    out_slice->offset = (NSUInteger)inner_offset;
    return 1;
}

static int metal_vision_host_pointer_slice(const uocr_metal_context *ctx,
                                           const void *bytes,
                                           uint64_t byte_length,
                                           uocr_metal_buffer_slice *out_slice) {
    if (metal_vision_scratch_pointer_slice(ctx, bytes, byte_length, out_slice)) {
        return 1;
    }
    if (out_slice == NULL || ctx == NULL || !ctx->vision_bindings.valid || bytes == NULL || byte_length == 0u ||
        byte_length > (uint64_t)NSUIntegerMax) {
        return 0;
    }
    for (uint32_t i = 0u; i < ctx->vision_bindings.count; ++i) {
        const uocr_metal_vision_binding *binding = &ctx->vision_bindings.tensors[i];
        if (metal_host_range_to_slice(binding->buffer, binding->offset, binding->payload_size, bytes, byte_length, out_slice)) {
            return 1;
        }
    }
    return 0;
}

static id<MTLBuffer> metal_new_or_retain_vision_buffer_with_bytes(uocr_metal_context *ctx,
                                                                  const void *bytes,
                                                                  NSUInteger length,
                                                                  MTLResourceOptions options,
                                                                  NSUInteger *out_offset) {
    if (out_offset != NULL) {
        *out_offset = 0u;
    }
    uocr_metal_buffer_slice slice;
    if (metal_vision_host_pointer_slice(ctx, bytes, (uint64_t)length, &slice)) {
        [slice.buffer retain];
        if (out_offset != NULL) {
            *out_offset = slice.offset;
        }
        metal_profile_add_event_ms(ctx, "metal.vision_binding_cache.direct_use", 0.0);
        return slice.buffer;
    }
    return metal_new_buffer_with_bytes(ctx, bytes, length, options);
}

static id<MTLBuffer> metal_new_or_retain_vision_output_buffer(uocr_metal_context *ctx,
                                                              void *out,
                                                              NSUInteger length,
                                                              MTLResourceOptions options,
                                                              NSUInteger *out_offset,
                                                              int *out_needs_copy) {
    if (out_offset != NULL) {
        *out_offset = 0u;
    }
    if (out_needs_copy != NULL) {
        *out_needs_copy = 1;
    }
    uocr_metal_buffer_slice slice;
    if (metal_vision_scratch_pointer_slice(ctx, out, (uint64_t)length, &slice)) {
        [slice.buffer retain];
        if (out_offset != NULL) {
            *out_offset = slice.offset;
        }
        if (out_needs_copy != NULL) {
            *out_needs_copy = 0;
        }
        metal_profile_add_event_ms(ctx, "metal.vision_workspace.direct_output", 0.0);
        return slice.buffer;
    }
    return metal_new_buffer_with_length(ctx, length, options);
}

static void metal_zero_buffer_range(id<MTLBuffer> buffer, NSUInteger offset, NSUInteger length) {
    if (buffer == nil || length == 0u) {
        return;
    }
    uint8_t *contents = (uint8_t *)[buffer contents];
    if (contents != NULL) {
        memset(contents + offset, 0, (size_t)length);
    }
}

static void metal_copy_buffer_range_to_host_if_needed(void *out,
                                                      id<MTLBuffer> buffer,
                                                      NSUInteger offset,
                                                      NSUInteger length,
                                                      int needs_copy) {
    if (!needs_copy || out == NULL || buffer == nil || length == 0u) {
        return;
    }
    const uint8_t *contents = (const uint8_t *)[buffer contents];
    if (contents != NULL) {
        memcpy(out, contents + offset, (size_t)length);
    }
}

static int metal_wait_for_command_buffer_profiled(uocr_metal_context *ctx,
                                                  id<MTLCommandBuffer> cb,
                                                  const char *op_name,
                                                  char *error,
                                                  size_t error_size) {
    if (cb == nil) {
        return metal_fail(error, error_size, "failed to create %s command buffer", op_name);
    }
    UOCR_METAL_COMMIT_AND_WAIT_PROFILED(ctx, cb);
    if (cb.status == MTLCommandBufferStatusError) {
        NSString *description = cb.error != nil ? [cb.error localizedDescription] : @"unknown command-buffer error";
        return metal_fail(error, error_size, "%s command failed: %s", op_name, [description UTF8String]);
    }
    return 1;
}

static id<MTLCommandBuffer> metal_new_command_buffer(uocr_metal_context *ctx) {
    if (ctx == NULL || ctx->queue == nil) {
        return nil;
    }
    if (ctx->active_command_buffer != nil) {
        return ctx->active_command_buffer;
    }
#pragma clang diagnostic push
#pragma clang diagnostic ignored "-Wobjc-method-access"
    id<MTLCommandBuffer> cb = [ctx->queue commandBuffer];
#pragma clang diagnostic pop
    if (cb != nil && metal_profile_enabled(ctx)) {
        uocr_profile_add_metal_command_buffer(ctx->profile);
    }
    return cb;
}

static id<MTLComputeCommandEncoder> metal_compute_command_encoder(uocr_metal_context *ctx, id<MTLCommandBuffer> cb) {
#pragma clang diagnostic push
#pragma clang diagnostic ignored "-Wobjc-method-access"
    id<MTLComputeCommandEncoder> enc = [cb computeCommandEncoder];
#pragma clang diagnostic pop
    if (enc != nil && metal_profile_enabled(ctx)) {
        uocr_profile_add_metal_command_encoder(ctx->profile);
    }
    return enc;
}

static id<MTLBlitCommandEncoder> metal_blit_command_encoder(uocr_metal_context *ctx, id<MTLCommandBuffer> cb) {
#pragma clang diagnostic push
#pragma clang diagnostic ignored "-Wobjc-method-access"
    id<MTLBlitCommandEncoder> enc = [cb blitCommandEncoder];
#pragma clang diagnostic pop
    if (enc != nil && metal_profile_enabled(ctx)) {
        uocr_profile_add_metal_command_encoder(ctx->profile);
    }
    return enc;
}

static int metal_command_batch_active(const uocr_metal_context *ctx) {
    return ctx != NULL && ctx->active_command_buffer != nil;
}

static int metal_command_batch_begin(uocr_metal_context *ctx, char *error, size_t error_size) {
    if (ctx == NULL || ctx->queue == nil) {
        return metal_fail(error, error_size, "invalid Metal command batch context");
    }
    if (ctx->active_command_buffer != nil) {
        return 1;
    }
    id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
    if (cb == nil) {
        return metal_fail(error, error_size, "failed to create Metal command batch buffer");
    }
    ctx->active_command_buffer = [cb retain];
    return 1;
}

static void metal_command_batch_abort(uocr_metal_context *ctx) {
    if (ctx == NULL || ctx->active_command_buffer == nil) {
        return;
    }
    [ctx->active_command_buffer release];
    ctx->active_command_buffer = nil;
    if (ctx->transient_retains != nil) {
        @synchronized(ctx->transient_retains) {
            [ctx->transient_retains removeAllObjects];
        }
    }
}

static int metal_command_batch_commit_and_wait(uocr_metal_context *ctx,
                                               const char *op_name,
                                               char *error,
                                               size_t error_size) {
    if (ctx == NULL) {
        return metal_fail(error, error_size, "invalid Metal command batch wait context");
    }
    id<MTLCommandBuffer> cb = ctx->active_command_buffer;
    if (cb == nil) {
        return 1;
    }
    ctx->active_command_buffer = nil;
    const int ok = metal_wait_for_command_buffer_profiled(ctx, cb, op_name, error, error_size);
    [cb release];
    return ok;
}

static id<MTLCommandBuffer> metal_command_buffer_for_op(uocr_metal_context *ctx,
                                                        int *out_owned,
                                                        const char *op_name,
                                                        char *error,
                                                        size_t error_size) {
    if (out_owned != NULL) {
        *out_owned = 0;
    }
    if (ctx == NULL || ctx->queue == nil) {
        (void)metal_fail(error, error_size, "invalid %s command context", op_name);
        return nil;
    }
    if (ctx->active_command_buffer != nil) {
        return ctx->active_command_buffer;
    }
    id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
    if (cb == nil) {
        (void)metal_fail(error, error_size, "failed to create %s command buffer", op_name);
        return nil;
    }
    if (out_owned != NULL) {
        *out_owned = 1;
    }
    return cb;
}

static int metal_finish_command_buffer_for_op(uocr_metal_context *ctx,
                                              id<MTLCommandBuffer> cb,
                                              int owned,
                                              const char *op_name,
                                              char *error,
                                              size_t error_size) {
    if (!owned) {
        return 1;
    }
    return metal_wait_for_command_buffer_profiled(ctx, cb, op_name, error, error_size);
}

typedef struct uocr_metal_mps_class_cache {
    int attempted;
    int available;
    Class descriptor_class;
    Class array_class;
    Class matmul_class;
} uocr_metal_mps_class_cache;

static const uocr_metal_mps_class_cache *metal_mps_classes(void) {
    static uocr_metal_mps_class_cache cache;
    if (cache.attempted) {
        return &cache;
    }
    cache.attempted = 1;
    cache.matmul_class = NSClassFromString(@"MPSNDArrayMatrixMultiplication");
    cache.descriptor_class = NSClassFromString(@"MPSNDArrayDescriptor");
    cache.array_class = NSClassFromString(@"MPSNDArray");
    if (cache.matmul_class == Nil || cache.descriptor_class == Nil || cache.array_class == Nil) {
        NSBundle *bundle = [NSBundle bundleWithPath:@"/System/Library/Frameworks/MetalPerformanceShaders.framework"];
        if (bundle != nil) {
            (void)[bundle load];
        }
        cache.matmul_class = NSClassFromString(@"MPSNDArrayMatrixMultiplication");
        cache.descriptor_class = NSClassFromString(@"MPSNDArrayDescriptor");
        cache.array_class = NSClassFromString(@"MPSNDArray");
    }
    cache.available = cache.matmul_class != Nil && cache.descriptor_class != Nil && cache.array_class != Nil;
    return &cache;
}

static int metal_mps_framework_available(void) {
    return metal_mps_classes()->available;
}

static int metal_mps_matmul_nt_f16_flops(uint32_t rows,
                                         uint32_t in_features,
                                         uint32_t out_features,
                                         uint64_t *out_flops) {
    uint64_t tmp = 0u;
    uint64_t flops = 0u;
    if (out_flops == NULL || rows == 0u || in_features == 0u || out_features == 0u ||
        !checked_mul_u64((uint64_t)rows, (uint64_t)in_features, &tmp) ||
        !checked_mul_u64(tmp, (uint64_t)out_features, &flops) ||
        !checked_mul_u64(flops, 2u, &flops)) {
        return 0;
    }
    *out_flops = flops;
    return 1;
}

static int metal_mps_matmul_nt_f16_is_large(uint32_t rows, uint32_t in_features, uint32_t out_features) {
    uint64_t flops = 0u;
    return metal_mps_matmul_nt_f16_flops(rows, in_features, out_features, &flops) &&
           flops >= UOCR_METAL_MPS_MATMUL_MIN_FLOPS;
}

static int metal_mps_matmul_nt_f16_should_use(uint32_t rows, uint32_t in_features, uint32_t out_features) {
    return metal_mps_framework_available() && metal_mps_matmul_nt_f16_is_large(rows, in_features, out_features);
}

static void metal_public_mps_large_gemm_require_begin(uocr_metal_context *ctx) {
    if (ctx != NULL && ctx->public_mps_large_gemm_required_depth != UINT32_MAX) {
        ++ctx->public_mps_large_gemm_required_depth;
    }
}

static void metal_public_mps_large_gemm_require_end(uocr_metal_context *ctx) {
    if (ctx != NULL && ctx->public_mps_large_gemm_required_depth != 0u) {
        --ctx->public_mps_large_gemm_required_depth;
    }
}

static int metal_public_mps_matmul_fallback_allowed(uocr_metal_context *ctx,
                                                    uint32_t rows,
                                                    uint32_t in_features,
                                                    uint32_t out_features,
                                                    const char *op_name,
                                                    char *error,
                                                    size_t error_size) {
    if (ctx == NULL || ctx->public_mps_large_gemm_required_depth == 0u ||
        !metal_mps_matmul_nt_f16_is_large(rows, in_features, out_features)) {
        return 1;
    }
    uint64_t flops = 0u;
    (void)metal_mps_matmul_nt_f16_flops(rows, in_features, out_features, &flops);
    if (!metal_mps_framework_available()) {
        return metal_fail(error,
                          error_size,
                          "public Metal OCR requires MPSNDArray matmul for large %s (%ux%u x %u, %llu FLOPs), but MPS is unavailable",
                          op_name != NULL ? op_name : "GEMM",
                          rows,
                          in_features,
                          out_features,
                          (unsigned long long)flops);
    }
    return 1;
}

static id metal_mps_descriptor_for_shape(uocr_metal_context *ctx,
                                         uint32_t rows,
                                         uint32_t cols,
                                         int transpose,
                                         uint32_t data_type) {
    const uocr_metal_mps_class_cache *classes = metal_mps_classes();
    if (!classes->available || rows == 0u || cols == 0u) {
        return nil;
    }
    NSString *key = [NSString stringWithFormat:@"%u:%u:%u:%u", rows, cols, transpose ? 1u : 0u, data_type];
    id cached = (ctx != NULL && ctx->mps_descriptor_cache != nil && key != nil) ? [ctx->mps_descriptor_cache objectForKey:key] : nil;
    if (cached != nil) {
        metal_profile_add_event_ms(ctx, "metal.mps.descriptor_cache.hit", 0.0);
        return cached;
    }
    const uint64_t descriptor_start_ns = uocr_profile_now_ns();
    id desc = [classes->descriptor_class descriptorWithDataType:data_type
                                                          shape:@[ @((NSUInteger)rows), @((NSUInteger)cols) ]];
    metal_profile_add_event_now(ctx, "metal.mps.ndarray_descriptor", descriptor_start_ns);
    if (desc == nil) {
        return nil;
    }
    if (metal_profile_enabled(ctx)) {
        uocr_profile_add_metal_mps_descriptor(ctx->profile);
        uocr_profile_add_metal_nsarray(ctx->profile); /* descriptor shape literal */
    }
    [desc setPreferPackedRows:YES];
    if (transpose) {
        [desc transposeDimension:0u withDimension:1u];
    }
    if (ctx != NULL && ctx->mps_descriptor_cache != nil && key != nil) {
        [ctx->mps_descriptor_cache setObject:desc forKey:key];
        metal_profile_add_event_ms(ctx, "metal.mps.descriptor_cache.create", 0.0);
    }
    return desc;
}

static NSString *metal_mps_ndarray_cache_key(uocr_metal_buffer_slice slice,
                                             uint32_t rows,
                                             uint32_t cols,
                                             int transpose,
                                             uint32_t data_type) {
    return [NSString stringWithFormat:@"%p:%llu:%u:%u:%u:%u",
                                      (void *)slice.buffer,
                                      (unsigned long long)slice.offset,
                                      rows,
                                      cols,
                                      transpose ? 1u : 0u,
                                      data_type];
}

static id metal_mps_matrix_array_from_slice(uocr_metal_context *ctx,
                                            uocr_metal_buffer_slice slice,
                                            uint32_t rows,
                                            uint32_t cols,
                                            int transpose,
                                            uint32_t data_type,
                                            int cache_if_model_backed,
                                            int cache_if_workspace_backed,
                                            uint64_t byte_length) {
    const uocr_metal_mps_class_cache *classes = metal_mps_classes();
    if (!classes->available || slice.buffer == nil || rows == 0u || cols == 0u) {
        return nil;
    }
    NSString *array_key = nil;
    NSMutableDictionary<NSString *, id> *array_cache = nil;
    const char *cache_hit_event = NULL;
    const char *cache_create_event = NULL;
    if (cache_if_model_backed && ctx != NULL && ctx->mps_weight_ndarray_cache != nil &&
        metal_slice_is_model_backed(ctx, slice, byte_length)) {
        array_cache = ctx->mps_weight_ndarray_cache;
        cache_hit_event = "metal.mps.weight_ndarray_cache.hit";
        cache_create_event = "metal.mps.weight_ndarray_cache.create";
    } else if (cache_if_workspace_backed && ctx != NULL && ctx->mps_workspace_ndarray_cache != nil &&
               metal_slice_is_workspace_backed(ctx, slice, byte_length)) {
        array_cache = ctx->mps_workspace_ndarray_cache;
        cache_hit_event = "metal.mps.workspace_ndarray_cache.hit";
        cache_create_event = "metal.mps.workspace_ndarray_cache.create";
    }
    if (array_cache != nil) {
        array_key = metal_mps_ndarray_cache_key(slice, rows, cols, transpose, data_type);
        id cached = array_key != nil ? [array_cache objectForKey:array_key] : nil;
        if (cached != nil) {
            [cached retain];
            metal_profile_add_event_ms(ctx, cache_hit_event, 0.0);
            return cached;
        }
    }
    id desc = metal_mps_descriptor_for_shape(ctx, rows, cols, transpose, data_type);
    if (desc == nil) {
        return nil;
    }
    const uint64_t ndarray_start_ns = uocr_profile_now_ns();
    id array = [[classes->array_class alloc] initWithBuffer:slice.buffer offset:slice.offset descriptor:desc];
    metal_profile_add_event_now(ctx, "metal.mps.ndarray_create", ndarray_start_ns);
    if (array != nil && metal_profile_enabled(ctx)) {
        uocr_profile_add_metal_mps_ndarray(ctx->profile);
    }
    if (array != nil && array_cache != nil && array_key != nil) {
        [array_cache setObject:array forKey:array_key];
        metal_profile_add_event_ms(ctx, cache_create_event, 0.0);
    }
    return array;
}

static int metal_matrix_subslice(uocr_metal_buffer_slice base,
                                  uint64_t base_bytes,
                                  uint32_t row_offset,
                                  uint32_t rows,
                                  uint32_t cols,
                                  uint64_t element_bytes,
                                  uocr_metal_buffer_slice *out_slice,
                                  uint64_t *out_bytes) {
    if (out_slice == NULL || out_bytes == NULL || base.buffer == nil || rows == 0u || cols == 0u ||
        element_bytes == 0u) {
        return 0;
    }
    uint64_t row_bytes = 0u;
    uint64_t relative_offset = 0u;
    uint64_t bytes = 0u;
    uint64_t end = 0u;
    uint64_t absolute_offset = 0u;
    if (!checked_mul_u64((uint64_t)cols, element_bytes, &row_bytes) ||
        !checked_mul_u64((uint64_t)row_offset, row_bytes, &relative_offset) ||
        !checked_mul_u64((uint64_t)rows, row_bytes, &bytes) ||
        !checked_add_u64(relative_offset, bytes, &end) || end > base_bytes ||
        !checked_add_u64((uint64_t)base.offset, relative_offset, &absolute_offset) ||
        absolute_offset > (uint64_t)NSUIntegerMax) {
        return 0;
    }
    out_slice->buffer = base.buffer;
    out_slice->offset = (NSUInteger)absolute_offset;
    *out_bytes = bytes;
    return metal_slice_valid(*out_slice, bytes);
}

static int metal_prebuild_mps_workspace_matrix_ndarray(uocr_metal_context *ctx,
                                                       uocr_metal_buffer_slice slice,
                                                       uint64_t slice_bytes,
                                                       uint32_t rows,
                                                       uint32_t cols,
                                                       uint32_t data_type,
                                                       const char *label,
                                                       char *error,
                                                       size_t error_size) {
    if (ctx == NULL || rows == 0u || cols == 0u ||
        (data_type != UOCR_METAL_MPS_DATA_TYPE_FLOAT16 && data_type != UOCR_METAL_MPS_DATA_TYPE_FLOAT32) ||
        !metal_slice_valid(slice, slice_bytes)) {
        return metal_fail(error, error_size, "invalid Metal MPS workspace NDArray prebuild request for %s", label != NULL ? label : "workspace");
    }
    id array = metal_mps_matrix_array_from_slice(ctx,
                                                  slice,
                                                  rows,
                                                  cols,
                                                  0,
                                                  data_type,
                                                  0,
                                                  1,
                                                  slice_bytes);
    if (array == nil) {
        return metal_fail(error,
                          error_size,
                          "failed to prebuild Metal MPS workspace NDArray for %s",
                          label != NULL ? label : "workspace");
    }
    [array release];
    return 1;
}

static int metal_prebuild_mps_workspace_matmul_io(uocr_metal_context *ctx,
                                                  uocr_metal_buffer_slice input_base,
                                                  uint64_t input_base_bytes,
                                                  uint32_t input_row_offset,
                                                  uocr_metal_buffer_slice dst_base,
                                                  uint64_t dst_base_bytes,
                                                  uint32_t dst_row_offset,
                                                  uint32_t rows,
                                                  uint32_t in_features,
                                                  uint32_t out_features,
                                                  uint32_t dst_data_type,
                                                  const char *label,
                                                  char *error,
                                                  size_t error_size) {
    if (!metal_mps_matmul_nt_f16_should_use(rows, in_features, out_features)) {
        return 1;
    }
    const uint64_t dst_element_bytes = dst_data_type == UOCR_METAL_MPS_DATA_TYPE_FLOAT32 ? (uint64_t)sizeof(float) : 2u;
    uocr_metal_buffer_slice input_slice;
    uocr_metal_buffer_slice dst_slice;
    uint64_t input_bytes = 0u;
    uint64_t dst_bytes = 0u;
    if (!metal_matrix_subslice(input_base,
                               input_base_bytes,
                               input_row_offset,
                               rows,
                               in_features,
                               2u,
                               &input_slice,
                               &input_bytes) ||
        !metal_matrix_subslice(dst_base,
                               dst_base_bytes,
                               dst_row_offset,
                               rows,
                               out_features,
                               dst_element_bytes,
                               &dst_slice,
                               &dst_bytes)) {
        return metal_fail(error,
                          error_size,
                          "invalid Metal MPS workspace matmul slice prebuild for %s",
                          label != NULL ? label : "workspace");
    }
    if (!metal_prebuild_mps_workspace_matrix_ndarray(ctx,
                                                     input_slice,
                                                     input_bytes,
                                                     rows,
                                                     in_features,
                                                     UOCR_METAL_MPS_DATA_TYPE_FLOAT16,
                                                     label,
                                                     error,
                                                     error_size)) {
        return 0;
    }
    return metal_prebuild_mps_workspace_matrix_ndarray(ctx,
                                                       dst_slice,
                                                       dst_bytes,
                                                       rows,
                                                       out_features,
                                                       dst_data_type,
                                                       label,
                                                       error,
                                                       error_size);
}

static int metal_prebuild_mps_vision_matmul_io(uocr_metal_context *ctx,
                                               uocr_metal_vision_workspace_slice input,
                                               uint32_t input_row_offset,
                                               uocr_metal_vision_workspace_slice dst,
                                               uint32_t dst_row_offset,
                                               uint32_t rows,
                                               uint32_t in_features,
                                               uint32_t out_features,
                                               const char *label,
                                               char *error,
                                               size_t error_size) {
    uocr_metal_buffer_slice input_base = { input.buffer, input.offset };
    uocr_metal_buffer_slice dst_base = { dst.buffer, dst.offset };
    return metal_prebuild_mps_workspace_matmul_io(ctx,
                                                  input_base,
                                                  input.bytes,
                                                  input_row_offset,
                                                  dst_base,
                                                  dst.bytes,
                                                  dst_row_offset,
                                                  rows,
                                                  in_features,
                                                  out_features,
                                                  UOCR_METAL_MPS_DATA_TYPE_FLOAT16,
                                                  label,
                                                  error,
                                                  error_size);
}

static int metal_prebuild_mps_vision_shape_ndarrays(uocr_metal_context *ctx,
                                                    const uocr_metal_vision_workspace *workspace,
                                                    uint32_t patch_grid,
                                                    uint32_t projected_grid,
                                                    uint32_t view_count,
                                                    char *error,
                                                    size_t error_size) {
    if (ctx == NULL || workspace == NULL || patch_grid == 0u || projected_grid == 0u || view_count == 0u) {
        return metal_fail(error, error_size, "invalid Metal MPS vision workspace shape prebuild request");
    }
    const uint32_t patch_tokens = patch_grid * patch_grid;
    const uint32_t projected_tokens = projected_grid * projected_grid;
    const uint32_t clip_tokens = projected_tokens + UOCR_CLIP_CLASS_TOKENS;
    const uint32_t windows_per_side = (patch_grid + UOCR_SAM_WINDOW_SIZE - 1u) / UOCR_SAM_WINDOW_SIZE;
    const uint32_t window_rows = windows_per_side * windows_per_side * UOCR_SAM_WINDOW_TOKENS;

#define PREBUILD_VISION_IO(input_slice, dst_slice, rows_, in_features_, out_features_, label_) \
    do {                                                                                       \
        if (!metal_prebuild_mps_vision_matmul_io(ctx,                                             \
                                                 (input_slice),                                  \
                                                 0u,                                             \
                                                 (dst_slice),                                    \
                                                 0u,                                             \
                                                 (rows_),                                        \
                                                 (in_features_),                                 \
                                                 (out_features_),                                \
                                                 (label_),                                       \
                                                 error,                                          \
                                                 error_size)) {                                  \
            return 0;                                                                           \
        }                                                                                       \
    } while (0)

    PREBUILD_VISION_IO(workspace->sam_block_norm1_bhwc, workspace->sam_block_q, patch_tokens, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM global Q workspace");
    PREBUILD_VISION_IO(workspace->sam_block_norm1_bhwc, workspace->sam_block_k, patch_tokens, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM global K workspace");
    PREBUILD_VISION_IO(workspace->sam_block_norm1_bhwc, workspace->sam_block_v, patch_tokens, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM global V workspace");
    PREBUILD_VISION_IO(workspace->sam_block_window_tokens, workspace->sam_block_q, window_rows, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM window Q workspace");
    PREBUILD_VISION_IO(workspace->sam_block_window_tokens, workspace->sam_block_k, window_rows, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM window K workspace");
    PREBUILD_VISION_IO(workspace->sam_block_window_tokens, workspace->sam_block_v, window_rows, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM window V workspace");
    PREBUILD_VISION_IO(workspace->sam_block_attention, workspace->sam_block_residual1_bhwc, patch_tokens, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM global projection workspace");
    PREBUILD_VISION_IO(workspace->sam_block_attention, workspace->sam_block_projected_windows, window_rows, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM window projection workspace");
    PREBUILD_VISION_IO(workspace->sam_block_norm2_bhwc, workspace->sam_block_mlp_intermediate, patch_tokens, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_MLP_INTERMEDIATE, "SAM MLP lin1 workspace");
    PREBUILD_VISION_IO(workspace->sam_block_mlp_intermediate, workspace->sam_block_mlp_bhwc, patch_tokens, UOCR_SAM_MLP_INTERMEDIATE, UOCR_SAM_HIDDEN_SIZE, "SAM MLP lin2 workspace");
    if (view_count > 1u && workspace->projected_row_capacity >= projected_tokens) {
        uint32_t sam_view_capacity = workspace->projected_row_capacity / projected_tokens;
        if (sam_view_capacity > view_count) {
            sam_view_capacity = view_count;
        }
        if (sam_view_capacity > 1u) {
            const uint32_t batch_patch_rows = sam_view_capacity * patch_tokens;
            const uint32_t batch_window_rows = sam_view_capacity * window_rows;
            PREBUILD_VISION_IO(workspace->sam_block_norm1_bhwc, workspace->sam_block_q, batch_patch_rows, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM global Q batch workspace");
            PREBUILD_VISION_IO(workspace->sam_block_norm1_bhwc, workspace->sam_block_k, batch_patch_rows, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM global K batch workspace");
            PREBUILD_VISION_IO(workspace->sam_block_norm1_bhwc, workspace->sam_block_v, batch_patch_rows, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM global V batch workspace");
            PREBUILD_VISION_IO(workspace->sam_block_window_tokens, workspace->sam_block_q, batch_window_rows, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM window Q batch workspace");
            PREBUILD_VISION_IO(workspace->sam_block_window_tokens, workspace->sam_block_k, batch_window_rows, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM window K batch workspace");
            PREBUILD_VISION_IO(workspace->sam_block_window_tokens, workspace->sam_block_v, batch_window_rows, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM window V batch workspace");
            PREBUILD_VISION_IO(workspace->sam_block_attention, workspace->sam_block_attention_bhwc, batch_patch_rows, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM global projection batch workspace");
            PREBUILD_VISION_IO(workspace->sam_block_attention, workspace->sam_block_projected_windows, batch_window_rows, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE, "SAM window projection batch workspace");
            PREBUILD_VISION_IO(workspace->sam_block_norm2_bhwc, workspace->sam_block_mlp_intermediate, batch_patch_rows, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_MLP_INTERMEDIATE, "SAM MLP lin1 batch workspace");
            PREBUILD_VISION_IO(workspace->sam_block_mlp_intermediate, workspace->sam_block_mlp_bhwc, batch_patch_rows, UOCR_SAM_MLP_INTERMEDIATE, UOCR_SAM_HIDDEN_SIZE, "SAM MLP lin2 batch workspace");
        }
    }
    PREBUILD_VISION_IO(workspace->clip_block_norm1, workspace->clip_block_q, clip_tokens, UOCR_CLIP_HIDDEN_SIZE, UOCR_CLIP_HIDDEN_SIZE, "CLIP Q workspace");
    PREBUILD_VISION_IO(workspace->clip_block_norm1, workspace->clip_block_k, clip_tokens, UOCR_CLIP_HIDDEN_SIZE, UOCR_CLIP_HIDDEN_SIZE, "CLIP K workspace");
    PREBUILD_VISION_IO(workspace->clip_block_norm1, workspace->clip_block_v, clip_tokens, UOCR_CLIP_HIDDEN_SIZE, UOCR_CLIP_HIDDEN_SIZE, "CLIP V workspace");
    PREBUILD_VISION_IO(workspace->clip_block_attention, workspace->clip_block_projected, clip_tokens, UOCR_CLIP_HIDDEN_SIZE, UOCR_CLIP_HIDDEN_SIZE, "CLIP output projection workspace");
    PREBUILD_VISION_IO(workspace->clip_block_norm2, workspace->clip_mlp_activated, clip_tokens, UOCR_CLIP_HIDDEN_SIZE, UOCR_CLIP_MLP_INTERMEDIATE, "CLIP fused MLP fc1 workspace");
    PREBUILD_VISION_IO(workspace->clip_mlp_activated, workspace->clip_block_mlp, clip_tokens, UOCR_CLIP_MLP_INTERMEDIATE, UOCR_CLIP_HIDDEN_SIZE, "CLIP MLP fc2 workspace");
    if (view_count > 1u && workspace->projected_row_capacity >= projected_tokens) {
        uint32_t clip_view_capacity = workspace->projected_row_capacity / projected_tokens;
        if (clip_view_capacity > view_count) {
            clip_view_capacity = view_count;
        }
        if (clip_view_capacity > 1u) {
            const uint32_t batch_clip_rows = clip_view_capacity * clip_tokens;
            PREBUILD_VISION_IO(workspace->clip_block_norm1, workspace->clip_block_q, batch_clip_rows, UOCR_CLIP_HIDDEN_SIZE, UOCR_CLIP_HIDDEN_SIZE, "CLIP Q batch workspace");
            PREBUILD_VISION_IO(workspace->clip_block_norm1, workspace->clip_block_k, batch_clip_rows, UOCR_CLIP_HIDDEN_SIZE, UOCR_CLIP_HIDDEN_SIZE, "CLIP K batch workspace");
            PREBUILD_VISION_IO(workspace->clip_block_norm1, workspace->clip_block_v, batch_clip_rows, UOCR_CLIP_HIDDEN_SIZE, UOCR_CLIP_HIDDEN_SIZE, "CLIP V batch workspace");
            PREBUILD_VISION_IO(workspace->clip_block_attention, workspace->clip_block_projected, batch_clip_rows, UOCR_CLIP_HIDDEN_SIZE, UOCR_CLIP_HIDDEN_SIZE, "CLIP output projection batch workspace");
            PREBUILD_VISION_IO(workspace->clip_block_norm2, workspace->clip_mlp_activated, batch_clip_rows, UOCR_CLIP_HIDDEN_SIZE, UOCR_CLIP_MLP_INTERMEDIATE, "CLIP fused MLP fc1 batch workspace");
            PREBUILD_VISION_IO(workspace->clip_mlp_activated, workspace->clip_block_mlp, batch_clip_rows, UOCR_CLIP_MLP_INTERMEDIATE, UOCR_CLIP_HIDDEN_SIZE, "CLIP MLP fc2 batch workspace");
        }
    }
    if (workspace->projected_row_capacity >= projected_tokens && workspace->projected_rows.buffer != nil) {
        PREBUILD_VISION_IO(workspace->concat, workspace->projected_rows, projected_tokens, UOCR_PROJECTOR_IN_SIZE, UOCR_HIDDEN_SIZE, "visual projector workspace");
    }

#undef PREBUILD_VISION_IO

    if (workspace->projected_row_capacity >= projected_tokens && workspace->projected_rows.buffer != nil) {
        uint32_t view_capacity = workspace->projected_row_capacity / projected_tokens;
        if (view_capacity > view_count) {
            view_capacity = view_count;
        }
        if (view_capacity > 1u) {
            if (!metal_prebuild_mps_vision_matmul_io(ctx,
                                                     workspace->concat,
                                                     0u,
                                                     workspace->projected_rows,
                                                     0u,
                                                     view_capacity * projected_tokens,
                                                     UOCR_PROJECTOR_IN_SIZE,
                                                     UOCR_HIDDEN_SIZE,
                                                     "visual projector batch workspace",
                                                     error,
                                                     error_size)) {
                return 0;
            }
        }
        for (uint32_t view = 1u; view < view_capacity; ++view) {
            uocr_metal_buffer_slice input_base = { workspace->concat.buffer, workspace->concat.offset };
            uocr_metal_buffer_slice dst_base = { workspace->projected_rows.buffer, workspace->projected_rows.offset };
            if (!metal_prebuild_mps_workspace_matmul_io(ctx,
                                                        input_base,
                                                        workspace->concat.bytes,
                                                        0u,
                                                        dst_base,
                                                        workspace->projected_rows.bytes,
                                                        view * projected_tokens,
                                                        projected_tokens,
                                                        UOCR_PROJECTOR_IN_SIZE,
                                                        UOCR_HIDDEN_SIZE,
                                                        UOCR_METAL_MPS_DATA_TYPE_FLOAT16,
                                                        "visual projector workspace view",
                                                        error,
                                                        error_size)) {
                return 0;
            }
        }
    }
    return 1;
}

enum {
    UOCR_METAL_MPS_VISION_PREBUILD_LOCAL = 1u,
    UOCR_METAL_MPS_VISION_PREBUILD_GLOBAL = 2u
};

static int metal_prebuild_mps_vision_workspace_ndarrays(uocr_metal_context *ctx,
                                                        const uocr_metal_vision_workspace *workspace,
                                                        uint32_t local_view_count,
                                                        uint32_t global_view_count,
                                                        char *error,
                                                        size_t error_size) {
    if (ctx == NULL || workspace == NULL) {
        return metal_fail(error, error_size, "invalid Metal MPS vision workspace prebuild request");
    }
    if (!metal_mps_framework_available()) {
        return 1;
    }
    uint32_t shape_mask = 0u;
    if (local_view_count != 0u) {
        shape_mask |= UOCR_METAL_MPS_VISION_PREBUILD_LOCAL;
    }
    if (global_view_count != 0u) {
        shape_mask |= UOCR_METAL_MPS_VISION_PREBUILD_GLOBAL;
    }
    if (shape_mask == 0u) {
        return 1;
    }
    if (ctx->mps_vision_workspace_prebuild_generation == ctx->mps_workspace_cache_generation &&
        (ctx->mps_vision_workspace_prebuild_shape_mask & shape_mask) == shape_mask &&
        ctx->mps_vision_workspace_prebuild_projected_row_capacity >= workspace->projected_row_capacity &&
        ctx->mps_vision_workspace_prebuild_local_view_count >= local_view_count &&
        ctx->mps_vision_workspace_prebuild_global_view_count >= global_view_count) {
        metal_profile_add_event_ms(ctx, "metal.mps.workspace_prebuild.vision.cached", 0.0);
        return 1;
    }

    const uint64_t start_ns = uocr_profile_now_ns();
    if (local_view_count != 0u &&
        !metal_prebuild_mps_vision_shape_ndarrays(ctx,
                                                  workspace,
                                                  UOCR_LOCAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE,
                                                  UOCR_LOCAL_GRID_QUERIES,
                                                  local_view_count,
                                                  error,
                                                  error_size)) {
        return 0;
    }
    if (global_view_count != 0u &&
        !metal_prebuild_mps_vision_shape_ndarrays(ctx,
                                                  workspace,
                                                  UOCR_GLOBAL_VIEW_SIZE / UOCR_VISION_PATCH_SIZE,
                                                  UOCR_GLOBAL_GRID_QUERIES,
                                                  global_view_count,
                                                  error,
                                                  error_size)) {
        return 0;
    }
    ctx->mps_vision_workspace_prebuild_generation = ctx->mps_workspace_cache_generation;
    ctx->mps_vision_workspace_prebuild_shape_mask |= shape_mask;
    if (ctx->mps_vision_workspace_prebuild_projected_row_capacity < workspace->projected_row_capacity) {
        ctx->mps_vision_workspace_prebuild_projected_row_capacity = workspace->projected_row_capacity;
    }
    if (ctx->mps_vision_workspace_prebuild_local_view_count < local_view_count) {
        ctx->mps_vision_workspace_prebuild_local_view_count = local_view_count;
    }
    if (ctx->mps_vision_workspace_prebuild_global_view_count < global_view_count) {
        ctx->mps_vision_workspace_prebuild_global_view_count = global_view_count;
    }
    metal_profile_add_event_now(ctx, "metal.mps.workspace_prebuild.vision", start_ns);
    return 1;
}

static int metal_tensor_shape2_is(const uocr_tensor_entry *tensor, uint32_t rows, uint32_t cols) {
    return tensor != NULL && tensor->rank == 2u && tensor->logical_shape[0] == rows &&
           tensor->logical_shape[1] == cols && tensor->physical_shape[0] == rows &&
           tensor->physical_shape[1] == cols;
}

static int metal_tensor_is_mps_gemm_weight(const uocr_tensor_entry *tensor) {
    if (tensor == NULL || tensor->usage != UOCR_TENSOR_USAGE_RUNTIME || tensor->qtype != UOCR_TENSOR_F16 ||
        tensor->rank != 2u || tensor->logical_shape[0] == 0u || tensor->logical_shape[1] == 0u ||
        tensor->physical_shape[0] != tensor->logical_shape[0] || tensor->physical_shape[1] != tensor->logical_shape[1]) {
        return 0;
    }
    switch (tensor->family) {
        case UOCR_TENSOR_FAMILY_LM_HEAD:
        case UOCR_TENSOR_FAMILY_LAYER_ATTN:
        case UOCR_TENSOR_FAMILY_LAYER_DENSE_MLP:
        case UOCR_TENSOR_FAMILY_MOE_ROUTER:
        case UOCR_TENSOR_FAMILY_MOE_EXPERT:
        case UOCR_TENSOR_FAMILY_MOE_SHARED:
        case UOCR_TENSOR_FAMILY_PROJECTOR:
            return 1;
        case UOCR_TENSOR_FAMILY_VISION_SAM:
            return metal_tensor_shape2_is(tensor, UOCR_SAM_QKV_SIZE, UOCR_SAM_HIDDEN_SIZE) ||
                   metal_tensor_shape2_is(tensor, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_HIDDEN_SIZE) ||
                   metal_tensor_shape2_is(tensor, UOCR_SAM_MLP_INTERMEDIATE, UOCR_SAM_HIDDEN_SIZE) ||
                   metal_tensor_shape2_is(tensor, UOCR_SAM_HIDDEN_SIZE, UOCR_SAM_MLP_INTERMEDIATE);
        case UOCR_TENSOR_FAMILY_VISION_CLIP:
            return metal_tensor_shape2_is(tensor, UOCR_CLIP_QKV_SIZE, UOCR_CLIP_HIDDEN_SIZE) ||
                   metal_tensor_shape2_is(tensor, UOCR_CLIP_HIDDEN_SIZE, UOCR_CLIP_HIDDEN_SIZE) ||
                   metal_tensor_shape2_is(tensor, UOCR_CLIP_MLP_INTERMEDIATE, UOCR_CLIP_HIDDEN_SIZE) ||
                   metal_tensor_shape2_is(tensor, UOCR_CLIP_HIDDEN_SIZE, UOCR_CLIP_MLP_INTERMEDIATE);
        default:
            return 0;
    }
}

static int metal_prebuild_mps_weight_ndarray(uocr_metal_context *ctx,
                                             const uocr_tensor_entry *tensor,
                                             char *error,
                                             size_t error_size) {
    if (ctx == NULL || tensor == NULL) {
        return metal_fail(error, error_size, "invalid Metal MPS weight prebuild request");
    }
    if (tensor->payload_size == 0u || tensor->payload_size > (uint64_t)NSUIntegerMax) {
        return metal_fail(error, error_size, "Metal MPS weight tensor %u has invalid payload size", tensor->id);
    }
    id<MTLBuffer> buffer = nil;
    NSUInteger offset = 0u;
    if (!metal_get_mapped_tensor_buffer(ctx, tensor->id, tensor->payload_size, &buffer, &offset, error, error_size)) {
        return 0;
    }
    uocr_metal_buffer_slice slice = { buffer, offset };
    id array = metal_mps_matrix_array_from_slice(ctx,
                                                  slice,
                                                  tensor->logical_shape[0],
                                                  tensor->logical_shape[1],
                                                  1,
                                                  UOCR_METAL_MPS_DATA_TYPE_FLOAT16,
                                                  1,
                                                  0,
                                                  tensor->payload_size);
    if (array == nil) {
        return metal_fail(error, error_size, "failed to prebuild Metal MPS weight NDArray for tensor %u", tensor->id);
    }
    [array release];
    return 1;
}

static int metal_prebuild_mps_model_objects(uocr_metal_context *ctx,
                                            const uocr_model_file *model,
                                            char *error,
                                            size_t error_size) {
    if (ctx == NULL || model == NULL || model->tensors == NULL) {
        return metal_fail(error, error_size, "invalid Metal MPS model prebuild request");
    }
    if (!metal_mps_framework_available()) {
        metal_profile_add_event_ms(ctx, "metal.mps.prebuild_model_objects.skipped", 0.0);
        return 1;
    }
    if (!uocr_metal_context_decoder_bindings_ready(ctx) && !uocr_metal_context_vision_bindings_ready(ctx)) {
        metal_profile_add_event_ms(ctx, "metal.mps.prebuild_model_objects.no_valid_bindings", 0.0);
        return 1;
    }

    const uint64_t prebuild_start_ns = uocr_profile_now_ns();
    @autoreleasepool {
        for (uint32_t i = 0u; i < model->tensor_count; ++i) {
            const uocr_tensor_entry *tensor = &model->tensors[i];
            if (!metal_tensor_is_mps_gemm_weight(tensor)) {
                continue;
            }
            if (!metal_prebuild_mps_weight_ndarray(ctx, tensor, error, error_size)) {
                return 0;
            }
        }
    }
    metal_profile_add_event_now(ctx, "metal.mps.prebuild_model_objects", prebuild_start_ns);
    metal_clear_error(error, error_size);
    return 1;
}

static id metal_ensure_mps_matmul_kernel(uocr_metal_context *ctx, char *error, size_t error_size) {
    if (ctx == NULL || ctx->device == nil) {
        (void)metal_fail(error, error_size, "invalid MPS matmul context");
        return nil;
    }
    if (!metal_mps_framework_available()) {
        (void)metal_fail(error, error_size, "MetalPerformanceShaders NDArray matmul is unavailable");
        return nil;
    }
    if (ctx->mps_matmul_kernel != nil) {
        return ctx->mps_matmul_kernel;
    }
    Class kernel_class = metal_mps_classes()->matmul_class;
    if (kernel_class == Nil) {
        (void)metal_fail(error, error_size, "MPSNDArrayMatrixMultiplication class is unavailable");
        return nil;
    }
    id kernel = [[kernel_class alloc] initWithDevice:ctx->device sourceCount:2u];
    if (kernel == nil) {
        (void)metal_fail(error, error_size, "failed to create MPS NDArray matmul kernel");
        return nil;
    }
    ctx->mps_matmul_kernel = kernel;
    return kernel;
}

static int metal_run_mps_matmul_nt_f16_to_type(uocr_metal_context *ctx,
                                               uocr_metal_buffer_slice input,
                                               uocr_metal_buffer_slice weight_nk,
                                               uocr_metal_buffer_slice dst,
                                               uint32_t rows,
                                               uint32_t in_features,
                                               uint32_t out_features,
                                               uint32_t dst_data_type,
                                               uint64_t dst_element_bytes,
                                               const char *op_name,
                                               char *error,
                                               size_t error_size) {
    const uint64_t input_bytes = (uint64_t)rows * (uint64_t)in_features * 2u;
    const uint64_t weight_bytes = (uint64_t)out_features * (uint64_t)in_features * 2u;
    uint64_t dst_values = 0u;
    uint64_t dst_bytes = 0u;
    if (!checked_mul_u64((uint64_t)rows, (uint64_t)out_features, &dst_values) ||
        !checked_mul_u64(dst_values, dst_element_bytes, &dst_bytes)) {
        return metal_fail(error, error_size, "%s MPS matmul output byte-size overflow", op_name != NULL ? op_name : "Metal");
    }
    if (ctx == NULL || rows == 0u || in_features == 0u || out_features == 0u || dst_element_bytes == 0u ||
        (dst_data_type != UOCR_METAL_MPS_DATA_TYPE_FLOAT16 && dst_data_type != UOCR_METAL_MPS_DATA_TYPE_FLOAT32) ||
        !metal_slice_valid(input, input_bytes) || !metal_slice_valid(weight_nk, weight_bytes) ||
        !metal_slice_valid(dst, dst_bytes)) {
        return metal_fail(error, error_size, "invalid %s MPS matmul request", op_name != NULL ? op_name : "Metal");
    }
    @autoreleasepool {
        const uint64_t mps_call_start_ns = uocr_profile_now_ns();
        const uint64_t setup_start_ns = uocr_profile_now_ns();
        id kernel = metal_ensure_mps_matmul_kernel(ctx, error, error_size);
        if (kernel == nil) {
            return 0;
        }
        id x_array = metal_mps_matrix_array_from_slice(ctx,
                                                        input,
                                                        rows,
                                                        in_features,
                                                        0,
                                                        UOCR_METAL_MPS_DATA_TYPE_FLOAT16,
                                                        0,
                                                        1,
                                                        input_bytes);
        id w_array = metal_mps_matrix_array_from_slice(ctx,
                                                        weight_nk,
                                                        out_features,
                                                        in_features,
                                                        1,
                                                        UOCR_METAL_MPS_DATA_TYPE_FLOAT16,
                                                        1,
                                                        0,
                                                        weight_bytes);
        id y_array = metal_mps_matrix_array_from_slice(ctx,
                                                        dst,
                                                        rows,
                                                        out_features,
                                                        0,
                                                        dst_data_type,
                                                        0,
                                                        1,
                                                        dst_bytes);
        if (x_array == nil || w_array == nil || y_array == nil) {
            [x_array release];
            [w_array release];
            [y_array release];
            return metal_fail(error, error_size, "failed to create %s MPS NDArrays", op_name != NULL ? op_name : "Metal");
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op_name != NULL ? op_name : "MPS matmul", error, error_size);
        if (cb == nil) {
            [x_array release];
            [w_array release];
            [y_array release];
            return 0;
        }
        const uint64_t encode_start_ns = uocr_profile_now_ns();
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            [x_array release];
            [w_array release];
            [y_array release];
            return metal_fail(error, error_size, "failed to create %s MPS matmul encoder", op_name != NULL ? op_name : "Metal");
        }
        id source_arrays[2] = { x_array, w_array };
        NSArray *sources = [[NSArray alloc] initWithObjects:source_arrays count:2u];
        if (metal_profile_enabled(ctx)) {
            uocr_profile_add_metal_nsarray(ctx->profile);
        }
        metal_profile_add_event_now(ctx, "metal.mps.matmul.setup", setup_start_ns);
        if (sources == nil) {
            [x_array release];
            [w_array release];
            [y_array release];
            return metal_fail(error, error_size, "failed to create %s MPS source array", op_name != NULL ? op_name : "Metal");
        }
        [kernel encodeToCommandEncoder:enc
                          commandBuffer:cb
                           sourceArrays:sources
                       destinationArray:y_array];
        [enc endEncoding];
        metal_profile_add_event_now(ctx, "metal.mps.matmul.encode", encode_start_ns);
        [sources release];
        const uint64_t retain_start_ns = uocr_profile_now_ns();
        const int retained = metal_retain_mps_matmul_arrays_until_completed(ctx, cb, x_array, w_array, y_array, error, error_size);
        metal_profile_add_event_now(ctx, "metal.mps.matmul.retain", retain_start_ns);
        [x_array release];
        [w_array release];
        [y_array release];
        if (!retained) {
            return 0;
        }
        const uint64_t finish_start_ns = uocr_profile_now_ns();
        const int ok = metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op_name != NULL ? op_name : "MPS matmul", error, error_size);
        if (owned_command_buffer) {
            metal_profile_add_event_now(ctx, "metal.mps.matmul.wait", finish_start_ns);
        } else {
            metal_profile_add_event_ms(ctx, "metal.mps.matmul.batched", 0.0);
        }
        metal_profile_add_event_now(ctx, "metal.mps.matmul", mps_call_start_ns);
        return ok;
    }
}

static int metal_run_mps_matmul_nt_f16(uocr_metal_context *ctx,
                                       uocr_metal_buffer_slice input,
                                       uocr_metal_buffer_slice weight_nk,
                                       uocr_metal_buffer_slice dst,
                                       uint32_t rows,
                                       uint32_t in_features,
                                       uint32_t out_features,
                                       const char *op_name,
                                       char *error,
                                       size_t error_size) {
    return metal_run_mps_matmul_nt_f16_to_type(ctx,
                                               input,
                                               weight_nk,
                                               dst,
                                               rows,
                                               in_features,
                                               out_features,
                                               UOCR_METAL_MPS_DATA_TYPE_FLOAT16,
                                               2u,
                                               op_name,
                                               error,
                                               error_size);
}

static int metal_run_mps_matmul_nt_f16_to_f32(uocr_metal_context *ctx,
                                              uocr_metal_buffer_slice input,
                                              uocr_metal_buffer_slice weight_nk,
                                              uocr_metal_buffer_slice dst,
                                              uint32_t rows,
                                              uint32_t in_features,
                                              uint32_t out_features,
                                              const char *op_name,
                                              char *error,
                                              size_t error_size) {
    return metal_run_mps_matmul_nt_f16_to_type(ctx,
                                               input,
                                               weight_nk,
                                               dst,
                                               rows,
                                               in_features,
                                               out_features,
                                               UOCR_METAL_MPS_DATA_TYPE_FLOAT32,
                                               (uint64_t)sizeof(float),
                                               op_name,
                                               error,
                                               error_size);
}

static int metal_hidden_arena_segment_slice(const uocr_metal_context *ctx,
                                            uint32_t slot,
                                            uint32_t segment,
                                            uint32_t n_tokens,
                                            uocr_metal_buffer_slice *out_slice,
                                            uint64_t *out_bytes) {
    if (out_slice == NULL || out_bytes == NULL || ctx == NULL || !ctx->has_kv_cache_layout ||
        ctx->runtime_arenas[UOCR_METAL_ARENA_HIDDEN_PINGPONG].buffer == nil ||
        segment >= UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS || slot >= ctx->kv_cache_layout.batch_slots ||
        n_tokens == 0u || n_tokens > ctx->kv_cache_layout.prompt_token_capacity) {
        return 0;
    }
    uint64_t segment_values = 0u;
    uint64_t segment_bytes = 0u;
    uint64_t slot_bytes = 0u;
    uint64_t segment_offset = 0u;
    uint64_t offset = 0u;
    uint64_t bytes = 0u;
    if (!checked_mul_u64((uint64_t)ctx->kv_cache_layout.prompt_token_capacity, (uint64_t)UOCR_HIDDEN_SIZE, &segment_values) ||
        !checked_mul_u64(segment_values, 2u, &segment_bytes) ||
        !checked_mul_u64(segment_bytes, (uint64_t)UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS, &slot_bytes) ||
        !checked_mul_u64((uint64_t)slot, slot_bytes, &offset) ||
        !checked_mul_u64((uint64_t)segment, segment_bytes, &segment_offset) ||
        !checked_add_u64(offset, segment_offset, &offset) ||
        !checked_mul_u64((uint64_t)n_tokens, (uint64_t)UOCR_HIDDEN_SIZE * 2u, &bytes) ||
        offset > (uint64_t)NSUIntegerMax) {
        return 0;
    }
    uocr_metal_buffer_slice slice;
    slice.buffer = ctx->runtime_arenas[UOCR_METAL_ARENA_HIDDEN_PINGPONG].buffer;
    slice.offset = (NSUInteger)offset;
    if (!metal_slice_valid(slice, bytes)) {
        return 0;
    }
    *out_slice = slice;
    *out_bytes = bytes;
    return 1;
}

static int metal_prompt_arena_slice(const uocr_metal_context *ctx,
                                    uint32_t slot,
                                    uint32_t n_tokens,
                                    uocr_metal_buffer_slice *out_slice,
                                    uint64_t *out_bytes) {
    if (out_slice == NULL || out_bytes == NULL || ctx == NULL) {
        return 0;
    }
    uint64_t offset = 0u;
    uint64_t bytes = 0u;
    if (!metal_prompt_arena_slot_offset(ctx, slot, n_tokens, &offset, &bytes) || offset > (uint64_t)NSUIntegerMax) {
        return 0;
    }
    uocr_metal_buffer_slice slice;
    slice.buffer = ctx->runtime_arenas[UOCR_METAL_ARENA_PROMPT_EMBEDDINGS].buffer;
    slice.offset = (NSUInteger)offset;
    if (!metal_slice_valid(slice, bytes)) {
        return 0;
    }
    *out_slice = slice;
    *out_bytes = bytes;
    return 1;
}

static int metal_moe_intermediate_slice(const uocr_metal_context *ctx,
                                        uint32_t slot,
                                        uint64_t requested_bytes,
                                        uocr_metal_buffer_slice *out_slice) {
    if (out_slice == NULL || ctx == NULL || !ctx->has_kv_cache_layout || requested_bytes == 0u ||
        ctx->runtime_arenas[UOCR_METAL_ARENA_MOE_INTERMEDIATE].buffer == nil ||
        slot >= ctx->kv_cache_layout.batch_slots) {
        return 0;
    }
    const uint64_t per_token_values = (uint64_t)UOCR_MOE_TOP_K * (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE +
                                      (uint64_t)UOCR_MOE_SHARED_INTERMEDIATE;
    uint64_t per_slot_values = 0u;
    uint64_t per_slot_bytes = 0u;
    uint64_t offset = 0u;
    if (!checked_mul_u64((uint64_t)ctx->kv_cache_layout.prompt_token_capacity, per_token_values, &per_slot_values) ||
        !checked_mul_u64(per_slot_values, 2u, &per_slot_bytes) ||
        !checked_mul_u64((uint64_t)slot, per_slot_bytes, &offset) ||
        offset > (uint64_t)NSUIntegerMax) {
        return 0;
    }
    uocr_metal_buffer_slice slice;
    slice.buffer = ctx->runtime_arenas[UOCR_METAL_ARENA_MOE_INTERMEDIATE].buffer;
    slice.offset = (NSUInteger)offset;
    if (requested_bytes > per_slot_bytes || !metal_slice_valid(slice, requested_bytes)) {
        return 0;
    }
    *out_slice = slice;
    return 1;
}

static int metal_router_arena_slices(const uocr_metal_context *ctx,
                                     uint32_t slot,
                                     uint32_t n_tokens,
                                     uocr_metal_buffer_slice *logits,
                                     uocr_metal_buffer_slice *top_ids,
                                     uocr_metal_buffer_slice *top_weights,
                                     uint64_t *logits_bytes,
                                     uint64_t *top_ids_bytes,
                                     uint64_t *top_weights_bytes) {
    if (ctx == NULL || logits == NULL || top_ids == NULL || top_weights == NULL || logits_bytes == NULL ||
        top_ids_bytes == NULL || top_weights_bytes == NULL || !ctx->has_kv_cache_layout || n_tokens == 0u ||
        n_tokens > ctx->kv_cache_layout.prompt_token_capacity || slot >= ctx->kv_cache_layout.batch_slots ||
        ctx->runtime_arenas[UOCR_METAL_ARENA_ROUTER_TOPK].buffer == nil) {
        return 0;
    }
    uint64_t router_capacity_values = 0u;
    uint64_t top_capacity_values = 0u;
    uint64_t router_capacity_bytes = 0u;
    uint64_t top_capacity_ids_bytes = 0u;
    uint64_t top_capacity_weights_bytes = 0u;
    uint64_t slot_bytes = 0u;
    uint64_t slot_base = 0u;
    uint64_t request_router_values = 0u;
    uint64_t request_top_values = 0u;
    if (!checked_mul_u64((uint64_t)ctx->kv_cache_layout.prompt_token_capacity, (uint64_t)UOCR_ROUTED_EXPERTS, &router_capacity_values) ||
        !checked_mul_u64((uint64_t)ctx->kv_cache_layout.prompt_token_capacity, (uint64_t)UOCR_MOE_TOP_K, &top_capacity_values) ||
        !checked_mul_u64(router_capacity_values, (uint64_t)sizeof(float), &router_capacity_bytes) ||
        !checked_mul_u64(top_capacity_values, (uint64_t)sizeof(uint32_t), &top_capacity_ids_bytes) ||
        !checked_mul_u64(top_capacity_values, (uint64_t)sizeof(float), &top_capacity_weights_bytes) ||
        !checked_add_u64(router_capacity_bytes, top_capacity_ids_bytes, &slot_bytes) ||
        !checked_add_u64(slot_bytes, top_capacity_weights_bytes, &slot_bytes) ||
        !checked_mul_u64((uint64_t)slot, slot_bytes, &slot_base) ||
        !checked_mul_u64((uint64_t)n_tokens, (uint64_t)UOCR_ROUTED_EXPERTS, &request_router_values) ||
        !checked_mul_u64((uint64_t)n_tokens, (uint64_t)UOCR_MOE_TOP_K, &request_top_values) ||
        slot_base > (uint64_t)NSUIntegerMax) {
        return 0;
    }
    *logits_bytes = request_router_values * (uint64_t)sizeof(float);
    *top_ids_bytes = request_top_values * (uint64_t)sizeof(uint32_t);
    *top_weights_bytes = request_top_values * (uint64_t)sizeof(float);
    logits->buffer = ctx->runtime_arenas[UOCR_METAL_ARENA_ROUTER_TOPK].buffer;
    logits->offset = (NSUInteger)slot_base;
    top_ids->buffer = logits->buffer;
    top_ids->offset = (NSUInteger)(slot_base + router_capacity_bytes);
    top_weights->buffer = logits->buffer;
    top_weights->offset = (NSUInteger)(slot_base + router_capacity_bytes + top_capacity_ids_bytes);
    return metal_slice_valid(*logits, *logits_bytes) && metal_slice_valid(*top_ids, *top_ids_bytes) &&
           metal_slice_valid(*top_weights, *top_weights_bytes);
}

static int metal_hidden_arena_token_slice(const uocr_metal_context *ctx,
                                          uint32_t slot,
                                          uint32_t segment,
                                          uint32_t token_index,
                                          uocr_metal_buffer_slice *out_slice) {
    if (out_slice == NULL || token_index >= UOCR_MAX_POSITIONS) {
        return 0;
    }
    uocr_metal_buffer_slice segment_slice;
    uint64_t covered_bytes = 0u;
    if (!metal_hidden_arena_segment_slice(ctx, slot, segment, token_index + 1u, &segment_slice, &covered_bytes)) {
        return 0;
    }
    (void)covered_bytes;
    const uint64_t row_bytes = (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    uint64_t row_offset = 0u;
    uint64_t offset = 0u;
    if (!checked_mul_u64((uint64_t)token_index, row_bytes, &row_offset) ||
        !checked_add_u64((uint64_t)segment_slice.offset, row_offset, &offset) ||
        offset > (uint64_t)NSUIntegerMax) {
        return 0;
    }
    out_slice->buffer = segment_slice.buffer;
    out_slice->offset = (NSUInteger)offset;
    return metal_slice_valid(*out_slice, row_bytes);
}

static uint64_t metal_decode_selection_scratch_bytes_per_slot(void) {
    return (uint64_t)UOCR_VOCAB_SIZE * (uint64_t)sizeof(float);
}

static int metal_decode_selection_scratch_slice(const uocr_metal_context *ctx,
                                                uint32_t slot,
                                                uocr_metal_buffer_slice *scratch) {
    if (ctx == NULL || scratch == NULL || !ctx->has_kv_cache_layout || slot >= ctx->kv_cache_layout.batch_slots ||
        ctx->scratch[UOCR_METAL_SCRATCH_LOGITS].buffer == nil) {
        return 0;
    }
    const uint64_t scratch_bytes_per_slot = metal_decode_selection_scratch_bytes_per_slot();
    uint64_t scratch_offset = 0u;
    if (!checked_mul_u64((uint64_t)slot, scratch_bytes_per_slot, &scratch_offset) ||
        scratch_offset > (uint64_t)NSUIntegerMax) {
        return 0;
    }
    scratch->buffer = ctx->scratch[UOCR_METAL_SCRATCH_LOGITS].buffer;
    scratch->offset = (NSUInteger)scratch_offset;
    return metal_slice_valid(*scratch, scratch_bytes_per_slot);
}

static int metal_token_readback_arena_slices(const uocr_metal_context *ctx,
                                             uint32_t slot,
                                             uocr_metal_buffer_slice *next_token,
                                             uocr_metal_buffer_slice *score) {
    if (ctx == NULL || next_token == NULL || score == NULL || !ctx->has_kv_cache_layout ||
        slot >= ctx->kv_cache_layout.batch_slots ||
        ctx->runtime_arenas[UOCR_METAL_ARENA_LOGITS_READBACK].buffer == nil ||
        !ctx->runtime_arenas[UOCR_METAL_ARENA_LOGITS_READBACK].cpu_visible) {
        return 0;
    }
    const uint64_t token_bytes = (uint64_t)ctx->kv_cache_layout.batch_slots * (uint64_t)sizeof(int32_t);
    const uint64_t score_base = token_bytes;
    uint64_t token_offset = 0u;
    uint64_t score_offset = 0u;
    if (!checked_mul_u64((uint64_t)slot, (uint64_t)sizeof(int32_t), &token_offset) ||
        !checked_add_u64(score_base, (uint64_t)slot * (uint64_t)sizeof(float), &score_offset) ||
        token_offset > (uint64_t)NSUIntegerMax || score_offset > (uint64_t)NSUIntegerMax) {
        return 0;
    }
    next_token->buffer = ctx->runtime_arenas[UOCR_METAL_ARENA_LOGITS_READBACK].buffer;
    next_token->offset = (NSUInteger)token_offset;
    score->buffer = next_token->buffer;
    score->offset = (NSUInteger)score_offset;
    return metal_slice_valid(*next_token, (uint64_t)sizeof(int32_t)) &&
           metal_slice_valid(*score, (uint64_t)sizeof(float));
}

static int metal_prebuild_mps_runtime_workspace_ndarrays(uocr_metal_context *ctx,
                                                         uint32_t n_tokens,
                                                         char *error,
                                                         size_t error_size) {
    if (ctx == NULL) {
        return metal_fail(error, error_size, "invalid Metal MPS runtime workspace prebuild request");
    }
    if (!metal_mps_framework_available()) {
        return 1;
    }
    if (!ctx->has_kv_cache_layout || ctx->kv_cache_layout.batch_slots == 0u ||
        ctx->kv_cache_layout.prompt_token_capacity == 0u || n_tokens == 0u ||
        n_tokens > ctx->kv_cache_layout.prompt_token_capacity) {
        return metal_fail(error, error_size, "Metal MPS runtime workspace prebuild requires allocated runtime arenas");
    }
    if (ctx->mps_runtime_workspace_prebuild_generation == ctx->mps_workspace_cache_generation &&
        ctx->mps_runtime_workspace_prebuild_token_count == n_tokens) {
        metal_profile_add_event_ms(ctx, "metal.mps.workspace_prebuild.runtime.cached", 0.0);
        return 1;
    }

    const uint64_t start_ns = uocr_profile_now_ns();
    const int use_attention_mps = metal_mps_matmul_nt_f16_should_use(n_tokens, UOCR_HIDDEN_SIZE, UOCR_HIDDEN_SIZE);
    const int use_dense_down_mps = metal_mps_matmul_nt_f16_should_use(n_tokens,
                                                                      UOCR_DENSE_LAYER0_INTERMEDIATE,
                                                                      UOCR_HIDDEN_SIZE);
    const int use_shared_down_mps = metal_mps_matmul_nt_f16_should_use(n_tokens,
                                                                       UOCR_MOE_SHARED_INTERMEDIATE,
                                                                       UOCR_HIDDEN_SIZE);
    const int use_router_mps = metal_mps_matmul_nt_f16_should_use(n_tokens, UOCR_HIDDEN_SIZE, UOCR_ROUTED_EXPERTS);
    if (!use_attention_mps && !use_dense_down_mps && !use_shared_down_mps && !use_router_mps) {
        ctx->mps_runtime_workspace_prebuild_generation = ctx->mps_workspace_cache_generation;
        ctx->mps_runtime_workspace_prebuild_token_count = n_tokens;
        metal_profile_add_event_ms(ctx, "metal.mps.workspace_prebuild.runtime.not_used", 0.0);
        return 1;
    }

    for (uint32_t slot = 0u; slot < ctx->kv_cache_layout.batch_slots; ++slot) {
        if (use_attention_mps) {
            uocr_metal_buffer_slice prompt;
            uint64_t prompt_bytes = 0u;
            if (!metal_prompt_arena_slice(ctx, slot, n_tokens, &prompt, &prompt_bytes)) {
                return metal_fail(error, error_size, "failed to prebuild Metal MPS prompt workspace NDArray for slot %u", slot);
            }
            if (!metal_prebuild_mps_workspace_matrix_ndarray(ctx,
                                                             prompt,
                                                             prompt_bytes,
                                                             n_tokens,
                                                             UOCR_HIDDEN_SIZE,
                                                             UOCR_METAL_MPS_DATA_TYPE_FLOAT16,
                                                             "decoder prompt workspace",
                                                             error,
                                                             error_size)) {
                return 0;
            }
        }

        if (use_attention_mps || use_dense_down_mps || use_shared_down_mps || use_router_mps) {
            for (uint32_t segment = 0u; segment < UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS; ++segment) {
                uocr_metal_buffer_slice hidden;
                uint64_t hidden_bytes = 0u;
                if (!metal_hidden_arena_segment_slice(ctx, slot, segment, n_tokens, &hidden, &hidden_bytes)) {
                    return metal_fail(error,
                                      error_size,
                                      "failed to prebuild Metal MPS hidden workspace NDArray for slot %u segment %u",
                                      slot,
                                      segment);
                }
                if (!metal_prebuild_mps_workspace_matrix_ndarray(ctx,
                                                                 hidden,
                                                                 hidden_bytes,
                                                                 n_tokens,
                                                                 UOCR_HIDDEN_SIZE,
                                                                 UOCR_METAL_MPS_DATA_TYPE_FLOAT16,
                                                                 "decoder hidden workspace",
                                                                 error,
                                                                 error_size)) {
                    return 0;
                }
            }
        }

        uocr_metal_buffer_slice mid;
        if (use_dense_down_mps) {
            const uint64_t dense_mid_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_DENSE_LAYER0_INTERMEDIATE * 2u;
            if (!metal_moe_intermediate_slice(ctx, slot, dense_mid_bytes, &mid)) {
                return metal_fail(error, error_size, "failed to prebuild Metal MPS dense-MLP intermediate workspace for slot %u", slot);
            }
            if (!metal_prebuild_mps_workspace_matrix_ndarray(ctx,
                                                             mid,
                                                             dense_mid_bytes,
                                                             n_tokens,
                                                             UOCR_DENSE_LAYER0_INTERMEDIATE,
                                                             UOCR_METAL_MPS_DATA_TYPE_FLOAT16,
                                                             "decoder dense MLP intermediate workspace",
                                                             error,
                                                             error_size)) {
                return 0;
            }
        }
        if (use_shared_down_mps) {
            const uint64_t shared_mid_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_SHARED_INTERMEDIATE * 2u;
            if (!metal_moe_intermediate_slice(ctx, slot, shared_mid_bytes, &mid)) {
                return metal_fail(error, error_size, "failed to prebuild Metal MPS shared-expert intermediate workspace for slot %u", slot);
            }
            if (!metal_prebuild_mps_workspace_matrix_ndarray(ctx,
                                                             mid,
                                                             shared_mid_bytes,
                                                             n_tokens,
                                                             UOCR_MOE_SHARED_INTERMEDIATE,
                                                             UOCR_METAL_MPS_DATA_TYPE_FLOAT16,
                                                             "decoder shared-expert intermediate workspace",
                                                             error,
                                                             error_size)) {
                return 0;
            }
        }

        if (use_router_mps) {
            uocr_metal_buffer_slice router_logits;
            uocr_metal_buffer_slice top_ids;
            uocr_metal_buffer_slice top_weights;
            uint64_t router_logits_bytes = 0u;
            uint64_t top_ids_bytes = 0u;
            uint64_t top_weights_bytes = 0u;
            if (!metal_router_arena_slices(ctx,
                                           slot,
                                           n_tokens,
                                           &router_logits,
                                           &top_ids,
                                           &top_weights,
                                           &router_logits_bytes,
                                           &top_ids_bytes,
                                           &top_weights_bytes)) {
                return metal_fail(error, error_size, "failed to prebuild Metal MPS router-logit workspace for slot %u", slot);
            }
            (void)top_ids;
            (void)top_weights;
            (void)top_ids_bytes;
            (void)top_weights_bytes;
            if (!metal_prebuild_mps_workspace_matrix_ndarray(ctx,
                                                             router_logits,
                                                             router_logits_bytes,
                                                             n_tokens,
                                                             UOCR_ROUTED_EXPERTS,
                                                             UOCR_METAL_MPS_DATA_TYPE_FLOAT32,
                                                             "decoder router-logit workspace",
                                                             error,
                                                             error_size)) {
                return 0;
            }
        }
    }

    ctx->mps_runtime_workspace_prebuild_generation = ctx->mps_workspace_cache_generation;
    ctx->mps_runtime_workspace_prebuild_token_count = n_tokens;
    metal_profile_add_event_now(ctx, "metal.mps.workspace_prebuild.runtime", start_ns);
    return 1;
}

typedef struct uocr_metal_decode_selection_slices {
    uocr_metal_buffer_slice ban_flags;
    uocr_metal_buffer_slice partial_scores;
    uocr_metal_buffer_slice partial_ids;
    uint32_t partial_count;
} uocr_metal_decode_selection_slices;

static int metal_selection_scratch_subslice(uocr_metal_buffer_slice base,
                                            uint64_t relative_offset,
                                            uint64_t bytes,
                                            uocr_metal_buffer_slice *out) {
    if (out == NULL || relative_offset > (uint64_t)NSUIntegerMax || base.offset > NSUIntegerMax - (NSUInteger)relative_offset) {
        return 0;
    }
    out->buffer = base.buffer;
    out->offset = base.offset + (NSUInteger)relative_offset;
    return metal_slice_valid(*out, bytes);
}

static int metal_decode_selection_slices(uocr_metal_buffer_slice scratch,
                                         uint32_t banned_capacity,
                                         uocr_metal_decode_selection_slices *out) {
    if (out == NULL) {
        return 0;
    }
    memset(out, 0, sizeof(*out));
    const uint32_t partial_count = (UOCR_VOCAB_SIZE + UOCR_METAL_LM_HEAD_ARGMAX_TILE_TOKENS - 1u) /
                                   UOCR_METAL_LM_HEAD_ARGMAX_TILE_TOKENS;
    const uint64_t ban_flags_bytes = banned_capacity != 0u ? (uint64_t)UOCR_VOCAB_SIZE : 0u;
    uint64_t partial_bytes = 0u;
    if (!checked_mul_u64((uint64_t)partial_count, (uint64_t)sizeof(float), &partial_bytes)) {
        return 0;
    }

    uint64_t cursor = 0u;
#define METAL_SELECTION_ALIGN_CURSOR()                     \
    do {                                                    \
        if (!align_up_u64_checked(cursor, 16u, &cursor)) {  \
            return 0;                                       \
        }                                                   \
    } while (0)

    METAL_SELECTION_ALIGN_CURSOR();
    const uint64_t ban_flags_offset = cursor;
    if (!checked_add_u64(cursor, ban_flags_bytes, &cursor)) return 0;
    METAL_SELECTION_ALIGN_CURSOR();
    const uint64_t partial_scores_offset = cursor;
    if (!checked_add_u64(cursor, partial_bytes, &cursor)) return 0;
    METAL_SELECTION_ALIGN_CURSOR();
    const uint64_t partial_ids_offset = cursor;
    if (!checked_add_u64(cursor, partial_bytes, &cursor)) return 0;
#undef METAL_SELECTION_ALIGN_CURSOR

    const uint64_t scratch_bytes = (uint64_t)UOCR_VOCAB_SIZE * (uint64_t)sizeof(float);
    if (cursor > scratch_bytes || !metal_slice_valid(scratch, scratch_bytes)) {
        return 0;
    }
    if (!metal_selection_scratch_subslice(scratch, ban_flags_offset, ban_flags_bytes, &out->ban_flags) ||
        !metal_selection_scratch_subslice(scratch, partial_scores_offset, partial_bytes, &out->partial_scores) ||
        !metal_selection_scratch_subslice(scratch, partial_ids_offset, partial_bytes, &out->partial_ids)) {
        return 0;
    }
    out->partial_count = partial_count;
    return 1;
}

static int32_t *metal_token_slice_cpu_ptr(uocr_metal_buffer_slice token) {
    if (token.buffer == nil) {
        return NULL;
    }
    void *base = [token.buffer contents];
    if (base == NULL) {
        return NULL;
    }
    return (int32_t *)((uint8_t *)base + (size_t)token.offset);
}

static float *metal_score_slice_cpu_ptr(uocr_metal_buffer_slice score) {
    if (score.buffer == nil) {
        return NULL;
    }
    void *base = [score.buffer contents];
    if (base == NULL) {
        return NULL;
    }
    return (float *)((uint8_t *)base + (size_t)score.offset);
}

static int metal_read_slice_to_host(uocr_metal_context *ctx,
                                    uocr_metal_buffer_slice src,
                                    uint64_t bytes,
                                    void *out,
                                    const char *op_name,
                                    char *error,
                                    size_t error_size) {
    if (ctx == NULL || out == NULL || bytes == 0u || bytes > (uint64_t)SIZE_MAX || !metal_slice_valid(src, bytes)) {
        return metal_fail(error, error_size, "invalid %s readback request", op_name);
    }
    @autoreleasepool {
        id<MTLBuffer> readback = metal_new_buffer_with_length(ctx, (NSUInteger)bytes, MTLResourceStorageModeShared);
        if (readback == nil) {
            return metal_fail(error, error_size, "failed to allocate %s readback buffer", op_name);
        }
        id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            [readback release];
            return metal_fail(error, error_size, "failed to create %s readback command buffer", op_name);
        }
        id<MTLBlitCommandEncoder> blit = metal_blit_command_encoder(ctx, cb);
        if (blit == nil) {
            [readback release];
            return metal_fail(error, error_size, "failed to create %s readback blit encoder", op_name);
        }
        [blit copyFromBuffer:src.buffer sourceOffset:src.offset toBuffer:readback destinationOffset:0u size:(NSUInteger)bytes];
        [blit endEncoding];
        if (!metal_wait_for_command_buffer_profiled(ctx, cb, op_name, error, error_size)) {
            [readback release];
            return 0;
        }
        memcpy(out, [readback contents], (size_t)bytes);
        [readback release];
    }
    return 1;
}

static int metal_copy_slice(uocr_metal_context *ctx,
                            uocr_metal_buffer_slice src,
                            uocr_metal_buffer_slice dst,
                            uint64_t bytes,
                            const char *op_name,
                            char *error,
                            size_t error_size) {
    if (ctx == NULL || bytes == 0u || bytes > (uint64_t)NSUIntegerMax ||
        !metal_slice_valid(src, bytes) || !metal_slice_valid(dst, bytes)) {
        return metal_fail(error, error_size, "invalid %s copy request", op_name);
    }
    @autoreleasepool {
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op_name, error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLBlitCommandEncoder> blit = metal_blit_command_encoder(ctx, cb);
        if (blit == nil) {
            return metal_fail(error, error_size, "failed to create %s copy blit encoder", op_name);
        }
        [blit copyFromBuffer:src.buffer sourceOffset:src.offset toBuffer:dst.buffer destinationOffset:dst.offset size:(NSUInteger)bytes];
        [blit endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op_name, error, error_size);
    }
}

static int metal_run_residual_add_f16(uocr_metal_context *ctx,
                                       uocr_metal_buffer_slice base,
                                       uocr_metal_buffer_slice update,
                                       uocr_metal_buffer_slice dst,
                                       uint32_t value_count,
                                       const char *op_name,
                                       char *error,
                                       size_t error_size) {
    const uint64_t bytes = (uint64_t)value_count * 2u;
    if (ctx == NULL || value_count == 0u || !metal_slice_valid(base, bytes) ||
        !metal_slice_valid(update, bytes) || !metal_slice_valid(dst, bytes)) {
        return metal_fail(error, error_size, "invalid %s residual-add request", op_name != NULL ? op_name : "Metal");
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_clip_residual_add_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op_name != NULL ? op_name : "residual add", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create %s residual-add command encoder", op_name != NULL ? op_name : "Metal");
        }
        NSUInteger threads = pipeline.threadExecutionWidth;
        if (threads == 0u) threads = 1u;
        if (threads > 256u) threads = 256u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:base.buffer offset:base.offset atIndex:0u];
        [enc setBuffer:update.buffer offset:update.offset atIndex:1u];
        [enc setBuffer:dst.buffer offset:dst.offset atIndex:2u];
        [enc setBytes:&value_count length:sizeof(value_count) atIndex:3u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)value_count, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op_name != NULL ? op_name : "residual add", error, error_size);
    }
}

static int metal_run_bias_add_f16_inplace(uocr_metal_context *ctx,
                                           uocr_metal_buffer_slice dst,
