        !checked_mul_u64((uint64_t)rows, (uint64_t)cols, &value_count) ||
        !checked_mul_u64(value_count, 2u, &dst_bytes) ||
        !checked_mul_u64((uint64_t)cols, 2u, &bias_bytes) ||
