static int metal_run_packed_qkv_mps_f16(uocr_metal_context *ctx,
                                         uocr_metal_buffer_slice src,
                                         uocr_metal_buffer_slice packed_weight,
                                         uocr_metal_buffer_slice packed_bias,
                                         uocr_metal_buffer_slice q_dst,
                                         uocr_metal_buffer_slice k_dst,
                                         uocr_metal_buffer_slice v_dst,
                                         uint32_t rows,
                                         uint32_t hidden_size,
                                         const char *op_name,
                                         char *error,
                                         size_t error_size) {
    uint64_t projection_values = 0u;
    uint64_t projection_bytes = 0u;
    uint64_t hidden_bytes = 0u;
    if (ctx == NULL || rows == 0u || hidden_size == 0u ||
        !checked_mul_u64((uint64_t)hidden_size, (uint64_t)hidden_size, &projection_values) ||
        !checked_mul_u64(projection_values, 2u, &projection_bytes) ||
        !checked_mul_u64((uint64_t)hidden_size, 2u, &hidden_bytes) ||
        projection_bytes > (uint64_t)NSUIntegerMax || hidden_bytes > (uint64_t)NSUIntegerMax) {
        return metal_fail(error, error_size, "invalid %s MPS QKV request", op_name != NULL ? op_name : "Metal");
    }
    const int had_active_batch = metal_command_batch_active(ctx);
    if (!metal_command_batch_begin(ctx, error, error_size)) {
        return 0;
    }
    int ok = 1;
    for (uint32_t projection = 0u; projection < 3u && ok; ++projection) {
        uint64_t weight_offset = 0u;
        uint64_t bias_offset = 0u;
        if (!checked_mul_u64((uint64_t)projection, projection_bytes, &weight_offset) ||
            !checked_mul_u64((uint64_t)projection, hidden_bytes, &bias_offset)) {
            ok = metal_fail(error, error_size, "%s MPS QKV offset overflow", op_name != NULL ? op_name : "Metal");
            break;
        }
        uocr_metal_buffer_slice weight_slice = packed_weight;
        uocr_metal_buffer_slice bias_slice = packed_bias;
        if ((uint64_t)weight_slice.offset > (uint64_t)NSUIntegerMax - weight_offset ||
            (uint64_t)bias_slice.offset > (uint64_t)NSUIntegerMax - bias_offset) {
            ok = metal_fail(error, error_size, "%s MPS QKV offset exceeds NSUIntegerMax", op_name != NULL ? op_name : "Metal");
            break;
        }
        weight_slice.offset += (NSUInteger)weight_offset;
        bias_slice.offset += (NSUInteger)bias_offset;
        uocr_metal_buffer_slice dst = projection == 0u ? q_dst : (projection == 1u ? k_dst : v_dst);
        ok = metal_run_mps_matmul_nt_f16(ctx,
                                         src,
                                         weight_slice,
                                         dst,
                                         rows,
                                         hidden_size,
                                         hidden_size,
                                         op_name,
                                         error,
                                         error_size) &&
             metal_run_bias_add_f16_inplace(ctx,
                                            dst,
                                            bias_slice,
                                            rows,
                                            hidden_size,
                                            op_name,
                                            error,
                                            error_size);
    }
    if (!ok) {
        if (!had_active_batch) {
            metal_command_batch_abort(ctx);
        }
        return 0;
    }
    if (!had_active_batch && !metal_command_batch_commit_and_wait(ctx, op_name != NULL ? op_name : "MPS QKV", error, error_size)) {
        return 0;
    }
    return 1;
}

static const uocr_metal_decoder_binding *metal_require_decoder_binding_index(const uocr_metal_context *ctx,
                                                                             uint32_t binding_index,
                                                                             const char *label,
                                                                             char *error,
                                                                             size_t error_size) {
    const int profile_on = metal_profile_enabled(ctx);
    const uint64_t lookup_start_ns = profile_on ? uocr_profile_now_ns() : 0u;
    if (ctx == NULL || !ctx->decoder_bindings.valid || binding_index >= ctx->decoder_bindings.count) {
        (void)metal_fail(error, error_size, "missing cached decoder tensor for %s", label != NULL ? label : "binding");
        return NULL;
    }
    const uocr_metal_decoder_binding *binding = &ctx->decoder_bindings.tensors[binding_index];
    if (binding->buffer == nil) {
        (void)metal_fail(error,
                         error_size,
                         "cached decoder tensor for %s has no Metal buffer (id=%u)",
                         label != NULL ? label : "binding",
                         binding->tensor_id);
        return NULL;
    }
    if (profile_on) {
        metal_profile_add_event_now(ctx, "metal.decoder_binding_cache.direct_lookup", lookup_start_ns);
    }
    return binding;
}

static int metal_run_token_embedding_from_token_slot_f16(uocr_metal_context *ctx,
                                                         uocr_metal_buffer_slice token_id,
                                                         uocr_metal_buffer_slice dst,
                                                         char *error,
                                                         size_t error_size) {
    if (ctx == NULL || !metal_slice_valid(token_id, sizeof(int32_t)) ||
        !metal_slice_valid(dst, (uint64_t)UOCR_HIDDEN_SIZE * 2u)) {
        return metal_fail(error, error_size, "invalid integrated token-embedding request");
    }
    const uint64_t table_bytes = (uint64_t)UOCR_VOCAB_SIZE * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uocr_metal_decoder_binding *embedding = metal_require_decoder_binding_index(ctx,
                                                                                      ctx->decoder_bindings.token_embedding,
                                                                                      "token embedding",
                                                                                      error,
                                                                                      error_size);
    if (embedding == NULL || !metal_buffer_range_valid(embedding->buffer, embedding->offset, table_bytes)) {
        return 0;
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_get_rows_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated token embedding", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated token-embedding command encoder");
        }
        uocr_metal_get_rows_params params;
        params.table_rows = UOCR_VOCAB_SIZE;
        params.row_width = UOCR_HIDDEN_SIZE;
        params.n_row_ids = 1u;
        params.reserved = 0u;
        NSUInteger threads = pipeline.threadExecutionWidth;
        if (threads == 0u) threads = 1u;
        if (threads > (NSUInteger)UOCR_HIDDEN_SIZE) threads = (NSUInteger)UOCR_HIDDEN_SIZE;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:embedding->buffer offset:embedding->offset atIndex:0u];
        [enc setBuffer:token_id.buffer offset:token_id.offset atIndex:1u];
        [enc setBuffer:dst.buffer offset:dst.offset atIndex:2u];
        [enc setBytes:&params length:sizeof(params) atIndex:3u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)UOCR_HIDDEN_SIZE, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated token embedding", error, error_size);
    }
}

static uint32_t metal_no_repeat_candidate_count(uint32_t sequence_len, uint32_t ngram_size, uint32_t window);

static int metal_run_no_repeat_collect_ban_flags_to_slice(uocr_metal_context *ctx,
                                                          uocr_metal_buffer_slice sequence,
                                                          uocr_metal_buffer_slice ban_flags,
                                                          uint32_t sequence_len,
                                                          uint32_t ngram_size,
                                                          uint32_t window,
                                                          uint32_t candidate_count,
                                                          char *error,
                                                          size_t error_size) {
    if (candidate_count == 0u) {
        return 1;
    }
    uint64_t sequence_bytes = 0u;
    if (ctx == NULL || sequence_len == 0u || ngram_size == 0u ||
        !checked_mul_u64((uint64_t)sequence_len, (uint64_t)sizeof(int32_t), &sequence_bytes) ||
        !metal_slice_valid(sequence, sequence_bytes) || !metal_slice_valid(ban_flags, (uint64_t)UOCR_VOCAB_SIZE)) {
        return metal_fail(error, error_size, "invalid integrated no-repeat collection request");
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_no_repeat_collect_banned_i32", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        NSUInteger threads = metal_power2_threadgroup_width(128u, pipeline.maxTotalThreadsPerThreadgroup);
        if (threads > (NSUInteger)candidate_count) {
            threads = metal_power2_threadgroup_width((NSUInteger)candidate_count, threads);
        }
        if (threads == 0u) {
            threads = 1u;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated no-repeat collection", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLBlitCommandEncoder> blit = metal_blit_command_encoder(ctx, cb);
        if (blit == nil) {
            return metal_fail(error, error_size, "failed to create integrated no-repeat flag-clear encoder");
        }
        [blit fillBuffer:ban_flags.buffer range:NSMakeRange(ban_flags.offset, (NSUInteger)UOCR_VOCAB_SIZE) value:0u];
        [blit endEncoding];
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated no-repeat collection encoder");
        }
        uocr_metal_no_repeat_collect_params params;
        params.sequence_len = sequence_len;
        params.ngram_size = ngram_size;
        params.window = window;
        params.candidate_count = candidate_count;
        params.vocab_size = UOCR_VOCAB_SIZE;
        params.reserved0 = 0u;
        params.reserved1 = 0u;
        params.reserved2 = 0u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:sequence.buffer offset:sequence.offset atIndex:0u];
        [enc setBuffer:ban_flags.buffer offset:ban_flags.offset atIndex:1u];
        [enc setBytes:&params length:sizeof(params) atIndex:2u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)candidate_count, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated no-repeat collection", error, error_size);
    }
}

static int metal_run_lm_head_argmax_f16(uocr_metal_context *ctx,
                                        uocr_metal_buffer_slice input,
                                        uocr_metal_buffer_slice ban_flags,
                                        uint32_t banned_count,
                                        uocr_metal_buffer_slice partial_scores,
                                        uocr_metal_buffer_slice partial_ids,
                                        uint32_t partial_count,
                                        char *error,
                                        size_t error_size) {
    const uint64_t input_bytes = (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t weight_bytes = (uint64_t)UOCR_VOCAB_SIZE * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    uint64_t partial_bytes = 0u;
    const uint32_t expected_partials = (UOCR_VOCAB_SIZE + UOCR_METAL_LM_HEAD_ARGMAX_TILE_TOKENS - 1u) /
                                       UOCR_METAL_LM_HEAD_ARGMAX_TILE_TOKENS;
    if (ctx == NULL || partial_count != expected_partials ||
        !checked_mul_u64((uint64_t)partial_count, (uint64_t)sizeof(float), &partial_bytes) ||
        !metal_slice_valid(input, input_bytes) ||
        (banned_count != 0u && !metal_slice_valid(ban_flags, (uint64_t)UOCR_VOCAB_SIZE)) ||
        !metal_slice_valid(partial_scores, partial_bytes) || !metal_slice_valid(partial_ids, partial_bytes)) {
        return metal_fail(error, error_size, "invalid integrated fused LM-head argmax request");
    }
    const uocr_metal_decoder_binding *lm_head = metal_require_decoder_binding_index(ctx,
                                                                                    ctx->decoder_bindings.lm_head,
                                                                                    "LM head",
                                                                                    error,
                                                                                    error_size);
    if (lm_head == NULL || !metal_buffer_range_valid(lm_head->buffer, lm_head->offset, weight_bytes)) {
        return 0;
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_lm_head_argmax_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        const NSUInteger threads = (NSUInteger)UOCR_METAL_LM_HEAD_ARGMAX_THREADS;
        if (pipeline.maxTotalThreadsPerThreadgroup < threads) {
            return metal_fail(error,
                              error_size,
                              "integrated fused LM-head argmax requires %u threads per threadgroup, device supports %llu",
                              UOCR_METAL_LM_HEAD_ARGMAX_THREADS,
                              (unsigned long long)pipeline.maxTotalThreadsPerThreadgroup);
        }
        const uint64_t sum_bytes = (uint64_t)threads * (uint64_t)sizeof(float);
        const uint64_t id_bytes = (uint64_t)threads * (uint64_t)sizeof(uint32_t);
        const uint64_t hidden_bytes = (uint64_t)UOCR_HIDDEN_SIZE * 2u;
        uint64_t tg_bytes = 0u;
        if (!checked_add_u64(sum_bytes, id_bytes, &tg_bytes) ||
            !checked_add_u64(tg_bytes, hidden_bytes, &tg_bytes) ||
            tg_bytes > (uint64_t)ctx->device.maxThreadgroupMemoryLength) {
            return metal_fail(error, error_size, "integrated fused LM-head argmax threadgroup memory exceeds device limit");
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated fused LM-head argmax", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated fused LM-head argmax encoder");
        }
        uocr_metal_lm_head_argmax_params params;
        params.vocab_size = UOCR_VOCAB_SIZE;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.tile_tokens = UOCR_METAL_LM_HEAD_ARGMAX_TILE_TOKENS;
        params.lanes_per_token = UOCR_METAL_LM_HEAD_ARGMAX_LANES_PER_TOKEN;
        params.banned_count = banned_count;
        params.partial_count = partial_count;
        params.reserved0 = 0u;
        params.reserved1 = 0u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:input.buffer offset:input.offset atIndex:0u];
        [enc setBuffer:lm_head->buffer offset:lm_head->offset atIndex:1u];
        [enc setBuffer:ban_flags.buffer offset:ban_flags.offset atIndex:2u];
        [enc setBuffer:partial_scores.buffer offset:partial_scores.offset atIndex:3u];
        [enc setBuffer:partial_ids.buffer offset:partial_ids.offset atIndex:4u];
        [enc setBytes:&params length:sizeof(params) atIndex:5u];
        [enc setThreadgroupMemoryLength:(NSUInteger)sum_bytes atIndex:0u];
        [enc setThreadgroupMemoryLength:(NSUInteger)id_bytes atIndex:1u];
        [enc setThreadgroupMemoryLength:(NSUInteger)hidden_bytes atIndex:2u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)partial_count, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated fused LM-head argmax", error, error_size);
    }
}

static int metal_run_argmax_pairs_to_token(uocr_metal_context *ctx,
                                           uocr_metal_buffer_slice partial_scores,
                                           uocr_metal_buffer_slice partial_ids,
                                           uint32_t partial_count,
                                           uocr_metal_buffer_slice token_slot,
                                           uocr_metal_buffer_slice score_slot,
                                           char *error,
                                           size_t error_size) {
    uint64_t partial_bytes = 0u;
    if (ctx == NULL || partial_count == 0u ||
        !checked_mul_u64((uint64_t)partial_count, (uint64_t)sizeof(float), &partial_bytes) ||
        !metal_slice_valid(partial_scores, partial_bytes) || !metal_slice_valid(partial_ids, partial_bytes) ||
        !metal_slice_valid(token_slot, (uint64_t)sizeof(int32_t)) ||
        !metal_slice_valid(score_slot, (uint64_t)sizeof(float))) {
        return metal_fail(error, error_size, "invalid integrated argmax-pair finalization request");
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_argmax_pairs_f32", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        const NSUInteger threads = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        const uint64_t score_tg_bytes = (uint64_t)threads * (uint64_t)sizeof(float);
        const uint64_t id_tg_bytes = (uint64_t)threads * (uint64_t)sizeof(uint32_t);
        uint64_t tg_bytes = 0u;
        if (!checked_add_u64(score_tg_bytes, id_tg_bytes, &tg_bytes) ||
            tg_bytes > (uint64_t)ctx->device.maxThreadgroupMemoryLength) {
            return metal_fail(error, error_size, "integrated argmax-pair finalization threadgroup memory exceeds device limit");
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated argmax-pair finalization", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated argmax-pair finalization encoder");
        }
        uocr_metal_argmax_pairs_params params;
        params.count = partial_count;
        params.reserved0 = 0u;
        params.reserved1 = 0u;
        params.reserved2 = 0u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:partial_scores.buffer offset:partial_scores.offset atIndex:0u];
        [enc setBuffer:partial_ids.buffer offset:partial_ids.offset atIndex:1u];
        [enc setBuffer:token_slot.buffer offset:token_slot.offset atIndex:2u];
        [enc setBuffer:score_slot.buffer offset:score_slot.offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc setThreadgroupMemoryLength:(NSUInteger)score_tg_bytes atIndex:0u];
        [enc setThreadgroupMemoryLength:(NSUInteger)id_tg_bytes atIndex:1u];
        [enc dispatchThreadgroups:MTLSizeMake(1u, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated argmax-pair finalization", error, error_size);
    }
}

static int metal_run_rmsnorm_buffer_f16(uocr_metal_context *ctx,
                                        uocr_metal_buffer_slice src,
                                        const uocr_metal_decoder_binding *weight,
                                        uint32_t n_rows,
                                        uocr_metal_buffer_slice dst,
                                        const char *op_name,
                                        char *error,
                                        size_t error_size) {
    const uint64_t hidden_bytes = (uint64_t)n_rows * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (ctx == NULL || weight == NULL || n_rows == 0u || !metal_slice_valid(src, hidden_bytes) ||
        !metal_slice_valid(dst, hidden_bytes) || !metal_buffer_range_valid(weight->buffer, weight->offset, UOCR_HIDDEN_SIZE * 2ull)) {
        return metal_fail(error, error_size, "invalid %s RMSNorm request", op_name);
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_rmsnorm_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        const NSUInteger threads = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        if ((uint64_t)threads * sizeof(float) > (uint64_t)ctx->device.maxThreadgroupMemoryLength) {
            return metal_fail(error, error_size, "%s RMSNorm threadgroup memory exceeds device limit", op_name);
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op_name, error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create %s RMSNorm command encoder", op_name);
        }
        uocr_metal_rmsnorm_params params;
        params.n_rows = n_rows;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.eps = UOCR_RMS_NORM_EPS;
        params.reserved = 0u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:src.buffer offset:src.offset atIndex:0u];
        [enc setBuffer:weight->buffer offset:weight->offset atIndex:1u];
        [enc setBuffer:dst.buffer offset:dst.offset atIndex:2u];
        [enc setBytes:&params length:sizeof(params) atIndex:3u];
        [enc setThreadgroupMemoryLength:threads * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)n_rows, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op_name, error, error_size);
    }
}

static int metal_select_next_token_from_hidden_slice_f16(uocr_metal_context *ctx,
                                                        uocr_metal_buffer_slice hidden,
                                                        uocr_metal_buffer_slice norm_scratch,
                                                        uocr_metal_buffer_slice selection_scratch,
                                                        uocr_metal_buffer_slice token_slot,
                                                        uocr_metal_buffer_slice score_slot,
                                                        uocr_metal_buffer_slice no_repeat_sequence,
                                                        uint32_t sequence_len,
                                                        uint32_t no_repeat_ngram_size,
                                                        uint32_t no_repeat_window,
                                                        uint32_t *token_id_out,
                                                        float *score_out,
                                                        char *error,
                                                        size_t error_size) {
    if (ctx == NULL || token_id_out == NULL || score_out == NULL || sequence_len == 0u ||
        !metal_slice_valid(hidden, (uint64_t)UOCR_HIDDEN_SIZE * 2u) ||
        !metal_slice_valid(norm_scratch, (uint64_t)UOCR_HIDDEN_SIZE * 2u) ||
        !metal_slice_valid(selection_scratch, metal_decode_selection_scratch_bytes_per_slot()) ||
        !metal_slice_valid(token_slot, sizeof(int32_t)) ||
        !metal_slice_valid(score_slot, sizeof(float))) {
        return metal_fail(error, error_size, "invalid integrated next-token selection request");
    }
    const uocr_metal_decoder_binding *final_norm = metal_require_decoder_binding_index(ctx,
                                                                                       ctx->decoder_bindings.final_norm,
                                                                                       "final norm",
                                                                                       error,
                                                                                       error_size);
    if (final_norm == NULL) {
        return 0;
    }
    const uint32_t banned_capacity = metal_no_repeat_candidate_count(sequence_len,
                                                                     no_repeat_ngram_size,
                                                                     no_repeat_window);
    uocr_metal_decode_selection_slices selection_slices;
    if (!metal_decode_selection_slices(selection_scratch, banned_capacity, &selection_slices)) {
        return metal_fail(error, error_size, "integrated next-token selection scratch layout is invalid");
    }
    if (banned_capacity != 0u) {
        uint64_t sequence_bytes = 0u;
        if (!checked_mul_u64((uint64_t)sequence_len, (uint64_t)sizeof(int32_t), &sequence_bytes) ||
            !metal_slice_valid(no_repeat_sequence, sequence_bytes)) {
            return metal_fail(error, error_size, "integrated reusable no-repeat sequence buffer is invalid");
        }
        metal_profile_add_event_ms(ctx, "metal.decode.no_repeat_sequence_reuse", 0.0);
    }

    const uint64_t final_norm_start_ns = uocr_profile_now_ns();
    if (!metal_run_rmsnorm_buffer_f16(ctx,
                                      hidden,
                                      final_norm,
                                      1u,
                                      norm_scratch,
                                      "integrated final RMSNorm",
                                      error,
                                      error_size)) {
        return 0;
    }
    metal_profile_add_event_now(ctx, "metal.final_norm", final_norm_start_ns);
    metal_profile_add_event_now(ctx, "metal.decode.final_norm", final_norm_start_ns);

    const uint64_t no_repeat_start_ns = uocr_profile_now_ns();
    if (!metal_run_no_repeat_collect_ban_flags_to_slice(ctx,
                                                        no_repeat_sequence,
                                                        selection_slices.ban_flags,
                                                        sequence_len,
                                                        no_repeat_ngram_size,
                                                        no_repeat_window,
                                                        banned_capacity,
                                                        error,
                                                        error_size)) {
        return 0;
    }
    metal_profile_add_event_now(ctx, "metal.no_repeat", no_repeat_start_ns);
    metal_profile_add_event_now(ctx, "metal.decode.no_repeat_collect", no_repeat_start_ns);

    const uint64_t lm_head_start_ns = uocr_profile_now_ns();
    if (!metal_run_lm_head_argmax_f16(ctx,
                                      norm_scratch,
                                      selection_slices.ban_flags,
                                      banned_capacity,
                                      selection_slices.partial_scores,
                                      selection_slices.partial_ids,
                                      selection_slices.partial_count,
                                      error,
                                      error_size)) {
        return 0;
    }
    metal_profile_add_event_now(ctx, "metal.lm_head_selection", lm_head_start_ns);
    metal_profile_add_event_now(ctx, "metal.decode.lm_head_selection", lm_head_start_ns);

    const uint64_t final_argmax_start_ns = uocr_profile_now_ns();
    if (!metal_run_argmax_pairs_to_token(ctx,
                                         selection_slices.partial_scores,
                                         selection_slices.partial_ids,
                                         selection_slices.partial_count,
                                         token_slot,
                                         score_slot,
                                         error,
                                         error_size)) {
        return 0;
    }
    metal_profile_add_event_now(ctx, "metal.lm_head_final_argmax", final_argmax_start_ns);
    metal_profile_add_event_now(ctx, "metal.decode.lm_head_final_argmax", final_argmax_start_ns);
    if (metal_command_batch_active(ctx)) {
        const uint64_t command_wait_start_ns = uocr_profile_now_ns();
        if (!metal_command_batch_commit_and_wait(ctx, "integrated next-token selection", error, error_size)) {
            return 0;
        }
        metal_profile_add_event_now(ctx, "metal.decode.command_wait", command_wait_start_ns);
    }

    const uint64_t token_readback_start_ns = uocr_profile_now_ns();
    int32_t *token_ptr = metal_token_slice_cpu_ptr(token_slot);
    float *score_ptr = metal_score_slice_cpu_ptr(score_slot);
    if (token_ptr == NULL || score_ptr == NULL) {
        return metal_fail(error, error_size, "integrated next-token selection requires CPU-visible result slots");
    }
    if (*token_ptr < 0 || (uint32_t)*token_ptr >= UOCR_VOCAB_SIZE) {
        return metal_fail(error, error_size, "integrated greedy argmax selected invalid token id %d", *token_ptr);
    }
    *token_id_out = (uint32_t)*token_ptr;
    *score_out = *score_ptr;
    metal_profile_add_event_now(ctx, "metal.token_readback", token_readback_start_ns);
    metal_profile_add_event_now(ctx, "metal.decode.token_readback", token_readback_start_ns);
    return 1;
}

static int metal_run_attention_qkv_buffer_f16(uocr_metal_context *ctx,
                                              uocr_metal_buffer_slice src,
                                              const uocr_metal_decoder_binding *q_weight,
                                              const uocr_metal_decoder_binding *k_weight,
                                              const uocr_metal_decoder_binding *v_weight,
                                              uint32_t n_tokens,
                                              uocr_metal_buffer_slice q_dst,
                                              uocr_metal_buffer_slice k_dst,
                                              uocr_metal_buffer_slice v_dst,
                                              char *error,
                                              size_t error_size) {
    const uint64_t hidden_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t weight_bytes = (uint64_t)UOCR_HIDDEN_SIZE * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (ctx == NULL || q_weight == NULL || k_weight == NULL || v_weight == NULL || n_tokens == 0u ||
        !metal_slice_valid(src, hidden_bytes) || !metal_slice_valid(q_dst, hidden_bytes) ||
        !metal_slice_valid(k_dst, hidden_bytes) || !metal_slice_valid(v_dst, hidden_bytes) ||
        !metal_buffer_range_valid(q_weight->buffer, q_weight->offset, weight_bytes) ||
        !metal_buffer_range_valid(k_weight->buffer, k_weight->offset, weight_bytes) ||
        !metal_buffer_range_valid(v_weight->buffer, v_weight->offset, weight_bytes)) {
        return metal_fail(error, error_size, "invalid integrated attention QKV request");
    }
    uint64_t output_values = 0u;
    if (!checked_mul_u64((uint64_t)n_tokens, (uint64_t)UOCR_HIDDEN_SIZE * 3u, &output_values) ||
        output_values > (uint64_t)UINT32_MAX) {
        return metal_fail(error, error_size, "integrated attention QKV dispatch size overflow");
    }
    if (metal_mps_matmul_nt_f16_should_use(n_tokens, UOCR_HIDDEN_SIZE, UOCR_HIDDEN_SIZE)) {
        uocr_metal_buffer_slice q_weight_slice = { q_weight->buffer, q_weight->offset };
        uocr_metal_buffer_slice k_weight_slice = { k_weight->buffer, k_weight->offset };
        uocr_metal_buffer_slice v_weight_slice = { v_weight->buffer, v_weight->offset };
        return metal_run_mps_matmul_nt_f16(ctx,
                                           src,
                                           q_weight_slice,
                                           q_dst,
                                           n_tokens,
                                           UOCR_HIDDEN_SIZE,
                                           UOCR_HIDDEN_SIZE,
                                           "integrated attention Q MPS matmul",
                                           error,
                                           error_size) &&
               metal_run_mps_matmul_nt_f16(ctx,
                                           src,
                                           k_weight_slice,
                                           k_dst,
                                           n_tokens,
                                           UOCR_HIDDEN_SIZE,
                                           UOCR_HIDDEN_SIZE,
                                           "integrated attention K MPS matmul",
                                           error,
                                           error_size) &&
               metal_run_mps_matmul_nt_f16(ctx,
                                           src,
                                           v_weight_slice,
                                           v_dst,
                                           n_tokens,
                                           UOCR_HIDDEN_SIZE,
                                           UOCR_HIDDEN_SIZE,
                                           "integrated attention V MPS matmul",
                                           error,
                                           error_size);
    }
    if (!metal_public_mps_matmul_fallback_allowed(ctx,
                                                  n_tokens,
                                                  UOCR_HIDDEN_SIZE,
                                                  UOCR_HIDDEN_SIZE,
                                                  "integrated attention QKV",
                                                  error,
                                                  error_size)) {
        return 0;
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_attention_qkvo_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        const NSUInteger threads = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated attention QKV", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated attention QKV command encoder");
        }
        uocr_metal_attention_projection_params params;
        params.n_tokens = n_tokens;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.projection_count = 3u;
        params.reserved = 0u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:src.buffer offset:src.offset atIndex:0u];
        [enc setBuffer:q_weight->buffer offset:q_weight->offset atIndex:1u];
        [enc setBuffer:k_weight->buffer offset:k_weight->offset atIndex:2u];
        [enc setBuffer:v_weight->buffer offset:v_weight->offset atIndex:3u];
        [enc setBuffer:q_weight->buffer offset:q_weight->offset atIndex:4u];
        [enc setBuffer:q_dst.buffer offset:q_dst.offset atIndex:5u];
        [enc setBuffer:k_dst.buffer offset:k_dst.offset atIndex:6u];
        [enc setBuffer:v_dst.buffer offset:v_dst.offset atIndex:7u];
        [enc setBuffer:q_dst.buffer offset:q_dst.offset atIndex:8u];
        [enc setBytes:&params length:sizeof(params) atIndex:9u];
        [enc setThreadgroupMemoryLength:threads * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)output_values, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated attention QKV", error, error_size);
    }
}

static int metal_run_rope_qk_buffer_f16(uocr_metal_context *ctx,
                                        uocr_metal_buffer_slice q,
                                        uocr_metal_buffer_slice k,
                                        uint32_t n_tokens,
                                        uint32_t position_start,
                                        char *error,
                                        size_t error_size) {
    const uint64_t hidden_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    uint64_t pair_threads = 0u;
    if (ctx == NULL || n_tokens == 0u || !metal_slice_valid(q, hidden_bytes) || !metal_slice_valid(k, hidden_bytes) ||
        !checked_mul_u64((uint64_t)n_tokens, (uint64_t)UOCR_ATTENTION_HEADS * (UOCR_HEAD_DIM / 2u), &pair_threads) ||
        pair_threads > (uint64_t)UINT32_MAX) {
        return metal_fail(error, error_size, "invalid integrated RoPE request");
    }
    uint64_t position_end = 0u;
    if (!checked_add_u64((uint64_t)position_start, (uint64_t)n_tokens, &position_end) ||
        position_end > UOCR_MAX_POSITIONS) {
        return metal_fail(error, error_size, "integrated RoPE position range exceeds max positions");
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_rope_qk_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        NSUInteger threads = pipeline.threadExecutionWidth;
        if (threads == 0u) threads = 1u;
        if (threads > 256u) threads = 256u;
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated RoPE", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated RoPE command encoder");
        }
        uocr_metal_rope_qk_params params;
        params.n_tokens = n_tokens;
        params.heads = UOCR_ATTENTION_HEADS;
        params.head_dim = UOCR_HEAD_DIM;
        params.position_start = position_start;
        params.freq_scale = -2.0f * log2f((float)UOCR_ROPE_THETA) / (float)UOCR_HEAD_DIM;
        params.reserved0 = 0u;
        params.reserved1 = 0u;
        params.reserved2 = 0u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:q.buffer offset:q.offset atIndex:0u];
        [enc setBuffer:k.buffer offset:k.offset atIndex:1u];
        [enc setBuffer:q.buffer offset:q.offset atIndex:2u];
        [enc setBuffer:k.buffer offset:k.offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)pair_threads, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated RoPE", error, error_size);
    }
}

static int metal_run_kv_write_buffer_f16(uocr_metal_context *ctx,
                                         uocr_metal_buffer_slice k_src,
                                         uocr_metal_buffer_slice v_src,
                                         uint32_t n_tokens,
                                         uint32_t layer,
                                         uint32_t slot,
                                         uint32_t prompt_length,
                                         uint32_t position_start,
                                         char *error,
                                         size_t error_size) {
    if (ctx == NULL || !ctx->has_kv_cache_layout || n_tokens == 0u || layer >= UOCR_DECODER_LAYERS ||
        slot >= ctx->kv_cache_layout.batch_slots || prompt_length == 0u ||
        prompt_length > ctx->kv_cache_layout.prompt_token_capacity) {
        return metal_fail(error, error_size, "invalid integrated KV write request");
    }
    const uint64_t src_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_KV_HEADS * (uint64_t)UOCR_HEAD_DIM * 2u;
    if (!metal_slice_valid(k_src, src_bytes) || !metal_slice_valid(v_src, src_bytes)) {
        return metal_fail(error, error_size, "integrated KV write source buffers are invalid");
    }
    id<MTLBuffer> kv = ctx->runtime_arenas[UOCR_METAL_ARENA_KV_CACHE].buffer;
    if (!metal_buffer_range_valid(kv, (NSUInteger)ctx->kv_cache_layout.k_offset_bytes, ctx->kv_cache_layout.tensor_bytes) ||
        !metal_buffer_range_valid(kv, (NSUInteger)ctx->kv_cache_layout.v_offset_bytes, ctx->kv_cache_layout.tensor_bytes)) {
        return metal_fail(error, error_size, "integrated KV cache arena is invalid");
    }
    uint64_t src_values = src_bytes / 2u;
    if (src_values > (uint64_t)UINT32_MAX) {
        return metal_fail(error, error_size, "integrated KV write dispatch size overflow");
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_kv_cache_write_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        NSUInteger threads = pipeline.threadExecutionWidth;
        if (threads == 0u) threads = 1u;
        if (threads > 256u) threads = 256u;
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated KV write", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated KV write command encoder");
        }
        uocr_metal_kv_cache_write_params params;
        params.n_tokens = n_tokens;
        params.batch_slots = ctx->kv_cache_layout.batch_slots;
        params.cache_token_capacity = ctx->kv_cache_layout.cache_token_capacity;
        params.layer = layer;
        params.slot = slot;
        params.prompt_length = prompt_length;
        params.position_start = position_start;
        params.heads = UOCR_KV_HEADS;
        params.head_dim = UOCR_HEAD_DIM;
        params.ring_window = UOCR_GENERATED_RING_WINDOW;
        params.reserved0 = 0u;
        params.reserved1 = 0u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:k_src.buffer offset:k_src.offset atIndex:0u];
        [enc setBuffer:v_src.buffer offset:v_src.offset atIndex:1u];
        [enc setBuffer:kv offset:(NSUInteger)ctx->kv_cache_layout.k_offset_bytes atIndex:2u];
        [enc setBuffer:kv offset:(NSUInteger)ctx->kv_cache_layout.v_offset_bytes atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)src_values, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated KV write", error, error_size);
    }
}

static int metal_run_decode_attention_buffer_f16(uocr_metal_context *ctx,
                                                 uocr_metal_buffer_slice q,
                                                 uint32_t layer,
                                                 uint32_t slot,
                                                 uint32_t prompt_length,
                                                 uint32_t generated_count,
                                                 uocr_metal_buffer_slice dst,
                                                 char *error,
                                                 size_t error_size) {
    const uint64_t hidden_bytes = (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    if (ctx == NULL || !ctx->has_kv_cache_layout || layer >= UOCR_DECODER_LAYERS ||
        slot >= ctx->kv_cache_layout.batch_slots || prompt_length == 0u ||
        prompt_length > ctx->kv_cache_layout.prompt_token_capacity ||
        generated_count > UOCR_MAX_POSITIONS - prompt_length ||
        !metal_slice_valid(q, hidden_bytes) || !metal_slice_valid(dst, hidden_bytes)) {
        return metal_fail(error, error_size, "invalid integrated decode attention request");
    }
    uocr_metal_decode_attention_plan plan;
    if (!uocr_metal_kv_cache_decode_attention_plan(prompt_length,
                                                   ctx->kv_cache_layout.prompt_token_capacity,
                                                   generated_count,
                                                   &plan)) {
        return metal_fail(error, error_size, "invalid integrated decode attention plan");
    }
    id<MTLBuffer> kv = ctx->runtime_arenas[UOCR_METAL_ARENA_KV_CACHE].buffer;
    if (!metal_buffer_range_valid(kv, (NSUInteger)ctx->kv_cache_layout.k_offset_bytes, ctx->kv_cache_layout.tensor_bytes) ||
        !metal_buffer_range_valid(kv, (NSUInteger)ctx->kv_cache_layout.v_offset_bytes, ctx->kv_cache_layout.tensor_bytes)) {
        return metal_fail(error, error_size, "integrated decode attention KV arena is invalid");
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_decode_attention_flash_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        const NSUInteger threads = 32u;
        if (pipeline.maxTotalThreadsPerThreadgroup < threads) {
            return metal_fail(error, error_size, "integrated decode flash-attention pipeline cannot run one simdgroup per head");
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated decode attention", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated decode attention command encoder");
        }
        uocr_metal_decode_attention_params params;
        memset(&params, 0, sizeof(params));
        params.batch_slots = ctx->kv_cache_layout.batch_slots;
        params.cache_token_capacity = ctx->kv_cache_layout.cache_token_capacity;
        params.layer = layer;
        params.slot = slot;
        params.prompt_length = prompt_length;
        params.generated_count = generated_count;
        params.attention_length = plan.attention_length;
        params.first_generated = plan.first_generated_index;
        params.heads = UOCR_ATTENTION_HEADS;
        params.head_dim = UOCR_HEAD_DIM;
        params.ring_window = UOCR_GENERATED_RING_WINDOW;
        params.scale = 1.0f / sqrtf((float)UOCR_HEAD_DIM);
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:q.buffer offset:q.offset atIndex:0u];
        [enc setBuffer:kv offset:(NSUInteger)ctx->kv_cache_layout.k_offset_bytes atIndex:1u];
        [enc setBuffer:kv offset:(NSUInteger)ctx->kv_cache_layout.v_offset_bytes atIndex:2u];
        [enc setBuffer:dst.buffer offset:dst.offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)UOCR_ATTENTION_HEADS, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated decode attention", error, error_size);
    }
}

static int metal_run_prefill_attention_buffer_f16(uocr_metal_context *ctx,
                                                  uocr_metal_buffer_slice q,
                                                  uocr_metal_buffer_slice k,
                                                  uocr_metal_buffer_slice v,
                                                  uint32_t n_tokens,
                                                  uocr_metal_buffer_slice dst,
                                                  char *error,
                                                  size_t error_size) {
    const uint64_t hidden_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    uint64_t query_blocks = ((uint64_t)n_tokens + 3u) / 4u;
    if (ctx == NULL || n_tokens == 0u || n_tokens > UOCR_MAX_POSITIONS ||
        !metal_slice_valid(q, hidden_bytes) || !metal_slice_valid(k, hidden_bytes) ||
        !metal_slice_valid(v, hidden_bytes) || !metal_slice_valid(dst, hidden_bytes) ||
        query_blocks > (uint64_t)UINT32_MAX) {
        return metal_fail(error, error_size, "invalid integrated prefill attention request");
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_prefill_attention_flash_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        const NSUInteger threads = 128u;
        if (pipeline.maxTotalThreadsPerThreadgroup < threads) {
            return metal_fail(error, error_size, "integrated prefill flash-attention pipeline cannot run four simdgroups per block");
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated prefill attention", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated prefill attention command encoder");
        }
        uocr_metal_prefill_attention_params params;
        params.n_tokens = n_tokens;
        params.heads = UOCR_ATTENTION_HEADS;
        params.head_dim = UOCR_HEAD_DIM;
        params.scale = 1.0f / sqrtf((float)UOCR_HEAD_DIM);
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:q.buffer offset:q.offset atIndex:0u];
        [enc setBuffer:k.buffer offset:k.offset atIndex:1u];
        [enc setBuffer:v.buffer offset:v.offset atIndex:2u];
        [enc setBuffer:dst.buffer offset:dst.offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)UOCR_ATTENTION_HEADS, (NSUInteger)query_blocks, 1u)
             threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated prefill attention", error, error_size);
    }
}

static int metal_run_attention_output_residual_buffer_f16(uocr_metal_context *ctx,
                                                          uocr_metal_buffer_slice context,
                                                          const uocr_metal_decoder_binding *o_weight,
                                                          uocr_metal_buffer_slice residual,
                                                          uint32_t n_tokens,
                                                          uocr_metal_buffer_slice dst,
                                                          char *error,
                                                          size_t error_size) {
    const uint64_t hidden_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t weight_bytes = (uint64_t)UOCR_HIDDEN_SIZE * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    uint64_t output_values = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE;
    if (ctx == NULL || o_weight == NULL || n_tokens == 0u || !metal_slice_valid(context, hidden_bytes) ||
        !metal_slice_valid(residual, hidden_bytes) || !metal_slice_valid(dst, hidden_bytes) ||
        !metal_buffer_range_valid(o_weight->buffer, o_weight->offset, weight_bytes) || output_values > UINT32_MAX) {
        return metal_fail(error, error_size, "invalid integrated attention output request");
    }
    if (metal_mps_matmul_nt_f16_should_use(n_tokens, UOCR_HIDDEN_SIZE, UOCR_HIDDEN_SIZE)) {
        uocr_metal_buffer_slice weight_slice = { o_weight->buffer, o_weight->offset };
        return metal_run_mps_matmul_nt_f16(ctx,
                                           context,
                                           weight_slice,
                                           dst,
                                           n_tokens,
                                           UOCR_HIDDEN_SIZE,
                                           UOCR_HIDDEN_SIZE,
                                           "integrated attention output MPS matmul",
                                           error,
                                           error_size) &&
               metal_run_residual_add_f16(ctx,
                                          dst,
                                          residual,
                                          dst,
                                          (uint32_t)output_values,
                                          "integrated attention output MPS residual add",
                                          error,
                                          error_size);
    }
    if (!metal_public_mps_matmul_fallback_allowed(ctx,
                                                  n_tokens,
                                                  UOCR_HIDDEN_SIZE,
                                                  UOCR_HIDDEN_SIZE,
                                                  "integrated attention output",
                                                  error,
                                                  error_size)) {
        return 0;
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_attention_output_residual_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        const NSUInteger threads = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated attention output", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated attention output command encoder");
        }
        uocr_metal_attention_output_params params;
        params.n_tokens = n_tokens;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.reserved0 = 0u;
        params.reserved1 = 0u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:context.buffer offset:context.offset atIndex:0u];
        [enc setBuffer:o_weight->buffer offset:o_weight->offset atIndex:1u];
        [enc setBuffer:residual.buffer offset:residual.offset atIndex:2u];
        [enc setBuffer:dst.buffer offset:dst.offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc setThreadgroupMemoryLength:threads * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)output_values, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated attention output", error, error_size);
    }
}

static int metal_run_dense_swiglu_buffer_f16(uocr_metal_context *ctx,
                                             uocr_metal_buffer_slice input,
                                             const uocr_metal_decoder_binding *gate_weight,
                                             const uocr_metal_decoder_binding *up_weight,
                                             const uocr_metal_decoder_binding *down_weight,
                                             uocr_metal_buffer_slice residual,
                                             int has_residual,
                                             uint32_t n_tokens,
                                             uint32_t intermediate_size,
                                             uocr_metal_buffer_slice mid,
                                             uocr_metal_buffer_slice dst,
                                             const char *op_name,
                                             char *error,
                                             size_t error_size) {
    const uint64_t hidden_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t gate_weight_bytes = (uint64_t)intermediate_size * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t down_weight_bytes = (uint64_t)UOCR_HIDDEN_SIZE * (uint64_t)intermediate_size * 2u;
    const uint64_t mid_bytes = (uint64_t)n_tokens * (uint64_t)intermediate_size * 2u;
    uint64_t gate_values = (uint64_t)n_tokens * (uint64_t)intermediate_size;
    uint64_t down_values = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE;
    if (ctx == NULL || gate_weight == NULL || up_weight == NULL || down_weight == NULL || n_tokens == 0u ||
        intermediate_size == 0u || gate_values > UINT32_MAX || down_values > UINT32_MAX ||
        !metal_slice_valid(input, hidden_bytes) || !metal_slice_valid(mid, mid_bytes) ||
        !metal_slice_valid(dst, hidden_bytes) || (has_residual && !metal_slice_valid(residual, hidden_bytes)) ||
        !metal_buffer_range_valid(gate_weight->buffer, gate_weight->offset, gate_weight_bytes) ||
        !metal_buffer_range_valid(up_weight->buffer, up_weight->offset, gate_weight_bytes) ||
        !metal_buffer_range_valid(down_weight->buffer, down_weight->offset, down_weight_bytes)) {
        return metal_fail(error, error_size, "invalid %s SwiGLU request", op_name);
    }
    const int use_mps_down = metal_mps_matmul_nt_f16_should_use(n_tokens, intermediate_size, UOCR_HIDDEN_SIZE);
    if (!use_mps_down &&
        !metal_public_mps_matmul_fallback_allowed(ctx,
                                                  n_tokens,
                                                  intermediate_size,
                                                  UOCR_HIDDEN_SIZE,
                                                  op_name,
                                                  error,
                                                  error_size)) {
        return 0;
    }
    @autoreleasepool {
        id<MTLComputePipelineState> gate_pipeline = metal_get_pipeline(ctx, "uocr_dense_swiglu_gate_up_f16", error, error_size);
        id<MTLComputePipelineState> down_pipeline = use_mps_down ? nil :
            metal_get_pipeline(ctx, "uocr_dense_swiglu_down_f16_to_f16", error, error_size);
        if (gate_pipeline == nil || (!use_mps_down && down_pipeline == nil)) {
            return 0;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op_name, error, error_size);
        if (cb == nil) {
            return 0;
        }
        uocr_metal_dense_swiglu_params params;
        params.n_tokens = n_tokens;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.intermediate_size = intermediate_size;
        params.has_residual = has_residual ? 1u : 0u;
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create %s gate/up command encoder", op_name);
        }
        const NSUInteger gate_threads = metal_power2_threadgroup_width(256u, gate_pipeline.maxTotalThreadsPerThreadgroup);
        [enc setComputePipelineState:gate_pipeline];
        [enc setBuffer:input.buffer offset:input.offset atIndex:0u];
        [enc setBuffer:gate_weight->buffer offset:gate_weight->offset atIndex:1u];
        [enc setBuffer:up_weight->buffer offset:up_weight->offset atIndex:2u];
        [enc setBuffer:mid.buffer offset:mid.offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc setThreadgroupMemoryLength:gate_threads * 2u * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)gate_values, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(gate_threads, 1u, 1u)];
        [enc endEncoding];

        if (use_mps_down) {
            uocr_metal_buffer_slice down_weight_slice = { down_weight->buffer, down_weight->offset };
            if (!metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op_name, error, error_size) ||
                !metal_run_mps_matmul_nt_f16(ctx,
                                             mid,
                                             down_weight_slice,
                                             dst,
                                             n_tokens,
                                             intermediate_size,
                                             UOCR_HIDDEN_SIZE,
                                             op_name,
                                             error,
                                             error_size)) {
                return 0;
            }
            if (has_residual) {
                return metal_run_residual_add_f16(ctx,
                                                  dst,
                                                  residual,
                                                  dst,
                                                  (uint32_t)down_values,
                                                  op_name,
                                                  error,
                                                  error_size);
            }
            return 1;
        }

        enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create %s down command encoder", op_name);
        }
        const NSUInteger down_threads = metal_power2_threadgroup_width(256u, down_pipeline.maxTotalThreadsPerThreadgroup);
        [enc setComputePipelineState:down_pipeline];
        [enc setBuffer:mid.buffer offset:mid.offset atIndex:0u];
        [enc setBuffer:down_weight->buffer offset:down_weight->offset atIndex:1u];
        [enc setBuffer:(has_residual ? residual.buffer : input.buffer) offset:(has_residual ? residual.offset : input.offset) atIndex:2u];
        [enc setBuffer:dst.buffer offset:dst.offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc setThreadgroupMemoryLength:down_threads * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)down_values, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(down_threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op_name, error, error_size);
    }
}

static int metal_run_moe_router_buffer_f16(uocr_metal_context *ctx,
                                           uocr_metal_buffer_slice input,
                                           const uocr_metal_decoder_binding *router_weight,
                                           uint32_t slot,
                                           uint32_t n_tokens,
                                           uocr_metal_buffer_slice *top_ids_out,
                                           uocr_metal_buffer_slice *top_weights_out,
                                           char *error,
                                           size_t error_size) {
    const uint64_t hidden_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t weight_bytes = (uint64_t)UOCR_ROUTED_EXPERTS * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    uocr_metal_buffer_slice logits;
    uocr_metal_buffer_slice top_ids;
    uocr_metal_buffer_slice top_weights;
    uint64_t logits_bytes = 0u;
    uint64_t top_ids_bytes = 0u;
    uint64_t top_weights_bytes = 0u;
    uint64_t router_values = (uint64_t)n_tokens * (uint64_t)UOCR_ROUTED_EXPERTS;
    if (ctx == NULL || router_weight == NULL || top_ids_out == NULL || top_weights_out == NULL || n_tokens == 0u ||
        router_values > UINT32_MAX || !metal_slice_valid(input, hidden_bytes) ||
        !metal_buffer_range_valid(router_weight->buffer, router_weight->offset, weight_bytes) ||
        !metal_router_arena_slices(ctx, slot, n_tokens, &logits, &top_ids, &top_weights,
                                   &logits_bytes, &top_ids_bytes, &top_weights_bytes)) {
        return metal_fail(error, error_size, "invalid integrated MoE router request");
    }
    (void)logits_bytes;
    (void)top_ids_bytes;
    (void)top_weights_bytes;
    const int use_mps_logits = metal_mps_matmul_nt_f16_should_use(n_tokens, UOCR_HIDDEN_SIZE, UOCR_ROUTED_EXPERTS);
    if (!use_mps_logits &&
        !metal_public_mps_matmul_fallback_allowed(ctx,
                                                  n_tokens,
                                                  UOCR_HIDDEN_SIZE,
                                                  UOCR_ROUTED_EXPERTS,
                                                  "integrated MoE router logits",
                                                  error,
                                                  error_size)) {
        return 0;
    }
    @autoreleasepool {
        id<MTLComputePipelineState> logits_pipeline = use_mps_logits ? nil :
            metal_get_pipeline(ctx, "uocr_moe_router_logits_f16_to_f32", error, error_size);
        id<MTLComputePipelineState> topk_pipeline = metal_get_pipeline(ctx, "uocr_moe_router_softmax_topk_f32", error, error_size);
        if ((!use_mps_logits && logits_pipeline == nil) || topk_pipeline == nil) {
            return 0;
        }
        if (topk_pipeline.maxTotalThreadsPerThreadgroup < (NSUInteger)UOCR_ROUTED_EXPERTS) {
            return metal_fail(error, error_size, "integrated MoE router top-k pipeline does not support 64 threads");
        }
        uocr_metal_moe_router_params params;
        params.n_tokens = n_tokens;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.experts = UOCR_ROUTED_EXPERTS;
        params.top_k = UOCR_MOE_TOP_K;

        if (use_mps_logits) {
            uocr_metal_buffer_slice router_weight_slice = { router_weight->buffer, router_weight->offset };
            const uint64_t router_mps_start_ns = uocr_profile_now_ns();
            if (!metal_run_mps_matmul_nt_f16_to_f32(ctx,
                                                    input,
                                                    router_weight_slice,
                                                    logits,
                                                    n_tokens,
                                                    UOCR_HIDDEN_SIZE,
                                                    UOCR_ROUTED_EXPERTS,
                                                    "integrated MoE router MPS logits",
                                                    error,
                                                    error_size)) {
                return 0;
            }
            metal_profile_add_event_now(ctx, "metal.prefill.moe_router_mps_logits", router_mps_start_ns);
        }

        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated MoE router", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = nil;
        if (!use_mps_logits) {
            enc = metal_compute_command_encoder(ctx, cb);
            if (enc == nil) {
                return metal_fail(error, error_size, "failed to create integrated MoE router logits encoder");
            }
            const NSUInteger logits_threads = metal_power2_threadgroup_width(256u, logits_pipeline.maxTotalThreadsPerThreadgroup);
            [enc setComputePipelineState:logits_pipeline];
            [enc setBuffer:input.buffer offset:input.offset atIndex:0u];
            [enc setBuffer:router_weight->buffer offset:router_weight->offset atIndex:1u];
            [enc setBuffer:logits.buffer offset:logits.offset atIndex:2u];
            [enc setBytes:&params length:sizeof(params) atIndex:3u];
            [enc setThreadgroupMemoryLength:logits_threads * sizeof(float) atIndex:0u];
            [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)router_values, 1u, 1u)
                 threadsPerThreadgroup:MTLSizeMake(logits_threads, 1u, 1u)];
            [enc endEncoding];
        }

        enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated MoE router top-k encoder");
        }
        const NSUInteger topk_threads = metal_power2_threadgroup_width(64u, topk_pipeline.maxTotalThreadsPerThreadgroup);
        const NSUInteger topk_scratch_bytes = ((NSUInteger)UOCR_ROUTED_EXPERTS + topk_threads) * sizeof(float) +
                                              (NSUInteger)UOCR_ROUTED_EXPERTS * sizeof(uint32_t);
        [enc setComputePipelineState:topk_pipeline];
        [enc setBuffer:logits.buffer offset:logits.offset atIndex:0u];
        [enc setBuffer:logits.buffer offset:logits.offset atIndex:1u];
        [enc setBuffer:top_ids.buffer offset:top_ids.offset atIndex:2u];
        [enc setBuffer:top_weights.buffer offset:top_weights.offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc setThreadgroupMemoryLength:topk_scratch_bytes atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)n_tokens, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(topk_threads, 1u, 1u)];
        [enc endEncoding];
        if (!metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated MoE router", error, error_size)) {
            return 0;
        }
    }
    *top_ids_out = top_ids;
    *top_weights_out = top_weights;
    return 1;
}

static int metal_expert_interleaved_slab_for_layer(const uocr_metal_context *ctx,
                                                   uint32_t layer,
                                                   uocr_metal_buffer_slice *out_slab,
                                                   char *error,
                                                   size_t error_size) {
    if (ctx == NULL || out_slab == NULL || layer == 0u || layer >= UOCR_DECODER_LAYERS) {
        return metal_fail(error, error_size, "invalid integrated MoE expert slab request");
    }
    const uocr_metal_decoder_expert_slab_cache *slab = &ctx->decoder_bindings.layers[layer].expert_slab;
    if (!ctx->decoder_bindings.valid || !slab->valid || slab->buffer == nil) {
        return metal_fail(error,
                          error_size,
                          "missing cached integrated MoE expert slab for layer %u",
                          layer);
    }
    if (!metal_buffer_range_valid(slab->buffer, slab->offset, slab->byte_length)) {
        return metal_fail(error,
                          error_size,
                          "cached integrated MoE expert slab for layer %u is outside its Metal buffer",
                          layer);
    }
    out_slab->buffer = slab->buffer;
    out_slab->offset = slab->offset;
    return 1;
}

static int metal_run_moe_interleaved_buffer_f16(uocr_metal_context *ctx,
                                                uocr_metal_buffer_slice input,
                                                uocr_metal_buffer_slice top_ids,
                                                uocr_metal_buffer_slice top_weights,
                                                uocr_metal_buffer_slice expert_slab,
                                                uint32_t slot,
                                                uint32_t n_tokens,
                                                uocr_metal_buffer_slice mid,
                                                uocr_metal_buffer_slice dst,
                                                char *error,
                                                size_t error_size) {
    (void)slot;
    const uint64_t hidden_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE * 2u;
    const uint64_t top_ids_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_TOP_K * sizeof(uint32_t);
    const uint64_t top_weights_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_TOP_K * sizeof(float);
    const uint64_t mid_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_TOP_K * (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE * 2u;
    const uint64_t projection_values = (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE * (uint64_t)UOCR_HIDDEN_SIZE;
    const uint64_t slab_bytes = projection_values * 2u * 3u * (uint64_t)UOCR_ROUTED_EXPERTS;
    uint64_t gate_values = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_TOP_K * (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE;
    uint64_t down_values = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE;
    if (ctx == NULL || n_tokens == 0u || gate_values > UINT32_MAX || down_values > UINT32_MAX ||
        !metal_slice_valid(input, hidden_bytes) || !metal_slice_valid(top_ids, top_ids_bytes) ||
        !metal_slice_valid(top_weights, top_weights_bytes) || !metal_slice_valid(expert_slab, slab_bytes) ||
        !metal_slice_valid(mid, mid_bytes) || !metal_slice_valid(dst, hidden_bytes)) {
        return metal_fail(error, error_size, "invalid integrated routed MoE request");
    }
    @autoreleasepool {
        id<MTLComputePipelineState> gate_pipeline = metal_get_pipeline(ctx, "uocr_moe_prefill_interleaved_gate_up_f16", error, error_size);
        id<MTLComputePipelineState> down_pipeline = metal_get_pipeline(ctx, "uocr_moe_prefill_interleaved_down_sum_f16_to_f16", error, error_size);
        if (gate_pipeline == nil || down_pipeline == nil) {
            return 0;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated routed MoE", error, error_size);
        if (cb == nil) {
            return 0;
        }
        uocr_metal_moe_prefill_interleaved_params params;
        params.n_tokens = n_tokens;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.intermediate_size = UOCR_MOE_EXPERT_INTERMEDIATE;
        params.expert_count = UOCR_ROUTED_EXPERTS;
        params.top_k = UOCR_MOE_TOP_K;
        params.expert_stride_values = (uint32_t)(projection_values * 3u);
        params.up_offset_values = (uint32_t)projection_values;
        params.down_offset_values = (uint32_t)(projection_values * 2u);
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated routed MoE gate/up encoder");
        }
        const NSUInteger gate_threads = metal_power2_threadgroup_width(256u, gate_pipeline.maxTotalThreadsPerThreadgroup);
        [enc setComputePipelineState:gate_pipeline];
        [enc setBuffer:input.buffer offset:input.offset atIndex:0u];
        [enc setBuffer:top_ids.buffer offset:top_ids.offset atIndex:1u];
        [enc setBuffer:expert_slab.buffer offset:expert_slab.offset atIndex:2u];
        [enc setBuffer:mid.buffer offset:mid.offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc setThreadgroupMemoryLength:gate_threads * 2u * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)gate_values, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(gate_threads, 1u, 1u)];
        [enc endEncoding];

        enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated routed MoE down encoder");
        }
        const NSUInteger down_threads = metal_power2_threadgroup_width(256u, down_pipeline.maxTotalThreadsPerThreadgroup);
        [enc setComputePipelineState:down_pipeline];
        [enc setBuffer:mid.buffer offset:mid.offset atIndex:0u];
        [enc setBuffer:top_ids.buffer offset:top_ids.offset atIndex:1u];
        [enc setBuffer:top_weights.buffer offset:top_weights.offset atIndex:2u];
        [enc setBuffer:expert_slab.buffer offset:expert_slab.offset atIndex:3u];
        [enc setBuffer:dst.buffer offset:dst.offset atIndex:4u];
        [enc setBytes:&params length:sizeof(params) atIndex:5u];
        [enc setThreadgroupMemoryLength:down_threads * sizeof(float) atIndex:0u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)down_values, 1u, 1u)
             threadsPerThreadgroup:MTLSizeMake(down_threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated routed MoE", error, error_size);
    }
}

static int metal_run_moe_combine_buffer_f16(uocr_metal_context *ctx,
                                            uocr_metal_buffer_slice routed,
                                            uocr_metal_buffer_slice shared,
                                            uocr_metal_buffer_slice residual,
                                            uint32_t n_tokens,
                                            uocr_metal_buffer_slice dst,
                                            char *error,
                                            size_t error_size) {
    const uint64_t hidden_values = (uint64_t)n_tokens * (uint64_t)UOCR_HIDDEN_SIZE;
    const uint64_t hidden_bytes = hidden_values * 2u;
    if (ctx == NULL || n_tokens == 0u || hidden_values > UINT32_MAX || !metal_slice_valid(routed, hidden_bytes) ||
        !metal_slice_valid(shared, hidden_bytes) || !metal_slice_valid(residual, hidden_bytes) ||
        !metal_slice_valid(dst, hidden_bytes)) {
        return metal_fail(error, error_size, "invalid integrated MoE combine request");
    }
    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_moe_combine_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "integrated MoE combine", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create integrated MoE combine command encoder");
        }
        uocr_metal_moe_combine_params params;
        params.n_tokens = n_tokens;
        params.hidden_size = UOCR_HIDDEN_SIZE;
        params.has_residual = 1u;
        params.reserved = 0u;
        NSUInteger threads = pipeline.threadExecutionWidth;
        if (threads == 0u) threads = 1u;
        if (threads > 256u) threads = 256u;
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:routed.buffer offset:routed.offset atIndex:0u];
        [enc setBuffer:shared.buffer offset:shared.offset atIndex:1u];
        [enc setBuffer:residual.buffer offset:residual.offset atIndex:2u];
        [enc setBuffer:dst.buffer offset:dst.offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)hidden_values, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "integrated MoE combine", error, error_size);
    }
}

static int metal_run_decoder_decode_one_f16(uocr_metal_context *ctx,
                                            uint32_t slot,
                                            uint32_t prompt_length,
                                            uint32_t generated_count_after_write,
                                            char *error,
                                            size_t error_size) {
    if (ctx == NULL || !ctx->has_kv_cache_layout || slot >= ctx->kv_cache_layout.batch_slots ||
        prompt_length == 0u || prompt_length > ctx->kv_cache_layout.prompt_token_capacity ||
        generated_count_after_write == 0u || generated_count_after_write > UOCR_MAX_POSITIONS - prompt_length) {
        return metal_fail(error, error_size, "invalid integrated decoder decode-step request");
    }
    const uint32_t position = prompt_length + generated_count_after_write - 1u;
    const uint64_t hidden_bytes = (uint64_t)UOCR_HIDDEN_SIZE * 2u;

    uocr_metal_buffer_slice scratch[UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS];
    for (uint32_t i = 0u; i < UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS; ++i) {
        uint64_t bytes = 0u;
        if (!metal_hidden_arena_segment_slice(ctx, slot, i, 1u, &scratch[i], &bytes) || bytes != hidden_bytes) {
            return metal_fail(error, error_size, "integrated decode requires hidden scratch segment %u", i);
        }
    }

#define RUN_DECODE_TIMED(bucket_name, call_expr)                     \
    do {                                                            \
        const uint64_t decode_bucket_start_ns__ = uocr_profile_now_ns(); \
        if (!(call_expr)) {                                         \
            return 0;                                               \
        }                                                           \
        metal_profile_add_event_now(ctx, (bucket_name), decode_bucket_start_ns__); \
    } while (0)

    uocr_metal_buffer_slice current = scratch[0];
    uint32_t current_segment = 0u;
    for (uint32_t layer = 0u; layer < UOCR_DECODER_LAYERS; ++layer) {
        const uint64_t layer_start_ns = uocr_profile_now_ns();
        uint32_t available[UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS];
        uint32_t available_count = 0u;
        for (uint32_t i = 0u; i < UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS; ++i) {
            if (i != current_segment) {
                available[available_count++] = i;
            }
        }
        if (available_count < 4u) {
            return metal_fail(error, error_size, "integrated decode scratch assignment failed at layer %u", layer);
        }
        const uint32_t norm_segment = available[0];
        const uint32_t q_segment = available[1];
        const uint32_t k_segment = available[2];
        const uint32_t v_segment = available[3];
        uocr_metal_buffer_slice norm = scratch[norm_segment];
        uocr_metal_buffer_slice q = scratch[q_segment];
        uocr_metal_buffer_slice k = scratch[k_segment];
        uocr_metal_buffer_slice v = scratch[v_segment];
        uocr_metal_buffer_slice output = k;
        const uint32_t output_segment = k_segment;

        const uocr_metal_decoder_layer_binding_cache *layer_bindings = &ctx->decoder_bindings.layers[layer];
        const uocr_metal_decoder_binding *input_norm = metal_require_decoder_binding_index(ctx,
                                                                                           layer_bindings->input_norm,
                                                                                           "decode input RMSNorm",
                                                                                           error,
                                                                                           error_size);
        const uocr_metal_decoder_binding *post_norm = metal_require_decoder_binding_index(ctx,
                                                                                          layer_bindings->post_attn_norm,
                                                                                          "decode post-attention RMSNorm",
                                                                                          error,
                                                                                          error_size);
        const uocr_metal_decoder_binding *q_weight = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->q_proj,
                                                                                         "decode attention q_proj",
                                                                                         error,
                                                                                         error_size);
        const uocr_metal_decoder_binding *k_weight = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->k_proj,
                                                                                         "decode attention k_proj",
                                                                                         error,
                                                                                         error_size);
        const uocr_metal_decoder_binding *v_weight = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->v_proj,
                                                                                         "decode attention v_proj",
                                                                                         error,
                                                                                         error_size);
        const uocr_metal_decoder_binding *o_weight = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->o_proj,
                                                                                         "decode attention o_proj",
                                                                                         error,
                                                                                         error_size);
        if (input_norm == NULL || post_norm == NULL || q_weight == NULL || k_weight == NULL || v_weight == NULL || o_weight == NULL) {
            return 0;
        }

        RUN_DECODE_TIMED("metal.decode.attention_norm",
                         metal_run_rmsnorm_buffer_f16(ctx,
                                                      current,
                                                      input_norm,
                                                      1u,
                                                      norm,
                                                      "integrated decode input RMSNorm",
                                                      error,
                                                      error_size));
        RUN_DECODE_TIMED("metal.decode.attention_projections",
                         metal_run_attention_qkv_buffer_f16(ctx,
                                                            norm,
                                                            q_weight,
                                                            k_weight,
                                                            v_weight,
                                                            1u,
                                                            q,
                                                            k,
                                                            v,
                                                            error,
                                                            error_size));
        RUN_DECODE_TIMED("metal.decode.rope",
                         metal_run_rope_qk_buffer_f16(ctx, q, k, 1u, position, error, error_size));
        RUN_DECODE_TIMED("metal.decode.kv_write",
                         metal_run_kv_write_buffer_f16(ctx,
                                                       k,
                                                       v,
                                                       1u,
                                                       layer,
                                                       slot,
                                                       prompt_length,
                                                       position,
                                                       error,
                                                       error_size));
        RUN_DECODE_TIMED("metal.decode.attention",
                         metal_run_decode_attention_buffer_f16(ctx,
                                                               q,
                                                               layer,
                                                               slot,
                                                               prompt_length,
                                                               generated_count_after_write,
                                                               norm,
                                                               error,
                                                               error_size));
        RUN_DECODE_TIMED("metal.decode.attention_projections",
                         metal_run_attention_output_residual_buffer_f16(ctx,
                                                                        norm,
                                                                        o_weight,
                                                                        current,
                                                                        1u,
                                                                        q,
                                                                        error,
                                                                        error_size));
        RUN_DECODE_TIMED("metal.decode.post_attention_norm",
                         metal_run_rmsnorm_buffer_f16(ctx,
                                                      q,
                                                      post_norm,
                                                      1u,
                                                      norm,
                                                      "integrated decode post-attention RMSNorm",
                                                      error,
                                                      error_size));

        if (layer == 0u) {
            const uocr_metal_decoder_binding *gate = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->dense_gate,
                                                                                         "decode layer0 dense gate",
                                                                                         error,
                                                                                         error_size);
            const uocr_metal_decoder_binding *up = metal_require_decoder_binding_index(ctx,
                                                                                       layer_bindings->dense_up,
                                                                                       "decode layer0 dense up",
                                                                                       error,
                                                                                       error_size);
            const uocr_metal_decoder_binding *down = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->dense_down,
                                                                                         "decode layer0 dense down",
                                                                                         error,
                                                                                         error_size);
            const uint64_t mid_bytes = (uint64_t)UOCR_DENSE_LAYER0_INTERMEDIATE * 2u;
            uocr_metal_buffer_slice mid;
            if (gate == NULL || up == NULL || down == NULL) {
                return 0;
            }
            if (!metal_moe_intermediate_slice(ctx, slot, mid_bytes, &mid)) {
                return metal_fail(error, error_size, "integrated decode layer0 dense MLP intermediate slice is invalid");
            }
            RUN_DECODE_TIMED("metal.decode.dense_mlp",
                             metal_run_dense_swiglu_buffer_f16(ctx,
                                                               norm,
                                                               gate,
                                                               up,
                                                               down,
                                                               q,
                                                               1,
                                                               1u,
                                                               UOCR_DENSE_LAYER0_INTERMEDIATE,
                                                               mid,
                                                               output,
                                                               "integrated decode layer0 dense SwiGLU",
                                                               error,
                                                               error_size));
        } else {
            const uocr_metal_decoder_binding *router = metal_require_decoder_binding_index(ctx,
                                                                                           layer_bindings->moe_router,
                                                                                           "decode MoE router",
                                                                                           error,
                                                                                           error_size);
            const uocr_metal_decoder_binding *shared_gate = metal_require_decoder_binding_index(ctx,
                                                                                                layer_bindings->moe_shared_gate,
                                                                                                "decode MoE shared gate",
                                                                                                error,
                                                                                                error_size);
            const uocr_metal_decoder_binding *shared_up = metal_require_decoder_binding_index(ctx,
                                                                                              layer_bindings->moe_shared_up,
                                                                                              "decode MoE shared up",
                                                                                              error,
                                                                                              error_size);
            const uocr_metal_decoder_binding *shared_down = metal_require_decoder_binding_index(ctx,
                                                                                                layer_bindings->moe_shared_down,
                                                                                                "decode MoE shared down",
                                                                                                error,
                                                                                                error_size);
            uocr_metal_buffer_slice top_ids;
            uocr_metal_buffer_slice top_weights;
            uocr_metal_buffer_slice expert_slab;
            const uint64_t shared_mid_bytes = (uint64_t)UOCR_MOE_SHARED_INTERMEDIATE * 2u;
            const uint64_t routed_mid_bytes = (uint64_t)UOCR_MOE_TOP_K * (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE * 2u;
            uocr_metal_buffer_slice mid;
            if (router == NULL || shared_gate == NULL || shared_up == NULL || shared_down == NULL) {
                return 0;
            }
            RUN_DECODE_TIMED("metal.decode.moe_router",
                             metal_run_moe_router_buffer_f16(ctx,
                                                             norm,
                                                             router,
                                                             slot,
                                                             1u,
                                                             &top_ids,
                                                             &top_weights,
                                                             error,
                                                             error_size));
            if (!metal_moe_intermediate_slice(ctx, slot, shared_mid_bytes, &mid)) {
                return metal_fail(error, error_size, "integrated decode MoE shared intermediate slice is invalid");
            }
            RUN_DECODE_TIMED("metal.decode.moe_shared_experts",
                             metal_run_dense_swiglu_buffer_f16(ctx,
                                                               norm,
                                                               shared_gate,
                                                               shared_up,
                                                               shared_down,
                                                               q,
                                                               0,
                                                               1u,
                                                               UOCR_MOE_SHARED_INTERMEDIATE,
                                                               mid,
                                                               v,
                                                               "integrated decode MoE shared experts",
                                                               error,
                                                               error_size));
            RUN_DECODE_TIMED("metal.decode.moe_expert_slab",
                             metal_expert_interleaved_slab_for_layer(ctx, layer, &expert_slab, error, error_size));
            if (!metal_moe_intermediate_slice(ctx, slot, routed_mid_bytes, &mid)) {
                return metal_fail(error, error_size, "integrated decode MoE routed intermediate slice is invalid");
            }
            RUN_DECODE_TIMED("metal.decode.moe_routed_experts",
                             metal_run_moe_interleaved_buffer_f16(ctx,
                                                                  norm,
                                                                  top_ids,
                                                                  top_weights,
                                                                  expert_slab,
                                                                  slot,
                                                                  1u,
                                                                  mid,
                                                                  current,
                                                                  error,
                                                                  error_size));
            RUN_DECODE_TIMED("metal.decode.moe_combine",
                             metal_run_moe_combine_buffer_f16(ctx, current, v, q, 1u, output, error, error_size));
        }

        current = output;
        current_segment = output_segment;
        metal_profile_add_event_now(ctx, "metal.decode.layer", layer_start_ns);
        metal_profile_add_event_now(ctx, "metal.decode.layer_kernels", layer_start_ns);
        metal_profile_add_event_now_f(ctx, layer_start_ns, "metal.decode.layer.%02u", layer);
    }

    if (current_segment != 0u) {
        RUN_DECODE_TIMED("metal.decode.final_hidden_copy",
                         metal_copy_slice(ctx,
                                          current,
                                          scratch[0],
                                          hidden_bytes,
                                          "integrated decode final-hidden copy",
                                          error,
                                          error_size));
    }
#undef RUN_DECODE_TIMED
    return 1;
}

static int metal_run_decoder_prefill_text_f16(uocr_metal_context *ctx,
                                              uint32_t slot,
                                              uint32_t n_tokens,
                                              char *error,
                                              size_t error_size) {
    uocr_metal_buffer_slice prompt;
    uint64_t hidden_bytes = 0u;
    if (!metal_prompt_arena_slice(ctx, slot, n_tokens, &prompt, &hidden_bytes)) {
        return metal_fail(error, error_size, "integrated prefill requires a valid prompt arena slice");
    }

    uocr_metal_buffer_slice scratch[UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS];
    for (uint32_t i = 0u; i < UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS; ++i) {
        uint64_t bytes = 0u;
        if (!metal_hidden_arena_segment_slice(ctx, slot, i, n_tokens, &scratch[i], &bytes) || bytes != hidden_bytes) {
            return metal_fail(error, error_size, "integrated prefill requires hidden scratch segment %u", i);
        }
    }

    const uint64_t prefill_command_encoding_start_ns = uocr_profile_now_ns();
    if (!metal_command_batch_begin(ctx, error, error_size)) {
        return 0;
    }

    uocr_metal_buffer_slice current = prompt;
    uint32_t current_segment = UINT32_MAX;
    for (uint32_t layer = 0u; layer < UOCR_DECODER_LAYERS; ++layer) {
        const uint64_t layer_start_ns = uocr_profile_now_ns();
        uint32_t available[UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS];
        uint32_t available_count = 0u;
        for (uint32_t i = 0u; i < UOCR_METAL_HIDDEN_SCRATCH_SEGMENTS; ++i) {
            if (i != current_segment) {
                available[available_count++] = i;
            }
        }
        if (available_count < 4u) {
            return metal_fail(error, error_size, "integrated prefill scratch assignment failed at layer %u", layer);
        }
        const uint32_t norm_segment = available[0];
        const uint32_t q_segment = available[1];
        const uint32_t k_segment = available[2];
        const uint32_t v_segment = available[3];
        uocr_metal_buffer_slice norm = scratch[norm_segment];
        uocr_metal_buffer_slice q = scratch[q_segment];
        uocr_metal_buffer_slice k = scratch[k_segment];
        uocr_metal_buffer_slice v = scratch[v_segment];
        uocr_metal_buffer_slice output = k;
        const uint32_t output_segment = k_segment;

        char label[64];
        snprintf(label, sizeof(label), "layer%u input RMSNorm", layer);
        const uocr_metal_decoder_layer_binding_cache *layer_bindings = &ctx->decoder_bindings.layers[layer];
        const uocr_metal_decoder_binding *input_norm = metal_require_decoder_binding_index(ctx,
                                                                                           layer_bindings->input_norm,
                                                                                           label,
                                                                                           error,
                                                                                           error_size);
        const uocr_metal_decoder_binding *post_norm = metal_require_decoder_binding_index(ctx,
                                                                                          layer_bindings->post_attn_norm,
                                                                                          "post-attention norm",
                                                                                          error,
                                                                                          error_size);
        const uocr_metal_decoder_binding *q_weight = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->q_proj,
                                                                                         "attention q_proj",
                                                                                         error,
                                                                                         error_size);
        const uocr_metal_decoder_binding *k_weight = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->k_proj,
                                                                                         "attention k_proj",
                                                                                         error,
                                                                                         error_size);
        const uocr_metal_decoder_binding *v_weight = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->v_proj,
                                                                                         "attention v_proj",
                                                                                         error,
                                                                                         error_size);
        const uocr_metal_decoder_binding *o_weight = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->o_proj,
                                                                                         "attention o_proj",
                                                                                         error,
                                                                                         error_size);
        if (input_norm == NULL || post_norm == NULL || q_weight == NULL || k_weight == NULL || v_weight == NULL || o_weight == NULL) {
            return 0;
        }

        if (!metal_run_rmsnorm_buffer_f16(ctx, current, input_norm, n_tokens, norm, "integrated input RMSNorm", error, error_size) ||
            !metal_run_attention_qkv_buffer_f16(ctx, norm, q_weight, k_weight, v_weight, n_tokens, q, k, v, error, error_size) ||
            !metal_run_rope_qk_buffer_f16(ctx, q, k, n_tokens, 0u, error, error_size) ||
            !metal_run_kv_write_buffer_f16(ctx, k, v, n_tokens, layer, slot, n_tokens, 0u, error, error_size) ||
            !metal_run_prefill_attention_buffer_f16(ctx, q, k, v, n_tokens, norm, error, error_size) ||
            !metal_run_attention_output_residual_buffer_f16(ctx, norm, o_weight, current, n_tokens, q, error, error_size) ||
            !metal_run_rmsnorm_buffer_f16(ctx, q, post_norm, n_tokens, norm, "integrated post-attention RMSNorm", error, error_size)) {
            return 0;
        }

        if (layer == 0u) {
            const uocr_metal_decoder_binding *gate = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->dense_gate,
                                                                                         "layer0 dense gate",
                                                                                         error,
                                                                                         error_size);
            const uocr_metal_decoder_binding *up = metal_require_decoder_binding_index(ctx,
                                                                                       layer_bindings->dense_up,
                                                                                       "layer0 dense up",
                                                                                       error,
                                                                                       error_size);
            const uocr_metal_decoder_binding *down = metal_require_decoder_binding_index(ctx,
                                                                                         layer_bindings->dense_down,
                                                                                         "layer0 dense down",
                                                                                         error,
                                                                                         error_size);
            const uint64_t mid_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_DENSE_LAYER0_INTERMEDIATE * 2u;
            uocr_metal_buffer_slice mid;
            if (gate == NULL || up == NULL || down == NULL ||
                !metal_moe_intermediate_slice(ctx, slot, mid_bytes, &mid) ||
                !metal_run_dense_swiglu_buffer_f16(ctx,
                                                   norm,
                                                   gate,
                                                   up,
                                                   down,
                                                   q,
                                                   1,
                                                   n_tokens,
                                                   UOCR_DENSE_LAYER0_INTERMEDIATE,
                                                   mid,
                                                   output,
                                                   "integrated layer0 dense SwiGLU",
                                                   error,
                                                   error_size)) {
                return 0;
            }
        } else {
            const uocr_metal_decoder_binding *router = metal_require_decoder_binding_index(ctx,
                                                                                           layer_bindings->moe_router,
                                                                                           "MoE router",
                                                                                           error,
                                                                                           error_size);
            const uocr_metal_decoder_binding *shared_gate = metal_require_decoder_binding_index(ctx,
                                                                                                layer_bindings->moe_shared_gate,
                                                                                                "MoE shared gate",
                                                                                                error,
                                                                                                error_size);
            const uocr_metal_decoder_binding *shared_up = metal_require_decoder_binding_index(ctx,
                                                                                              layer_bindings->moe_shared_up,
                                                                                              "MoE shared up",
                                                                                              error,
                                                                                              error_size);
            const uocr_metal_decoder_binding *shared_down = metal_require_decoder_binding_index(ctx,
                                                                                                layer_bindings->moe_shared_down,
                                                                                                "MoE shared down",
                                                                                                error,
                                                                                                error_size);
            uocr_metal_buffer_slice top_ids;
            uocr_metal_buffer_slice top_weights;
            uocr_metal_buffer_slice expert_slab;
            const uint64_t shared_mid_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_SHARED_INTERMEDIATE * 2u;
            const uint64_t routed_mid_bytes = (uint64_t)n_tokens * (uint64_t)UOCR_MOE_TOP_K *
                                              (uint64_t)UOCR_MOE_EXPERT_INTERMEDIATE * 2u;
            uocr_metal_buffer_slice mid;
            if (router == NULL || shared_gate == NULL || shared_up == NULL || shared_down == NULL ||
                !metal_run_moe_router_buffer_f16(ctx, norm, router, slot, n_tokens, &top_ids, &top_weights, error, error_size) ||
                !metal_moe_intermediate_slice(ctx, slot, shared_mid_bytes, &mid) ||
                !metal_run_dense_swiglu_buffer_f16(ctx,
                                                   norm,
                                                   shared_gate,
                                                   shared_up,
                                                   shared_down,
                                                   q,
                                                   0,
                                                   n_tokens,
                                                   UOCR_MOE_SHARED_INTERMEDIATE,
                                                   mid,
                                                   v,
                                                   "integrated MoE shared experts",
                                                   error,
                                                   error_size) ||
                !metal_expert_interleaved_slab_for_layer(ctx, layer, &expert_slab, error, error_size) ||
                !metal_moe_intermediate_slice(ctx, slot, routed_mid_bytes, &mid) ||
                !metal_run_moe_interleaved_buffer_f16(ctx,
                                                      norm,
                                                      top_ids,
                                                      top_weights,
                                                      expert_slab,
                                                      slot,
                                                      n_tokens,
                                                      mid,
                                                      current,
                                                      error,
                                                      error_size) ||
                !metal_run_moe_combine_buffer_f16(ctx, current, v, q, n_tokens, output, error, error_size)) {
                return 0;
            }
        }

        current = output;
        current_segment = output_segment;
        metal_profile_add_event_now(ctx, "metal.prefill.layer", layer_start_ns);
        metal_profile_add_event_now_f(ctx, layer_start_ns, "metal.prefill.layer.%02u", layer);
    }

    if (current_segment != 0u) {
        if (!metal_copy_slice(ctx, current, scratch[0], hidden_bytes, "integrated prefill final-hidden copy", error, error_size)) {
            return 0;
        }
        current_segment = 0u;
    }
    metal_profile_add_event_now(ctx, "metal.prefill.command_encoding", prefill_command_encoding_start_ns);
    const uint64_t prefill_command_wait_start_ns = uocr_profile_now_ns();
    if (!metal_command_batch_commit_and_wait(ctx, "integrated decoder prefill batch", error, error_size)) {
        ctx->has_integrated_prefill = 0;
        return 0;
    }
    metal_profile_add_event_now(ctx, "metal.prefill.command_wait", prefill_command_wait_start_ns);
    ctx->has_integrated_prefill = 1;
    ctx->integrated_prefill_slot = slot;
    ctx->integrated_prefill_tokens = n_tokens;
    ctx->integrated_prefill_final_segment = current_segment;
    return 1;
}

static int metal_context_generate_f16_impl(uocr_metal_context *ctx,
                                           const uocr_metal_decoder_request_f16 *request,
                                           id<MTLBuffer> image_features_buffer,
                                           NSUInteger image_features_offset,
                                           uocr_metal_decoder_result_f16 *result,
                                           char *error,
                                           size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || request == NULL || result == NULL) {
        return metal_fail(error, error_size, "invalid Metal integrated decoder request");
    }
    metal_decoder_result_reset(result);

    if (!metal_decoder_runtime_arenas_ready(ctx)) {
        return metal_fail(error, error_size, "Metal integrated decoder requires allocated runtime arenas");
    }
    if (!uocr_metal_context_decoder_bindings_ready(ctx) ||
        ctx->decoder_bindings.token_embedding == UOCR_METAL_DECODER_BINDING_INDEX_INVALID ||
        ctx->decoder_bindings.final_norm == UOCR_METAL_DECODER_BINDING_INDEX_INVALID ||
        ctx->decoder_bindings.lm_head == UOCR_METAL_DECODER_BINDING_INDEX_INVALID) {
        const char *binding_error = ctx->decoder_binding_error[0] != '\0' ?
                                        ctx->decoder_binding_error :
                                        "decoder tensor bindings are not validated";
        return metal_fail(error,
                          error_size,
                          "Metal integrated decoder requires validated fp16 decoder tensor bindings: %s",
                          binding_error);
    }
    if (request->input_ids == NULL || request->image_mask == NULL || request->n_tokens == 0u) {
        return metal_fail(error, error_size, "Metal integrated decoder requires input ids, image mask, and prompt tokens");
    }
    if (request->slot >= ctx->kv_cache_layout.batch_slots) {
        return metal_fail(error,
                          error_size,
                          "Metal integrated decoder slot %u exceeds allocated batch slots %u",
                          request->slot,
                          ctx->kv_cache_layout.batch_slots);
    }
    metal_integrated_decoder_state_reset(ctx, request->slot);

    if (request->n_tokens > ctx->kv_cache_layout.prompt_token_capacity) {
        return metal_fail(error,
                          error_size,
                          "Metal integrated decoder prompt length %u exceeds prompt arena capacity %u",
                          request->n_tokens,
                          ctx->kv_cache_layout.prompt_token_capacity);
    }
    if (request->n_tokens > UOCR_MAX_POSITIONS || request->max_new_tokens > UOCR_MAX_POSITIONS - request->n_tokens) {
        return metal_fail(error, error_size, "Metal integrated decoder sequence length exceeds max positions");
    }
    if (request->no_repeat_ngram_size == 0u && request->no_repeat_window != 0u) {
        return metal_fail(error, error_size, "Metal integrated decoder no_repeat_window is set but no_repeat_ngram_size is zero");
    }
    if (request->no_repeat_ngram_size > UOCR_MAX_POSITIONS || request->no_repeat_window > UOCR_MAX_POSITIONS) {
        return metal_fail(error, error_size, "Metal integrated decoder no-repeat configuration exceeds max positions");
    }
    if (request->max_new_tokens > 0u &&
        (result->generated_ids == NULL || result->generated_capacity < request->max_new_tokens)) {
        return metal_fail(error,
                          error_size,
                          "Metal integrated decoder generated-token output capacity %u is smaller than requested %u",
                          result->generated_capacity,
                          request->max_new_tokens);
    }

    uint32_t image_mask_count = 0u;
    for (uint32_t i = 0u; i < request->n_tokens; ++i) {
        if (request->input_ids[i] < 0 || (uint32_t)request->input_ids[i] >= UOCR_VOCAB_SIZE) {
            return metal_fail(error,
                              error_size,
                              "Metal integrated decoder token id %d at position %u is outside vocab %u",
                              request->input_ids[i],
                              i,
                              UOCR_VOCAB_SIZE);
        }
        if (request->image_mask[i] > 1u) {
            return metal_fail(error,
                              error_size,
                              "Metal integrated decoder image mask value %u at position %u is not 0/1",
                              (unsigned)request->image_mask[i],
                              i);
        }
        image_mask_count += request->image_mask[i] != 0u ? 1u : 0u;
    }

    if (request->image_span_length == 0u) {
        if (request->image_span_start != UINT32_MAX || request->image_features_f16 != NULL || image_mask_count != 0u) {
            return metal_fail(error,
                              error_size,
                              "Metal integrated decoder text-only requests must use UINT32_MAX image span, no image features, and an empty image mask");
        }
    } else {
        if ((request->image_features_f16 == NULL && image_features_buffer == nil) ||
            request->image_span_start == UINT32_MAX ||
            request->image_span_start > request->n_tokens ||
            request->image_span_length > request->n_tokens - request->image_span_start) {
            return metal_fail(error, error_size, "Metal integrated decoder image span/features are invalid");
        }
        if (image_mask_count != request->image_span_length) {
            return metal_fail(error,
                              error_size,
                              "Metal integrated decoder image mask count %u does not match image span length %u",
                              image_mask_count,
                              request->image_span_length);
        }
        for (uint32_t i = 0u; i < request->image_span_length; ++i) {
            const uint32_t pos = request->image_span_start + i;
            if (request->image_mask[pos] == 0u) {
                return metal_fail(error,
                                  error_size,
                                  "Metal integrated decoder image span position %u is not marked in image mask",
                                  pos);
            }
        }
    }

    const uint64_t pipeline_prewarm_start_ns = uocr_profile_now_ns();
    if (!metal_prewarm_integrated_decoder_pipelines(ctx, error, error_size)) {
        char detail[512];
        (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
        return metal_fail(error, error_size, "failed to prepare integrated Metal fp16 decoder pipelines: %s", detail);
    }
    metal_profile_add_event_now(ctx, "metal.pipeline_prewarm", pipeline_prewarm_start_ns);

    if (!metal_prebuild_mps_runtime_workspace_ndarrays(ctx, request->n_tokens, error, error_size)) {
        return 0;
    }

    if (!metal_command_batch_begin(ctx, error, error_size)) {
        return 0;
    }

    const uint64_t prompt_assembly_start_ns = uocr_profile_now_ns();
    if (!metal_context_assemble_prompt_from_model_to_arena_f16(ctx,
                                                               request->input_ids,
                                                               request->n_tokens,
                                                               request->image_span_length != 0u ? request->image_span_start : UINT32_MAX,
                                                               request->image_span_length,
                                                               request->image_features_f16,
                                                               image_features_buffer,
                                                               image_features_offset,
                                                               request->slot,
                                                               error,
                                                               error_size)) {
        char detail[512];
        (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
        metal_command_batch_abort(ctx);
        return metal_fail(error, error_size, "failed to assemble integrated prompt into Metal prefill graph: %s", detail);
    }
    metal_profile_add_event_now(ctx, "metal.prompt_assembly", prompt_assembly_start_ns);
    metal_profile_add_event_now(ctx, "metal.prefill.prompt_assembly", prompt_assembly_start_ns);

    const uocr_metal_hot_path_alloc_guard prefill_guard =
        metal_hot_path_alloc_guard_begin(ctx);
    char prefill_error[512];
    prefill_error[0] = '\0';
    const uint64_t prefill_start_ns = uocr_profile_now_ns();
    const int prefill_ok = metal_run_decoder_prefill_text_f16(ctx,
                                                             request->slot,
                                                             request->n_tokens,
                                                             prefill_error,
                                                             sizeof(prefill_error));
    if (!metal_hot_path_alloc_guard_end(ctx,
                                        &prefill_guard,
                                        "integrated Metal fp16 prompt prefill",
                                        error,
                                        error_size)) {
        metal_command_batch_abort(ctx);
        ctx->has_integrated_prefill = 0;
        return 0;
    }
    if (!prefill_ok) {
        metal_command_batch_abort(ctx);
        ctx->has_integrated_prefill = 0;
        return metal_fail(error,
                          error_size,
                          "integrated Metal fp16 prompt prefill failed: %s",
                          prefill_error[0] != '\0' ? prefill_error : "unknown error");
    }
    metal_profile_add_event_now(ctx, "metal.prefill", prefill_start_ns);

    if (request->max_new_tokens == 0u) {
        metal_clear_error(error, error_size);
        return 1;
    }

    uocr_prepared_request sequence_request;
    memset(&sequence_request, 0, sizeof(sequence_request));
    sequence_request.input_ids = request->input_ids;
    sequence_request.image_mask = request->image_mask;
    sequence_request.n_tokens = request->n_tokens;
    sequence_request.max_new_tokens = request->max_new_tokens;
    sequence_request.no_repeat_ngram_size = request->no_repeat_ngram_size;
    sequence_request.no_repeat_window = request->no_repeat_window;

    uocr_sequence_state sequence_state;
    char sequence_error[256];
    memset(&sequence_state, 0, sizeof(sequence_state));
    memset(sequence_error, 0, sizeof(sequence_error));
    int sequence_status = uocr_build_sequence_state(&sequence_request,
                                                    &sequence_state,
                                                    sequence_error,
                                                    sizeof(sequence_error));
    if (sequence_status != UOCR_OK) {
        return metal_fail(error,
                          error_size,
                          "failed to build integrated Metal fp16 sequence state: %s",
                          sequence_error[0] != '\0' ? sequence_error : uocr_status_string(sequence_status));
    }

    uint64_t sequence_len_u64 = 0u;
    uint64_t sequence_bytes = 0u;
    if (!checked_add_u64((uint64_t)request->n_tokens, (uint64_t)request->max_new_tokens, &sequence_len_u64) ||
        sequence_len_u64 > (uint64_t)UINT32_MAX ||
        !checked_mul_u64(sequence_len_u64, (uint64_t)sizeof(int32_t), &sequence_bytes) ||
        sequence_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error, error_size, "integrated Metal fp16 decode sequence buffer size overflow");
    }
    int32_t *sequence = (int32_t *)uocr_malloc((size_t)sequence_bytes);
    if (sequence == NULL) {
        return metal_fail(error, error_size, "failed to allocate integrated Metal fp16 decode sequence buffer");
    }
    sequence_status = uocr_sequence_attach_generation_buffers(&sequence_state,
                                                             result->generated_ids,
                                                             result->generated_capacity,
                                                             sequence,
                                                             (uint32_t)sequence_len_u64);
    if (sequence_status != UOCR_OK) {
        uocr_free(sequence);
        return metal_fail(error,
                          error_size,
                          "failed to attach integrated Metal fp16 generation buffers: %s",
                          uocr_status_string(sequence_status));
    }

    uint64_t selection_scratch_bytes = 0u;
    if (!checked_mul_u64(metal_decode_selection_scratch_bytes_per_slot(),
                         (uint64_t)ctx->kv_cache_layout.batch_slots,
                         &selection_scratch_bytes) ||
        !uocr_metal_context_ensure_scratch(ctx,
                                           UOCR_METAL_SCRATCH_LOGITS,
                                           selection_scratch_bytes,
                                           0,
                                           error,
                                           error_size)) {
        uocr_free(sequence);
        return metal_fail(error, error_size, "integrated Metal fp16 decode selection scratch allocation failed");
    }

    uocr_metal_buffer_slice selection_scratch;
    uocr_metal_buffer_slice token_slot;
    uocr_metal_buffer_slice score_slot;
    uocr_metal_buffer_slice norm_scratch;
    uint64_t one_hidden_bytes = 0u;
    if (!metal_decode_selection_scratch_slice(ctx, request->slot, &selection_scratch) ||
        !metal_token_readback_arena_slices(ctx, request->slot, &token_slot, &score_slot) ||
        !metal_hidden_arena_segment_slice(ctx, request->slot, 1u, 1u, &norm_scratch, &one_hidden_bytes) ||
        one_hidden_bytes != (uint64_t)UOCR_HIDDEN_SIZE * 2u) {
        uocr_free(sequence);
        return metal_fail(error, error_size, "integrated Metal fp16 decode arena slices are invalid");
    }

    uocr_metal_buffer_slice no_repeat_sequence;
    uint64_t no_repeat_sequence_bytes = 0u;
    if (!metal_no_repeat_sequence_slice(ctx,
                                        request->slot,
                                        (uint32_t)sequence_len_u64,
                                        &no_repeat_sequence,
                                        &no_repeat_sequence_bytes)) {
        uocr_free(sequence);
        return metal_fail(error, error_size, "integrated Metal fp16 no-repeat sequence buffer is invalid");
    }
    uocr_metal_buffer_slice prompt_token_ids;
    uint64_t prompt_token_ids_bytes = 0u;
    if (!metal_prompt_token_ids_slice(ctx, request->slot, request->n_tokens, &prompt_token_ids, &prompt_token_ids_bytes) ||
        prompt_token_ids_bytes != (uint64_t)request->n_tokens * (uint64_t)sizeof(int32_t)) {
        uocr_free(sequence);
        return metal_fail(error, error_size, "integrated Metal fp16 prompt token-id slice is invalid");
    }
    const uint64_t no_repeat_init_start_ns = uocr_profile_now_ns();
    if (!metal_copy_slice(ctx,
                          prompt_token_ids,
                          no_repeat_sequence,
                          prompt_token_ids_bytes,
                          "integrated no-repeat sequence init",
                          error,
                          error_size)) {
        uocr_free(sequence);
        return 0;
    }
    metal_profile_add_event_now(ctx, "metal.decode.no_repeat_sequence_init", no_repeat_init_start_ns);
    (void)no_repeat_sequence_bytes;

    uocr_metal_buffer_slice hidden_for_selection;
    if (!metal_hidden_arena_token_slice(ctx,
                                        request->slot,
                                        ctx->integrated_prefill_final_segment,
                                        request->n_tokens - 1u,
                                        &hidden_for_selection)) {
        uocr_free(sequence);
        return metal_fail(error, error_size, "integrated Metal fp16 prefill final-token hidden slice is invalid");
    }

    const uocr_metal_hot_path_alloc_guard decode_loop_guard =
        metal_hot_path_alloc_guard_begin(ctx);
    const uint64_t decode_loop_start_ns = uocr_profile_now_ns();
    int decode_loop_ok = 1;
    char decode_loop_error[512];
    decode_loop_error[0] = '\0';

#define UOCR_METAL_DECODE_LOOP_FAIL(...)                    \
    do {                                                    \
        (void)snprintf(decode_loop_error,                   \
                       sizeof(decode_loop_error),           \
                       __VA_ARGS__);                        \
        decode_loop_ok = 0;                                 \
        goto decode_loop_done;                              \
    } while (0)

    while (!uocr_sequence_generation_done(&sequence_state)) {
        const uint64_t decode_iteration_start_ns = uocr_profile_now_ns();
        const uint64_t selection_command_encoding_start_ns = uocr_profile_now_ns();
        if (!metal_command_batch_begin(ctx, error, error_size)) {
            char detail[512];
            (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
            UOCR_METAL_DECODE_LOOP_FAIL("integrated Metal fp16 decode command batch begin failed: %s", detail);
        }
        metal_profile_add_event_now(ctx, "metal.decode.command_encoding", selection_command_encoding_start_ns);
        uint32_t token_id = UINT32_MAX;
        float score = 0.0f;
        uocr_no_repeat_ngram_config no_repeat_config;
        const uint64_t no_repeat_state_start_ns = uocr_profile_now_ns();
        const int no_repeat_status = uocr_sequence_no_repeat_config(&sequence_state, &no_repeat_config);
        if (no_repeat_status != UOCR_OK) {
            UOCR_METAL_DECODE_LOOP_FAIL("integrated Metal fp16 no-repeat state is invalid: %s",
                                        uocr_status_string(no_repeat_status));
        }
        metal_profile_add_event_now(ctx, "metal.no_repeat_state", no_repeat_state_start_ns);
        metal_profile_add_event_now(ctx, "metal.decode.no_repeat_state", no_repeat_state_start_ns);
        const uint64_t token_selection_start_ns = uocr_profile_now_ns();
        const uocr_metal_hot_path_alloc_guard token_selection_guard = metal_hot_path_alloc_guard_begin(ctx);
        const int token_selection_ok = metal_select_next_token_from_hidden_slice_f16(ctx,
                                                                                    hidden_for_selection,
                                                                                    norm_scratch,
                                                                                    selection_scratch,
                                                                                    token_slot,
                                                                                    score_slot,
                                                                                    no_repeat_sequence,
                                                                                    no_repeat_config.sequence != NULL ? no_repeat_config.sequence_len : sequence_state.token_history_count,
                                                                                    no_repeat_config.ngram_size,
                                                                                    no_repeat_config.window,
                                                                                    &token_id,
                                                                                    &score,
                                                                                    error,
                                                                                    error_size);
        if (!metal_hot_path_alloc_guard_end(ctx,
                                            &token_selection_guard,
                                            "integrated Metal fp16 token-selection hot path",
                                            error,
                                            error_size)) {
            char detail[512];
            (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
            UOCR_METAL_DECODE_LOOP_FAIL("integrated Metal fp16 token-selection hot path guard failed: %s", detail);
        }
        if (!token_selection_ok) {
            char detail[512];
            (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
            UOCR_METAL_DECODE_LOOP_FAIL("integrated Metal fp16 next-token selection failed: %s", detail);
        }
        metal_profile_add_event_now(ctx, "metal.next_token_selection", token_selection_start_ns);
        if (sequence_state.generated_count == 0u) {
            metal_profile_add_event_now(ctx, "metal.first_token", token_selection_start_ns);
        }
        if (token_id >= UOCR_VOCAB_SIZE) {
            UOCR_METAL_DECODE_LOOP_FAIL("integrated Metal fp16 selected invalid token id %u", token_id);
        }

        const uint64_t cpu_sequence_update_start_ns = uocr_profile_now_ns();
        const uint32_t generated_index = sequence_state.generated_count;
        const int accept_status = uocr_sequence_accept_generated_token(&sequence_state, (int32_t)token_id, NULL, 0u);
        if (accept_status != UOCR_OK) {
            UOCR_METAL_DECODE_LOOP_FAIL("integrated Metal fp16 generated-token state update failed: %s",
                                        uocr_status_string(accept_status));
        }
        if (result->generated_scores_f32_or_null != NULL) {
            result->generated_scores_f32_or_null[generated_index] = score;
        }
        result->generated_count = sequence_state.generated_count;
        result->last_token_id = token_id;
        result->last_score_f32 = score;
        if (sequence_state.token_history_count == 0u || sequence_state.token_history_count > (uint32_t)sequence_len_u64) {
            UOCR_METAL_DECODE_LOOP_FAIL("integrated Metal fp16 no-repeat sequence append index is invalid");
        }
        metal_profile_add_event_now(ctx, "metal.decode.cpu_sequence_update", cpu_sequence_update_start_ns);
        if (sequence_state.eos) {
            result->stopped_on_eos = 1u;
            break;
        }
        if (uocr_sequence_generation_done(&sequence_state)) {
            metal_profile_add_event_now(ctx, "metal.decode_iteration", decode_iteration_start_ns);
            break;
        }

        metal_profile_add_event_ms(ctx, "metal.decode.token_slot_reuse", 0.0);
        const uint64_t decode_command_encoding_start_ns = uocr_profile_now_ns();
        if (!metal_command_batch_begin(ctx, error, error_size)) {
            char detail[512];
            (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
            UOCR_METAL_DECODE_LOOP_FAIL("integrated Metal fp16 decode command batch begin failed: %s", detail);
        }
        metal_profile_add_event_now(ctx, "metal.decode.command_encoding", decode_command_encoding_start_ns);
        const uint64_t no_repeat_append_start_ns = uocr_profile_now_ns();
        uocr_metal_buffer_slice no_repeat_append = no_repeat_sequence;
        uint64_t no_repeat_append_offset = 0u;
        if (!checked_mul_u64((uint64_t)(sequence_state.token_history_count - 1u),
                             (uint64_t)sizeof(int32_t),
                             &no_repeat_append_offset) ||
            no_repeat_append_offset > (uint64_t)NSUIntegerMax ||
            no_repeat_append.offset > NSUIntegerMax - (NSUInteger)no_repeat_append_offset) {
            UOCR_METAL_DECODE_LOOP_FAIL("integrated Metal fp16 no-repeat sequence append offset is invalid");
        }
        no_repeat_append.offset += (NSUInteger)no_repeat_append_offset;
        if (!metal_copy_slice(ctx,
                              token_slot,
                              no_repeat_append,
                              (uint64_t)sizeof(int32_t),
                              "integrated no-repeat sequence append",
                              error,
                              error_size)) {
            char detail[512];
            (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
            UOCR_METAL_DECODE_LOOP_FAIL("integrated Metal fp16 no-repeat sequence append failed: %s", detail);
        }
        metal_profile_add_event_now(ctx, "metal.decode.no_repeat_sequence_append", no_repeat_append_start_ns);
        const uint64_t decode_step_start_ns = uocr_profile_now_ns();
        uocr_metal_buffer_slice decode_input;
        uint64_t decode_input_bytes = 0u;
        if (!metal_hidden_arena_segment_slice(ctx, request->slot, 0u, 1u, &decode_input, &decode_input_bytes) ||
            decode_input_bytes != (uint64_t)UOCR_HIDDEN_SIZE * 2u) {
            UOCR_METAL_DECODE_LOOP_FAIL("integrated Metal fp16 generated-token embedding slice is invalid");
        }
        const uint64_t token_embedding_start_ns = uocr_profile_now_ns();
        if (!metal_run_token_embedding_from_token_slot_f16(ctx, token_slot, decode_input, error, error_size)) {
            char detail[512];
            (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
            UOCR_METAL_DECODE_LOOP_FAIL("integrated Metal fp16 generated-token embedding failed: %s", detail);
        }
        metal_profile_add_event_now(ctx, "metal.decode.token_embedding", token_embedding_start_ns);
        if (!metal_run_decoder_decode_one_f16(ctx,
                                              request->slot,
                                              request->n_tokens,
                                              sequence_state.generated_count,
                                              error,
                                              error_size)) {
            char detail[512];
            (void)snprintf(detail, sizeof(detail), "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
            UOCR_METAL_DECODE_LOOP_FAIL("integrated Metal fp16 decode step failed: %s", detail);
        }
        if (!metal_hidden_arena_segment_slice(ctx, request->slot, 0u, 1u, &hidden_for_selection, &one_hidden_bytes) ||
            one_hidden_bytes != (uint64_t)UOCR_HIDDEN_SIZE * 2u) {
            UOCR_METAL_DECODE_LOOP_FAIL("integrated Metal fp16 decode hidden slice is invalid");
        }
        metal_profile_add_event_now(ctx, "metal.decode_step", decode_step_start_ns);
        metal_profile_add_event_now(ctx, "metal.decode_iteration", decode_iteration_start_ns);
    }

decode_loop_done:
#undef UOCR_METAL_DECODE_LOOP_FAIL

    if (!metal_hot_path_alloc_guard_end(ctx,
                                        &decode_loop_guard,
                                        "integrated Metal fp16 decode token loop",
                                        error,
                                        error_size)) {
        metal_command_batch_abort(ctx);
        uocr_free(sequence);
        return 0;
    }
    uocr_free(sequence);
    if (!decode_loop_ok) {
        metal_command_batch_abort(ctx);
        return metal_fail(error, error_size, "%s", decode_loop_error);
    }
    metal_profile_add_event_now(ctx, "metal.decode_loop", decode_loop_start_ns);
    metal_clear_error(error, error_size);
    return 1;
}

int uocr_metal_context_generate_f16(uocr_metal_context *ctx,
                                    const uocr_metal_decoder_request_f16 *request,
                                    uocr_metal_decoder_result_f16 *result,
                                    char *error,
                                    size_t error_size) {
    metal_public_mps_large_gemm_require_begin(ctx);
    const int ok = metal_context_generate_f16_impl(ctx,
                                                  request,
                                                  nil,
                                                  0u,
                                                  result,
                                                  error,
                                                  error_size);
    metal_public_mps_large_gemm_require_end(ctx);
    return ok;
}

static int metal_context_generate_image_f16_impl(uocr_metal_context *ctx,
                                          const uocr_prepared_request *request,
                                          uint32_t max_views_per_chunk,
                                          uint32_t slot,
                                          uocr_metal_decoder_result_f16 *result,
                                          char *error,
                                          size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || request == NULL || result == NULL) {
        return metal_fail(error, error_size, "invalid Metal image generation request");
    }
    if (!uocr_metal_context_vision_bindings_ready(ctx)) {
        return metal_fail(error,
                          error_size,
                          "Metal image generation requires validated fp16 vision tensor bindings: %s",
                          uocr_metal_context_vision_binding_error(ctx));
    }

    char detail[512];
    detail[0] = '\0';
    uocr_sequence_state sequence_state;
    memset(&sequence_state, 0, sizeof(sequence_state));
    int status = uocr_build_sequence_state(request, &sequence_state, detail, sizeof(detail));
    if (status != UOCR_OK) {
        return metal_fail(error,
                          error_size,
                          "Metal image generation sequence validation failed: %s",
                          detail[0] != '\0' ? detail : uocr_status_string(status));
    }
    if (sequence_state.image_span_start == UOCR_SEQUENCE_NO_IMAGE_SPAN || sequence_state.image_span_length == 0u) {
        return metal_fail(error, error_size, "Metal image generation requires one image span");
    }

    uocr_vision_schedule schedule;
    memset(&schedule, 0, sizeof(schedule));
    detail[0] = '\0';
    status = uocr_plan_vision_schedule(request, max_views_per_chunk, NULL, 0u, &schedule, detail, sizeof(detail));
    if (status != UOCR_OK) {
        return metal_fail(error,
                          error_size,
                          "Metal image generation vision schedule failed: %s",
                          detail[0] != '\0' ? detail : uocr_status_string(status));
    }
    if (schedule.final_visual_tokens == 0u || schedule.final_visual_tokens != sequence_state.image_span_length) {
        return metal_fail(error,
                          error_size,
                          "Metal image generation visual rows %u do not match image span length %u",
                          schedule.final_visual_tokens,
                          sequence_state.image_span_length);
    }

    uocr_metal_vision_workspace scratch;
    memset(&scratch, 0, sizeof(scratch));
    const uocr_metal_runtime_arena_guard vision_arena_guard = metal_runtime_arena_guard_begin(ctx);
    const uint64_t vision_start_ns = uocr_profile_now_ns();
    const int vision_ok = metal_context_encode_visual_features_to_workspace_f16(ctx,
                                                                                request,
                                                                                max_views_per_chunk,
                                                                                &schedule,
                                                                                &scratch,
                                                                                0,
                                                                                error,
                                                                                error_size);
    if (!metal_runtime_arena_guard_end(ctx,
                                       &vision_arena_guard,
                                       "Metal image vision hot path",
                                       error,
                                       error_size)) {
        metal_vision_workspace_reset(&scratch);
        return 0;
    }
    if (!vision_ok) {
        char vision_detail[512];
        metal_copy_error_detail(vision_detail, sizeof(vision_detail), error);
        return metal_fail(error, error_size, "Metal image vision encoding failed: %s", vision_detail);
    }
    metal_profile_add_event_now(ctx, "metal.vision", vision_start_ns);

    uocr_metal_decoder_request_f16 decoder_request;
    memset(&decoder_request, 0, sizeof(decoder_request));
    decoder_request.input_ids = request->input_ids;
    decoder_request.image_mask = request->image_mask;
    decoder_request.image_features_f16 = NULL;
    decoder_request.n_tokens = request->n_tokens;
    decoder_request.max_new_tokens = request->max_new_tokens;
    decoder_request.slot = slot;
    decoder_request.image_span_start = sequence_state.image_span_start;
    decoder_request.image_span_length = sequence_state.image_span_length;
    decoder_request.no_repeat_ngram_size = request->no_repeat_ngram_size;
    decoder_request.no_repeat_window = request->no_repeat_window;

    const uint64_t generate_start_ns = uocr_profile_now_ns();
    const int ok = metal_context_generate_f16_impl(ctx,
                                                   &decoder_request,
                                                   scratch.final_visual_rows.buffer,
                                                   scratch.final_visual_rows.offset,
                                                   result,
                                                   error,
                                                   error_size);
    if (ok) {
        metal_profile_add_event_now(ctx, "metal.image_generate", generate_start_ns);
    }
    metal_vision_workspace_reset(&scratch);
    return ok;
}

int uocr_metal_context_generate_image_f16(uocr_metal_context *ctx,
                                          const uocr_prepared_request *request,
                                          uint32_t max_views_per_chunk,
                                          uint32_t slot,
                                          uocr_metal_decoder_result_f16 *result,
                                          char *error,
                                          size_t error_size) {
    metal_public_mps_large_gemm_require_begin(ctx);
    const int ok = metal_context_generate_image_f16_impl(ctx,
                                                        request,
                                                        max_views_per_chunk,
                                                        slot,
                                                        result,
                                                        error,
                                                        error_size);
    metal_public_mps_large_gemm_require_end(ctx);
    return ok;
}

int uocr_metal_context_diagnostic_get_rows_f16(uocr_metal_context *ctx,
                                    const uint16_t *table_f16,
                                    uint32_t table_rows,
                                    uint32_t row_width,
                                    const int32_t *row_ids,
                                    uint32_t n_row_ids,
                                    uocr_metal_get_rows_output_type output_type,
                                    void *out,
                                    char *error,
                                    size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || table_f16 == NULL || row_ids == NULL || out == NULL ||
        table_rows == 0u || row_width == 0u || n_row_ids == 0u) {
        return metal_fail(error, error_size, "invalid Metal get-rows request");
    }
    if (output_type != UOCR_METAL_GET_ROWS_OUTPUT_F16 && output_type != UOCR_METAL_GET_ROWS_OUTPUT_F32) {
        return metal_fail(error, error_size, "unsupported Metal get-rows output type %d", (int)output_type);
    }

    for (uint32_t i = 0u; i < n_row_ids; ++i) {
        if (row_ids[i] < 0 || (uint32_t)row_ids[i] >= table_rows) {
            return metal_fail(error,
                              error_size,
                              "Metal get-rows id %d at position %u is outside table rows %u",
                              row_ids[i],
                              i,
                              table_rows);
        }
    }

    uint64_t table_values = 0u;
    uint64_t table_bytes = 0u;
    uint64_t out_values = 0u;
    uint64_t out_bytes = 0u;
    uint64_t ids_bytes = 0u;
    const uint64_t out_element_bytes = output_type == UOCR_METAL_GET_ROWS_OUTPUT_F16 ? 2u : (uint64_t)sizeof(float);
    if (!checked_mul_u64((uint64_t)table_rows, (uint64_t)row_width, &table_values) ||
        !checked_mul_u64(table_values, 2u, &table_bytes) ||
        !checked_mul_u64((uint64_t)n_row_ids, (uint64_t)row_width, &out_values) ||
        !checked_mul_u64(out_values, out_element_bytes, &out_bytes) ||
        !checked_mul_u64((uint64_t)n_row_ids, (uint64_t)sizeof(int32_t), &ids_bytes)) {
        return metal_fail(error, error_size, "Metal get-rows byte-size overflow");
    }

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (table_bytes > max_buffer_length || ids_bytes > max_buffer_length || out_bytes > max_buffer_length ||
        table_bytes > (uint64_t)SIZE_MAX || ids_bytes > (uint64_t)SIZE_MAX || out_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error,
                          error_size,
                          "Metal get-rows buffers exceed maxBufferLength %llu",
                          (unsigned long long)max_buffer_length);
    }

    @autoreleasepool {
        const char *function_name = output_type == UOCR_METAL_GET_ROWS_OUTPUT_F16 ?
                                        "uocr_get_rows_f16_to_f16" :
                                        "uocr_get_rows_f16_to_f32";
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, function_name, error, error_size);
        if (pipeline == nil) {
            return 0;
        }

        id<MTLBuffer> table = metal_new_buffer_with_bytes(ctx, table_f16, (NSUInteger)table_bytes, MTLResourceStorageModeShared);
        if (table == nil) {
            return metal_fail(error, error_size, "failed to allocate Metal get-rows table buffer");
        }
        table.label = @"uocr_get_rows_table_f16";

        id<MTLBuffer> ids = metal_new_buffer_with_bytes(ctx, row_ids, (NSUInteger)ids_bytes, MTLResourceStorageModeShared);
        if (ids == nil) {
            [table release];
            return metal_fail(error, error_size, "failed to allocate Metal get-rows id buffer");
        }
        ids.label = @"uocr_get_rows_ids";

        id<MTLBuffer> dst = metal_new_buffer_with_length(ctx, (NSUInteger)out_bytes, MTLResourceStorageModeShared);
        if (dst == nil) {
            [ids release];
            [table release];
            return metal_fail(error, error_size, "failed to allocate Metal get-rows output buffer");
        }
        dst.label = @"uocr_get_rows_output";
        memset([dst contents], 0, (size_t)out_bytes);

        id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            [dst release];
            [ids release];
            [table release];
            return metal_fail(error, error_size, "failed to create Metal get-rows command buffer");
        }
        cb.label = @"uocr_get_rows_command_buffer";

        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            [dst release];
            [ids release];
            [table release];
            return metal_fail(error, error_size, "failed to create Metal get-rows command encoder");
        }

        uocr_metal_get_rows_params params;
        params.table_rows = table_rows;
        params.row_width = row_width;
        params.n_row_ids = n_row_ids;
        params.reserved = 0u;

        [enc setComputePipelineState:pipeline];
        [enc setBuffer:table offset:0u atIndex:0u];
        [enc setBuffer:ids offset:0u atIndex:1u];
        [enc setBuffer:dst offset:0u atIndex:2u];
        [enc setBytes:&params length:sizeof(params) atIndex:3u];

        NSUInteger threads_per_group = pipeline.threadExecutionWidth;
        if (threads_per_group == 0u) {
            threads_per_group = 1u;
        }
        if (threads_per_group > (NSUInteger)row_width) {
            threads_per_group = (NSUInteger)row_width;
        }
        [enc dispatchThreads:MTLSizeMake((NSUInteger)row_width, (NSUInteger)n_row_ids, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
        [enc endEncoding];

        UOCR_METAL_COMMIT_AND_WAIT_PROFILED(ctx, cb);
        if (cb.status == MTLCommandBufferStatusError) {
            NSString *description = cb.error != nil ? [cb.error localizedDescription] : @"unknown command-buffer error";
            [dst release];
            [ids release];
            [table release];
            return metal_fail(error, error_size, "Metal get-rows command failed: %s", [description UTF8String]);
        }

        memcpy(out, [dst contents], (size_t)out_bytes);
        [dst release];
        [ids release];
        [table release];
    }

    metal_clear_error(error, error_size);
    return 1;
}

int uocr_metal_context_diagnostic_get_rows_q8_0(uocr_metal_context *ctx,
                                     const void *table_q8_0,
                                     uint32_t table_rows,
                                     uint32_t logical_width,
                                     uint32_t physical_width,
                                     const int32_t *row_ids,
                                     uint32_t n_row_ids,
                                     uocr_metal_get_rows_output_type output_type,
                                     void *out,
                                     char *error,
                                     size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || table_q8_0 == NULL || row_ids == NULL || out == NULL || table_rows == 0u ||
        logical_width == 0u || physical_width == 0u || n_row_ids == 0u) {
        return metal_fail(error, error_size, "invalid Metal Q8_0 get-rows request");
    }
    if (logical_width > physical_width || (physical_width % 32u) != 0u) {
        return metal_fail(error,
                          error_size,
                          "invalid Metal Q8_0 get-rows widths logical=%u physical=%u",
                          logical_width,
                          physical_width);
    }
    if (output_type != UOCR_METAL_GET_ROWS_OUTPUT_F16 && output_type != UOCR_METAL_GET_ROWS_OUTPUT_F32) {
        return metal_fail(error, error_size, "unsupported Metal Q8_0 get-rows output type %d", (int)output_type);
    }
    for (uint32_t i = 0u; i < n_row_ids; ++i) {
        if (row_ids[i] < 0 || (uint32_t)row_ids[i] >= table_rows) {
            return metal_fail(error,
                              error_size,
                              "Metal Q8_0 get-rows id %d at position %u is outside table rows %u",
                              row_ids[i],
                              i,
                              table_rows);
        }
    }

    uint64_t blocks_per_row = 0u;
    uint64_t row_size = 0u;
    uint64_t table_bytes = 0u;
    uint64_t out_values = 0u;
    uint64_t out_bytes = 0u;
    uint64_t ids_bytes = 0u;
    const uint64_t out_element_bytes = output_type == UOCR_METAL_GET_ROWS_OUTPUT_F16 ? 2u : (uint64_t)sizeof(float);
    if (!checked_mul_u64((uint64_t)(physical_width / 32u), 34u, &row_size) ||
        !checked_mul_u64((uint64_t)table_rows, row_size, &table_bytes) ||
        !checked_mul_u64((uint64_t)n_row_ids, (uint64_t)logical_width, &out_values) ||
        !checked_mul_u64(out_values, out_element_bytes, &out_bytes) ||
        !checked_mul_u64((uint64_t)n_row_ids, (uint64_t)sizeof(int32_t), &ids_bytes)) {
        return metal_fail(error, error_size, "Metal Q8_0 get-rows byte-size overflow");
    }
    blocks_per_row = (uint64_t)physical_width / 32u;
    if (blocks_per_row == 0u || row_size > UINT32_MAX) {
        return metal_fail(error, error_size, "Metal Q8_0 get-rows row size is invalid");
    }

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (table_bytes > max_buffer_length || ids_bytes > max_buffer_length || out_bytes > max_buffer_length ||
        table_bytes > (uint64_t)SIZE_MAX || ids_bytes > (uint64_t)SIZE_MAX || out_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error,
                          error_size,
                          "Metal Q8_0 get-rows buffers exceed maxBufferLength %llu",
                          (unsigned long long)max_buffer_length);
    }

    @autoreleasepool {
        const char *function_name = output_type == UOCR_METAL_GET_ROWS_OUTPUT_F16 ?
                                        "uocr_get_rows_q8_0_to_f16" :
                                        "uocr_get_rows_q8_0_to_f32";
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, function_name, error, error_size);
        if (pipeline == nil) {
            return 0;
        }

        id<MTLBuffer> table = metal_new_buffer_with_bytes(ctx, table_q8_0, (NSUInteger)table_bytes, MTLResourceStorageModeShared);
        if (table == nil) {
            return metal_fail(error, error_size, "failed to allocate Metal Q8_0 get-rows table buffer");
        }
        table.label = @"uocr_get_rows_table_q8_0";

        id<MTLBuffer> ids = metal_new_buffer_with_bytes(ctx, row_ids, (NSUInteger)ids_bytes, MTLResourceStorageModeShared);
        if (ids == nil) {
            [table release];
            return metal_fail(error, error_size, "failed to allocate Metal Q8_0 get-rows id buffer");
        }
        ids.label = @"uocr_get_rows_q8_ids";

        id<MTLBuffer> dst = metal_new_buffer_with_length(ctx, (NSUInteger)out_bytes, MTLResourceStorageModeShared);
        if (dst == nil) {
            [ids release];
            [table release];
            return metal_fail(error, error_size, "failed to allocate Metal Q8_0 get-rows output buffer");
        }
        dst.label = @"uocr_get_rows_q8_output";
        memset([dst contents], 0, (size_t)out_bytes);

        id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            [dst release];
            [ids release];
            [table release];
            return metal_fail(error, error_size, "failed to create Metal Q8_0 get-rows command buffer");
        }
        cb.label = @"uocr_get_rows_q8_command_buffer";

        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            [dst release];
            [ids release];
            [table release];
            return metal_fail(error, error_size, "failed to create Metal Q8_0 get-rows command encoder");
        }

        uocr_metal_get_rows_q8_params params;
        params.table_rows = table_rows;
        params.logical_width = logical_width;
        params.physical_width = physical_width;
        params.n_row_ids = n_row_ids;
        params.row_size = (uint32_t)row_size;
        params.reserved0 = 0u;
        params.reserved1 = 0u;
        params.reserved2 = 0u;

        [enc setComputePipelineState:pipeline];
        [enc setBuffer:table offset:0u atIndex:0u];
        [enc setBuffer:ids offset:0u atIndex:1u];
        [enc setBuffer:dst offset:0u atIndex:2u];
        [enc setBytes:&params length:sizeof(params) atIndex:3u];

        NSUInteger threads_per_group = pipeline.threadExecutionWidth;
        if (threads_per_group == 0u) {
            threads_per_group = 1u;
        }
        if (threads_per_group > (NSUInteger)logical_width) {
            threads_per_group = (NSUInteger)logical_width;
        }
        [enc dispatchThreads:MTLSizeMake((NSUInteger)logical_width, (NSUInteger)n_row_ids, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
        [enc endEncoding];

        UOCR_METAL_COMMIT_AND_WAIT_PROFILED(ctx, cb);
        if (cb.status == MTLCommandBufferStatusError) {
            NSString *description = cb.error != nil ? [cb.error localizedDescription] : @"unknown command-buffer error";
            [dst release];
            [ids release];
            [table release];
            return metal_fail(error, error_size, "Metal Q8_0 get-rows command failed: %s", [description UTF8String]);
        }

        memcpy(out, [dst contents], (size_t)out_bytes);
        [dst release];
        [ids release];
        [table release];
    }

    metal_clear_error(error, error_size);
    return 1;
}

static int validate_prompt_text_token_ids(const int32_t *input_ids,
                                          uint32_t n_tokens,
                                          uint32_t table_rows,
                                          uint32_t image_span_start,
                                          uint32_t image_span_length,
                                          char *error,
                                          size_t error_size) {
    const int has_image_span = image_span_length != 0u;
    const uint64_t image_span_end = has_image_span ? (uint64_t)image_span_start + (uint64_t)image_span_length : 0u;
    for (uint32_t i = 0u; i < n_tokens; ++i) {
        if (has_image_span && i >= image_span_start && (uint64_t)i < image_span_end) {
            continue;
        }
        if (input_ids[i] < 0 || (uint32_t)input_ids[i] >= table_rows) {
            return metal_fail(error,
                              error_size,
                              "Metal prompt token id %d at position %u is outside embedding rows %u",
                              input_ids[i],
                              i,
                              table_rows);
        }
    }
    return 1;
}

static int metal_context_assemble_prompt_f16_with_table_buffer_to_buffer(uocr_metal_context *ctx,
                                                                          id<MTLBuffer> table_buffer,
                                                                          NSUInteger table_offset,
                                                                          uint32_t table_rows,
                                                                          uint32_t hidden_size,
                                                                          const int32_t *input_ids,
                                                                          uint32_t n_tokens,
                                                                          id<MTLBuffer> input_ids_buffer,
                                                                          NSUInteger input_ids_offset,
                                                                          uint32_t image_span_start,
                                                                          uint32_t image_span_length,
                                                                          const uint16_t *image_features_f16,
                                                                          id<MTLBuffer> image_features_buffer,
                                                                          NSUInteger image_features_offset,
                                                                          id<MTLBuffer> dst_buffer,
                                                                          NSUInteger dst_offset,
                                                                          const char *op_name,
                                                                          char *error,
                                                                          size_t error_size) {
    const char *op = op_name != NULL ? op_name : "Metal prompt assembly";
    if (ctx == NULL || table_buffer == nil || input_ids == NULL || dst_buffer == nil ||
        table_rows == 0u || hidden_size == 0u || n_tokens == 0u) {
        return metal_fail(error, error_size, "invalid %s request", op);
    }

    const int has_image_span = image_span_length != 0u;
    if (has_image_span) {
        uint64_t image_end = 0u;
        if (image_span_start == UINT32_MAX ||
            !checked_add_u64((uint64_t)image_span_start, (uint64_t)image_span_length, &image_end) ||
            image_span_start >= n_tokens || image_end > (uint64_t)n_tokens) {
            return metal_fail(error,
                              error_size,
                              "%s image span [%u,%llu) is outside %u tokens",
                              op,
                              image_span_start,
                              (unsigned long long)image_end,
                              n_tokens);
        }
        if (image_features_f16 == NULL && image_features_buffer == nil) {
            return metal_fail(error, error_size, "%s image span requires image features", op);
        }
    } else if (image_span_start != UINT32_MAX) {
        return metal_fail(error, error_size, "%s text-only path should use UINT32_MAX image span start", op);
    }

    if (!validate_prompt_text_token_ids(input_ids,
                                        n_tokens,
                                        table_rows,
                                        image_span_start,
                                        image_span_length,
                                        error,
                                        error_size)) {
        return 0;
    }

    uint64_t table_values = 0u;
    uint64_t table_bytes = 0u;
    uint64_t token_bytes = 0u;
    uint64_t output_values = 0u;
    uint64_t output_bytes = 0u;
    uint64_t image_values = 0u;
    uint64_t image_bytes = 0u;
    if (!checked_mul_u64((uint64_t)table_rows, (uint64_t)hidden_size, &table_values) ||
        !checked_mul_u64(table_values, 2u, &table_bytes) ||
        !checked_mul_u64((uint64_t)n_tokens, (uint64_t)sizeof(int32_t), &token_bytes) ||
        !checked_mul_u64((uint64_t)n_tokens, (uint64_t)hidden_size, &output_values) ||
        !checked_mul_u64(output_values, 2u, &output_bytes) ||
        !checked_mul_u64((uint64_t)image_span_length, (uint64_t)hidden_size, &image_values) ||
        !checked_mul_u64(image_values, 2u, &image_bytes)) {
        return metal_fail(error, error_size, "%s byte-size overflow", op);
    }

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (token_bytes > max_buffer_length || image_bytes > max_buffer_length ||
        token_bytes > (uint64_t)SIZE_MAX || image_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error,
                          error_size,
                          "%s transient buffers exceed maxBufferLength %llu",
                          op,
                          (unsigned long long)max_buffer_length);
    }
    const uint64_t table_offset_u64 = (uint64_t)table_offset;
    const uint64_t table_length = (uint64_t)[table_buffer length];
    uint64_t table_end = 0u;
    if (!checked_add_u64(table_offset_u64, table_bytes, &table_end) || table_end > table_length) {
        return metal_fail(error,
                          error_size,
                          "%s embedding table range [%llu,%llu) exceeds Metal buffer length %llu",
                          op,
                          (unsigned long long)table_offset_u64,
                          (unsigned long long)table_end,
                          (unsigned long long)table_length);
    }
    if (has_image_span && image_features_buffer != nil) {
        const uint64_t image_offset_u64 = (uint64_t)image_features_offset;
        const uint64_t image_length = (uint64_t)[image_features_buffer length];
        uint64_t image_end = 0u;
        if (!checked_add_u64(image_offset_u64, image_bytes, &image_end) || image_end > image_length) {
            return metal_fail(error,
                              error_size,
                              "%s image-feature range [%llu,%llu) exceeds Metal buffer length %llu",
                              op,
                              (unsigned long long)image_offset_u64,
                              (unsigned long long)image_end,
                              (unsigned long long)image_length);
        }
    }

    const uint64_t dst_offset_u64 = (uint64_t)dst_offset;
    const uint64_t dst_length = (uint64_t)[dst_buffer length];
    uint64_t dst_end = 0u;
    if (!checked_add_u64(dst_offset_u64, output_bytes, &dst_end) || dst_end > dst_length) {
        return metal_fail(error,
                          error_size,
                          "%s output range [%llu,%llu) exceeds Metal buffer length %llu",
                          op,
                          (unsigned long long)dst_offset_u64,
                          (unsigned long long)dst_end,
                          (unsigned long long)dst_length);
    }

    uint64_t image_dst_offset = 0u;
    if (has_image_span) {
        uint64_t image_dst_values = 0u;
        uint64_t image_dst_delta = 0u;
        if (!checked_mul_u64((uint64_t)image_span_start, (uint64_t)hidden_size, &image_dst_values) ||
            !checked_mul_u64(image_dst_values, 2u, &image_dst_delta) ||
            !checked_add_u64(dst_offset_u64, image_dst_delta, &image_dst_offset) ||
            image_dst_offset > (uint64_t)NSUIntegerMax || image_bytes > (uint64_t)NSUIntegerMax) {
            return metal_fail(error, error_size, "%s image-span output offset overflow", op);
        }
    }

    @autoreleasepool {
        const char *function_name = has_image_span ? "uocr_assemble_prompt_text_skip_image_f16" : "uocr_assemble_prompt_text_f16";
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, function_name, error, error_size);
        if (pipeline == nil) {
            return 0;
        }

        id<MTLBuffer> tokens = input_ids_buffer;
        NSUInteger tokens_bind_offset = input_ids_offset;
        int owns_tokens = 0;
        if (tokens != nil) {
            const uint64_t token_offset_u64 = (uint64_t)input_ids_offset;
            const uint64_t token_length = (uint64_t)[tokens length];
            uint64_t token_end = 0u;
            if (!checked_add_u64(token_offset_u64, token_bytes, &token_end) || token_end > token_length) {
                return metal_fail(error,
                                  error_size,
                                  "%s persistent token-id range [%llu,%llu) exceeds Metal buffer length %llu",
                                  op,
                                  (unsigned long long)token_offset_u64,
                                  (unsigned long long)token_end,
                                  (unsigned long long)token_length);
            }
        } else {
            tokens = metal_new_buffer_with_bytes(ctx, input_ids, (NSUInteger)token_bytes, MTLResourceStorageModeShared);
            if (tokens == nil) {
                return metal_fail(error, error_size, "failed to allocate %s token-id buffer", op);
            }
            tokens.label = @"uocr_prompt_input_ids";
            tokens_bind_offset = 0u;
            owns_tokens = 1;
        }

        id<MTLBuffer> image_features = nil;
        NSUInteger image_features_bind_offset = 0u;
        int owns_image_features = 0;
        if (has_image_span) {
            if (image_features_buffer != nil) {
                image_features = image_features_buffer;
                image_features_bind_offset = image_features_offset;
            } else {
                image_features = metal_new_buffer_with_bytes(ctx, image_features_f16, (NSUInteger)image_bytes, MTLResourceStorageModeShared);
                if (image_features == nil) {
                    if (owns_tokens) {
                        [tokens release];
                    }
                    return metal_fail(error, error_size, "failed to allocate %s image-feature buffer", op);
                }
                image_features.label = @"uocr_prompt_image_features_f16";
                owns_image_features = 1;
            }
        }

        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, op, error, error_size);
        if (cb == nil) {
            if (owns_image_features) {
                [image_features release];
            }
            if (owns_tokens) {
                [tokens release];
            }
            return 0;
        }
        if (owned_command_buffer) {
            cb.label = @"uocr_prompt_assembly_command_buffer";
        }

        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            if (owns_image_features) {
                [image_features release];
            }
            if (owns_tokens) {
                [tokens release];
            }
            return metal_fail(error, error_size, "failed to create %s command encoder", op);
        }

        uocr_metal_prompt_assembly_params params;
        params.table_rows = table_rows;
        params.hidden_size = hidden_size;
        params.n_tokens = n_tokens;
        params.image_span_start = has_image_span ? image_span_start : UINT32_MAX;
        params.image_span_length = image_span_length;
        params.reserved0 = 0u;
        params.reserved1 = 0u;
        params.reserved2 = 0u;

        const uint64_t token_gather_start_ns = uocr_profile_now_ns();
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:table_buffer offset:table_offset atIndex:0u];
        [enc setBuffer:tokens offset:tokens_bind_offset atIndex:1u];
        [enc setBuffer:dst_buffer offset:dst_offset atIndex:2u];
        [enc setBytes:&params length:sizeof(params) atIndex:3u];

        NSUInteger threads_per_group = pipeline.threadExecutionWidth;
        if (threads_per_group == 0u) {
            threads_per_group = 1u;
        }
        if (threads_per_group > (NSUInteger)hidden_size) {
            threads_per_group = (NSUInteger)hidden_size;
        }
        [enc dispatchThreads:MTLSizeMake((NSUInteger)hidden_size, (NSUInteger)n_tokens, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
        [enc endEncoding];
        metal_profile_add_event_now(ctx, "metal.prompt.token_gather", token_gather_start_ns);
        metal_profile_add_event_now(ctx, "metal.prefill.token_gather", token_gather_start_ns);

        if (has_image_span) {
            const uint64_t image_blit_start_ns = uocr_profile_now_ns();
            id<MTLBlitCommandEncoder> blit = metal_blit_command_encoder(ctx, cb);
            if (blit == nil) {
                if (owns_image_features) {
                    [image_features release];
                }
                if (owns_tokens) {
                    [tokens release];
                }
                return metal_fail(error, error_size, "failed to create %s image-span blit encoder", op);
            }
            [blit copyFromBuffer:image_features
                    sourceOffset:image_features_bind_offset
                        toBuffer:dst_buffer
               destinationOffset:(NSUInteger)image_dst_offset
                            size:(NSUInteger)image_bytes];
            [blit endEncoding];
            metal_profile_add_event_now(ctx, "metal.prompt.image_span_blit", image_blit_start_ns);
            metal_profile_add_event_now(ctx, "metal.prefill.image_span_blit", image_blit_start_ns);
        }

        if (!owned_command_buffer) {
            if (owns_tokens && !metal_retain_transient_until_completed(ctx, cb, tokens, error, error_size)) {
                if (owns_image_features) {
                    [image_features release];
                }
                [tokens release];
                return 0;
            }
            if (owns_image_features && !metal_retain_transient_until_completed(ctx, cb, image_features, error, error_size)) {
                [image_features release];
                if (owns_tokens) {
                    [tokens release];
                }
                return 0;
            }
        }
        if (!metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, op, error, error_size)) {
            if (owns_image_features) {
                [image_features release];
            }
            if (owns_tokens) {
                [tokens release];
            }
            return 0;
        }

        if (owns_image_features) {
            [image_features release];
        }
        if (owns_tokens) {
            [tokens release];
        }
    }

    metal_clear_error(error, error_size);
    return 1;
}

static int metal_context_assemble_prompt_f16_with_table_buffer(uocr_metal_context *ctx,
                                                                id<MTLBuffer> table_buffer,
                                                                NSUInteger table_offset,
                                                                uint32_t table_rows,
                                                                uint32_t hidden_size,
                                                                const int32_t *input_ids,
                                                                uint32_t n_tokens,
                                                                uint32_t image_span_start,
                                                                uint32_t image_span_length,
                                                                const uint16_t *image_features_f16,
                                                                uint16_t *out_prompt_f16,
                                                                const char *op_name,
                                                                char *error,
                                                                size_t error_size) {
    const char *op = op_name != NULL ? op_name : "Metal prompt assembly";
    if (ctx == NULL || table_buffer == nil || input_ids == NULL || out_prompt_f16 == NULL ||
        table_rows == 0u || hidden_size == 0u || n_tokens == 0u) {
        return metal_fail(error, error_size, "invalid %s request", op);
    }

    uint64_t output_values = 0u;
    uint64_t output_bytes = 0u;
    if (!checked_mul_u64((uint64_t)n_tokens, (uint64_t)hidden_size, &output_values) ||
        !checked_mul_u64(output_values, 2u, &output_bytes) || output_bytes > (uint64_t)SIZE_MAX ||
        output_bytes > metal_device_max_buffer_length(ctx->device)) {
        return metal_fail(error, error_size, "%s output byte-size overflow", op);
    }

    @autoreleasepool {
        id<MTLBuffer> dst = metal_new_buffer_with_length(ctx, (NSUInteger)output_bytes, MTLResourceStorageModeShared);
        if (dst == nil) {
            return metal_fail(error, error_size, "failed to allocate %s output buffer", op);
        }
        dst.label = @"uocr_prompt_embeddings_f16";

        const int status = metal_context_assemble_prompt_f16_with_table_buffer_to_buffer(ctx,
                                                                                         table_buffer,
                                                                                         table_offset,
                                                                                         table_rows,
                                                                                         hidden_size,
                                                                                         input_ids,
                                                                                         n_tokens,
                                                                                         nil,
                                                                                         0u,
                                                                                         image_span_start,
                                                                                         image_span_length,
                                                                                         image_features_f16,
                                                                                         nil,
                                                                                         0u,
                                                                                         dst,
                                                                                         0u,
                                                                                         op,
                                                                                         error,
                                                                                         error_size);
        if (status == 1) {
            memcpy(out_prompt_f16, [dst contents], (size_t)output_bytes);
        }
        [dst release];
        return status;
    }
}

