            [k_dst release];
            [q_dst release];
            [bias release];
            [weight release];
            [src release];
            return metal_fail(error, error_size, "failed to create Metal SAM QKV command buffer");
        }
        cb.label = @"uocr_sam_qkv_command_buffer";

        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
