    }
    if (UOCR_CLIP_HIDDEN_SIZE != 1024u || UOCR_CLIP_BLOCKS != 24u || UOCR_CLIP_LAYERNORM_EPS != 1.0e-5f ||
        UOCR_CLIP_PRE_LAYERNORM_EPS != UOCR_CLIP_LAYERNORM_EPS || UOCR_CLIP_GLOBAL_TOKENS != 257u ||
        UOCR_CLIP_LOCAL_TOKENS != 101u) {
