        }
        bias.label = bias_label;

        const int ok = metal_context_layernorm_f16_with_parameter_buffers(ctx,
                                                                         input_f16,
                                                                         weight,
                                                                         weight_offset,
                                                                         bias,
                                                                         bias_offset,
                                                                         token_count,
                                                                         UOCR_CLIP_HIDDEN_SIZE,
                                                                         UOCR_CLIP_LAYERNORM_EPS,
                                                                         output_type,
                                                                         out,
                                                                         op_name,
                                                                         error,
                                                                         error_size);
        [bias release];
        [weight release];
        return ok;
    }
