        return metal_fail(error, error_size, "unsupported Metal CLIP MLP output type %d", (int)output_type);
    }
    if (UOCR_CLIP_HIDDEN_SIZE != 1024u || UOCR_CLIP_MLP_INTERMEDIATE != 4096u ||
        UOCR_CLIP_GLOBAL_TOKENS != 257u || UOCR_CLIP_LOCAL_TOKENS != 101u) {
        return metal_fail(error, error_size, "Metal CLIP MLP constants are inconsistent");
    }

    uint64_t input_values = 0u;
    uint64_t mid_values = 0u;
    uint64_t output_values = 0u;
    uint64_t fc1_weight_values = 0u;
    uint64_t fc2_weight_values = 0u;
    uint64_t input_bytes = 0u;
    uint64_t mid_bytes = 0u;
    uint64_t output_bytes = 0u;
    uint64_t fc1_weight_bytes = 0u;
    uint64_t fc2_weight_bytes = 0u;
    uint64_t fc1_bias_bytes = 0u;
    uint64_t fc2_bias_bytes = 0u;
    const uint64_t output_element_bytes = output_type == UOCR_METAL_DENSE_OUTPUT_F16 ? 2u : (uint64_t)sizeof(float);
    if (!checked_mul_u64((uint64_t)token_count, (uint64_t)UOCR_CLIP_HIDDEN_SIZE, &input_values) ||
        !checked_mul_u64((uint64_t)token_count, (uint64_t)UOCR_CLIP_MLP_INTERMEDIATE, &mid_values) ||
        !checked_mul_u64((uint64_t)token_count, (uint64_t)UOCR_CLIP_HIDDEN_SIZE, &output_values) ||
        !checked_mul_u64((uint64_t)UOCR_CLIP_MLP_INTERMEDIATE, (uint64_t)UOCR_CLIP_HIDDEN_SIZE, &fc1_weight_values) ||
        !checked_mul_u64((uint64_t)UOCR_CLIP_HIDDEN_SIZE, (uint64_t)UOCR_CLIP_MLP_INTERMEDIATE, &fc2_weight_values) ||
        !checked_mul_u64(input_values, 2u, &input_bytes) ||
        !checked_mul_u64(mid_values, 2u, &mid_bytes) ||
        !checked_mul_u64(output_values, output_element_bytes, &output_bytes) ||
        !checked_mul_u64(fc1_weight_values, 2u, &fc1_weight_bytes) ||
        !checked_mul_u64(fc2_weight_values, 2u, &fc2_weight_bytes) ||
        !checked_mul_u64((uint64_t)UOCR_CLIP_MLP_INTERMEDIATE, 2u, &fc1_bias_bytes) ||
        !checked_mul_u64((uint64_t)UOCR_CLIP_HIDDEN_SIZE, 2u, &fc2_bias_bytes) ||
        input_bytes > (uint64_t)SIZE_MAX || mid_bytes > (uint64_t)SIZE_MAX || output_bytes > (uint64_t)SIZE_MAX ||
        fc1_weight_bytes > (uint64_t)SIZE_MAX || fc2_weight_bytes > (uint64_t)SIZE_MAX ||
        fc1_bias_bytes > (uint64_t)SIZE_MAX || fc2_bias_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error, error_size, "Metal CLIP MLP byte-size overflow");
    }

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (input_bytes > max_buffer_length || mid_bytes > max_buffer_length || output_bytes > max_buffer_length ||
        fc1_weight_bytes > max_buffer_length || fc2_weight_bytes > max_buffer_length ||
        fc1_bias_bytes > max_buffer_length || fc2_bias_bytes > max_buffer_length) {
        return metal_fail(error,
                          error_size,
                          "Metal CLIP MLP buffers exceed maxBufferLength %llu",
                          (unsigned long long)max_buffer_length);
    }

    uint64_t host_scratch_bytes = 0u;
    if (!checked_mul_u64(mid_bytes, 2u, &host_scratch_bytes)) {
        return metal_fail(error, error_size, "Metal CLIP MLP host scratch byte-size overflow");
    }
    if (!metal_memory_reserve(ctx, UOCR_MEMORY_VISION_HOST_STAGING, host_scratch_bytes, "CLIP MLP host scratch", error, error_size)) {
        return 0;
    }

    int result = 0;
    uint16_t *fc1_out_f16 = (uint16_t *)malloc((size_t)mid_bytes);
    uint16_t *activated_f16 = (uint16_t *)malloc((size_t)mid_bytes);
    if (fc1_out_f16 == NULL || activated_f16 == NULL) {
        result = metal_fail(error, error_size, "failed to allocate Metal CLIP MLP intermediate buffers");
        goto cleanup_clip_mlp;
    }

    if (!uocr_metal_context_diagnostic_dense_f16(ctx,
                                      input_f16,
                                      fc1_weight_f16,
                                      fc1_bias_f16,
                                      token_count,
                                      UOCR_CLIP_HIDDEN_SIZE,
                                      UOCR_CLIP_MLP_INTERMEDIATE,
                                      UOCR_METAL_DENSE_OUTPUT_F16,
                                      fc1_out_f16,
                                      error,
                                      error_size)) {
        char detail[512];
        (void)snprintf(detail,
                       sizeof(detail),
                       "%s",
                       (error != NULL && error[0] != '\0') ? error : "unknown error");
        result = metal_fail(error, error_size, "failed to compute Metal CLIP MLP fc1: %s", detail);
        goto cleanup_clip_mlp;
    }

    if (!uocr_metal_context_diagnostic_clip_quickgelu_f16(ctx,
                                               fc1_out_f16,
                                               token_count,
                                               UOCR_METAL_DENSE_OUTPUT_F16,
                                               activated_f16,
                                               error,
                                               error_size)) {
        char detail[512];
        (void)snprintf(detail,
                       sizeof(detail),
                       "%s",
                       (error != NULL && error[0] != '\0') ? error : "unknown error");
        result = metal_fail(error, error_size, "failed to compute Metal CLIP MLP QuickGELU: %s", detail);
        goto cleanup_clip_mlp;
    }

    if (!uocr_metal_context_diagnostic_dense_f16(ctx,
                                      activated_f16,
                                      fc2_weight_f16,
                                      fc2_bias_f16,
                                      token_count,
                                      UOCR_CLIP_MLP_INTERMEDIATE,
                                      UOCR_CLIP_HIDDEN_SIZE,
                                      output_type,
                                      out,
                                      error,
                                      error_size)) {
        char detail[512];
        (void)snprintf(detail,
                       sizeof(detail),
                       "%s",
                       (error != NULL && error[0] != '\0') ? error : "unknown error");
        result = metal_fail(error, error_size, "failed to compute Metal CLIP MLP fc2: %s", detail);
        goto cleanup_clip_mlp;
    }

    result = 1;

cleanup_clip_mlp:
    free(activated_f16);
    free(fc1_out_f16);
    metal_memory_release(ctx, UOCR_MEMORY_VISION_HOST_STAGING, host_scratch_bytes);
    if (result) {
        metal_clear_error(error, error_size);
    }
    return result;
}

int uocr_metal_context_diagnostic_clip_residual_add_f16(uocr_metal_context *ctx,
                                             const uint16_t *base_f16,
                                             const uint16_t *update_f16,
                                             uint32_t token_count,
                                             uocr_metal_dense_output_type output_type,
                                             void *out,
                                             char *error,
                                             size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || base_f16 == NULL || update_f16 == NULL || out == NULL) {
        return metal_fail(error, error_size, "invalid Metal CLIP residual request");
    }
    if (token_count != UOCR_CLIP_GLOBAL_TOKENS && token_count != UOCR_CLIP_LOCAL_TOKENS) {
        return metal_fail(error, error_size, "invalid Metal CLIP residual token count %u", token_count);
    }
    if (output_type != UOCR_METAL_DENSE_OUTPUT_F16 && output_type != UOCR_METAL_DENSE_OUTPUT_F32) {
        return metal_fail(error, error_size, "unsupported Metal CLIP residual output type %d", (int)output_type);
    }
    if (UOCR_CLIP_HIDDEN_SIZE != 1024u || UOCR_CLIP_GLOBAL_TOKENS != 257u || UOCR_CLIP_LOCAL_TOKENS != 101u) {
        return metal_fail(error, error_size, "Metal CLIP residual constants are inconsistent");
    }

    uint64_t value_count_u64 = 0u;
    uint64_t input_bytes = 0u;
    uint64_t output_bytes = 0u;
    const uint64_t output_element_bytes = output_type == UOCR_METAL_DENSE_OUTPUT_F16 ? 2u : (uint64_t)sizeof(float);
    if (!checked_mul_u64((uint64_t)token_count, (uint64_t)UOCR_CLIP_HIDDEN_SIZE, &value_count_u64) ||
        !checked_mul_u64(value_count_u64, 2u, &input_bytes) ||
        !checked_mul_u64(value_count_u64, output_element_bytes, &output_bytes) ||
        value_count_u64 > (uint64_t)UINT32_MAX || input_bytes > (uint64_t)SIZE_MAX ||
        output_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error, error_size, "Metal CLIP residual byte-size overflow");
    }
    const uint32_t value_count = (uint32_t)value_count_u64;

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (input_bytes > max_buffer_length || output_bytes > max_buffer_length) {
        return metal_fail(error,
                          error_size,
                          "Metal CLIP residual buffers exceed maxBufferLength %llu",
                          (unsigned long long)max_buffer_length);
    }

    int result = 0;
    @autoreleasepool {
        const char *function_name = output_type == UOCR_METAL_DENSE_OUTPUT_F16 ?
                                        "uocr_clip_residual_add_f16_to_f16" :
                                        "uocr_clip_residual_add_f16_to_f32";
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, function_name, error, error_size);
        if (pipeline == nil) {
            return 0;
        }

        id<MTLBuffer> base = nil;
        id<MTLBuffer> update = nil;
        id<MTLBuffer> dst = nil;
        id<MTLCommandBuffer> cb = nil;
        id<MTLComputeCommandEncoder> enc = nil;

        NSUInteger base_offset = 0u;
        base = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                            base_f16,
                                                            (NSUInteger)input_bytes,
                                                            MTLResourceStorageModeShared,
                                                            &base_offset);
        if (base == nil) {
            result = metal_fail(error, error_size, "failed to allocate Metal CLIP residual base buffer");
            goto cleanup_clip_residual;
        }
        base.label = @"uocr_clip_residual_base_f16";

        NSUInteger update_offset = 0u;
        update = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                              update_f16,
                                                              (NSUInteger)input_bytes,
                                                              MTLResourceStorageModeShared,
                                                              &update_offset);
        if (update == nil) {
            result = metal_fail(error, error_size, "failed to allocate Metal CLIP residual update buffer");
            goto cleanup_clip_residual;
        }
        update.label = @"uocr_clip_residual_update_f16";

        NSUInteger dst_offset = 0u;
        int dst_needs_copy = 1;
        dst = metal_new_or_retain_vision_output_buffer(ctx,
                                                       out,
                                                       (NSUInteger)output_bytes,
                                                       MTLResourceStorageModeShared,
                                                       &dst_offset,
                                                       &dst_needs_copy);
        if (dst == nil) {
            result = metal_fail(error, error_size, "failed to allocate Metal CLIP residual output buffer");
            goto cleanup_clip_residual;
        }
        dst.label = @"uocr_clip_residual_output";
        metal_zero_buffer_range(dst, dst_offset, (NSUInteger)output_bytes);

        cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            result = metal_fail(error, error_size, "failed to create Metal CLIP residual command buffer");
            goto cleanup_clip_residual;
        }
        cb.label = @"uocr_clip_residual_command_buffer";

        enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            result = metal_fail(error, error_size, "failed to create Metal CLIP residual command encoder");
            goto cleanup_clip_residual;
        }

        const NSUInteger threads_per_group = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:base offset:base_offset atIndex:0u];
        [enc setBuffer:update offset:update_offset atIndex:1u];
        [enc setBuffer:dst offset:dst_offset atIndex:2u];
        [enc setBytes:&value_count length:sizeof(value_count) atIndex:3u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)value_count, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
        [enc endEncoding];

        UOCR_METAL_COMMIT_AND_WAIT_PROFILED(ctx, cb);
        if (cb.status == MTLCommandBufferStatusError) {
            NSString *description = cb.error != nil ? [cb.error localizedDescription] : @"unknown command-buffer error";
            result = metal_fail(error, error_size, "Metal CLIP residual command failed: %s", [description UTF8String]);
            goto cleanup_clip_residual;
        }

        metal_copy_buffer_range_to_host_if_needed(out, dst, dst_offset, (NSUInteger)output_bytes, dst_needs_copy);
        result = 1;

    cleanup_clip_residual:
        [dst release];
        [update release];
        [base release];
    }

    if (result) {
        metal_clear_error(error, error_size);
    }
    return result;
}

static int metal_clip_transformer_block_has_weights(const uocr_metal_clip_transformer_block_f16 *block) {
    return block != NULL && block->ln1_weight_f16 != NULL && block->ln1_bias_f16 != NULL &&
           block->qkv_weight_f16 != NULL && block->qkv_bias_f16 != NULL &&
           block->out_proj_weight_f16 != NULL && block->out_proj_bias_f16 != NULL &&
           block->ln2_weight_f16 != NULL && block->ln2_bias_f16 != NULL &&
           block->mlp_fc1_weight_f16 != NULL && block->mlp_fc1_bias_f16 != NULL &&
           block->mlp_fc2_weight_f16 != NULL && block->mlp_fc2_bias_f16 != NULL;
}

static void metal_copy_error_detail(char *detail, size_t detail_size, const char *error) {
    if (detail == NULL || detail_size == 0u) {
        return;
    }
    (void)snprintf(detail, detail_size, "%s", (error != NULL && error[0] != '\0') ? error : "unknown error");
}

static int metal_clip_transformer_activation_bytes(uint32_t token_count,
                                                   uint64_t *value_count,
                                                   uint64_t *f16_bytes,
                                                   char *error,
                                                   size_t error_size) {
    uint64_t values = 0u;
    uint64_t bytes = 0u;
    if (!checked_mul_u64((uint64_t)token_count, (uint64_t)UOCR_CLIP_HIDDEN_SIZE, &values) ||
        !checked_mul_u64(values, 2u, &bytes) || values > (uint64_t)UINT32_MAX || bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error, error_size, "Metal CLIP transformer byte-size overflow");
    }
    if (value_count != NULL) {
        *value_count = values;
    }
    if (f16_bytes != NULL) {
        *f16_bytes = bytes;
    }
    return 1;
}

static int metal_context_clip_attention_batch_f16_to_slice(uocr_metal_context *ctx,
                                                            uocr_metal_vision_workspace_slice q_tokens,
                                                            uocr_metal_vision_workspace_slice k_tokens,
                                                            uocr_metal_vision_workspace_slice v_tokens,
                                                            uint32_t token_count,
                                                            uint32_t view_count,
                                                            uocr_metal_vision_workspace_slice out_tokens,
                                                            char *error,
                                                            size_t error_size) {
    uint64_t values_per_view = 0u;
    uint64_t values = 0u;
    uint64_t bytes = 0u;
    if (ctx == NULL || view_count == 0u ||
        (token_count != UOCR_CLIP_GLOBAL_TOKENS && token_count != UOCR_CLIP_LOCAL_TOKENS) ||
        !checked_mul_u64((uint64_t)token_count, (uint64_t)UOCR_CLIP_HIDDEN_SIZE, &values_per_view) ||
        !checked_mul_u64(values_per_view, (uint64_t)view_count, &values) ||
        !metal_vision_f16_bytes(values, &bytes) ||
        !metal_vision_require_workspace_slice_f16(q_tokens, bytes, "CLIP batch attention Q", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(k_tokens, bytes, "CLIP batch attention K", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(v_tokens, bytes, "CLIP batch attention V", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(out_tokens, bytes, "CLIP batch attention output", error, error_size)) {
        return 0;
    }
    if (UOCR_CLIP_HIDDEN_SIZE != 1024u || UOCR_CLIP_ATTENTION_HEADS != 16u || UOCR_CLIP_HEAD_DIM != 64u ||
        UOCR_CLIP_ATTENTION_HEADS * UOCR_CLIP_HEAD_DIM != UOCR_CLIP_HIDDEN_SIZE) {
        return metal_fail(error, error_size, "Metal CLIP batch attention constants are inconsistent");
    }

    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_sam_window_attention_flash_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        const NSUInteger threads_per_group = 128u;
        if (pipeline.maxTotalThreadsPerThreadgroup < threads_per_group) {
            return metal_fail(error, error_size, "Metal CLIP batch flash attention cannot run four simdgroups per block");
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "Metal CLIP batch attention", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal CLIP batch attention command encoder");
        }

        uocr_metal_sam_window_attention_params params;
        params.windows = 1u;
        params.tokens_per_window = token_count;
        params.heads = UOCR_CLIP_ATTENTION_HEADS;
        params.head_dim = UOCR_CLIP_HEAD_DIM;
        params.scale = 1.0f / sqrtf((float)UOCR_CLIP_HEAD_DIM);
        params.batch_size = view_count;
        params.reserved1 = 0u;
        params.reserved2 = 0u;

        const NSUInteger query_blocks = (NSUInteger)((token_count + 3u) / 4u);
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:q_tokens.buffer offset:q_tokens.offset atIndex:0u];
        [enc setBuffer:k_tokens.buffer offset:k_tokens.offset atIndex:1u];
        [enc setBuffer:v_tokens.buffer offset:v_tokens.offset atIndex:2u];
        [enc setBuffer:out_tokens.buffer offset:out_tokens.offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)UOCR_CLIP_ATTENTION_HEADS, query_blocks, (NSUInteger)view_count)
             threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "Metal CLIP batch attention", error, error_size);
    }
}

static int metal_context_clip_mlp_batch_workspace_f16_to_slice(uocr_metal_context *ctx,
                                                               uocr_metal_vision_workspace_slice input_tokens,
                                                               const uocr_metal_clip_transformer_block_slices_f16 *block,
                                                               uint32_t rows,
                                                               uocr_metal_vision_workspace_slice out_tokens,
                                                               uocr_metal_vision_workspace *scratch,
                                                               char *error,
                                                               size_t error_size) {
    uint64_t hidden_values = 0u;
    uint64_t hidden_bytes = 0u;
    uint64_t mid_values = 0u;
    uint64_t mid_bytes = 0u;
    const uint64_t fc1_weight_bytes = (uint64_t)UOCR_CLIP_MLP_INTERMEDIATE * (uint64_t)UOCR_CLIP_HIDDEN_SIZE * 2u;
    const uint64_t fc1_bias_bytes = (uint64_t)UOCR_CLIP_MLP_INTERMEDIATE * 2u;
    const uint64_t fc2_weight_bytes = (uint64_t)UOCR_CLIP_HIDDEN_SIZE * (uint64_t)UOCR_CLIP_MLP_INTERMEDIATE * 2u;
    const uint64_t fc2_bias_bytes = (uint64_t)UOCR_CLIP_HIDDEN_SIZE * 2u;
    if (ctx == NULL || block == NULL || rows == 0u || scratch == NULL ||
        !checked_mul_u64((uint64_t)rows, (uint64_t)UOCR_CLIP_HIDDEN_SIZE, &hidden_values) ||
        !metal_vision_f16_bytes(hidden_values, &hidden_bytes) ||
        !checked_mul_u64((uint64_t)rows, (uint64_t)UOCR_CLIP_MLP_INTERMEDIATE, &mid_values) ||
        !metal_vision_f16_bytes(mid_values, &mid_bytes) ||
        !metal_vision_require_workspace_slice_f16(input_tokens, hidden_bytes, "CLIP batch MLP input", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(out_tokens, hidden_bytes, "CLIP batch MLP output", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->clip_mlp_activated, mid_bytes, "CLIP batch MLP activation", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->mlp_fc1_weight, fc1_weight_bytes, "CLIP MLP fc1 weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->mlp_fc1_bias, fc1_bias_bytes, "CLIP MLP fc1 bias", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->mlp_fc2_weight, fc2_weight_bytes, "CLIP MLP fc2 weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->mlp_fc2_bias, fc2_bias_bytes, "CLIP MLP fc2 bias", error, error_size)) {
        return 0;
    }

    uocr_metal_buffer_slice input_slice = { input_tokens.buffer, input_tokens.offset };
    uocr_metal_buffer_slice fc1_dst_slice = { scratch->clip_mlp_activated.buffer, scratch->clip_mlp_activated.offset };
    uocr_metal_buffer_slice out_slice = { out_tokens.buffer, out_tokens.offset };
    if (!metal_run_mps_matmul_nt_f16(ctx,
                                     input_slice,
                                     block->mlp_fc1_weight.slice,
                                     fc1_dst_slice,
                                     rows,
                                     UOCR_CLIP_HIDDEN_SIZE,
                                     UOCR_CLIP_MLP_INTERMEDIATE,
                                     "Metal CLIP batch MLP fc1 MPS matmul",
                                     error,
                                     error_size) ||
        !metal_run_bias_quickgelu_f16_inplace(ctx,
                                              fc1_dst_slice,
                                              block->mlp_fc1_bias.slice,
                                              rows,
                                              UOCR_CLIP_MLP_INTERMEDIATE,
                                              "Metal CLIP batch MLP fused bias QuickGELU",
                                              error,
                                              error_size) ||
        !metal_run_mps_matmul_nt_f16(ctx,
                                     fc1_dst_slice,
                                     block->mlp_fc2_weight.slice,
                                     out_slice,
                                     rows,
                                     UOCR_CLIP_MLP_INTERMEDIATE,
                                     UOCR_CLIP_HIDDEN_SIZE,
                                     "Metal CLIP batch MLP fc2 MPS matmul",
                                     error,
                                     error_size) ||
        !metal_run_bias_add_f16_inplace(ctx,
                                        out_slice,
                                        block->mlp_fc2_bias.slice,
                                        rows,
                                        UOCR_CLIP_HIDDEN_SIZE,
                                        "Metal CLIP batch MLP fc2 bias",
                                        error,
                                        error_size)) {
        char detail[512];
        metal_copy_error_detail(detail, sizeof(detail), error);
        return metal_fail(error, error_size, "failed to compute Metal CLIP batch MLP: %s", detail);
    }
    return 1;
}

static int metal_context_clip_transformer_batch_block_workspace_f16_to_slice(uocr_metal_context *ctx,
                                                                             uocr_metal_vision_workspace_slice input_tokens,
                                                                             const uocr_metal_clip_transformer_block_slices_f16 *block,
                                                                             uint32_t token_count,
                                                                             uint32_t view_count,
                                                                             uocr_metal_vision_workspace_slice out_tokens,
                                                                             uocr_metal_vision_workspace *scratch,
                                                                             char *error,
                                                                             size_t error_size) {
    if (ctx == NULL || block == NULL || view_count == 0u || scratch == NULL) {
        return metal_fail(error, error_size, "invalid Metal CLIP batch transformer block request");
    }
    if (token_count != UOCR_CLIP_GLOBAL_TOKENS && token_count != UOCR_CLIP_LOCAL_TOKENS) {
        return metal_fail(error, error_size, "invalid Metal CLIP batch transformer token count %u", token_count);
    }
    if (UOCR_CLIP_HIDDEN_SIZE != 1024u || UOCR_CLIP_BLOCKS != 24u || UOCR_CLIP_ATTENTION_HEADS != 16u ||
        UOCR_CLIP_HEAD_DIM != 64u || UOCR_CLIP_QKV_SIZE != 3072u || UOCR_CLIP_MLP_INTERMEDIATE != 4096u ||
        UOCR_CLIP_GLOBAL_TOKENS != 257u || UOCR_CLIP_LOCAL_TOKENS != 101u) {
        return metal_fail(error, error_size, "Metal CLIP batch transformer block constants are inconsistent");
    }
    if (view_count > UINT32_MAX / token_count) {
        return metal_fail(error, error_size, "Metal CLIP batch transformer row count overflow");
    }
    const uint32_t rows = token_count * view_count;
    uint64_t hidden_values = 0u;
    uint64_t hidden_bytes = 0u;
    if (!checked_mul_u64((uint64_t)rows, (uint64_t)UOCR_CLIP_HIDDEN_SIZE, &hidden_values) ||
        hidden_values > (uint64_t)UINT32_MAX || !metal_vision_f16_bytes(hidden_values, &hidden_bytes) ||
        !metal_vision_require_workspace_slice_f16(input_tokens, hidden_bytes, "CLIP batch block input", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(out_tokens, hidden_bytes, "CLIP batch block output", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->clip_block_norm1, hidden_bytes, "CLIP batch block norm1", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->clip_block_q, hidden_bytes, "CLIP batch block Q", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->clip_block_k, hidden_bytes, "CLIP batch block K", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->clip_block_v, hidden_bytes, "CLIP batch block V", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->clip_block_attention, hidden_bytes, "CLIP batch block attention", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->clip_block_projected, hidden_bytes, "CLIP batch block projection", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->clip_block_residual1, hidden_bytes, "CLIP batch block residual1", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->clip_block_norm2, hidden_bytes, "CLIP batch block norm2", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->clip_block_mlp, hidden_bytes, "CLIP batch block MLP", error, error_size)) {
        return 0;
    }

    const uint64_t hidden_parameter_bytes = (uint64_t)UOCR_CLIP_HIDDEN_SIZE * 2u;
    const uint64_t qkv_weight_bytes = (uint64_t)UOCR_CLIP_QKV_SIZE * (uint64_t)UOCR_CLIP_HIDDEN_SIZE * 2u;
    const uint64_t qkv_bias_bytes = (uint64_t)UOCR_CLIP_QKV_SIZE * 2u;
    const uint64_t projection_weight_bytes = (uint64_t)UOCR_CLIP_HIDDEN_SIZE * (uint64_t)UOCR_CLIP_HIDDEN_SIZE * 2u;
    if (!metal_vision_require_tensor_slice_f16(block->ln1_weight, hidden_parameter_bytes, "CLIP block ln1 weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->ln1_bias, hidden_parameter_bytes, "CLIP block ln1 bias", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->qkv_weight, qkv_weight_bytes, "CLIP block QKV weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->qkv_bias, qkv_bias_bytes, "CLIP block QKV bias", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->out_proj_weight, projection_weight_bytes, "CLIP block output projection weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->out_proj_bias, hidden_parameter_bytes, "CLIP block output projection bias", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->ln2_weight, hidden_parameter_bytes, "CLIP block ln2 weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->ln2_bias, hidden_parameter_bytes, "CLIP block ln2 bias", error, error_size)) {
        return 0;
    }

#define RUN_CLIP_BATCH_BLOCK_STEP(step_name, call_expr)                                                \
    do {                                                                                                \
        if (!(call_expr)) {                                                                             \
            char detail[512];                                                                           \
            metal_copy_error_detail(detail, sizeof(detail), error);                                      \
            return metal_fail(error, error_size, "failed to compute Metal CLIP batch block %s: %s", step_name, detail); \
        }                                                                                               \
    } while (0)

    RUN_CLIP_BATCH_BLOCK_STEP("LayerNorm1",
                              metal_context_layernorm_f16_with_parameter_buffers(ctx,
                                                                                 input_tokens.f16,
                                                                                 block->ln1_weight.slice.buffer,
                                                                                 block->ln1_weight.slice.offset,
                                                                                 block->ln1_bias.slice.buffer,
                                                                                 block->ln1_bias.slice.offset,
                                                                                 rows,
                                                                                 UOCR_CLIP_HIDDEN_SIZE,
                                                                                 UOCR_CLIP_LAYERNORM_EPS,
                                                                                 UOCR_METAL_LAYERNORM_OUTPUT_F16,
                                                                                 scratch->clip_block_norm1.f16,
                                                                                 "Metal CLIP batch LayerNorm1",
                                                                                 error,
                                                                                 error_size));
    RUN_CLIP_BATCH_BLOCK_STEP("QKV",
                              metal_run_packed_qkv_mps_f16(ctx,
                                                            (uocr_metal_buffer_slice){scratch->clip_block_norm1.buffer, scratch->clip_block_norm1.offset},
                                                            block->qkv_weight.slice,
                                                            block->qkv_bias.slice,
                                                            (uocr_metal_buffer_slice){scratch->clip_block_q.buffer, scratch->clip_block_q.offset},
                                                            (uocr_metal_buffer_slice){scratch->clip_block_k.buffer, scratch->clip_block_k.offset},
                                                            (uocr_metal_buffer_slice){scratch->clip_block_v.buffer, scratch->clip_block_v.offset},
                                                            rows,
                                                            UOCR_CLIP_HIDDEN_SIZE,
                                                            "Metal CLIP batch QKV MPS matmul",
                                                            error,
                                                            error_size));
    RUN_CLIP_BATCH_BLOCK_STEP("attention",
                              metal_context_clip_attention_batch_f16_to_slice(ctx,
                                                                             scratch->clip_block_q,
                                                                             scratch->clip_block_k,
                                                                             scratch->clip_block_v,
                                                                             token_count,
                                                                             view_count,
                                                                             scratch->clip_block_attention,
                                                                             error,
                                                                             error_size));
    RUN_CLIP_BATCH_BLOCK_STEP("output projection",
                              metal_run_mps_matmul_nt_f16(ctx,
                                                          (uocr_metal_buffer_slice){scratch->clip_block_attention.buffer, scratch->clip_block_attention.offset},
                                                          block->out_proj_weight.slice,
                                                          (uocr_metal_buffer_slice){scratch->clip_block_projected.buffer, scratch->clip_block_projected.offset},
                                                          rows,
                                                          UOCR_CLIP_HIDDEN_SIZE,
                                                          UOCR_CLIP_HIDDEN_SIZE,
                                                          "Metal CLIP batch output projection MPS matmul",
                                                          error,
                                                          error_size) &&
                              metal_run_bias_add_f16_inplace(ctx,
                                                             (uocr_metal_buffer_slice){scratch->clip_block_projected.buffer, scratch->clip_block_projected.offset},
                                                             block->out_proj_bias.slice,
                                                             rows,
                                                             UOCR_CLIP_HIDDEN_SIZE,
                                                             "Metal CLIP batch output projection bias",
                                                             error,
                                                             error_size));
    RUN_CLIP_BATCH_BLOCK_STEP("attention residual",
                              metal_run_residual_add_f16(ctx,
                                                         (uocr_metal_buffer_slice){input_tokens.buffer, input_tokens.offset},
                                                         (uocr_metal_buffer_slice){scratch->clip_block_projected.buffer, scratch->clip_block_projected.offset},
                                                         (uocr_metal_buffer_slice){scratch->clip_block_residual1.buffer, scratch->clip_block_residual1.offset},
                                                         (uint32_t)hidden_values,
                                                         "Metal CLIP batch attention residual",
                                                         error,
                                                         error_size));
    RUN_CLIP_BATCH_BLOCK_STEP("LayerNorm2",
                              metal_context_layernorm_f16_with_parameter_buffers(ctx,
                                                                                 scratch->clip_block_residual1.f16,
                                                                                 block->ln2_weight.slice.buffer,
                                                                                 block->ln2_weight.slice.offset,
                                                                                 block->ln2_bias.slice.buffer,
                                                                                 block->ln2_bias.slice.offset,
                                                                                 rows,
                                                                                 UOCR_CLIP_HIDDEN_SIZE,
                                                                                 UOCR_CLIP_LAYERNORM_EPS,
                                                                                 UOCR_METAL_LAYERNORM_OUTPUT_F16,
                                                                                 scratch->clip_block_norm2.f16,
                                                                                 "Metal CLIP batch LayerNorm2",
                                                                                 error,
                                                                                 error_size));
    RUN_CLIP_BATCH_BLOCK_STEP("MLP",
                              metal_context_clip_mlp_batch_workspace_f16_to_slice(ctx,
                                                                                  scratch->clip_block_norm2,
                                                                                  block,
                                                                                  rows,
                                                                                  scratch->clip_block_mlp,
                                                                                  scratch,
                                                                                  error,
                                                                                  error_size));
    RUN_CLIP_BATCH_BLOCK_STEP("MLP residual",
                              metal_run_residual_add_f16(ctx,
                                                         (uocr_metal_buffer_slice){scratch->clip_block_residual1.buffer, scratch->clip_block_residual1.offset},
                                                         (uocr_metal_buffer_slice){scratch->clip_block_mlp.buffer, scratch->clip_block_mlp.offset},
                                                         (uocr_metal_buffer_slice){out_tokens.buffer, out_tokens.offset},
                                                         (uint32_t)hidden_values,
                                                         "Metal CLIP batch MLP residual",
                                                         error,
                                                         error_size));

#undef RUN_CLIP_BATCH_BLOCK_STEP

    return 1;
}

static int metal_context_clip_transformer_batch_workspace_f16_to_slice(uocr_metal_context *ctx,
                                                                       uocr_metal_vision_workspace_slice input_tokens,
                                                                       const uocr_metal_clip_transformer_block_slices_f16 *blocks,
                                                                       uint32_t block_count,
                                                                       uint32_t token_count,
                                                                       uint32_t view_count,
                                                                       uocr_metal_vision_workspace_slice out_tokens,
                                                                       uocr_metal_vision_workspace *scratch,
                                                                       char *error,
                                                                       size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || input_tokens.buffer == nil || input_tokens.f16 == NULL || blocks == NULL || out_tokens.buffer == nil ||
        out_tokens.f16 == NULL || scratch == NULL || view_count == 0u) {
        return metal_fail(error, error_size, "invalid Metal CLIP batch transformer request");
    }
    if (block_count != UOCR_CLIP_BLOCKS) {
        return metal_fail(error, error_size, "invalid Metal CLIP batch transformer block count %u", block_count);
    }
    if (token_count != UOCR_CLIP_GLOBAL_TOKENS && token_count != UOCR_CLIP_LOCAL_TOKENS) {
        return metal_fail(error, error_size, "invalid Metal CLIP batch transformer token count %u", token_count);
    }
    if (view_count > UINT32_MAX / token_count) {
        return metal_fail(error, error_size, "Metal CLIP batch transformer row count overflow");
    }
    const uint32_t rows = token_count * view_count;
    uint64_t hidden_values = 0u;
    uint64_t hidden_bytes = 0u;
    if (!checked_mul_u64((uint64_t)rows, (uint64_t)UOCR_CLIP_HIDDEN_SIZE, &hidden_values) ||
        !metal_vision_f16_bytes(hidden_values, &hidden_bytes) ||
        !metal_vision_require_workspace_slice_f16(input_tokens, hidden_bytes, "CLIP batch transformer input", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(out_tokens, hidden_bytes, "CLIP batch transformer output", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->clip_a, hidden_bytes, "CLIP batch transformer state A", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->clip_b, hidden_bytes, "CLIP batch transformer state B", error, error_size)) {
        return 0;
    }

    uocr_metal_vision_workspace_slice current = input_tokens;
    uocr_metal_vision_workspace_slice state_a = scratch->clip_b;
    uocr_metal_vision_workspace_slice state_b = scratch->clip_a;
    uocr_metal_vision_workspace_slice next = state_a;
    const uint64_t clip_blocks_start_ns = uocr_profile_now_ns();
    for (uint32_t block_index = 0u; block_index < block_count; ++block_index) {
        const uint64_t block_start_ns = uocr_profile_now_ns();
        const int is_last = block_index + 1u == block_count;
        uocr_metal_vision_workspace_slice block_out = is_last ? out_tokens : next;
        if (block_out.buffer == current.buffer && block_out.offset == current.offset) {
            return metal_fail(error, error_size, "Metal CLIP batch transformer attempted in-place block output");
        }
        if (!metal_context_clip_transformer_batch_block_workspace_f16_to_slice(ctx,
                                                                               current,
                                                                               &blocks[block_index],
                                                                               token_count,
                                                                               view_count,
                                                                               block_out,
                                                                               scratch,
                                                                               error,
                                                                               error_size)) {
            char detail[512];
            metal_copy_error_detail(detail, sizeof(detail), error);
            return metal_fail(error,
                              error_size,
                              "failed to compute Metal CLIP batch transformer block %u: %s",
                              block_index,
                              detail);
        }
        if (!is_last) {
            current = block_out;
            next = (block_out.buffer == state_a.buffer && block_out.offset == state_a.offset) ? state_b : state_a;
        }
        metal_profile_add_event_now(ctx, view_count > 1u ? "metal.vision.clip_block_batch" : "metal.vision.clip_block", block_start_ns);
        metal_profile_add_event_now_f(ctx,
                                      block_start_ns,
                                      view_count > 1u ? "metal.vision.clip_block_batch.%02u" : "metal.vision.clip_block.%02u",
                                      block_index);
    }
    metal_profile_add_event_now(ctx, view_count > 1u ? "metal.vision.clip_blocks_batch" : "metal.vision.clip_blocks", clip_blocks_start_ns);
    metal_clear_error(error, error_size);
    return 1;
}

int uocr_metal_context_diagnostic_clip_transformer_block_f16(uocr_metal_context *ctx,
                                                  const uint16_t *input_f16,
                                                  const uocr_metal_clip_transformer_block_f16 *block,
                                                  uint32_t token_count,
                                                  uocr_metal_dense_output_type output_type,
                                                  void *out,
                                                  char *error,
                                                  size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || input_f16 == NULL || !metal_clip_transformer_block_has_weights(block) || out == NULL) {
        return metal_fail(error, error_size, "invalid Metal CLIP transformer block request");
    }
    if (token_count != UOCR_CLIP_GLOBAL_TOKENS && token_count != UOCR_CLIP_LOCAL_TOKENS) {
        return metal_fail(error, error_size, "invalid Metal CLIP transformer block token count %u", token_count);
    }
    if (output_type != UOCR_METAL_DENSE_OUTPUT_F16 && output_type != UOCR_METAL_DENSE_OUTPUT_F32) {
        return metal_fail(error, error_size, "unsupported Metal CLIP transformer block output type %d", (int)output_type);
    }
    if (UOCR_CLIP_HIDDEN_SIZE != 1024u || UOCR_CLIP_BLOCKS != 24u || UOCR_CLIP_ATTENTION_HEADS != 16u ||
        UOCR_CLIP_HEAD_DIM != 64u || UOCR_CLIP_QKV_SIZE != 3072u || UOCR_CLIP_MLP_INTERMEDIATE != 4096u ||
        UOCR_CLIP_GLOBAL_TOKENS != 257u || UOCR_CLIP_LOCAL_TOKENS != 101u) {
        return metal_fail(error, error_size, "Metal CLIP transformer block constants are inconsistent");
    }

    uint64_t hidden_values = 0u;
    uint64_t hidden_bytes = 0u;
    if (!metal_clip_transformer_activation_bytes(token_count, &hidden_values, &hidden_bytes, error, error_size)) {
        return 0;
    }
    (void)hidden_values;

    uint64_t host_scratch_bytes = 0u;
    if (!checked_mul_u64(hidden_bytes, 9u, &host_scratch_bytes)) {
        return metal_fail(error, error_size, "Metal CLIP transformer block host scratch byte-size overflow");
    }
    if (!metal_memory_reserve(ctx, UOCR_MEMORY_VISION_HOST_STAGING, host_scratch_bytes, "CLIP transformer block host scratch", error, error_size)) {
        return 0;
    }

    int result = 0;
    uint16_t *norm1_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    uint16_t *q_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    uint16_t *k_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    uint16_t *v_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    uint16_t *attention_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    uint16_t *projected_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    uint16_t *residual1_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    uint16_t *norm2_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    uint16_t *mlp_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    if (norm1_f16 == NULL || q_f16 == NULL || k_f16 == NULL || v_f16 == NULL || attention_f16 == NULL ||
        projected_f16 == NULL || residual1_f16 == NULL || norm2_f16 == NULL || mlp_f16 == NULL) {
        result = metal_fail(error, error_size, "failed to allocate Metal CLIP transformer block scratch buffers");
        goto cleanup_clip_transformer_block;
    }

#define RUN_CLIP_BLOCK_STEP(step_name, call_expr)                                                        \
    do {                                                                                                \
        if (!(call_expr)) {                                                                             \
            char detail[512];                                                                           \
            metal_copy_error_detail(detail, sizeof(detail), error);                                      \
            result = metal_fail(error, error_size, "failed to compute Metal CLIP transformer block %s: %s", step_name, detail); \
            goto cleanup_clip_transformer_block;                                                        \
        }                                                                                               \
    } while (0)

    RUN_CLIP_BLOCK_STEP("LayerNorm1",
                        uocr_metal_context_diagnostic_clip_layernorm_f16(ctx,
                                                              input_f16,
                                                              block->ln1_weight_f16,
                                                              block->ln1_bias_f16,
                                                              token_count,
                                                              UOCR_METAL_LAYERNORM_OUTPUT_F16,
                                                              norm1_f16,
                                                              error,
                                                              error_size));
    RUN_CLIP_BLOCK_STEP("QKV",
                        uocr_metal_context_diagnostic_clip_qkv_f16(ctx,
                                                         norm1_f16,
                                                         block->qkv_weight_f16,
                                                         block->qkv_bias_f16,
                                                         token_count,
                                                         UOCR_METAL_DENSE_OUTPUT_F16,
                                                         q_f16,
                                                         k_f16,
                                                         v_f16,
                                                         error,
                                                         error_size));
    RUN_CLIP_BLOCK_STEP("attention",
                        uocr_metal_context_diagnostic_clip_attention_f16(ctx,
                                                              q_f16,
                                                              k_f16,
                                                              v_f16,
                                                              token_count,
                                                              UOCR_METAL_DENSE_OUTPUT_F16,
                                                              attention_f16,
                                                              error,
                                                              error_size));
    RUN_CLIP_BLOCK_STEP("output projection",
                        uocr_metal_context_diagnostic_clip_output_projection_f16(ctx,
                                                                      attention_f16,
                                                                      block->out_proj_weight_f16,
                                                                      block->out_proj_bias_f16,
                                                                      token_count,
                                                                      UOCR_METAL_DENSE_OUTPUT_F16,
                                                                      projected_f16,
                                                                      error,
                                                                      error_size));
    RUN_CLIP_BLOCK_STEP("attention residual",
                        uocr_metal_context_diagnostic_clip_residual_add_f16(ctx,
                                                                 input_f16,
                                                                 projected_f16,
                                                                 token_count,
                                                                 UOCR_METAL_DENSE_OUTPUT_F16,
                                                                 residual1_f16,
                                                                 error,
                                                                 error_size));
    RUN_CLIP_BLOCK_STEP("LayerNorm2",
                        uocr_metal_context_diagnostic_clip_layernorm_f16(ctx,
                                                              residual1_f16,
                                                              block->ln2_weight_f16,
                                                              block->ln2_bias_f16,
                                                              token_count,
                                                              UOCR_METAL_LAYERNORM_OUTPUT_F16,
                                                              norm2_f16,
                                                              error,
                                                              error_size));
    RUN_CLIP_BLOCK_STEP("MLP",
                        uocr_metal_context_diagnostic_clip_mlp_f16(ctx,
                                                        norm2_f16,
                                                        block->mlp_fc1_weight_f16,
                                                        block->mlp_fc1_bias_f16,
                                                        block->mlp_fc2_weight_f16,
                                                        block->mlp_fc2_bias_f16,
                                                        token_count,
                                                        UOCR_METAL_DENSE_OUTPUT_F16,
                                                        mlp_f16,
                                                        error,
                                                        error_size));
    RUN_CLIP_BLOCK_STEP("MLP residual",
                        uocr_metal_context_diagnostic_clip_residual_add_f16(ctx,
                                                                 residual1_f16,
                                                                 mlp_f16,
                                                                 token_count,
                                                                 output_type,
                                                                 out,
                                                                 error,
                                                                 error_size));

#undef RUN_CLIP_BLOCK_STEP

    result = 1;

cleanup_clip_transformer_block:
    free(mlp_f16);
    free(norm2_f16);
    free(residual1_f16);
    free(projected_f16);
    free(attention_f16);
    free(v_f16);
    free(k_f16);
    free(q_f16);
    free(norm1_f16);
    metal_memory_release(ctx, UOCR_MEMORY_VISION_HOST_STAGING, host_scratch_bytes);
    if (result) {
        metal_clear_error(error, error_size);
    }
    return result;
}

int uocr_metal_context_diagnostic_clip_transformer_f16(uocr_metal_context *ctx,
                                            const uint16_t *input_f16,
                                            const uocr_metal_clip_transformer_block_f16 *blocks,
                                            uint32_t block_count,
                                            uint32_t token_count,
                                            uocr_metal_dense_output_type output_type,
                                            void *out,
                                            char *error,
                                            size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || input_f16 == NULL || blocks == NULL || out == NULL) {
        return metal_fail(error, error_size, "invalid Metal CLIP transformer request");
    }
    if (block_count != UOCR_CLIP_BLOCKS) {
        return metal_fail(error, error_size, "invalid Metal CLIP transformer block count %u", block_count);
    }
    if (token_count != UOCR_CLIP_GLOBAL_TOKENS && token_count != UOCR_CLIP_LOCAL_TOKENS) {
        return metal_fail(error, error_size, "invalid Metal CLIP transformer token count %u", token_count);
    }
    if (output_type != UOCR_METAL_DENSE_OUTPUT_F16 && output_type != UOCR_METAL_DENSE_OUTPUT_F32) {
        return metal_fail(error, error_size, "unsupported Metal CLIP transformer output type %d", (int)output_type);
    }
    for (uint32_t block_index = 0u; block_index < block_count; ++block_index) {
        if (!metal_clip_transformer_block_has_weights(&blocks[block_index])) {
            return metal_fail(error, error_size, "invalid Metal CLIP transformer block %u weights", block_index);
        }
    }

    uint64_t hidden_bytes = 0u;
    if (!metal_clip_transformer_activation_bytes(token_count, NULL, &hidden_bytes, error, error_size)) {
        return 0;
    }

    uint64_t host_scratch_bytes = 0u;
    if (!checked_mul_u64(hidden_bytes, 2u, &host_scratch_bytes)) {
        return metal_fail(error, error_size, "Metal CLIP transformer state host scratch byte-size overflow");
    }
    if (!metal_memory_reserve(ctx, UOCR_MEMORY_VISION_HOST_STAGING, host_scratch_bytes, "CLIP transformer state host scratch", error, error_size)) {
        return 0;
    }

    int result = 0;
    uint16_t *state_a_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    uint16_t *state_b_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    if (state_a_f16 == NULL || state_b_f16 == NULL) {
        result = metal_fail(error, error_size, "failed to allocate Metal CLIP transformer state buffers");
        goto cleanup_clip_transformer;
    }

    const uint16_t *current_f16 = input_f16;
    uint16_t *next_f16 = state_a_f16;
    const uint64_t clip_blocks_start_ns = uocr_profile_now_ns();
    for (uint32_t block_index = 0u; block_index < block_count; ++block_index) {
        const uint64_t block_start_ns = uocr_profile_now_ns();
        const int is_last = block_index + 1u == block_count;
        const uocr_metal_dense_output_type block_output_type = is_last ? output_type : UOCR_METAL_DENSE_OUTPUT_F16;
        void *block_out = is_last ? out : (void *)next_f16;
        if (!uocr_metal_context_diagnostic_clip_transformer_block_f16(ctx,
                                                           current_f16,
                                                           &blocks[block_index],
                                                           token_count,
                                                           block_output_type,
                                                           block_out,
                                                           error,
                                                           error_size)) {
            char detail[512];
            metal_copy_error_detail(detail, sizeof(detail), error);
            result = metal_fail(error,
                                error_size,
                                "failed to compute Metal CLIP transformer block %u: %s",
                                block_index,
                                detail);
            goto cleanup_clip_transformer;
        }
        if (!is_last) {
            current_f16 = next_f16;
            next_f16 = next_f16 == state_a_f16 ? state_b_f16 : state_a_f16;
        }
        metal_profile_add_event_now(ctx, "metal.vision.clip_block", block_start_ns);
        metal_profile_add_event_now_f(ctx, block_start_ns, "metal.vision.clip_block.%02u", block_index);
    }
    metal_profile_add_event_now(ctx, "metal.vision.clip_blocks", clip_blocks_start_ns);

    result = 1;

cleanup_clip_transformer:
    free(state_b_f16);
    free(state_a_f16);
    metal_memory_release(ctx, UOCR_MEMORY_VISION_HOST_STAGING, host_scratch_bytes);
    if (result) {
        metal_clear_error(error, error_size);
    }
    return result;
}

static int metal_vision_slice_has_bytes(uocr_metal_vision_workspace_slice slice, uint64_t bytes) {
    return slice.buffer != nil && slice.f16 != NULL && bytes != 0u && bytes <= slice.bytes;
}

int uocr_metal_context_diagnostic_clip_sam_concat_f16(uocr_metal_context *ctx,
                                           const uint16_t *clip_tokens_f16,
                                           const uint16_t *sam_nchw_f16,
                                           uint32_t grid_w,
                                           uint32_t grid_h,
                                           uocr_metal_dense_output_type output_type,
                                           void *out,
                                           char *error,
                                           size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || clip_tokens_f16 == NULL || sam_nchw_f16 == NULL || out == NULL) {
        return metal_fail(error, error_size, "invalid Metal CLIP/SAM concat request");
    }
    if (output_type != UOCR_METAL_DENSE_OUTPUT_F16 && output_type != UOCR_METAL_DENSE_OUTPUT_F32) {
        return metal_fail(error, error_size, "unsupported Metal CLIP/SAM concat output type %d", (int)output_type);
    }
    if (!((grid_w == UOCR_GLOBAL_GRID_QUERIES && grid_h == UOCR_GLOBAL_GRID_QUERIES) ||
          (grid_w == UOCR_LOCAL_GRID_QUERIES && grid_h == UOCR_LOCAL_GRID_QUERIES))) {
        return metal_fail(error, error_size, "unsupported Metal CLIP/SAM concat grid %ux%u", grid_w, grid_h);
    }
    if (UOCR_CLIP_HIDDEN_SIZE != 1024u || UOCR_SAM_FEATURE_CHANNELS != 1024u || UOCR_PROJECTOR_IN_SIZE != 2048u ||
        UOCR_PROJECTOR_IN_SIZE != UOCR_CLIP_HIDDEN_SIZE + UOCR_SAM_FEATURE_CHANNELS ||
        UOCR_CLIP_GLOBAL_TOKENS != 257u || UOCR_CLIP_LOCAL_TOKENS != 101u) {
        return metal_fail(error, error_size, "Metal CLIP/SAM concat constants are inconsistent");
    }

    uint64_t spatial = 0u;
    uint64_t clip_tokens = 0u;
    uint64_t clip_values = 0u;
    uint64_t sam_values = 0u;
    uint64_t output_values = 0u;
    uint64_t clip_bytes = 0u;
    uint64_t sam_bytes = 0u;
    uint64_t output_bytes = 0u;
    const uint64_t output_element_bytes = output_type == UOCR_METAL_DENSE_OUTPUT_F16 ? 2u : (uint64_t)sizeof(float);
    if (!checked_mul_u64((uint64_t)grid_w, (uint64_t)grid_h, &spatial) ||
        !checked_add_u64(spatial, (uint64_t)UOCR_CLIP_CLASS_TOKENS, &clip_tokens) ||
        (clip_tokens != (uint64_t)UOCR_CLIP_GLOBAL_TOKENS && clip_tokens != (uint64_t)UOCR_CLIP_LOCAL_TOKENS) ||
        !checked_mul_u64(clip_tokens, (uint64_t)UOCR_CLIP_HIDDEN_SIZE, &clip_values) ||
        !checked_mul_u64(spatial, (uint64_t)UOCR_SAM_FEATURE_CHANNELS, &sam_values) ||
        !checked_mul_u64(spatial, (uint64_t)UOCR_PROJECTOR_IN_SIZE, &output_values) ||
        !checked_mul_u64(clip_values, 2u, &clip_bytes) ||
        !checked_mul_u64(sam_values, 2u, &sam_bytes) ||
        !checked_mul_u64(output_values, output_element_bytes, &output_bytes) ||
        spatial > (uint64_t)UINT32_MAX || clip_bytes > (uint64_t)SIZE_MAX || sam_bytes > (uint64_t)SIZE_MAX ||
        output_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error, error_size, "Metal CLIP/SAM concat byte-size overflow");
    }

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (clip_bytes > max_buffer_length || sam_bytes > max_buffer_length || output_bytes > max_buffer_length) {
        return metal_fail(error,
                          error_size,
                          "Metal CLIP/SAM concat buffers exceed maxBufferLength %llu",
                          (unsigned long long)max_buffer_length);
    }

    int result = 0;
    @autoreleasepool {
        const char *function_name = output_type == UOCR_METAL_DENSE_OUTPUT_F16 ?
                                        "uocr_clip_sam_concat_f16_to_f16" :
                                        "uocr_clip_sam_concat_f16_to_f32";
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, function_name, error, error_size);
        if (pipeline == nil) {
            return 0;
        }

        id<MTLBuffer> clip = nil;
        id<MTLBuffer> sam = nil;
        id<MTLBuffer> dst = nil;
        id<MTLCommandBuffer> cb = nil;
        id<MTLComputeCommandEncoder> enc = nil;

        NSUInteger clip_offset = 0u;
        clip = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                            clip_tokens_f16,
                                                            (NSUInteger)clip_bytes,
                                                            MTLResourceStorageModeShared,
                                                            &clip_offset);
        if (clip == nil) {
            result = metal_fail(error, error_size, "failed to allocate Metal CLIP/SAM concat CLIP buffer");
            goto cleanup_clip_sam_concat;
        }
        clip.label = @"uocr_clip_sam_concat_clip_tokens_f16";

        NSUInteger sam_offset = 0u;
        sam = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                           sam_nchw_f16,
                                                           (NSUInteger)sam_bytes,
                                                           MTLResourceStorageModeShared,
                                                           &sam_offset);
        if (sam == nil) {
            result = metal_fail(error, error_size, "failed to allocate Metal CLIP/SAM concat SAM buffer");
            goto cleanup_clip_sam_concat;
        }
        sam.label = @"uocr_clip_sam_concat_sam_nchw_f16";

        NSUInteger dst_offset = 0u;
        int dst_needs_copy = 1;
        dst = metal_new_or_retain_vision_output_buffer(ctx,
                                                       out,
                                                       (NSUInteger)output_bytes,
                                                       MTLResourceStorageModeShared,
                                                       &dst_offset,
                                                       &dst_needs_copy);
        if (dst == nil) {
            result = metal_fail(error, error_size, "failed to allocate Metal CLIP/SAM concat output buffer");
            goto cleanup_clip_sam_concat;
        }
        dst.label = @"uocr_clip_sam_concat_output";
        metal_zero_buffer_range(dst, dst_offset, (NSUInteger)output_bytes);

        cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            result = metal_fail(error, error_size, "failed to create Metal CLIP/SAM concat command buffer");
            goto cleanup_clip_sam_concat;
        }
        cb.label = @"uocr_clip_sam_concat_command_buffer";

        enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            result = metal_fail(error, error_size, "failed to create Metal CLIP/SAM concat command encoder");
            goto cleanup_clip_sam_concat;
        }

        uocr_metal_clip_sam_concat_params params;
        params.grid_width = grid_w;
        params.grid_height = grid_h;
        params.hidden_size = UOCR_CLIP_HIDDEN_SIZE;
        params.projector_in_size = UOCR_PROJECTOR_IN_SIZE;

        NSUInteger threads_x = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        if (threads_x > (NSUInteger)UOCR_PROJECTOR_IN_SIZE) {
            threads_x = (NSUInteger)UOCR_PROJECTOR_IN_SIZE;
        }
        if (threads_x == 0u) {
            result = metal_fail(error, error_size, "Metal CLIP/SAM concat has invalid threadgroup width");
            goto cleanup_clip_sam_concat;
        }

        [enc setComputePipelineState:pipeline];
        [enc setBuffer:clip offset:clip_offset atIndex:0u];
        [enc setBuffer:sam offset:sam_offset atIndex:1u];
        [enc setBuffer:dst offset:dst_offset atIndex:2u];
        [enc setBytes:&params length:sizeof(params) atIndex:3u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)UOCR_PROJECTOR_IN_SIZE, (NSUInteger)spatial, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads_x, 1u, 1u)];
        [enc endEncoding];

        UOCR_METAL_COMMIT_AND_WAIT_PROFILED(ctx, cb);
        if (cb.status == MTLCommandBufferStatusError) {
            NSString *description = cb.error != nil ? [cb.error localizedDescription] : @"unknown command-buffer error";
            result = metal_fail(error, error_size, "Metal CLIP/SAM concat command failed: %s", [description UTF8String]);
            goto cleanup_clip_sam_concat;
        }

        metal_copy_buffer_range_to_host_if_needed(out, dst, dst_offset, (NSUInteger)output_bytes, dst_needs_copy);
        result = 1;

    cleanup_clip_sam_concat:
        [dst release];
        [sam release];
        [clip release];
    }

    if (result) {
        metal_clear_error(error, error_size);
    }
    return result;
}

int uocr_metal_context_diagnostic_visual_projector_f16(uocr_metal_context *ctx,
                                            const uint16_t *input_f16,
                                            const uint16_t *weight_f16,
                                            const uint16_t *bias_f16,
                                            uint32_t n_rows,
                                            uocr_metal_dense_output_type output_type,
                                            void *out,
                                            char *error,
                                            size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || input_f16 == NULL || weight_f16 == NULL || bias_f16 == NULL || out == NULL || n_rows == 0u) {
        return metal_fail(error, error_size, "invalid Metal visual projector request");
    }
    if (output_type != UOCR_METAL_DENSE_OUTPUT_F16 && output_type != UOCR_METAL_DENSE_OUTPUT_F32) {
        return metal_fail(error, error_size, "unsupported Metal visual projector output type %d", (int)output_type);
    }
    if (UOCR_PROJECTOR_IN_SIZE != 2048u || UOCR_HIDDEN_SIZE != 1280u) {
        return metal_fail(error, error_size, "Metal visual projector constants are inconsistent");
    }

    if (!uocr_metal_context_diagnostic_dense_f16(ctx,
                                      input_f16,
                                      weight_f16,
                                      bias_f16,
                                      n_rows,
                                      UOCR_PROJECTOR_IN_SIZE,
                                      UOCR_HIDDEN_SIZE,
                                      output_type,
                                      out,
                                      error,
                                      error_size)) {
        char detail[512];
        metal_copy_error_detail(detail, sizeof(detail), error);
        return metal_fail(error, error_size, "failed to compute Metal visual projector: %s", detail);
    }

    metal_clear_error(error, error_size);
    return 1;
}

static int metal_sam_transformer_block_has_weights(const uocr_metal_sam_transformer_block_f16 *block) {
    return block != NULL && block->norm1_weight_f16 != NULL && block->norm1_bias_f16 != NULL &&
           block->qkv_weight_f16 != NULL && block->qkv_bias_f16 != NULL &&
           block->proj_weight_f16 != NULL && block->proj_bias_f16 != NULL &&
           block->rel_pos_h_f16 != NULL && block->rel_pos_w_f16 != NULL &&
           block->rel_pos_h_length != 0u && block->rel_pos_w_length != 0u &&
           block->norm2_weight_f16 != NULL && block->norm2_bias_f16 != NULL &&
           block->mlp_lin1_weight_f16 != NULL && block->mlp_lin1_bias_f16 != NULL &&
           block->mlp_lin2_weight_f16 != NULL && block->mlp_lin2_bias_f16 != NULL;
}

static int metal_sam_transformer_activation_bytes(uint32_t grid_w,
                                                  uint32_t grid_h,
                                                  uint64_t *row_count,
                                                  uint64_t *hidden_bytes,
                                                  char *error,
                                                  size_t error_size) {
    if (grid_w == 0u || grid_h == 0u || grid_w > UOCR_SAM_MAX_GRID_SIZE || grid_h > UOCR_SAM_MAX_GRID_SIZE) {
        return metal_fail(error, error_size, "invalid Metal SAM transformer grid %ux%u", grid_w, grid_h);
    }
    uint64_t rows = 0u;
    uint64_t values = 0u;
    uint64_t bytes = 0u;
    if (!checked_mul_u64((uint64_t)grid_w, (uint64_t)grid_h, &rows) || rows == 0u ||
        rows > (uint64_t)UINT32_MAX || !checked_mul_u64(rows, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &values) ||
        !checked_mul_u64(values, 2u, &bytes) || values > (uint64_t)UINT32_MAX || bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error, error_size, "Metal SAM transformer byte-size overflow");
    }
    if (row_count != NULL) {
        *row_count = rows;
    }
    if (hidden_bytes != NULL) {
        *hidden_bytes = bytes;
    }
    return 1;
}

int uocr_metal_context_diagnostic_sam_transformer_block_f16(uocr_metal_context *ctx,
                                                 const uint16_t *input_bhwc_f16,
                                                 const uocr_metal_sam_transformer_block_f16 *block,
                                                 uint32_t grid_w,
                                                 uint32_t grid_h,
                                                 int use_global_attention,
                                                 uocr_metal_dense_output_type output_type,
                                                 void *out_bhwc,
                                                 char *error,
                                                 size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || input_bhwc_f16 == NULL || !metal_sam_transformer_block_has_weights(block) || out_bhwc == NULL) {
        return metal_fail(error, error_size, "invalid Metal SAM transformer block request");
    }
    if (output_type != UOCR_METAL_DENSE_OUTPUT_F16 && output_type != UOCR_METAL_DENSE_OUTPUT_F32) {
        return metal_fail(error, error_size, "unsupported Metal SAM transformer block output type %d", (int)output_type);
    }
    if (UOCR_SAM_HIDDEN_SIZE != 768u || UOCR_SAM_QKV_SIZE != 2304u || UOCR_SAM_ATTENTION_HEADS != 12u ||
        UOCR_SAM_HEAD_DIM != 64u || UOCR_SAM_ATTENTION_HEADS * UOCR_SAM_HEAD_DIM != UOCR_SAM_HIDDEN_SIZE ||
        UOCR_SAM_WINDOW_SIZE != 14u || UOCR_SAM_WINDOW_TOKENS != 196u || UOCR_SAM_MLP_INTERMEDIATE != 3072u) {
        return metal_fail(error, error_size, "Metal SAM transformer block constants are inconsistent");
    }

    uint64_t row_count_u64 = 0u;
    uint64_t hidden_bytes = 0u;
    if (!metal_sam_transformer_activation_bytes(grid_w, grid_h, &row_count_u64, &hidden_bytes, error, error_size)) {
        return 0;
    }
    const uint32_t row_count = (uint32_t)row_count_u64;

    uint32_t n_windows = 1u;
    uint32_t padded_w = grid_w;
    uint32_t padded_h = grid_h;
    uint64_t attention_rows_u64 = row_count_u64;
    uint64_t attention_values = 0u;
    uint64_t attention_bytes = 0u;
    if (!use_global_attention) {
        uint32_t windows_per_row = 0u;
        uint32_t windows_per_col = 0u;
        if (!sam_window_partition_geometry(grid_w,
                                           grid_h,
                                           &padded_w,
                                           &padded_h,
                                           &windows_per_row,
                                           &windows_per_col,
                                           &n_windows)) {
            return metal_fail(error, error_size, "invalid Metal SAM transformer window grid %ux%u", grid_w, grid_h);
        }
        if (!checked_mul_u64((uint64_t)n_windows, (uint64_t)UOCR_SAM_WINDOW_TOKENS, &attention_rows_u64)) {
            return metal_fail(error, error_size, "Metal SAM transformer window row-count overflow");
        }
    }
    if (!checked_mul_u64(attention_rows_u64, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &attention_values) ||
        !checked_mul_u64(attention_values, 2u, &attention_bytes) || attention_rows_u64 > (uint64_t)UINT32_MAX ||
        attention_values > (uint64_t)UINT32_MAX || attention_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error, error_size, "Metal SAM transformer attention byte-size overflow");
    }
    const uint32_t attention_rows = (uint32_t)attention_rows_u64;

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (hidden_bytes > max_buffer_length || attention_bytes > max_buffer_length) {
        return metal_fail(error,
                          error_size,
                          "Metal SAM transformer block buffers exceed maxBufferLength %llu",
                          (unsigned long long)max_buffer_length);
    }

    uint64_t hidden_host_scratch_bytes = 0u;
    uint64_t attention_host_scratch_bytes = 0u;
    uint64_t host_scratch_bytes = 0u;
    if (!checked_mul_u64(hidden_bytes, 5u, &hidden_host_scratch_bytes) ||
        !checked_mul_u64(attention_bytes, 6u, &attention_host_scratch_bytes) ||
        !checked_add_u64(hidden_host_scratch_bytes, attention_host_scratch_bytes, &host_scratch_bytes)) {
        return metal_fail(error, error_size, "Metal SAM transformer block host scratch byte-size overflow");
    }
    if (!metal_memory_reserve(ctx, UOCR_MEMORY_VISION_HOST_STAGING, host_scratch_bytes, "SAM transformer block host scratch", error, error_size)) {
        return 0;
    }

    int result = 0;
    uint16_t *norm1_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    uint16_t *window_tokens_f16 = (uint16_t *)malloc((size_t)attention_bytes);
    uint16_t *q_f16 = (uint16_t *)malloc((size_t)attention_bytes);
    uint16_t *k_f16 = (uint16_t *)malloc((size_t)attention_bytes);
    uint16_t *v_f16 = (uint16_t *)malloc((size_t)attention_bytes);
    uint16_t *attention_f16 = (uint16_t *)malloc((size_t)attention_bytes);
    uint16_t *projected_windows_f16 = (uint16_t *)malloc((size_t)attention_bytes);
    uint16_t *attention_bhwc_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    uint16_t *residual1_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    uint16_t *norm2_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    uint16_t *mlp_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    if (norm1_f16 == NULL || window_tokens_f16 == NULL || q_f16 == NULL || k_f16 == NULL || v_f16 == NULL ||
        attention_f16 == NULL || projected_windows_f16 == NULL || attention_bhwc_f16 == NULL || residual1_f16 == NULL ||
        norm2_f16 == NULL || mlp_f16 == NULL) {
        result = metal_fail(error, error_size, "failed to allocate Metal SAM transformer block scratch buffers");
        goto cleanup_sam_transformer_block;
    }

#define RUN_SAM_BLOCK_STEP(step_name, call_expr)                                                       \
    do {                                                                                                \
        if (!(call_expr)) {                                                                             \
            char detail[512];                                                                           \
            metal_copy_error_detail(detail, sizeof(detail), error);                                      \
            result = metal_fail(error, error_size, "failed to compute Metal SAM transformer block %s: %s", step_name, detail); \
            goto cleanup_sam_transformer_block;                                                         \
        }                                                                                               \
    } while (0)

    RUN_SAM_BLOCK_STEP("LayerNorm1",
                       uocr_metal_context_diagnostic_sam_layernorm_f16(ctx,
                                                             input_bhwc_f16,
                                                             block->norm1_weight_f16,
                                                             block->norm1_bias_f16,
                                                             row_count,
                                                             UOCR_METAL_LAYERNORM_OUTPUT_F16,
                                                             norm1_f16,
                                                             error,
                                                             error_size));

    if (use_global_attention) {
        RUN_SAM_BLOCK_STEP("QKV",
                           uocr_metal_context_diagnostic_sam_qkv_f16(ctx,
                                                           norm1_f16,
                                                           block->qkv_weight_f16,
                                                           block->qkv_bias_f16,
                                                           row_count,
                                                           UOCR_METAL_DENSE_OUTPUT_F16,
                                                           q_f16,
                                                           k_f16,
                                                           v_f16,
                                                           error,
                                                           error_size));
        RUN_SAM_BLOCK_STEP("relative-position attention",
                           uocr_metal_context_diagnostic_sam_rel_pos_attention_f16(ctx,
                                                                        q_f16,
                                                                        k_f16,
                                                                        v_f16,
                                                                        block->rel_pos_h_f16,
                                                                        block->rel_pos_w_f16,
                                                                        1u,
                                                                        grid_w,
                                                                        grid_h,
                                                                        block->rel_pos_h_length,
                                                                        block->rel_pos_w_length,
                                                                        UOCR_METAL_DENSE_OUTPUT_F16,
                                                                        attention_f16,
                                                                        error,
                                                                        error_size));
        RUN_SAM_BLOCK_STEP("attention projection residual",
                           uocr_metal_context_diagnostic_sam_attention_project_residual_f16(ctx,
                                                                                 attention_f16,
                                                                                 block->proj_weight_f16,
                                                                                 block->proj_bias_f16,
                                                                                 input_bhwc_f16,
                                                                                 row_count,
                                                                                 UOCR_METAL_DENSE_OUTPUT_F16,
                                                                                 residual1_f16,
                                                                                 error,
                                                                                 error_size));
    } else {
        uint32_t actual_windows = 0u;
        uint32_t actual_padded_w = 0u;
        uint32_t actual_padded_h = 0u;
        RUN_SAM_BLOCK_STEP("window partition",
                           uocr_metal_context_diagnostic_sam_window_partition_f16(ctx,
                                                                       norm1_f16,
                                                                       grid_w,
                                                                       grid_h,
                                                                       window_tokens_f16,
                                                                       &actual_windows,
                                                                       &actual_padded_w,
                                                                       &actual_padded_h,
                                                                       error,
                                                                       error_size));
        if (actual_windows != n_windows || actual_padded_w != padded_w || actual_padded_h != padded_h) {
            result = metal_fail(error, error_size, "Metal SAM transformer window geometry changed during partition");
            goto cleanup_sam_transformer_block;
        }
        RUN_SAM_BLOCK_STEP("window QKV",
                           uocr_metal_context_diagnostic_sam_qkv_f16(ctx,
                                                           window_tokens_f16,
                                                           block->qkv_weight_f16,
                                                           block->qkv_bias_f16,
                                                           attention_rows,
                                                           UOCR_METAL_DENSE_OUTPUT_F16,
                                                           q_f16,
                                                           k_f16,
                                                           v_f16,
                                                           error,
                                                           error_size));
        RUN_SAM_BLOCK_STEP("window relative-position attention",
                           uocr_metal_context_diagnostic_sam_rel_pos_attention_f16(ctx,
                                                                        q_f16,
                                                                        k_f16,
                                                                        v_f16,
                                                                        block->rel_pos_h_f16,
                                                                        block->rel_pos_w_f16,
                                                                        n_windows,
                                                                        UOCR_SAM_WINDOW_SIZE,
                                                                        UOCR_SAM_WINDOW_SIZE,
                                                                        block->rel_pos_h_length,
                                                                        block->rel_pos_w_length,
                                                                        UOCR_METAL_DENSE_OUTPUT_F16,
                                                                        attention_f16,
                                                                        error,
                                                                        error_size));
        RUN_SAM_BLOCK_STEP("window output projection",
                           uocr_metal_context_diagnostic_dense_f16(ctx,
                                                        attention_f16,
                                                        block->proj_weight_f16,
                                                        block->proj_bias_f16,
                                                        attention_rows,
                                                        UOCR_SAM_HIDDEN_SIZE,
                                                        UOCR_SAM_HIDDEN_SIZE,
                                                        UOCR_METAL_DENSE_OUTPUT_F16,
                                                        projected_windows_f16,
                                                        error,
                                                        error_size));
        RUN_SAM_BLOCK_STEP("window unpartition",
                           uocr_metal_context_diagnostic_sam_window_unpartition_f16(ctx,
                                                                         projected_windows_f16,
                                                                         grid_w,
                                                                         grid_h,
                                                                         attention_bhwc_f16,
                                                                         error,
                                                                         error_size));
        RUN_SAM_BLOCK_STEP("attention residual",
                           uocr_metal_context_diagnostic_sam_residual_add_f16(ctx,
                                                                    input_bhwc_f16,
                                                                    attention_bhwc_f16,
                                                                    row_count,
                                                                    UOCR_METAL_DENSE_OUTPUT_F16,
                                                                    residual1_f16,
                                                                    error,
                                                                    error_size));
    }

    RUN_SAM_BLOCK_STEP("LayerNorm2",
                       uocr_metal_context_diagnostic_sam_layernorm_f16(ctx,
                                                             residual1_f16,
                                                             block->norm2_weight_f16,
                                                             block->norm2_bias_f16,
                                                             row_count,
                                                             UOCR_METAL_LAYERNORM_OUTPUT_F16,
                                                             norm2_f16,
                                                             error,
                                                             error_size));
    RUN_SAM_BLOCK_STEP("MLP",
                       uocr_metal_context_diagnostic_sam_mlp_f16(ctx,
                                                       norm2_f16,
                                                       block->mlp_lin1_weight_f16,
                                                       block->mlp_lin1_bias_f16,
                                                       block->mlp_lin2_weight_f16,
                                                       block->mlp_lin2_bias_f16,
                                                       row_count,
                                                       UOCR_METAL_DENSE_OUTPUT_F16,
                                                       mlp_f16,
                                                       error,
                                                       error_size));
    RUN_SAM_BLOCK_STEP("MLP residual",
                       uocr_metal_context_diagnostic_sam_residual_add_f16(ctx,
                                                                residual1_f16,
                                                                mlp_f16,
                                                                row_count,
                                                                output_type,
                                                                out_bhwc,
                                                                error,
                                                                error_size));

#undef RUN_SAM_BLOCK_STEP

    result = 1;

cleanup_sam_transformer_block:
    free(mlp_f16);
    free(norm2_f16);
    free(residual1_f16);
    free(attention_bhwc_f16);
    free(projected_windows_f16);
    free(attention_f16);
    free(v_f16);
    free(k_f16);
    free(q_f16);
    free(window_tokens_f16);
    free(norm1_f16);
    metal_memory_release(ctx, UOCR_MEMORY_VISION_HOST_STAGING, host_scratch_bytes);
    if (result) {
        metal_clear_error(error, error_size);
    }
    return result;
}

int uocr_metal_context_diagnostic_sam_transformer_f16(uocr_metal_context *ctx,
                                           const uint16_t *input_bhwc_f16,
                                           const uocr_metal_sam_transformer_block_f16 *blocks,
                                           uint32_t block_count,
                                           uint32_t grid_w,
                                           uint32_t grid_h,
                                           uocr_metal_dense_output_type output_type,
                                           void *out_bhwc,
                                           char *error,
                                           size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || input_bhwc_f16 == NULL || blocks == NULL || out_bhwc == NULL) {
        return metal_fail(error, error_size, "invalid Metal SAM transformer request");
    }
    if (block_count != UOCR_SAM_BLOCKS) {
        return metal_fail(error, error_size, "invalid Metal SAM transformer block count %u", block_count);
    }
    if (output_type != UOCR_METAL_DENSE_OUTPUT_F16 && output_type != UOCR_METAL_DENSE_OUTPUT_F32) {
        return metal_fail(error, error_size, "unsupported Metal SAM transformer output type %d", (int)output_type);
    }
    for (uint32_t block_index = 0u; block_index < block_count; ++block_index) {
        if (!metal_sam_transformer_block_has_weights(&blocks[block_index])) {
            return metal_fail(error, error_size, "invalid Metal SAM transformer block %u weights", block_index);
        }
    }

    uint64_t hidden_bytes = 0u;
    if (!metal_sam_transformer_activation_bytes(grid_w, grid_h, NULL, &hidden_bytes, error, error_size)) {
        return 0;
    }

    uint64_t host_scratch_bytes = 0u;
    if (!checked_mul_u64(hidden_bytes, 2u, &host_scratch_bytes)) {
        return metal_fail(error, error_size, "Metal SAM transformer state host scratch byte-size overflow");
    }
    if (!metal_memory_reserve(ctx, UOCR_MEMORY_VISION_HOST_STAGING, host_scratch_bytes, "SAM transformer state host scratch", error, error_size)) {
        return 0;
    }

    int result = 0;
    uint16_t *state_a_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    uint16_t *state_b_f16 = (uint16_t *)malloc((size_t)hidden_bytes);
    if (state_a_f16 == NULL || state_b_f16 == NULL) {
        result = metal_fail(error, error_size, "failed to allocate Metal SAM transformer state buffers");
        goto cleanup_sam_transformer;
    }

    const uint16_t *current_f16 = input_bhwc_f16;
    uint16_t *next_f16 = state_a_f16;
    const uint64_t sam_blocks_start_ns = uocr_profile_now_ns();
    for (uint32_t block_index = 0u; block_index < block_count; ++block_index) {
        const uint64_t block_start_ns = uocr_profile_now_ns();
        const int is_last = block_index + 1u == block_count;
        const uocr_metal_dense_output_type block_output_type = is_last ? output_type : UOCR_METAL_DENSE_OUTPUT_F16;
        void *block_out = is_last ? out_bhwc : (void *)next_f16;
        if (!uocr_metal_context_diagnostic_sam_transformer_block_f16(ctx,
                                                          current_f16,
                                                          &blocks[block_index],
                                                          grid_w,
                                                          grid_h,
                                                          uocr_sam_block_uses_global_attention(block_index),
                                                          block_output_type,
                                                          block_out,
                                                          error,
                                                          error_size)) {
            char detail[512];
            metal_copy_error_detail(detail, sizeof(detail), error);
            result = metal_fail(error,
                                error_size,
                                "failed to compute Metal SAM transformer block %u: %s",
                                block_index,
                                detail);
            goto cleanup_sam_transformer;
        }
        if (!is_last) {
            current_f16 = next_f16;
            next_f16 = next_f16 == state_a_f16 ? state_b_f16 : state_a_f16;
        }
        metal_profile_add_event_now(ctx, "metal.vision.sam_block", block_start_ns);
        metal_profile_add_event_now_f(ctx, block_start_ns, "metal.vision.sam_block.%02u", block_index);
    }
    metal_profile_add_event_now(ctx, "metal.vision.sam_blocks", sam_blocks_start_ns);

    result = 1;

cleanup_sam_transformer:
    free(state_b_f16);
    free(state_a_f16);
    metal_memory_release(ctx, UOCR_MEMORY_VISION_HOST_STAGING, host_scratch_bytes);
    if (result) {
        metal_clear_error(error, error_size);
    }
    return result;
}

static int metal_sam_transformer_block_slices_have_weights(const uocr_metal_sam_transformer_block_slices_f16 *block) {
    return block != NULL && block->norm1_weight.host_f16 != NULL && block->norm1_bias.host_f16 != NULL &&
           block->qkv_weight.host_f16 != NULL && block->qkv_bias.host_f16 != NULL &&
           block->proj_weight.host_f16 != NULL && block->proj_bias.host_f16 != NULL &&
           block->rel_pos_h.host_f16 != NULL && block->rel_pos_w.host_f16 != NULL &&
           block->rel_pos_h_length != 0u && block->rel_pos_w_length != 0u &&
           block->norm2_weight.host_f16 != NULL && block->norm2_bias.host_f16 != NULL &&
           block->mlp_lin1_weight.host_f16 != NULL && block->mlp_lin1_bias.host_f16 != NULL &&
           block->mlp_lin2_weight.host_f16 != NULL && block->mlp_lin2_bias.host_f16 != NULL;
}

static int metal_context_sam_window_partition_batch_f16_to_slice(uocr_metal_context *ctx,
                                                                 uocr_metal_vision_workspace_slice input_bhwc,
                                                                 uint32_t grid_w,
                                                                 uint32_t grid_h,
                                                                 uint32_t view_count,
                                                                 uocr_metal_vision_workspace_slice out_windows,
                                                                 uint32_t *out_n_windows,
                                                                 uint32_t *out_padded_w,
                                                                 uint32_t *out_padded_h,
                                                                 char *error,
                                                                 size_t error_size) {
    uint32_t padded_w = 0u;
    uint32_t padded_h = 0u;
    uint32_t windows_per_row = 0u;
    uint32_t windows_per_col = 0u;
    uint32_t n_windows = 0u;
    if (ctx == NULL || view_count == 0u || out_n_windows == NULL || out_padded_w == NULL || out_padded_h == NULL ||
        !sam_window_partition_geometry(grid_w,
                                       grid_h,
                                       &padded_w,
                                       &padded_h,
                                       &windows_per_row,
                                       &windows_per_col,
                                       &n_windows)) {
        return metal_fail(error, error_size, "invalid Metal SAM window partition batch request");
    }

    uint64_t input_values_per_view = 0u;
    uint64_t input_values = 0u;
    uint64_t input_bytes = 0u;
    uint64_t window_tokens_per_view = 0u;
    uint64_t window_values_per_view = 0u;
    uint64_t window_values = 0u;
    uint64_t window_bytes = 0u;
    if (!metal_vision_square_grid_values(grid_w, grid_h, UOCR_SAM_HIDDEN_SIZE, &input_values_per_view) ||
        !checked_mul_u64(input_values_per_view, (uint64_t)view_count, &input_values) ||
        !metal_vision_f16_bytes(input_values, &input_bytes) ||
        !checked_mul_u64((uint64_t)n_windows, (uint64_t)UOCR_SAM_WINDOW_TOKENS, &window_tokens_per_view) ||
        !checked_mul_u64(window_tokens_per_view, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &window_values_per_view) ||
        !checked_mul_u64(window_values_per_view, (uint64_t)view_count, &window_values) ||
        !metal_vision_f16_bytes(window_values, &window_bytes) || window_values > (uint64_t)UINT32_MAX ||
        !metal_vision_require_workspace_slice_f16(input_bhwc, input_bytes, "SAM window partition batch input", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(out_windows, window_bytes, "SAM window partition batch output", error, error_size)) {
        return 0;
    }

    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_sam_window_partition_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "Metal SAM window partition batch", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal SAM window partition batch command encoder");
        }

        uocr_metal_sam_window_partition_params params;
        params.grid_width = grid_w;
        params.grid_height = grid_h;
        params.padded_width = padded_w;
        params.padded_height = padded_h;
        params.windows_per_row = windows_per_row;
        params.windows_per_col = windows_per_col;
        params.window_size = UOCR_SAM_WINDOW_SIZE;
        params.hidden_size = UOCR_SAM_HIDDEN_SIZE;
        params.batch_size = view_count;

        const NSUInteger threads_per_group = metal_power2_threadgroup_width(256u, pipeline.maxTotalThreadsPerThreadgroup);
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:input_bhwc.buffer offset:input_bhwc.offset atIndex:0u];
        [enc setBuffer:out_windows.buffer offset:out_windows.offset atIndex:1u];
        [enc setBytes:&params length:sizeof(params) atIndex:2u];
        [enc dispatchThreads:MTLSizeMake((NSUInteger)window_values, 1u, 1u)
       threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
        [enc endEncoding];
        if (!metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "Metal SAM window partition batch", error, error_size)) {
            return 0;
        }
    }

    *out_n_windows = n_windows;
    *out_padded_w = padded_w;
    *out_padded_h = padded_h;
    metal_clear_error(error, error_size);
    return 1;
}

