static int metal_context_sam_rel_pos_attention_batch_f16_to_slice(uocr_metal_context *ctx,
                                                                  uocr_metal_vision_workspace_slice q,
                                                                  uocr_metal_vision_workspace_slice k,
                                                                  uocr_metal_vision_workspace_slice v,
                                                                  uocr_metal_vision_tensor_f16 rel_pos_h,
                                                                  uocr_metal_vision_tensor_f16 rel_pos_w,
                                                                  uint32_t n_windows,
                                                                  uint32_t grid_w,
                                                                  uint32_t grid_h,
                                                                  uint32_t view_count,
                                                                  uint32_t rel_pos_h_length,
                                                                  uint32_t rel_pos_w_length,
                                                                  uocr_metal_vision_workspace_slice out,
                                                                  char *error,
                                                                  size_t error_size) {
    uint64_t tokens = 0u;
    uint64_t values_per_view = 0u;
    uint64_t values = 0u;
    uint64_t bytes = 0u;
    uint64_t rel_h_values = 0u;
    uint64_t rel_w_values = 0u;
    uint64_t rel_h_bytes = 0u;
    uint64_t rel_w_bytes = 0u;
    if (ctx == NULL || n_windows == 0u || view_count == 0u || grid_w == 0u || grid_h == 0u ||
        rel_pos_h_length == 0u || rel_pos_w_length == 0u ||
        !checked_mul_u64((uint64_t)grid_w, (uint64_t)grid_h, &tokens) || tokens == 0u ||
        tokens > (uint64_t)UINT32_MAX || tokens > (uint64_t)UOCR_SAM_MAX_GRID_TOKENS ||
        !checked_mul_u64((uint64_t)n_windows, tokens, &values_per_view) ||
        !checked_mul_u64(values_per_view, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &values_per_view) ||
        !checked_mul_u64(values_per_view, (uint64_t)view_count, &values) ||
        !metal_vision_f16_bytes(values, &bytes) ||
        !checked_mul_u64((uint64_t)rel_pos_h_length, (uint64_t)UOCR_SAM_HEAD_DIM, &rel_h_values) ||
        !checked_mul_u64((uint64_t)rel_pos_w_length, (uint64_t)UOCR_SAM_HEAD_DIM, &rel_w_values) ||
        !metal_vision_f16_bytes(rel_h_values, &rel_h_bytes) ||
        !metal_vision_f16_bytes(rel_w_values, &rel_w_bytes) ||
        !metal_vision_require_workspace_slice_f16(q, bytes, "SAM rel-pos batch Q", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(k, bytes, "SAM rel-pos batch K", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(v, bytes, "SAM rel-pos batch V", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(out, bytes, "SAM rel-pos batch output", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(rel_pos_h, rel_h_bytes, "SAM relative position H", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(rel_pos_w, rel_w_bytes, "SAM relative position W", error, error_size)) {
        return 0;
    }
    if (grid_w > UOCR_SAM_MAX_GRID_SIZE || grid_h > UOCR_SAM_MAX_GRID_SIZE ||
        rel_pos_h_length > UOCR_SAM_MAX_REL_POS_SIZE || rel_pos_w_length > UOCR_SAM_MAX_REL_POS_SIZE) {
        return metal_fail(error, error_size, "Metal SAM rel-pos batch dimensions exceed limits");
    }
    if (UOCR_SAM_ATTENTION_HEADS * UOCR_SAM_HEAD_DIM != UOCR_SAM_HIDDEN_SIZE) {
        return metal_fail(error, error_size, "Metal SAM rel-pos batch constants are inconsistent");
    }
    const uint64_t logical_windows = (uint64_t)n_windows * (uint64_t)view_count;
    if (logical_windows > (uint64_t)NSUIntegerMax) {
        return metal_fail(error, error_size, "Metal SAM rel-pos batch window-count overflow");
    }

    @autoreleasepool {
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, "uocr_sam_rel_pos_attention_flash_f16_to_f16", error, error_size);
        if (pipeline == nil) {
            return 0;
        }
        const NSUInteger threads_per_group = 128u;
        if (pipeline.maxTotalThreadsPerThreadgroup < threads_per_group) {
            return metal_fail(error, error_size, "Metal SAM rel-pos batch flash attention cannot run four simdgroups per block");
        }
        int owned_command_buffer = 0;
        id<MTLCommandBuffer> cb = metal_command_buffer_for_op(ctx, &owned_command_buffer, "Metal SAM rel-pos batch attention", error, error_size);
        if (cb == nil) {
            return 0;
        }
        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            return metal_fail(error, error_size, "failed to create Metal SAM rel-pos batch attention command encoder");
        }

        uocr_metal_sam_rel_pos_attention_params params;
        params.windows = n_windows;
        params.grid_width = grid_w;
        params.grid_height = grid_h;
        params.tokens_per_window = (uint32_t)tokens;
        params.heads = UOCR_SAM_ATTENTION_HEADS;
        params.head_dim = UOCR_SAM_HEAD_DIM;
        params.rel_pos_h_length = rel_pos_h_length;
        params.rel_pos_w_length = rel_pos_w_length;
        params.scale = 1.0f / sqrtf((float)UOCR_SAM_HEAD_DIM);
        params.batch_size = view_count;
        params.reserved1 = 0u;
        params.reserved2 = 0u;

        const NSUInteger query_blocks = (NSUInteger)(((uint32_t)tokens + 3u) / 4u);
        [enc setComputePipelineState:pipeline];
        [enc setBuffer:q.buffer offset:q.offset atIndex:0u];
        [enc setBuffer:k.buffer offset:k.offset atIndex:1u];
        [enc setBuffer:v.buffer offset:v.offset atIndex:2u];
        [enc setBuffer:rel_pos_h.slice.buffer offset:rel_pos_h.slice.offset atIndex:3u];
        [enc setBuffer:rel_pos_w.slice.buffer offset:rel_pos_w.slice.offset atIndex:4u];
        [enc setBuffer:out.buffer offset:out.offset atIndex:5u];
        [enc setBytes:&params length:sizeof(params) atIndex:6u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)UOCR_SAM_ATTENTION_HEADS, query_blocks, (NSUInteger)logical_windows)
             threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
        [enc endEncoding];
        return metal_finish_command_buffer_for_op(ctx, cb, owned_command_buffer, "Metal SAM rel-pos batch attention", error, error_size);
    }
}

static int metal_context_sam_mlp_batch_workspace_f16_to_slice(uocr_metal_context *ctx,
                                                             uocr_metal_vision_workspace_slice input,
                                                             const uocr_metal_sam_transformer_block_slices_f16 *block,
                                                             uint32_t rows,
                                                             uocr_metal_vision_workspace_slice intermediate,
                                                             uocr_metal_vision_workspace_slice out,
                                                             char *error,
                                                             size_t error_size) {
    uint64_t hidden_values = 0u;
    uint64_t hidden_bytes = 0u;
    uint64_t intermediate_values = 0u;
    uint64_t intermediate_bytes = 0u;
    const uint64_t lin1_weight_bytes = (uint64_t)UOCR_SAM_MLP_INTERMEDIATE * (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    const uint64_t lin1_bias_bytes = (uint64_t)UOCR_SAM_MLP_INTERMEDIATE * 2u;
    const uint64_t lin2_weight_bytes = (uint64_t)UOCR_SAM_HIDDEN_SIZE * (uint64_t)UOCR_SAM_MLP_INTERMEDIATE * 2u;
    const uint64_t lin2_bias_bytes = (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    if (ctx == NULL || !metal_sam_transformer_block_slices_have_weights(block) || rows == 0u ||
        !checked_mul_u64((uint64_t)rows, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &hidden_values) ||
        !metal_vision_f16_bytes(hidden_values, &hidden_bytes) ||
        !checked_mul_u64((uint64_t)rows, (uint64_t)UOCR_SAM_MLP_INTERMEDIATE, &intermediate_values) ||
        intermediate_values > (uint64_t)UINT32_MAX ||
        !metal_vision_f16_bytes(intermediate_values, &intermediate_bytes) ||
        !metal_vision_require_workspace_slice_f16(input, hidden_bytes, "SAM batch MLP input", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(intermediate, intermediate_bytes, "SAM batch MLP intermediate", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(out, hidden_bytes, "SAM batch MLP output", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->mlp_lin1_weight, lin1_weight_bytes, "SAM MLP lin1 weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->mlp_lin1_bias, lin1_bias_bytes, "SAM MLP lin1 bias", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->mlp_lin2_weight, lin2_weight_bytes, "SAM MLP lin2 weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->mlp_lin2_bias, lin2_bias_bytes, "SAM MLP lin2 bias", error, error_size)) {
        return 0;
    }

    uocr_metal_buffer_slice input_slice = { input.buffer, input.offset };
    uocr_metal_buffer_slice intermediate_slice = { intermediate.buffer, intermediate.offset };
    uocr_metal_buffer_slice out_slice = { out.buffer, out.offset };
    if (!metal_run_mps_matmul_nt_f16(ctx,
                                     input_slice,
                                     block->mlp_lin1_weight.slice,
                                     intermediate_slice,
                                     rows,
                                     UOCR_SAM_HIDDEN_SIZE,
                                     UOCR_SAM_MLP_INTERMEDIATE,
                                     "Metal SAM batch MLP lin1 MPS matmul",
                                     error,
                                     error_size) ||
        !metal_run_bias_gelu_f16_inplace(ctx,
                                         intermediate_slice,
                                         block->mlp_lin1_bias.slice,
                                         rows,
                                         UOCR_SAM_MLP_INTERMEDIATE,
                                         "Metal SAM batch MLP lin1 bias GELU",
                                         error,
                                         error_size) ||
        !metal_run_mps_matmul_nt_f16(ctx,
                                     intermediate_slice,
                                     block->mlp_lin2_weight.slice,
                                     out_slice,
                                     rows,
                                     UOCR_SAM_MLP_INTERMEDIATE,
                                     UOCR_SAM_HIDDEN_SIZE,
                                     "Metal SAM batch MLP lin2 MPS matmul",
                                     error,
                                     error_size) ||
        !metal_run_bias_add_f16_inplace(ctx,
                                        out_slice,
                                        block->mlp_lin2_bias.slice,
                                        rows,
                                        UOCR_SAM_HIDDEN_SIZE,
                                        "Metal SAM batch MLP lin2 bias add",
                                        error,
                                        error_size)) {
        char detail[512];
        metal_copy_error_detail(detail, sizeof(detail), error);
        return metal_fail(error, error_size, "failed to compute Metal SAM batch MLP: %s", detail);
    }
    return 1;
}

static int metal_context_sam_transformer_batch_block_workspace_f16_to_slice(uocr_metal_context *ctx,
                                                                           uocr_metal_vision_workspace_slice input_bhwc,
                                                                           const uocr_metal_sam_transformer_block_slices_f16 *block,
                                                                           uint32_t grid_w,
                                                                           uint32_t grid_h,
                                                                           uint32_t view_count,
                                                                           int use_global_attention,
                                                                           uocr_metal_vision_workspace_slice out_bhwc,
                                                                           uocr_metal_vision_workspace *scratch,
                                                                           char *error,
                                                                           size_t error_size) {
    if (ctx == NULL || !metal_sam_transformer_block_slices_have_weights(block) || view_count == 0u || scratch == NULL) {
        return metal_fail(error, error_size, "invalid Metal SAM batch transformer block request");
    }
    if (UOCR_SAM_HIDDEN_SIZE != 768u || UOCR_SAM_QKV_SIZE != 2304u || UOCR_SAM_ATTENTION_HEADS != 12u ||
        UOCR_SAM_HEAD_DIM != 64u || UOCR_SAM_ATTENTION_HEADS * UOCR_SAM_HEAD_DIM != UOCR_SAM_HIDDEN_SIZE ||
        UOCR_SAM_WINDOW_SIZE != 14u || UOCR_SAM_WINDOW_TOKENS != 196u || UOCR_SAM_MLP_INTERMEDIATE != 3072u) {
        return metal_fail(error, error_size, "Metal SAM batch transformer block constants are inconsistent");
    }

    uint64_t rows_per_view_u64 = 0u;
    uint64_t hidden_bytes_per_view = 0u;
    if (!metal_sam_transformer_activation_bytes(grid_w, grid_h, &rows_per_view_u64, &hidden_bytes_per_view, error, error_size)) {
        return 0;
    }
    if (rows_per_view_u64 > (uint64_t)(UINT32_MAX / view_count)) {
        return metal_fail(error, error_size, "Metal SAM batch transformer row-count overflow");
    }
    const uint32_t rows_per_view = (uint32_t)rows_per_view_u64;
    const uint32_t rows = rows_per_view * view_count;

    uint32_t n_windows = 1u;
    uint32_t padded_w = grid_w;
    uint32_t padded_h = grid_h;
    uint64_t attention_rows_per_view_u64 = rows_per_view_u64;
    if (!use_global_attention) {
        uint32_t windows_per_row = 0u;
        uint32_t windows_per_col = 0u;
        if (!sam_window_partition_geometry(grid_w,
                                           grid_h,
                                           &padded_w,
                                           &padded_h,
                                           &windows_per_row,
                                           &windows_per_col,
                                           &n_windows)) {
            return metal_fail(error, error_size, "invalid Metal SAM batch transformer window grid %ux%u", grid_w, grid_h);
        }
        if (!checked_mul_u64((uint64_t)n_windows, (uint64_t)UOCR_SAM_WINDOW_TOKENS, &attention_rows_per_view_u64)) {
            return metal_fail(error, error_size, "Metal SAM batch transformer window row-count overflow");
        }
    }
    if (attention_rows_per_view_u64 > (uint64_t)(UINT32_MAX / view_count)) {
        return metal_fail(error, error_size, "Metal SAM batch transformer attention row-count overflow");
    }
    const uint32_t attention_rows = (uint32_t)attention_rows_per_view_u64 * view_count;

    uint64_t hidden_values = 0u;
    uint64_t hidden_bytes = 0u;
    uint64_t attention_values = 0u;
    uint64_t attention_bytes = 0u;
    uint64_t mlp_values = 0u;
    uint64_t mlp_bytes = 0u;
    const uint64_t parameter_bytes = (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    const uint64_t qkv_weight_bytes = (uint64_t)UOCR_SAM_QKV_SIZE * (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    const uint64_t qkv_bias_bytes = (uint64_t)UOCR_SAM_QKV_SIZE * 2u;
    const uint64_t projection_weight_bytes = (uint64_t)UOCR_SAM_HIDDEN_SIZE * (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    const uint64_t rel_h_bytes = (uint64_t)block->rel_pos_h_length * (uint64_t)UOCR_SAM_HEAD_DIM * 2u;
    const uint64_t rel_w_bytes = (uint64_t)block->rel_pos_w_length * (uint64_t)UOCR_SAM_HEAD_DIM * 2u;
    if (!checked_mul_u64((uint64_t)rows, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &hidden_values) ||
        hidden_values > (uint64_t)UINT32_MAX || !metal_vision_f16_bytes(hidden_values, &hidden_bytes) ||
        !checked_mul_u64((uint64_t)attention_rows, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &attention_values) ||
        attention_values > (uint64_t)UINT32_MAX || !metal_vision_f16_bytes(attention_values, &attention_bytes) ||
        !checked_mul_u64((uint64_t)rows, (uint64_t)UOCR_SAM_MLP_INTERMEDIATE, &mlp_values) ||
        mlp_values > (uint64_t)UINT32_MAX || !metal_vision_f16_bytes(mlp_values, &mlp_bytes) ||
        !metal_vision_require_workspace_slice_f16(input_bhwc, hidden_bytes, "SAM batch block input", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(out_bhwc, hidden_bytes, "SAM batch block output", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->sam_block_norm1_bhwc, hidden_bytes, "SAM batch block norm1", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->sam_block_window_tokens, attention_bytes, "SAM batch block window tokens", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->sam_block_q, attention_bytes, "SAM batch block Q", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->sam_block_k, attention_bytes, "SAM batch block K", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->sam_block_v, attention_bytes, "SAM batch block V", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->sam_block_attention, attention_bytes, "SAM batch block attention", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->sam_block_projected_windows, attention_bytes, "SAM batch block projected windows", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->sam_block_attention_bhwc, hidden_bytes, "SAM batch block attention BHWC", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->sam_block_residual1_bhwc, hidden_bytes, "SAM batch block residual1", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->sam_block_norm2_bhwc, hidden_bytes, "SAM batch block norm2", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->sam_block_mlp_intermediate, mlp_bytes, "SAM batch block MLP intermediate", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->sam_block_mlp_bhwc, hidden_bytes, "SAM batch block MLP", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->norm1_weight, parameter_bytes, "SAM block norm1 weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->norm1_bias, parameter_bytes, "SAM block norm1 bias", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->qkv_weight, qkv_weight_bytes, "SAM block QKV weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->qkv_bias, qkv_bias_bytes, "SAM block QKV bias", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->proj_weight, projection_weight_bytes, "SAM block projection weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->proj_bias, parameter_bytes, "SAM block projection bias", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->rel_pos_h, rel_h_bytes, "SAM block relative position H", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->rel_pos_w, rel_w_bytes, "SAM block relative position W", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->norm2_weight, parameter_bytes, "SAM block norm2 weight", error, error_size) ||
        !metal_vision_require_tensor_slice_f16(block->norm2_bias, parameter_bytes, "SAM block norm2 bias", error, error_size)) {
        return 0;
    }

#define RUN_SAM_BATCH_BLOCK_STEP(step_name, call_expr)                                                \
    do {                                                                                                \
        if (!(call_expr)) {                                                                             \
            char detail[512];                                                                           \
            metal_copy_error_detail(detail, sizeof(detail), error);                                      \
            return metal_fail(error, error_size, "failed to compute Metal SAM batch block %s: %s", step_name, detail); \
        }                                                                                               \
    } while (0)

    RUN_SAM_BATCH_BLOCK_STEP("LayerNorm1",
                             metal_context_layernorm_f16_with_parameter_buffers(ctx,
                                                                                input_bhwc.f16,
                                                                                block->norm1_weight.slice.buffer,
                                                                                block->norm1_weight.slice.offset,
                                                                                block->norm1_bias.slice.buffer,
                                                                                block->norm1_bias.slice.offset,
                                                                                rows,
                                                                                UOCR_SAM_HIDDEN_SIZE,
                                                                                1.0e-6f,
                                                                                UOCR_METAL_LAYERNORM_OUTPUT_F16,
                                                                                scratch->sam_block_norm1_bhwc.f16,
                                                                                "Metal SAM batch LayerNorm1",
                                                                                error,
                                                                                error_size));

    if (use_global_attention) {
        RUN_SAM_BATCH_BLOCK_STEP("QKV",
                                 metal_run_packed_qkv_mps_f16(ctx,
                                                               (uocr_metal_buffer_slice){scratch->sam_block_norm1_bhwc.buffer, scratch->sam_block_norm1_bhwc.offset},
                                                               block->qkv_weight.slice,
                                                               block->qkv_bias.slice,
                                                               (uocr_metal_buffer_slice){scratch->sam_block_q.buffer, scratch->sam_block_q.offset},
                                                               (uocr_metal_buffer_slice){scratch->sam_block_k.buffer, scratch->sam_block_k.offset},
                                                               (uocr_metal_buffer_slice){scratch->sam_block_v.buffer, scratch->sam_block_v.offset},
                                                               rows,
                                                               UOCR_SAM_HIDDEN_SIZE,
                                                               "Metal SAM batch global QKV MPS matmul",
                                                               error,
                                                               error_size));
        RUN_SAM_BATCH_BLOCK_STEP("relative-position attention",
                                 metal_context_sam_rel_pos_attention_batch_f16_to_slice(ctx,
                                                                                       scratch->sam_block_q,
                                                                                       scratch->sam_block_k,
                                                                                       scratch->sam_block_v,
                                                                                       block->rel_pos_h,
                                                                                       block->rel_pos_w,
                                                                                       1u,
                                                                                       grid_w,
                                                                                       grid_h,
                                                                                       view_count,
                                                                                       block->rel_pos_h_length,
                                                                                       block->rel_pos_w_length,
                                                                                       scratch->sam_block_attention,
                                                                                       error,
                                                                                       error_size));
        RUN_SAM_BATCH_BLOCK_STEP("output projection",
                                 metal_run_mps_matmul_nt_f16(ctx,
                                                             (uocr_metal_buffer_slice){scratch->sam_block_attention.buffer, scratch->sam_block_attention.offset},
                                                             block->proj_weight.slice,
                                                             (uocr_metal_buffer_slice){scratch->sam_block_attention_bhwc.buffer, scratch->sam_block_attention_bhwc.offset},
                                                             rows,
                                                             UOCR_SAM_HIDDEN_SIZE,
                                                             UOCR_SAM_HIDDEN_SIZE,
                                                             "Metal SAM batch global output projection MPS matmul",
                                                             error,
                                                             error_size) &&
                                 metal_run_bias_add_f16_inplace(ctx,
                                                                (uocr_metal_buffer_slice){scratch->sam_block_attention_bhwc.buffer, scratch->sam_block_attention_bhwc.offset},
                                                                block->proj_bias.slice,
                                                                rows,
                                                                UOCR_SAM_HIDDEN_SIZE,
                                                                "Metal SAM batch global output projection bias",
                                                                error,
                                                                error_size));
        RUN_SAM_BATCH_BLOCK_STEP("attention residual",
                                 metal_run_residual_add_f16(ctx,
                                                            (uocr_metal_buffer_slice){input_bhwc.buffer, input_bhwc.offset},
                                                            (uocr_metal_buffer_slice){scratch->sam_block_attention_bhwc.buffer, scratch->sam_block_attention_bhwc.offset},
                                                            (uocr_metal_buffer_slice){scratch->sam_block_residual1_bhwc.buffer, scratch->sam_block_residual1_bhwc.offset},
                                                            (uint32_t)hidden_values,
                                                            "Metal SAM batch global attention residual",
                                                            error,
                                                            error_size));
    } else {
        uint32_t actual_windows = 0u;
        uint32_t actual_padded_w = 0u;
        uint32_t actual_padded_h = 0u;
        RUN_SAM_BATCH_BLOCK_STEP("window partition",
                                 metal_context_sam_window_partition_batch_f16_to_slice(ctx,
                                                                                       scratch->sam_block_norm1_bhwc,
                                                                                       grid_w,
                                                                                       grid_h,
                                                                                       view_count,
                                                                                       scratch->sam_block_window_tokens,
                                                                                       &actual_windows,
                                                                                       &actual_padded_w,
                                                                                       &actual_padded_h,
                                                                                       error,
                                                                                       error_size));
        if (actual_windows != n_windows || actual_padded_w != padded_w || actual_padded_h != padded_h) {
            return metal_fail(error, error_size, "Metal SAM batch window geometry changed during partition");
        }
        RUN_SAM_BATCH_BLOCK_STEP("window QKV",
                                 metal_run_packed_qkv_mps_f16(ctx,
                                                               (uocr_metal_buffer_slice){scratch->sam_block_window_tokens.buffer, scratch->sam_block_window_tokens.offset},
                                                               block->qkv_weight.slice,
                                                               block->qkv_bias.slice,
                                                               (uocr_metal_buffer_slice){scratch->sam_block_q.buffer, scratch->sam_block_q.offset},
                                                               (uocr_metal_buffer_slice){scratch->sam_block_k.buffer, scratch->sam_block_k.offset},
                                                               (uocr_metal_buffer_slice){scratch->sam_block_v.buffer, scratch->sam_block_v.offset},
                                                               attention_rows,
                                                               UOCR_SAM_HIDDEN_SIZE,
                                                               "Metal SAM batch window QKV MPS matmul",
                                                               error,
                                                               error_size));
        RUN_SAM_BATCH_BLOCK_STEP("window relative-position attention",
                                 metal_context_sam_rel_pos_attention_batch_f16_to_slice(ctx,
                                                                                       scratch->sam_block_q,
                                                                                       scratch->sam_block_k,
                                                                                       scratch->sam_block_v,
                                                                                       block->rel_pos_h,
                                                                                       block->rel_pos_w,
                                                                                       n_windows,
                                                                                       UOCR_SAM_WINDOW_SIZE,
                                                                                       UOCR_SAM_WINDOW_SIZE,
                                                                                       view_count,
                                                                                       block->rel_pos_h_length,
                                                                                       block->rel_pos_w_length,
                                                                                       scratch->sam_block_attention,
                                                                                       error,
                                                                                       error_size));
        RUN_SAM_BATCH_BLOCK_STEP("window output projection",
                                 metal_run_mps_matmul_nt_f16(ctx,
                                                             (uocr_metal_buffer_slice){scratch->sam_block_attention.buffer, scratch->sam_block_attention.offset},
                                                             block->proj_weight.slice,
                                                             (uocr_metal_buffer_slice){scratch->sam_block_projected_windows.buffer, scratch->sam_block_projected_windows.offset},
                                                             attention_rows,
                                                             UOCR_SAM_HIDDEN_SIZE,
                                                             UOCR_SAM_HIDDEN_SIZE,
                                                             "Metal SAM batch window output projection MPS matmul",
                                                             error,
                                                             error_size) &&
                                 metal_run_bias_add_f16_inplace(ctx,
                                                                (uocr_metal_buffer_slice){scratch->sam_block_projected_windows.buffer, scratch->sam_block_projected_windows.offset},
                                                                block->proj_bias.slice,
                                                                attention_rows,
                                                                UOCR_SAM_HIDDEN_SIZE,
                                                                "Metal SAM batch window output projection bias",
                                                                error,
                                                                error_size));
        RUN_SAM_BATCH_BLOCK_STEP("window unpartition",
                                 metal_context_sam_window_unpartition_batch_f16_to_slice(ctx,
                                                                                         scratch->sam_block_projected_windows,
                                                                                         grid_w,
                                                                                         grid_h,
                                                                                         view_count,
                                                                                         scratch->sam_block_attention_bhwc,
                                                                                         error,
                                                                                         error_size));
        RUN_SAM_BATCH_BLOCK_STEP("attention residual",
                                 metal_run_residual_add_f16(ctx,
                                                            (uocr_metal_buffer_slice){input_bhwc.buffer, input_bhwc.offset},
                                                            (uocr_metal_buffer_slice){scratch->sam_block_attention_bhwc.buffer, scratch->sam_block_attention_bhwc.offset},
                                                            (uocr_metal_buffer_slice){scratch->sam_block_residual1_bhwc.buffer, scratch->sam_block_residual1_bhwc.offset},
                                                            (uint32_t)hidden_values,
                                                            "Metal SAM batch window attention residual",
                                                            error,
                                                            error_size));
    }

    RUN_SAM_BATCH_BLOCK_STEP("LayerNorm2",
                             metal_context_layernorm_f16_with_parameter_buffers(ctx,
                                                                                scratch->sam_block_residual1_bhwc.f16,
                                                                                block->norm2_weight.slice.buffer,
                                                                                block->norm2_weight.slice.offset,
                                                                                block->norm2_bias.slice.buffer,
                                                                                block->norm2_bias.slice.offset,
                                                                                rows,
                                                                                UOCR_SAM_HIDDEN_SIZE,
                                                                                1.0e-6f,
                                                                                UOCR_METAL_LAYERNORM_OUTPUT_F16,
                                                                                scratch->sam_block_norm2_bhwc.f16,
                                                                                "Metal SAM batch LayerNorm2",
                                                                                error,
                                                                                error_size));
    RUN_SAM_BATCH_BLOCK_STEP("MLP",
                             metal_context_sam_mlp_batch_workspace_f16_to_slice(ctx,
                                                                                scratch->sam_block_norm2_bhwc,
                                                                                block,
                                                                                rows,
                                                                                scratch->sam_block_mlp_intermediate,
                                                                                scratch->sam_block_mlp_bhwc,
                                                                                error,
                                                                                error_size));
    RUN_SAM_BATCH_BLOCK_STEP("MLP residual",
                             metal_run_residual_add_f16(ctx,
                                                        (uocr_metal_buffer_slice){scratch->sam_block_residual1_bhwc.buffer, scratch->sam_block_residual1_bhwc.offset},
                                                        (uocr_metal_buffer_slice){scratch->sam_block_mlp_bhwc.buffer, scratch->sam_block_mlp_bhwc.offset},
                                                        (uocr_metal_buffer_slice){out_bhwc.buffer, out_bhwc.offset},
                                                        (uint32_t)hidden_values,
                                                        "Metal SAM batch MLP residual",
                                                        error,
                                                        error_size));

#undef RUN_SAM_BATCH_BLOCK_STEP

    return 1;
}

static int metal_context_sam_transformer_batch_workspace_f16_to_slice(uocr_metal_context *ctx,
                                                                      uocr_metal_vision_workspace_slice input_bhwc,
                                                                      const uocr_metal_sam_transformer_block_slices_f16 *blocks,
                                                                      uint32_t block_count,
                                                                      uint32_t grid_w,
                                                                      uint32_t grid_h,
                                                                      uint32_t view_count,
                                                                      uocr_metal_vision_workspace_slice out_bhwc,
                                                                      uocr_metal_vision_workspace *scratch,
                                                                      char *error,
                                                                      size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || input_bhwc.buffer == nil || input_bhwc.f16 == NULL || blocks == NULL || view_count == 0u ||
        out_bhwc.buffer == nil || out_bhwc.f16 == NULL || scratch == NULL) {
        return metal_fail(error, error_size, "invalid Metal SAM batch transformer request");
    }
    if (block_count != UOCR_SAM_BLOCKS) {
        return metal_fail(error, error_size, "invalid Metal SAM batch transformer block count %u", block_count);
    }
    uint64_t rows_per_view = 0u;
    uint64_t hidden_bytes_per_view = 0u;
    uint64_t hidden_values = 0u;
    uint64_t hidden_bytes = 0u;
    if (!metal_sam_transformer_activation_bytes(grid_w, grid_h, &rows_per_view, &hidden_bytes_per_view, error, error_size) ||
        rows_per_view > (uint64_t)(UINT32_MAX / view_count) ||
        !checked_mul_u64(rows_per_view, (uint64_t)view_count, &hidden_values) ||
        !checked_mul_u64(hidden_values, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &hidden_values) ||
        hidden_values > (uint64_t)UINT32_MAX || !metal_vision_f16_bytes(hidden_values, &hidden_bytes) ||
        !metal_vision_require_workspace_slice_f16(input_bhwc, hidden_bytes, "SAM batch transformer input", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(out_bhwc, hidden_bytes, "SAM batch transformer output", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->sam_patch_bhwc, hidden_bytes, "SAM batch transformer state A", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(scratch->sam_transformer_batch_bhwc, hidden_bytes, "SAM batch transformer state B", error, error_size)) {
        return 0;
    }
    for (uint32_t block_index = 0u; block_index < block_count; ++block_index) {
        if (!metal_sam_transformer_block_slices_have_weights(&blocks[block_index])) {
            return metal_fail(error, error_size, "invalid Metal SAM batch transformer block %u weights", block_index);
        }
    }

    uocr_metal_vision_workspace_slice current = input_bhwc;
    uocr_metal_vision_workspace_slice state_a = scratch->sam_patch_bhwc;
    uocr_metal_vision_workspace_slice state_b = scratch->sam_transformer_batch_bhwc;
    uocr_metal_vision_workspace_slice next = state_a;
    const uint64_t sam_blocks_start_ns = uocr_profile_now_ns();
    for (uint32_t block_index = 0u; block_index < block_count; ++block_index) {
        const uint64_t block_start_ns = uocr_profile_now_ns();
        const int is_last = block_index + 1u == block_count;
        uocr_metal_vision_workspace_slice block_out = is_last ? out_bhwc : next;
        if (block_out.buffer == current.buffer && block_out.offset == current.offset) {
            return metal_fail(error, error_size, "Metal SAM batch transformer attempted in-place block output");
        }
        if (!metal_context_sam_transformer_batch_block_workspace_f16_to_slice(ctx,
                                                                              current,
                                                                              &blocks[block_index],
                                                                              grid_w,
                                                                              grid_h,
                                                                              view_count,
                                                                              uocr_sam_block_uses_global_attention(block_index),
                                                                              block_out,
                                                                              scratch,
                                                                              error,
                                                                              error_size)) {
            char detail[512];
            metal_copy_error_detail(detail, sizeof(detail), error);
            return metal_fail(error,
                              error_size,
                              "failed to compute Metal SAM batch transformer block %u: %s",
                              block_index,
                              detail);
        }
        if (!is_last) {
            current = block_out;
            next = (block_out.buffer == state_a.buffer && block_out.offset == state_a.offset) ? state_b : state_a;
        }
        metal_profile_add_event_now(ctx, view_count > 1u ? "metal.vision.sam_block_batch" : "metal.vision.sam_block", block_start_ns);
        metal_profile_add_event_now_f(ctx,
                                      block_start_ns,
                                      view_count > 1u ? "metal.vision.sam_block_batch.%02u" : "metal.vision.sam_block.%02u",
                                      block_index);
    }
    metal_profile_add_event_now(ctx, view_count > 1u ? "metal.vision.sam_blocks_batch" : "metal.vision.sam_blocks", sam_blocks_start_ns);
    metal_clear_error(error, error_size);
    return 1;
}

static int metal_context_sam_mlp_workspace_f16(uocr_metal_context *ctx,
                                               uocr_metal_vision_workspace_slice input,
                                               const uocr_metal_sam_transformer_block_f16 *block,
                                               uint32_t n_rows,
                                               uocr_metal_vision_workspace_slice intermediate,
                                               uocr_metal_vision_workspace_slice out,
                                               char *error,
                                               size_t error_size) {
    const uint64_t hidden_bytes = (uint64_t)n_rows * (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    const uint64_t intermediate_bytes = (uint64_t)n_rows * (uint64_t)UOCR_SAM_MLP_INTERMEDIATE * 2u;
    const uint64_t lin1_weight_bytes = (uint64_t)UOCR_SAM_MLP_INTERMEDIATE * (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    const uint64_t lin2_weight_bytes = (uint64_t)UOCR_SAM_HIDDEN_SIZE * (uint64_t)UOCR_SAM_MLP_INTERMEDIATE * 2u;
    const uint64_t lin1_bias_bytes = (uint64_t)UOCR_SAM_MLP_INTERMEDIATE * 2u;
    const uint64_t lin2_bias_bytes = (uint64_t)UOCR_SAM_HIDDEN_SIZE * 2u;
    if (ctx == NULL || !metal_sam_transformer_block_has_weights(block) || n_rows == 0u ||
        !metal_vision_require_workspace_slice_f16(input, hidden_bytes, "SAM MLP input", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(intermediate, intermediate_bytes, "SAM MLP intermediate", error, error_size) ||
        !metal_vision_require_workspace_slice_f16(out, hidden_bytes, "SAM MLP output", error, error_size)) {
        return 0;
    }

    const int use_mps_lin1 = metal_mps_matmul_nt_f16_should_use(n_rows,
                                                                UOCR_SAM_HIDDEN_SIZE,
                                                                UOCR_SAM_MLP_INTERMEDIATE);
    const int use_mps_lin2 = metal_mps_matmul_nt_f16_should_use(n_rows,
                                                                UOCR_SAM_MLP_INTERMEDIATE,
                                                                UOCR_SAM_HIDDEN_SIZE);
    if (!use_mps_lin1 || !use_mps_lin2) {
        if ((!use_mps_lin1 &&
             !metal_public_mps_matmul_fallback_allowed(ctx,
                                                       n_rows,
                                                       UOCR_SAM_HIDDEN_SIZE,
                                                       UOCR_SAM_MLP_INTERMEDIATE,
                                                       "Metal SAM MLP lin1",
                                                       error,
                                                       error_size)) ||
            (!use_mps_lin2 &&
             !metal_public_mps_matmul_fallback_allowed(ctx,
                                                       n_rows,
                                                       UOCR_SAM_MLP_INTERMEDIATE,
                                                       UOCR_SAM_HIDDEN_SIZE,
                                                       "Metal SAM MLP lin2",
                                                       error,
                                                       error_size))) {
            return 0;
        }
        return uocr_metal_context_diagnostic_sam_mlp_f16(ctx,
                                              input.f16,
                                              block->mlp_lin1_weight_f16,
                                              block->mlp_lin1_bias_f16,
                                              block->mlp_lin2_weight_f16,
                                              block->mlp_lin2_bias_f16,
                                              n_rows,
                                              UOCR_METAL_DENSE_OUTPUT_F16,
                                              out.f16,
                                              error,
                                              error_size);
    }

    int result = 0;
    @autoreleasepool {
        id<MTLBuffer> lin1_weight = nil;
        id<MTLBuffer> lin1_bias = nil;
        id<MTLBuffer> lin2_weight = nil;
        id<MTLBuffer> lin2_bias = nil;
        NSUInteger lin1_weight_offset = 0u;
        NSUInteger lin1_bias_offset = 0u;
        NSUInteger lin2_weight_offset = 0u;
        NSUInteger lin2_bias_offset = 0u;

        lin1_weight = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                                   block->mlp_lin1_weight_f16,
                                                                   (NSUInteger)lin1_weight_bytes,
                                                                   MTLResourceStorageModeShared,
                                                                   &lin1_weight_offset);
        if (lin1_weight == nil) {
            result = metal_fail(error, error_size, "failed to bind Metal SAM MLP lin1 weight buffer");
            goto cleanup_sam_mlp_workspace;
        }
        lin1_weight.label = @"uocr_sam_mlp_workspace_lin1_weight_f16";

        lin1_bias = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                                 block->mlp_lin1_bias_f16,
                                                                 (NSUInteger)lin1_bias_bytes,
                                                                 MTLResourceStorageModeShared,
                                                                 &lin1_bias_offset);
        if (lin1_bias == nil) {
            result = metal_fail(error, error_size, "failed to bind Metal SAM MLP lin1 bias buffer");
            goto cleanup_sam_mlp_workspace;
        }
        lin1_bias.label = @"uocr_sam_mlp_workspace_lin1_bias_f16";

        lin2_weight = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                                   block->mlp_lin2_weight_f16,
                                                                   (NSUInteger)lin2_weight_bytes,
                                                                   MTLResourceStorageModeShared,
                                                                   &lin2_weight_offset);
        if (lin2_weight == nil) {
            result = metal_fail(error, error_size, "failed to bind Metal SAM MLP lin2 weight buffer");
            goto cleanup_sam_mlp_workspace;
        }
        lin2_weight.label = @"uocr_sam_mlp_workspace_lin2_weight_f16";

        lin2_bias = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                                 block->mlp_lin2_bias_f16,
                                                                 (NSUInteger)lin2_bias_bytes,
                                                                 MTLResourceStorageModeShared,
                                                                 &lin2_bias_offset);
        if (lin2_bias == nil) {
            result = metal_fail(error, error_size, "failed to bind Metal SAM MLP lin2 bias buffer");
            goto cleanup_sam_mlp_workspace;
        }
        lin2_bias.label = @"uocr_sam_mlp_workspace_lin2_bias_f16";

        uocr_metal_buffer_slice input_slice = { input.buffer, input.offset };
        uocr_metal_buffer_slice intermediate_slice = { intermediate.buffer, intermediate.offset };
        uocr_metal_buffer_slice out_slice = { out.buffer, out.offset };
        uocr_metal_buffer_slice lin1_weight_slice = { lin1_weight, lin1_weight_offset };
        uocr_metal_buffer_slice lin1_bias_slice = { lin1_bias, lin1_bias_offset };
        uocr_metal_buffer_slice lin2_weight_slice = { lin2_weight, lin2_weight_offset };
        uocr_metal_buffer_slice lin2_bias_slice = { lin2_bias, lin2_bias_offset };

        if (!metal_run_mps_matmul_nt_f16(ctx,
                                         input_slice,
                                         lin1_weight_slice,
                                         intermediate_slice,
                                         n_rows,
                                         UOCR_SAM_HIDDEN_SIZE,
                                         UOCR_SAM_MLP_INTERMEDIATE,
                                         "Metal SAM MLP lin1 MPS matmul",
                                         error,
                                         error_size) ||
            !metal_run_bias_gelu_f16_inplace(ctx,
                                             intermediate_slice,
                                             lin1_bias_slice,
                                             n_rows,
                                             UOCR_SAM_MLP_INTERMEDIATE,
                                             "Metal SAM MLP lin1 MPS bias GELU",
                                             error,
                                             error_size) ||
            !metal_run_mps_matmul_nt_f16(ctx,
                                         intermediate_slice,
                                         lin2_weight_slice,
                                         out_slice,
                                         n_rows,
                                         UOCR_SAM_MLP_INTERMEDIATE,
                                         UOCR_SAM_HIDDEN_SIZE,
                                         "Metal SAM MLP lin2 MPS matmul",
                                         error,
                                         error_size) ||
            !metal_run_bias_add_f16_inplace(ctx,
                                            out_slice,
                                            lin2_bias_slice,
                                            n_rows,
                                            UOCR_SAM_HIDDEN_SIZE,
                                            "Metal SAM MLP lin2 MPS bias add",
                                            error,
                                            error_size)) {
            result = 0;
            goto cleanup_sam_mlp_workspace;
        }
        result = 1;

    cleanup_sam_mlp_workspace:
        [lin2_bias release];
        [lin2_weight release];
        [lin1_bias release];
        [lin1_weight release];
    }

    if (result) {
        metal_clear_error(error, error_size);
    }
    return result;
}

static int metal_context_sam_transformer_block_workspace_f16(uocr_metal_context *ctx,
                                                             const uint16_t *input_bhwc_f16,
                                                             const uocr_metal_sam_transformer_block_f16 *block,
                                                             uint32_t grid_w,
                                                             uint32_t grid_h,
                                                             int use_global_attention,
                                                             uocr_metal_dense_output_type output_type,
                                                             void *out_bhwc,
                                                             uocr_metal_vision_workspace *scratch,
                                                             char *error,
                                                             size_t error_size) {
    if (ctx == NULL || input_bhwc_f16 == NULL || !metal_sam_transformer_block_has_weights(block) || out_bhwc == NULL ||
        scratch == NULL) {
        return metal_fail(error, error_size, "invalid Metal SAM workspace transformer block request");
    }

    uint64_t row_count_u64 = 0u;
    uint64_t hidden_bytes = 0u;
    if (!metal_sam_transformer_activation_bytes(grid_w, grid_h, &row_count_u64, &hidden_bytes, error, error_size)) {
        return 0;
    }
    const uint32_t row_count = (uint32_t)row_count_u64;

    uint32_t n_windows = 1u;
    uint32_t padded_w = grid_w;
    uint32_t padded_h = grid_h;
    uint64_t attention_rows_u64 = row_count_u64;
    if (!use_global_attention) {
        uint32_t windows_per_row = 0u;
        uint32_t windows_per_col = 0u;
        if (!sam_window_partition_geometry(grid_w,
                                           grid_h,
                                           &padded_w,
                                           &padded_h,
                                           &windows_per_row,
                                           &windows_per_col,
                                           &n_windows)) {
            return metal_fail(error, error_size, "invalid Metal SAM workspace transformer window grid %ux%u", grid_w, grid_h);
        }
        if (!checked_mul_u64((uint64_t)n_windows, (uint64_t)UOCR_SAM_WINDOW_TOKENS, &attention_rows_u64)) {
            return metal_fail(error, error_size, "Metal SAM workspace transformer window row-count overflow");
        }
    }
    uint64_t attention_values = 0u;
    uint64_t attention_bytes = 0u;
    if (!checked_mul_u64(attention_rows_u64, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &attention_values) ||
        !checked_mul_u64(attention_values, 2u, &attention_bytes) || attention_rows_u64 > (uint64_t)UINT32_MAX) {
        return metal_fail(error, error_size, "Metal SAM workspace transformer attention byte-size overflow");
    }
    const uint32_t attention_rows = (uint32_t)attention_rows_u64;
    if (!metal_vision_slice_has_bytes(scratch->sam_block_norm1_bhwc, hidden_bytes) ||
        !metal_vision_slice_has_bytes(scratch->sam_block_window_tokens, attention_bytes) ||
        !metal_vision_slice_has_bytes(scratch->sam_block_q, attention_bytes) ||
        !metal_vision_slice_has_bytes(scratch->sam_block_k, attention_bytes) ||
        !metal_vision_slice_has_bytes(scratch->sam_block_v, attention_bytes) ||
        !metal_vision_slice_has_bytes(scratch->sam_block_attention, attention_bytes) ||
        !metal_vision_slice_has_bytes(scratch->sam_block_projected_windows, attention_bytes) ||
        !metal_vision_slice_has_bytes(scratch->sam_block_attention_bhwc, hidden_bytes) ||
        !metal_vision_slice_has_bytes(scratch->sam_block_residual1_bhwc, hidden_bytes) ||
        !metal_vision_slice_has_bytes(scratch->sam_block_norm2_bhwc, hidden_bytes) ||
        !metal_vision_slice_has_bytes(scratch->sam_block_mlp_intermediate,
                                      (uint64_t)row_count * (uint64_t)UOCR_SAM_MLP_INTERMEDIATE * 2u) ||
        !metal_vision_slice_has_bytes(scratch->sam_block_mlp_bhwc, hidden_bytes)) {
        return metal_fail(error, error_size, "Metal SAM workspace transformer block scratch is too small");
    }

#define RUN_SAM_WORKSPACE_BLOCK_STEP(step_name, call_expr)                                              \
    do {                                                                                                \
        if (!(call_expr)) {                                                                             \
            char detail[512];                                                                           \
            metal_copy_error_detail(detail, sizeof(detail), error);                                      \
            return metal_fail(error, error_size, "failed to compute Metal SAM workspace block %s: %s", step_name, detail); \
        }                                                                                               \
    } while (0)

    RUN_SAM_WORKSPACE_BLOCK_STEP("LayerNorm1",
                                 uocr_metal_context_diagnostic_sam_layernorm_f16(ctx,
                                                                       input_bhwc_f16,
                                                                       block->norm1_weight_f16,
                                                                       block->norm1_bias_f16,
                                                                       row_count,
                                                                       UOCR_METAL_LAYERNORM_OUTPUT_F16,
                                                                       scratch->sam_block_norm1_bhwc.f16,
                                                                       error,
                                                                       error_size));

    if (use_global_attention) {
        RUN_SAM_WORKSPACE_BLOCK_STEP("QKV",
                                     uocr_metal_context_diagnostic_sam_qkv_f16(ctx,
                                                                     scratch->sam_block_norm1_bhwc.f16,
                                                                     block->qkv_weight_f16,
                                                                     block->qkv_bias_f16,
                                                                     row_count,
                                                                     UOCR_METAL_DENSE_OUTPUT_F16,
                                                                     scratch->sam_block_q.f16,
                                                                     scratch->sam_block_k.f16,
                                                                     scratch->sam_block_v.f16,
                                                                     error,
                                                                     error_size));
        RUN_SAM_WORKSPACE_BLOCK_STEP("relative-position attention",
                                     uocr_metal_context_diagnostic_sam_rel_pos_attention_f16(ctx,
                                                                                  scratch->sam_block_q.f16,
                                                                                  scratch->sam_block_k.f16,
                                                                                  scratch->sam_block_v.f16,
                                                                                  block->rel_pos_h_f16,
                                                                                  block->rel_pos_w_f16,
                                                                                  1u,
                                                                                  grid_w,
                                                                                  grid_h,
                                                                                  block->rel_pos_h_length,
                                                                                  block->rel_pos_w_length,
                                                                                  UOCR_METAL_DENSE_OUTPUT_F16,
                                                                                  scratch->sam_block_attention.f16,
                                                                                  error,
                                                                                  error_size));
        RUN_SAM_WORKSPACE_BLOCK_STEP("attention projection residual",
                                     uocr_metal_context_diagnostic_sam_attention_project_residual_f16(ctx,
                                                                                           scratch->sam_block_attention.f16,
                                                                                           block->proj_weight_f16,
                                                                                           block->proj_bias_f16,
                                                                                           input_bhwc_f16,
                                                                                           row_count,
                                                                                           UOCR_METAL_DENSE_OUTPUT_F16,
                                                                                           scratch->sam_block_residual1_bhwc.f16,
                                                                                           error,
                                                                                           error_size));
    } else {
        uint32_t actual_windows = 0u;
        uint32_t actual_padded_w = 0u;
        uint32_t actual_padded_h = 0u;
        RUN_SAM_WORKSPACE_BLOCK_STEP("window partition",
                                     uocr_metal_context_diagnostic_sam_window_partition_f16(ctx,
                                                                                 scratch->sam_block_norm1_bhwc.f16,
                                                                                 grid_w,
                                                                                 grid_h,
                                                                                 scratch->sam_block_window_tokens.f16,
                                                                                 &actual_windows,
                                                                                 &actual_padded_w,
                                                                                 &actual_padded_h,
                                                                                 error,
                                                                                 error_size));
        if (actual_windows != n_windows || actual_padded_w != padded_w || actual_padded_h != padded_h) {
            return metal_fail(error, error_size, "Metal SAM workspace window geometry changed during partition");
        }
        RUN_SAM_WORKSPACE_BLOCK_STEP("window QKV",
                                     uocr_metal_context_diagnostic_sam_qkv_f16(ctx,
                                                                     scratch->sam_block_window_tokens.f16,
                                                                     block->qkv_weight_f16,
                                                                     block->qkv_bias_f16,
                                                                     attention_rows,
                                                                     UOCR_METAL_DENSE_OUTPUT_F16,
                                                                     scratch->sam_block_q.f16,
                                                                     scratch->sam_block_k.f16,
                                                                     scratch->sam_block_v.f16,
                                                                     error,
                                                                     error_size));
        RUN_SAM_WORKSPACE_BLOCK_STEP("window relative-position attention",
                                     uocr_metal_context_diagnostic_sam_rel_pos_attention_f16(ctx,
                                                                                  scratch->sam_block_q.f16,
                                                                                  scratch->sam_block_k.f16,
                                                                                  scratch->sam_block_v.f16,
                                                                                  block->rel_pos_h_f16,
                                                                                  block->rel_pos_w_f16,
                                                                                  n_windows,
                                                                                  UOCR_SAM_WINDOW_SIZE,
                                                                                  UOCR_SAM_WINDOW_SIZE,
                                                                                  block->rel_pos_h_length,
                                                                                  block->rel_pos_w_length,
                                                                                  UOCR_METAL_DENSE_OUTPUT_F16,
                                                                                  scratch->sam_block_attention.f16,
                                                                                  error,
                                                                                  error_size));
        RUN_SAM_WORKSPACE_BLOCK_STEP("window output projection",
                                     uocr_metal_context_diagnostic_dense_f16(ctx,
                                                                  scratch->sam_block_attention.f16,
                                                                  block->proj_weight_f16,
                                                                  block->proj_bias_f16,
                                                                  attention_rows,
                                                                  UOCR_SAM_HIDDEN_SIZE,
                                                                  UOCR_SAM_HIDDEN_SIZE,
                                                                  UOCR_METAL_DENSE_OUTPUT_F16,
                                                                  scratch->sam_block_projected_windows.f16,
                                                                  error,
                                                                  error_size));
        RUN_SAM_WORKSPACE_BLOCK_STEP("window unpartition",
                                     uocr_metal_context_diagnostic_sam_window_unpartition_f16(ctx,
                                                                                   scratch->sam_block_projected_windows.f16,
                                                                                   grid_w,
                                                                                   grid_h,
                                                                                   scratch->sam_block_attention_bhwc.f16,
                                                                                   error,
                                                                                   error_size));
        RUN_SAM_WORKSPACE_BLOCK_STEP("attention residual",
                                     uocr_metal_context_diagnostic_sam_residual_add_f16(ctx,
                                                                             input_bhwc_f16,
                                                                             scratch->sam_block_attention_bhwc.f16,
                                                                             row_count,
                                                                             UOCR_METAL_DENSE_OUTPUT_F16,
                                                                             scratch->sam_block_residual1_bhwc.f16,
                                                                             error,
                                                                             error_size));
    }

    RUN_SAM_WORKSPACE_BLOCK_STEP("LayerNorm2",
                                 uocr_metal_context_diagnostic_sam_layernorm_f16(ctx,
                                                                       scratch->sam_block_residual1_bhwc.f16,
                                                                       block->norm2_weight_f16,
                                                                       block->norm2_bias_f16,
                                                                       row_count,
                                                                       UOCR_METAL_LAYERNORM_OUTPUT_F16,
                                                                       scratch->sam_block_norm2_bhwc.f16,
                                                                       error,
                                                                       error_size));
    RUN_SAM_WORKSPACE_BLOCK_STEP("MLP",
                                 metal_context_sam_mlp_workspace_f16(ctx,
                                                                     scratch->sam_block_norm2_bhwc,
                                                                     block,
                                                                     row_count,
                                                                     scratch->sam_block_mlp_intermediate,
                                                                     scratch->sam_block_mlp_bhwc,
                                                                     error,
                                                                     error_size));
    RUN_SAM_WORKSPACE_BLOCK_STEP("MLP residual",
                                 uocr_metal_context_diagnostic_sam_residual_add_f16(ctx,
                                                                          scratch->sam_block_residual1_bhwc.f16,
                                                                          scratch->sam_block_mlp_bhwc.f16,
                                                                          row_count,
                                                                          output_type,
                                                                          out_bhwc,
                                                                          error,
                                                                          error_size));

#undef RUN_SAM_WORKSPACE_BLOCK_STEP

    return 1;
}

static int metal_context_sam_transformer_workspace_f16(uocr_metal_context *ctx,
                                                       const uint16_t *input_bhwc_f16,
                                                       const uocr_metal_sam_transformer_block_f16 *blocks,
                                                       uint32_t block_count,
                                                       uint32_t grid_w,
                                                       uint32_t grid_h,
                                                       uocr_metal_dense_output_type output_type,
                                                       void *out_bhwc,
                                                       uocr_metal_vision_workspace *scratch,
                                                       char *error,
                                                       size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || input_bhwc_f16 == NULL || blocks == NULL || out_bhwc == NULL || scratch == NULL) {
        return metal_fail(error, error_size, "invalid Metal SAM workspace transformer request");
    }
    if (block_count != UOCR_SAM_BLOCKS) {
        return metal_fail(error, error_size, "invalid Metal SAM workspace transformer block count %u", block_count);
    }
    uint64_t hidden_bytes = 0u;
    if (!metal_sam_transformer_activation_bytes(grid_w, grid_h, NULL, &hidden_bytes, error, error_size)) {
        return 0;
    }
    if (!metal_vision_slice_has_bytes(scratch->sam_patch_bhwc, hidden_bytes) ||
        !metal_vision_slice_has_bytes(scratch->sam_transformer_bhwc, hidden_bytes)) {
        return metal_fail(error, error_size, "Metal SAM workspace transformer state scratch is too small");
    }
    for (uint32_t block_index = 0u; block_index < block_count; ++block_index) {
        if (!metal_sam_transformer_block_has_weights(&blocks[block_index])) {
            return metal_fail(error, error_size, "invalid Metal SAM workspace transformer block %u weights", block_index);
        }
    }

    const uint16_t *current_f16 = input_bhwc_f16;
    uint16_t *state_a_f16 = scratch->sam_patch_bhwc.f16;
    uint16_t *state_b_f16 = scratch->sam_transformer_bhwc.f16;
    uint16_t *next_f16 = state_a_f16;
    const uint64_t sam_blocks_start_ns = uocr_profile_now_ns();
    for (uint32_t block_index = 0u; block_index < block_count; ++block_index) {
        const uint64_t block_start_ns = uocr_profile_now_ns();
        const int is_last = block_index + 1u == block_count;
        const uocr_metal_dense_output_type block_output_type = is_last ? output_type : UOCR_METAL_DENSE_OUTPUT_F16;
        void *block_out = is_last ? out_bhwc : (void *)next_f16;
        if (block_out == (const void *)current_f16) {
            return metal_fail(error, error_size, "Metal SAM workspace transformer attempted in-place block output");
        }
        if (!metal_context_sam_transformer_block_workspace_f16(ctx,
                                                               current_f16,
                                                               &blocks[block_index],
                                                               grid_w,
                                                               grid_h,
                                                               uocr_sam_block_uses_global_attention(block_index),
                                                               block_output_type,
                                                               block_out,
                                                               scratch,
                                                               error,
                                                               error_size)) {
            char detail[512];
            metal_copy_error_detail(detail, sizeof(detail), error);
            return metal_fail(error,
                              error_size,
                              "failed to compute Metal SAM workspace transformer block %u: %s",
                              block_index,
                              detail);
        }
        if (!is_last) {
            current_f16 = (const uint16_t *)block_out;
            next_f16 = (block_out == (void *)state_a_f16) ? state_b_f16 : state_a_f16;
        }
        metal_profile_add_event_now(ctx, "metal.vision.sam_block", block_start_ns);
        metal_profile_add_event_now_f(ctx, block_start_ns, "metal.vision.sam_block.%02u", block_index);
    }
    metal_profile_add_event_now(ctx, "metal.vision.sam_blocks", sam_blocks_start_ns);
    metal_clear_error(error, error_size);
    return 1;
}

static int metal_context_sam_attention_f16(uocr_metal_context *ctx,
                                           const uint16_t *q_f16,
                                           const uint16_t *k_f16,
                                           const uint16_t *v_f16,
                                           uint32_t windows,
                                           uint32_t tokens_per_window,
                                           uocr_metal_dense_output_type output_type,
                                           void *out,
                                           const char *diagnostic_name,
                                           char *error,
                                           size_t error_size) {
    uint64_t attention_values = 0u;
    uint64_t input_bytes = 0u;
    uint64_t output_bytes = 0u;
    const uint64_t output_element_bytes = output_type == UOCR_METAL_DENSE_OUTPUT_F16 ? 2u : (uint64_t)sizeof(float);
    if (!checked_mul_u64((uint64_t)windows, (uint64_t)tokens_per_window, &attention_values) ||
        !checked_mul_u64(attention_values, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &attention_values) ||
        !checked_mul_u64(attention_values, 2u, &input_bytes) ||
        !checked_mul_u64(attention_values, output_element_bytes, &output_bytes) ||
        input_bytes > (uint64_t)SIZE_MAX || output_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error, error_size, "%s byte-size overflow", diagnostic_name);
    }

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (input_bytes > max_buffer_length || output_bytes > max_buffer_length) {
        return metal_fail(error,
                          error_size,
                          "%s buffers exceed maxBufferLength %llu",
                          diagnostic_name,
                          (unsigned long long)max_buffer_length);
    }

    @autoreleasepool {
        /* The Metal kernel is an all-to-all attention primitive parameterized
         * by tokens_per_window. Global attention is represented as one window
         * spanning the whole SAM patch grid.
         */
        const char *function_name = output_type == UOCR_METAL_DENSE_OUTPUT_F16 ?
                                        "uocr_sam_window_attention_flash_f16_to_f16" :
                                        "uocr_sam_window_attention_flash_f16_to_f32";
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, function_name, error, error_size);
        if (pipeline == nil) {
            return 0;
        }

        NSUInteger q_offset = 0u;
        id<MTLBuffer> q_src = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                                           q_f16,
                                                                           (NSUInteger)input_bytes,
                                                                           MTLResourceStorageModeShared,
                                                                           &q_offset);
        if (q_src == nil) {
            return metal_fail(error, error_size, "failed to allocate %s Q buffer", diagnostic_name);
        }
        q_src.label = @"uocr_sam_attention_q_f16";

        NSUInteger k_offset = 0u;
        id<MTLBuffer> k_src = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                                           k_f16,
                                                                           (NSUInteger)input_bytes,
                                                                           MTLResourceStorageModeShared,
                                                                           &k_offset);
        if (k_src == nil) {
            [q_src release];
            return metal_fail(error, error_size, "failed to allocate %s K buffer", diagnostic_name);
        }
        k_src.label = @"uocr_sam_attention_k_f16";

        NSUInteger v_offset = 0u;
        id<MTLBuffer> v_src = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                                           v_f16,
                                                                           (NSUInteger)input_bytes,
                                                                           MTLResourceStorageModeShared,
                                                                           &v_offset);
        if (v_src == nil) {
            [k_src release];
            [q_src release];
            return metal_fail(error, error_size, "failed to allocate %s V buffer", diagnostic_name);
        }
        v_src.label = @"uocr_sam_attention_v_f16";

        NSUInteger dst_offset = 0u;
        int dst_needs_copy = 1;
        id<MTLBuffer> dst = metal_new_or_retain_vision_output_buffer(ctx,
                                                                     out,
                                                                     (NSUInteger)output_bytes,
                                                                     MTLResourceStorageModeShared,
                                                                     &dst_offset,
                                                                     &dst_needs_copy);
        if (dst == nil) {
            [v_src release];
            [k_src release];
            [q_src release];
            return metal_fail(error, error_size, "failed to allocate %s output buffer", diagnostic_name);
        }
        dst.label = @"uocr_sam_attention_output";
        metal_zero_buffer_range(dst, dst_offset, (NSUInteger)output_bytes);

        id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            [dst release];
            [v_src release];
            [k_src release];
            [q_src release];
            return metal_fail(error, error_size, "failed to create %s command buffer", diagnostic_name);
        }
        cb.label = @"uocr_sam_attention_command_buffer";

        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            [dst release];
            [v_src release];
            [k_src release];
            [q_src release];
            return metal_fail(error, error_size, "failed to create %s command encoder", diagnostic_name);
        }

        uocr_metal_sam_window_attention_params params;
        params.windows = windows;
        params.tokens_per_window = tokens_per_window;
        params.heads = UOCR_SAM_ATTENTION_HEADS;
        params.head_dim = UOCR_SAM_HEAD_DIM;
        params.scale = 1.0f / sqrtf((float)UOCR_SAM_HEAD_DIM);
        params.batch_size = 1u;
        params.reserved1 = 0u;
        params.reserved2 = 0u;

        const NSUInteger threads_per_group = 128u;
        const NSUInteger query_blocks = (NSUInteger)((tokens_per_window + 3u) / 4u);
        if (pipeline.maxTotalThreadsPerThreadgroup < threads_per_group) {
            [dst release];
            [v_src release];
            [k_src release];
            [q_src release];
            return metal_fail(error, error_size, "%s flash path cannot run four simdgroups per block", diagnostic_name);
        }

        [enc setComputePipelineState:pipeline];
        [enc setBuffer:q_src offset:q_offset atIndex:0u];
        [enc setBuffer:k_src offset:k_offset atIndex:1u];
        [enc setBuffer:v_src offset:v_offset atIndex:2u];
        [enc setBuffer:dst offset:dst_offset atIndex:3u];
        [enc setBytes:&params length:sizeof(params) atIndex:4u];
        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)UOCR_SAM_ATTENTION_HEADS, query_blocks, (NSUInteger)windows)
             threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
        [enc endEncoding];

        UOCR_METAL_COMMIT_AND_WAIT_PROFILED(ctx, cb);
        if (cb.status == MTLCommandBufferStatusError) {
            NSString *description = cb.error != nil ? [cb.error localizedDescription] : @"unknown command-buffer error";
            [dst release];
            [v_src release];
            [k_src release];
            [q_src release];
            return metal_fail(error, error_size, "%s command failed: %s", diagnostic_name, [description UTF8String]);
        }

        metal_copy_buffer_range_to_host_if_needed(out, dst, dst_offset, (NSUInteger)output_bytes, dst_needs_copy);
        [dst release];
        [v_src release];
        [k_src release];
        [q_src release];
    }

    metal_clear_error(error, error_size);
    return 1;
}

int uocr_metal_context_diagnostic_sam_window_attention_f16(uocr_metal_context *ctx,
                                                const uint16_t *q_f16,
                                                const uint16_t *k_f16,
                                                const uint16_t *v_f16,
                                                uint32_t n_windows,
                                                uocr_metal_dense_output_type output_type,
                                                void *out,
                                                char *error,
                                                size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || q_f16 == NULL || k_f16 == NULL || v_f16 == NULL || out == NULL || n_windows == 0u) {
        return metal_fail(error, error_size, "invalid Metal SAM window attention request");
    }
    if (output_type != UOCR_METAL_DENSE_OUTPUT_F16 && output_type != UOCR_METAL_DENSE_OUTPUT_F32) {
        return metal_fail(error, error_size, "unsupported Metal SAM window attention output type %d", (int)output_type);
    }
    if (UOCR_SAM_ATTENTION_HEADS * UOCR_SAM_HEAD_DIM != UOCR_SAM_HIDDEN_SIZE ||
        UOCR_SAM_WINDOW_TOKENS != UOCR_SAM_WINDOW_SIZE * UOCR_SAM_WINDOW_SIZE) {
        return metal_fail(error, error_size, "Metal SAM window attention constants are inconsistent");
    }

    return metal_context_sam_attention_f16(ctx,
                                           q_f16,
                                           k_f16,
                                           v_f16,
                                           n_windows,
                                           UOCR_SAM_WINDOW_TOKENS,
                                           output_type,
                                           out,
                                           "Metal SAM window attention",
                                           error,
                                           error_size);
}

int uocr_metal_context_diagnostic_sam_global_attention_f16(uocr_metal_context *ctx,
                                                const uint16_t *q_f16,
                                                const uint16_t *k_f16,
                                                const uint16_t *v_f16,
                                                uint32_t grid_w,
                                                uint32_t grid_h,
                                                uocr_metal_dense_output_type output_type,
                                                void *out,
                                                char *error,
                                                size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || q_f16 == NULL || k_f16 == NULL || v_f16 == NULL || out == NULL ||
        grid_w == 0u || grid_h == 0u) {
        return metal_fail(error, error_size, "invalid Metal SAM global attention request");
    }
    if (output_type != UOCR_METAL_DENSE_OUTPUT_F16 && output_type != UOCR_METAL_DENSE_OUTPUT_F32) {
        return metal_fail(error, error_size, "unsupported Metal SAM global attention output type %d", (int)output_type);
    }
    if (UOCR_SAM_ATTENTION_HEADS * UOCR_SAM_HEAD_DIM != UOCR_SAM_HIDDEN_SIZE ||
        UOCR_SAM_MAX_GRID_TOKENS != UOCR_SAM_MAX_GRID_SIZE * UOCR_SAM_MAX_GRID_SIZE) {
        return metal_fail(error, error_size, "Metal SAM global attention constants are inconsistent");
    }
    if (grid_w > UOCR_SAM_MAX_GRID_SIZE || grid_h > UOCR_SAM_MAX_GRID_SIZE) {
        return metal_fail(error,
                          error_size,
                          "Metal SAM global attention grid %ux%u exceeds max %ux%u",
                          grid_w,
                          grid_h,
                          UOCR_SAM_MAX_GRID_SIZE,
                          UOCR_SAM_MAX_GRID_SIZE);
    }
    uint64_t tokens = 0u;
    if (!checked_mul_u64((uint64_t)grid_w, (uint64_t)grid_h, &tokens) || tokens == 0u ||
        tokens > (uint64_t)UOCR_SAM_MAX_GRID_TOKENS || tokens > (uint64_t)UINT32_MAX) {
        return metal_fail(error, error_size, "Metal SAM global attention token-count overflow");
    }

    return metal_context_sam_attention_f16(ctx,
                                           q_f16,
                                           k_f16,
                                           v_f16,
                                           1u,
                                           (uint32_t)tokens,
                                           output_type,
                                           out,
                                           "Metal SAM global attention",
                                           error,
                                           error_size);
}

int uocr_metal_context_diagnostic_sam_rel_pos_attention_f16(uocr_metal_context *ctx,
                                                 const uint16_t *q_f16,
                                                 const uint16_t *k_f16,
                                                 const uint16_t *v_f16,
                                                 const uint16_t *rel_pos_h_f16,
                                                 const uint16_t *rel_pos_w_f16,
                                                 uint32_t n_windows,
                                                 uint32_t grid_w,
                                                 uint32_t grid_h,
                                                 uint32_t rel_pos_h_length,
                                                 uint32_t rel_pos_w_length,
                                                 uocr_metal_dense_output_type output_type,
                                                 void *out,
                                                 char *error,
                                                 size_t error_size) {
    metal_clear_error(error, error_size);
    if (ctx == NULL || q_f16 == NULL || k_f16 == NULL || v_f16 == NULL || rel_pos_h_f16 == NULL ||
        rel_pos_w_f16 == NULL || out == NULL || n_windows == 0u || grid_w == 0u || grid_h == 0u ||
        rel_pos_h_length == 0u || rel_pos_w_length == 0u) {
        return metal_fail(error, error_size, "invalid Metal SAM relative-position attention request");
    }
    if (output_type != UOCR_METAL_DENSE_OUTPUT_F16 && output_type != UOCR_METAL_DENSE_OUTPUT_F32) {
        return metal_fail(error,
                          error_size,
                          "unsupported Metal SAM relative-position attention output type %d",
                          (int)output_type);
    }
    if (UOCR_SAM_ATTENTION_HEADS * UOCR_SAM_HEAD_DIM != UOCR_SAM_HIDDEN_SIZE ||
        UOCR_SAM_MAX_GRID_TOKENS != UOCR_SAM_MAX_GRID_SIZE * UOCR_SAM_MAX_GRID_SIZE ||
        UOCR_SAM_MAX_REL_POS_SIZE != 2u * UOCR_SAM_MAX_GRID_SIZE - 1u ||
        UOCR_SAM_WINDOW_REL_POS_SIZE != 2u * UOCR_SAM_WINDOW_SIZE - 1u) {
        return metal_fail(error, error_size, "Metal SAM relative-position attention constants are inconsistent");
    }
    if (grid_w > UOCR_SAM_MAX_GRID_SIZE || grid_h > UOCR_SAM_MAX_GRID_SIZE ||
        rel_pos_h_length > UOCR_SAM_MAX_REL_POS_SIZE || rel_pos_w_length > UOCR_SAM_MAX_REL_POS_SIZE) {
        return metal_fail(error,
                          error_size,
                          "Metal SAM relative-position attention dimensions exceed max grid/rel-pos limits");
    }

    uint64_t tokens = 0u;
    uint64_t attention_values = 0u;
    uint64_t input_bytes = 0u;
    uint64_t output_bytes = 0u;
    uint64_t rel_h_values = 0u;
    uint64_t rel_w_values = 0u;
    uint64_t rel_h_bytes = 0u;
    uint64_t rel_w_bytes = 0u;
    const uint64_t output_element_bytes = output_type == UOCR_METAL_DENSE_OUTPUT_F16 ? 2u : (uint64_t)sizeof(float);
    if (!checked_mul_u64((uint64_t)grid_w, (uint64_t)grid_h, &tokens) || tokens == 0u ||
        tokens > (uint64_t)UOCR_SAM_MAX_GRID_TOKENS || tokens > (uint64_t)UINT32_MAX ||
        !checked_mul_u64((uint64_t)n_windows, tokens, &attention_values) ||
        !checked_mul_u64(attention_values, (uint64_t)UOCR_SAM_HIDDEN_SIZE, &attention_values) ||
        !checked_mul_u64(attention_values, 2u, &input_bytes) ||
        !checked_mul_u64(attention_values, output_element_bytes, &output_bytes) ||
        !checked_mul_u64((uint64_t)rel_pos_h_length, (uint64_t)UOCR_SAM_HEAD_DIM, &rel_h_values) ||
        !checked_mul_u64((uint64_t)rel_pos_w_length, (uint64_t)UOCR_SAM_HEAD_DIM, &rel_w_values) ||
        !checked_mul_u64(rel_h_values, 2u, &rel_h_bytes) ||
        !checked_mul_u64(rel_w_values, 2u, &rel_w_bytes) ||
        input_bytes > (uint64_t)SIZE_MAX || output_bytes > (uint64_t)SIZE_MAX ||
        rel_h_bytes > (uint64_t)SIZE_MAX || rel_w_bytes > (uint64_t)SIZE_MAX) {
        return metal_fail(error, error_size, "Metal SAM relative-position attention byte-size overflow");
    }

    const uint64_t target_rel_h_length = 2u * (uint64_t)grid_h - 1u;
    const uint64_t target_rel_w_length = 2u * (uint64_t)grid_w - 1u;
    if (target_rel_h_length > (uint64_t)UOCR_SAM_MAX_REL_POS_SIZE ||
        target_rel_w_length > (uint64_t)UOCR_SAM_MAX_REL_POS_SIZE) {
        return metal_fail(error, error_size, "Metal SAM relative-position attention target rel-pos overflow");
    }

    const uint64_t max_buffer_length = metal_device_max_buffer_length(ctx->device);
    if (input_bytes > max_buffer_length || output_bytes > max_buffer_length ||
        rel_h_bytes > max_buffer_length || rel_w_bytes > max_buffer_length) {
        return metal_fail(error,
                          error_size,
                          "Metal SAM relative-position attention buffers exceed maxBufferLength %llu",
                          (unsigned long long)max_buffer_length);
    }

    @autoreleasepool {
        const char *function_name = output_type == UOCR_METAL_DENSE_OUTPUT_F16 ?
                                        "uocr_sam_rel_pos_attention_flash_f16_to_f16" :
                                        "uocr_sam_rel_pos_attention_flash_f16_to_f32";
        id<MTLComputePipelineState> pipeline = metal_get_pipeline(ctx, function_name, error, error_size);
        if (pipeline == nil) {
            return 0;
        }

        NSUInteger q_offset = 0u;
        id<MTLBuffer> q_src = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                                           q_f16,
                                                                           (NSUInteger)input_bytes,
                                                                           MTLResourceStorageModeShared,
                                                                           &q_offset);
        if (q_src == nil) {
            return metal_fail(error, error_size, "failed to allocate Metal SAM relative-position attention Q buffer");
        }
        q_src.label = @"uocr_sam_rel_pos_attention_q_f16";

        NSUInteger k_offset = 0u;
        id<MTLBuffer> k_src = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                                           k_f16,
                                                                           (NSUInteger)input_bytes,
                                                                           MTLResourceStorageModeShared,
                                                                           &k_offset);
        if (k_src == nil) {
            [q_src release];
            return metal_fail(error, error_size, "failed to allocate Metal SAM relative-position attention K buffer");
        }
        k_src.label = @"uocr_sam_rel_pos_attention_k_f16";

        NSUInteger v_offset = 0u;
        id<MTLBuffer> v_src = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                                           v_f16,
                                                                           (NSUInteger)input_bytes,
                                                                           MTLResourceStorageModeShared,
                                                                           &v_offset);
        if (v_src == nil) {
            [k_src release];
            [q_src release];
            return metal_fail(error, error_size, "failed to allocate Metal SAM relative-position attention V buffer");
        }
        v_src.label = @"uocr_sam_rel_pos_attention_v_f16";

        NSUInteger rel_h_offset = 0u;
        id<MTLBuffer> rel_h = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                                           rel_pos_h_f16,
                                                                           (NSUInteger)rel_h_bytes,
                                                                           MTLResourceStorageModeShared,
                                                                           &rel_h_offset);
        if (rel_h == nil) {
            [v_src release];
            [k_src release];
            [q_src release];
            return metal_fail(error, error_size, "failed to allocate Metal SAM relative-position H buffer");
        }
        rel_h.label = @"uocr_sam_rel_pos_h_f16";

        NSUInteger rel_w_offset = 0u;
        id<MTLBuffer> rel_w = metal_new_or_retain_vision_buffer_with_bytes(ctx,
                                                                           rel_pos_w_f16,
                                                                           (NSUInteger)rel_w_bytes,
                                                                           MTLResourceStorageModeShared,
                                                                           &rel_w_offset);
        if (rel_w == nil) {
            [rel_h release];
            [v_src release];
            [k_src release];
            [q_src release];
            return metal_fail(error, error_size, "failed to allocate Metal SAM relative-position W buffer");
        }
        rel_w.label = @"uocr_sam_rel_pos_w_f16";

        NSUInteger dst_offset = 0u;
        int dst_needs_copy = 1;
        id<MTLBuffer> dst = metal_new_or_retain_vision_output_buffer(ctx,
                                                                     out,
                                                                     (NSUInteger)output_bytes,
                                                                     MTLResourceStorageModeShared,
                                                                     &dst_offset,
                                                                     &dst_needs_copy);
        if (dst == nil) {
            [rel_w release];
            [rel_h release];
            [v_src release];
            [k_src release];
            [q_src release];
            return metal_fail(error, error_size, "failed to allocate Metal SAM relative-position attention output buffer");
        }
        dst.label = @"uocr_sam_rel_pos_attention_output";
        metal_zero_buffer_range(dst, dst_offset, (NSUInteger)output_bytes);

        id<MTLCommandBuffer> cb = metal_new_command_buffer(ctx);
        if (cb == nil) {
            [dst release];
            [rel_w release];
            [rel_h release];
            [v_src release];
            [k_src release];
            [q_src release];
            return metal_fail(error, error_size, "failed to create Metal SAM relative-position attention command buffer");
        }
        cb.label = @"uocr_sam_rel_pos_attention_command_buffer";

        id<MTLComputeCommandEncoder> enc = metal_compute_command_encoder(ctx, cb);
        if (enc == nil) {
            [dst release];
            [rel_w release];
            [rel_h release];
            [v_src release];
            [k_src release];
            [q_src release];
            return metal_fail(error, error_size, "failed to create Metal SAM relative-position attention command encoder");
        }

        uocr_metal_sam_rel_pos_attention_params params;
        params.windows = n_windows;
        params.grid_width = grid_w;
        params.grid_height = grid_h;
        params.tokens_per_window = (uint32_t)tokens;
        params.heads = UOCR_SAM_ATTENTION_HEADS;
        params.head_dim = UOCR_SAM_HEAD_DIM;
        params.rel_pos_h_length = rel_pos_h_length;
        params.rel_pos_w_length = rel_pos_w_length;
        params.scale = 1.0f / sqrtf((float)UOCR_SAM_HEAD_DIM);
        params.batch_size = 1u;
        params.reserved1 = 0u;
        params.reserved2 = 0u;

        const NSUInteger threads_per_group = 128u;
