        [enc setBuffer:v_src offset:v_offset atIndex:2u];
        [enc setBuffer:rel_h offset:rel_h_offset atIndex:3u];
        [enc setBuffer:rel_w offset:rel_w_offset atIndex:4u];
        [enc setBuffer:dst offset:dst_offset atIndex:5u];
