        [enc dispatchThreadgroups:MTLSizeMake((NSUInteger)UOCR_SAM_ATTENTION_HEADS, query_blocks, (NSUInteger)n_windows)
             threadsPerThreadgroup:MTLSizeMake(threads_per_group, 1u, 1u)];
