        input_bytes > (uint64_t)SIZE_MAX || top_ids_bytes > (uint64_t)SIZE_MAX ||
        top_weights_bytes > (uint64_t)SIZE_MAX || weight_bytes > (uint64_t)SIZE_MAX ||
