        input_bytes > (uint64_t)SIZE_MAX || output_bytes > (uint64_t)SIZE_MAX || cu_bytes > (uint64_t)SIZE_MAX ||
        attention_groups > (uint64_t)UINT32_MAX) {
        return metal_fail(error,
                          error_size,
